// ══════════════════════════════════════════════════════════════
// 【1】机场英语全攻略
// ══════════════════════════════════════════════════════════════
window.QB_EN_AIRPORT=[
  {c:'出国',q:'在机场值机（Check-in）时，工作人员问你"Do you have any baggage to check in?"，你应该回答什么？',o:['No, I\'ll carry it on.（没有，我带登机）','Yes, I want a window seat.（我要靠窗座）','My passport is here.（护照在这里）','I need a visa.（我需要签证）'],a:0,e:'"check in baggage"指托运行李。carry-on是随身行李，没有托运行李时说"No, I\'ll carry it on."'},
  {c:'出国',q:'海关人员问"What\'s the purpose of your visit?"，正确回答是？',o:['Tourism（旅游）','Terminal（航站楼）','Departure（出发）','Customs（海关）'],a:0,e:'purpose of visit=访问目的。旅游说Tourism，商务说Business，探亲说Visiting family'},
  {c:'出国',q:'"Your flight is boarding at Gate 32."这句话的意思是？',o:['你的航班在32号登机口登机','你的航班已延误32分钟','32号行李转盘有你的行李','第32排是你的座位'],a:0,e:'gate=登机口，boarding=登机。这是机场广播中非常常见的句型。'},
  {c:'出国',q:'你的行李没有到达，需要去找工作人员。你应该说什么？',o:['My luggage is missing / hasn\'t arrived.','I lost my passport.','Where is the gate?','I need to check in.'],a:0,e:'luggage/baggage=行李，missing=丢失。也可说"My suitcase didn\'t come out."'},
  {c:'出国',q:'"Departure"和"Arrival"分别是什么意思？',o:['出发；到达','到达；出发','检票；安检','托运；取行李'],a:0,e:'Departure=出发（离开），Arrival=到达（抵达）。机场标牌必须认识的两个词。'},
  {c:'出国',q:'安检时工作人员说"Please remove your shoes and belt."，你应该？',o:['脱鞋和皮带放传送带','只摘手表','把护照给他','出示登机牌'],a:0,e:'remove=脱掉/取下。过安检时鞋子、皮带、金属物品都需要放到篮子里通过X光机。'},
  {c:'出国',q:'你听到广播"This is the final boarding call for flight CA001."，说明什么？',o:['这是CA001航班的最后登机通知','CA001航班已经起飞','CA001航班已取消','CA001航班延误1小时'],a:0,e:'final boarding call=最后登机广播。听到这个你必须马上跑去登机口！'},
  {c:'出国',q:'在机场如何询问免税店的位置？',o:['Where is the duty-free shop?','Where is the check-in counter?','Where can I get my visa?','How much is the ticket?'],a:0,e:'duty-free shop=免税店。duty=税，duty-free=免税的。机场常见词汇。'},
  {c:'出国',q:'"Window seat or aisle seat?"，如果你想靠走道，应该回答？',o:['Aisle seat, please.','Window seat, please.','Middle seat, please.','I don\'t mind.（都可以）'],a:0,e:'window seat=靠窗座，aisle seat=靠走道座（aisle发音为"I-ul"）。靠窗好看风景，靠走道出行方便。'},
  {c:'出国',q:'你需要转机，不知道去哪里。你应该问：',o:['Where is the transit/connecting flight area?','Where is the baggage claim?','Can I upgrade my seat?','What\'s the WiFi password?'],a:0,e:'transit/connecting flight=转机。transit area=中转区。转机时要注意时间，别错过航班！'},
  {c:'出国',q:'"Your visa has expired."这句话是什么意思？',o:['你的签证已过期','你的签证即将到期','你的护照已过期','你没有申请签证'],a:0,e:'expire=到期，expired=已过期。visa=签证。出境前一定要确认签证有效期！'},
  {c:'出国',q:'机场的"Baggage Claim"区域是做什么用的？',o:['取托运行李','办理值机','申请签证','购买机票'],a:0,e:'Baggage Claim=行李领取处。飞机落地后去这里等你的托运行李。'},
];

// ══════════════════════════════════════════════════════════════
// 【2】酒店入住英语
// ══════════════════════════════════════════════════════════════
window.QB_EN_HOTEL=[
  {c:'出国',q:'酒店前台说"Do you have a reservation?"，你应该回答？',o:['Yes, I have a reservation under Zhang Wei.（是的，预订在张伟名下）','I want a double room.（我要双人房）','Where is the elevator?（电梯在哪里）','Can I have a wake-up call?（能帮我叫早吗）'],a:0,e:'reservation=预订。办理入住时要说名字，工作人员会查你的预订记录。'},
  {c:'出国',q:'你想要一间有海景的房间，应该说：',o:['I\'d like a room with an ocean view.','I need a room with a king-size bed.','Can I have a non-smoking room?','I want to check out early.'],a:0,e:'ocean view=海景，mountain view=山景，city view=城市景观。view=景色/景观。'},
  {c:'出国',q:'"Check-out time is 12:00 noon."意思是什么？',o:['退房时间是中午12点','入住时间是中午12点','叫早服务在中午12点','餐厅供应午餐到12点'],a:0,e:'check-out=退房（check-in=入住）。通常酒店退房时间是中午12点，入住是下午3点。'},
  {c:'出国',q:'你的房间空调坏了，你应该打电话说什么？',o:['The air conditioning in my room isn\'t working.','My room is too noisy.','I need more towels.','Can I upgrade my room?'],a:0,e:'air conditioning=空调，isn\'t working=不能用了/坏了。也可以说"The A/C is broken."'},
  {c:'出国',q:'早餐是否包含在房价内？你应该问：',o:['Is breakfast included in the room rate?','What time is breakfast?','Where is the restaurant?','Can I have room service?'],a:0,e:'included=包含，room rate=房价。很多酒店早餐需要额外付费，入住前要问清楚。'},
  {c:'出国',q:'"I\'d like to extend my stay for one more night."的意思是？',o:['我想多住一晚','我想提前一天退房','我需要更换房间','我要叫客房服务'],a:0,e:'extend=延长，stay=停留/住宿。如果计划有变需要多住，提前告知前台！'},
  {c:'出国',q:'你需要更多毛巾，应该对客房服务说：',o:['Could I have some extra towels, please?','Can you fix the TV?','I need to report a noise complaint.','Please clean my room.'],a:0,e:'extra=额外的，towels=毛巾。也可以说"Can I get more towels?"语气更随意。'},
  {c:'出国',q:'"The WiFi password is on the card on your desk."这句话的意思是？',o:['WiFi密码在桌上的卡片上','WiFi信号不好请重启路由器','桌上有你的账单','密码在大堂询问台'],a:0,e:'WiFi password=无线网络密码，card=卡片，desk=书桌。入住后问工作人员这句话！'},
  {c:'出国',q:'你想让前台帮你叫出租车，应该说：',o:['Could you call a taxi for me?','Can I borrow an umbrella?','Where is the nearest subway?','I\'d like to check in now.'],a:0,e:'call a taxi=叫出租车。也可以说"Can you arrange a car for me?"或"Is there a shuttle service?"'},
  {c:'出国',q:'"Do Not Disturb"牌子挂在门口意味着？',o:['请勿打扰（不要来打扫/敲门）','欢迎清洁服务','房间已无人入住','酒店已满员'],a:0,e:'"Do Not Disturb"=请勿打扰。这是酒店门把上的标牌，挂上去后服务员不会来敲门。'},
];

// ══════════════════════════════════════════════════════════════
// 【3】交通出行英语
// ══════════════════════════════════════════════════════════════
window.QB_EN_TRANSPORT=[
  {c:'出国',q:'你要去博物馆，询问路人的正确表达是？',o:['Excuse me, how do I get to the museum?','Where can I buy a ticket?','Is this seat taken?','What time does it open?'],a:0,e:'"How do I get to...?"=怎么去……？这是问路最自然的表达方式。'},
  {c:'出国',q:'司机说"The fare is 15 dollars."，意思是？',o:['车费是15美元','车程大约15分钟','我们还有15分钟到达','这辆车可以坐15人'],a:0,e:'fare=车费/票价，也用于公共交通（bus fare, train fare）。'},
  {c:'出国',q:'你在伦敦，想乘坐地铁（地下铁）应该找？',o:['The Underground / The Tube','The Subway (美式)','The Tram','The Overground'],a:0,e:'英国地铁叫Underground或Tube，美国叫Subway，香港叫MTR，新加坡叫MRT。注意区分！'},
  {c:'出国',q:'"This train is out of service."是什么意思？',o:['这列火车停止运营/不载客','这列火车准时出发','这是最后一班火车','这列火车已满员'],a:0,e:'out of service=停止服务。在地铁/公交上看到这个，说明这趟不载客，需要等下一趟。'},
  {c:'出国',q:'你想在公共汽车上询问这辆车是否到市中心，应该说？',o:['Does this bus go to the city center?','What\'s the next stop?','How much is the ticket?','Where is the bus stop?'],a:0,e:'go to=去往某地。city center=市中心（英式），downtown=市中心（美式）。'},
  {c:'出国',q:'租车时工作人员问"Do you have an international driver\'s license?"，这是问？',o:['你有没有国际驾照','你需要保险吗','你要租多少天','你要全险还是基础险'],a:0,e:'international driver\'s license=国际驾照。出境驾车需要国际驾照，中国驾照在大多数国家不通用！'},
  {c:'出国',q:'"The next station is Piccadilly Circus. Doors will open on the left."这是什么意思？',o:['下一站是皮卡迪利广场，门会在左侧打开','请从左侧出口离开','皮卡迪利广场换乘指示','广场在地铁站左边出口'],a:0,e:'这是伦敦地铁的经典广播。next station=下一站，doors open on the left/right=门在左/右侧开。'},
  {c:'出国',q:'你想打Uber/出租车去机场，告诉司机你要去T3航站楼，应该说？',o:['Please take me to Terminal 3 of the airport.','I need to go to Gate 3.','Take me to the subway station.','Can you drive faster?'],a:0,e:'terminal=航站楼（T1/T2/T3/T3），gate=登机口。到了机场再找登机口，告诉司机terminal即可。'},
  {c:'出国',q:'"Transfer"在交通中的意思是？',o:['换乘/转乘','终点站','单程票','往返票'],a:0,e:'transfer=换乘，也可指转机（transfer flight）。"I need to transfer at the next station."=我要在下一站换乘。'},
  {c:'出国',q:'火车票上写"Return ticket"，说明这是？',o:['往返票','单程票','头等舱票','学生票'],a:0,e:'return ticket=往返票，one-way ticket=单程票。英式英语用return，美式用round-trip。'},
];

