window.QB_EN_SHOPPING=[
  {c:'出国',q:'你在市场里看到一件衣服想问价格，应该说？',o:['How much does this cost? / What\'s the price?','Can I try this on?','Do you have this in a larger size?','I\'ll take it!'],a:0,e:'"How much does this cost?"和"What\'s the price?"都是问价格的标准表达，非常常用。'},
  {c:'出国',q:'你觉得价格太贵了，想砍价，应该说？',o:['That\'s too expensive. Can you give me a discount?','I\'ll take two!','Can I pay by credit card?','Do you accept cash?'],a:0,e:'"Can you give me a discount?"=能给我打折吗？discount=折扣。砍价要笑着说，语气不要太强硬！'},
  {c:'出国',q:'你想试穿一件衬衫，应该说？',o:['May I try this on?','Can I have this in blue?','What size do you have?','Is this on sale?'],a:0,e:'"try on"=试穿（衣服/鞋子）。试衣间叫fitting room或changing room。'},
  {c:'出国',q:'"This item is on sale."的意思是？',o:['这件商品正在打折','这件商品已售完','这件商品不能退换','这件商品是限量版'],a:0,e:'on sale=打折促销（注意：不是"待售"！待售是for sale）。on sale常见于商场促销标牌。'},
  {c:'出国',q:'你买了东西回到酒店发现有质量问题，想退货，应该说？',o:['I\'d like to return this / get a refund. It has a defect.','Can I exchange this for a different color?','I lost my receipt.','This is too small for me.'],a:0,e:'return=退货，refund=退款，defect=缺陷/质量问题。退货时一定要保留收据（receipt）！'},
  {c:'出国',q:'收银员问"Would you like a bag?"，你不需要购物袋应该说？',o:['No, thank you. I\'ll use my own bag.','Yes, I\'ll pay by card.','No, I don\'t want this anymore.','Can I have two bags?'],a:0,e:'许多国家超市的购物袋需要付费，自带袋子既省钱又环保。也可以直接说"No bags, thanks."'},
  {c:'出国',q:'你想用信用卡支付，应该问：',o:['Do you accept credit cards? / Can I pay by card?','Can I get a discount?','Do you have a loyalty card?','What\'s the exchange rate?'],a:0,e:'"pay by card"=刷卡支付，"pay by cash"=现金支付，"pay by phone"=手机支付。'},
  {c:'出国',q:'"This is a souvenir shop."这句话的意思是？',o:['这是一家纪念品商店','这是一家超市','这是一家免税店','这是一家跳蚤市场'],a:0,e:'souvenir=纪念品，souvenir shop=纪念品商店。旅游景点附近必有souvenir shop！'},
  {c:'出国',q:'你想要特定尺码的商品，应该问？',o:['Do you have this in size M / in a medium?','How much is the discount?','Is this waterproof?','Can you wrap it as a gift?'],a:0,e:'size M=中码，size S/M/L/XL是国际通用码。也可以问"Do you have a bigger/smaller size?"'},
  {c:'出国',q:'"The store is closing in 10 minutes."意思是？',o:['商店还有10分钟关门','这件商品打了10%折扣','请在10分钟内结账','店内共有10种商品'],a:0,e:'closing=关闭/打烊，closing time=打烊时间。听到这个要赶快结账啦！'},
];

