window.QB_EN_CULTURE.push(
  {c:'出国',q:'在法国，见面时通常的问候方式是？',o:['亲脸颊（La Bise，两颊互贴，通常是朋友间）或握手（正式场合）','鞠躬','合十礼（wai）','拥抱'],a:0,e:'La Bise（亲脸颊）是法国朋友/熟人间常见的问候方式，通常两侧各一次（地区不同次数不同）。初次见面的正式场合则握手。不必主动发起La Bise，跟着法国人做就好。'},
  {c:'出国',q:'在德国，以下哪种情况是失礼的行为？',o:['在餐厅大声嗳气（打嗝）','在正确的垃圾桶里分类扔垃圾','在商店门口排队时保持距离','在公共场所遵守交通灯'],a:0,e:'德国垃圾分类严格（废纸/有机物/塑料/玻璃分类），随地乱扔和不守时都是大忌。德国人极其守时，约定8点见面，8:00到就是准时，8:05就算迟到，一定要预先说明！'},
  {c:'出国',q:'在美国，陌生人之间通常的对话开场白"How are you?"期望什么样的回答？',o:['简短积极的回答（Fine, thanks! / Good, thanks! / Great!）而非真实的心情描述','详细讲述你当天的心情和烦恼','反问对方"How are YOU?"然后沉默','不需要回答直接进入正题'],a:0,e:'美国式"How are you?"通常是一种打招呼的礼节，不是真的在问你好不好。标准回答是"Good/Fine/Great, thanks! How about you?"，简短正面即可。把真实的心情长篇大论说出来反而会让对方尴尬。'},
  {c:'出国',q:'在英国，"queuing"（排队）文化有多重要？',o:['英国人排队文化极强，插队是非常严重的失礼行为，甚至可能引发言语冲突','英国人不在乎排队顺序','只在超市结账时排队','队列文化只适用于巴士站'],a:0,e:'Queue（排队）在英国几乎是国家宗教级别的习俗，从巴士站到超市再到观光景点，守序排队是基本素养。插队（jump the queue）会引来周围人的白眼甚至直接被批评。'},
  {c:'出国',q:'在中东（如阿联酋迪拜）旅游，关于着装，正确的是？',o:['在公共场所应着装保守（遮盖肩膀和膝盖），进入清真寺需穿着更为保守；在海滩和度假村则较宽松','可以穿任何服装，没有任何限制','女性必须全程穿罩袍','外国游客无需遵守当地着装规定'],a:0,e:'迪拜实行双重标准：公共场所（购物中心、街道、清真寺）要求保守着装，但在度假村、海滩、游泳池区域则接受泳装。进入清真寺女性必须穿覆盖全身的服装，可在清真寺入口借用长袍。'},
  {c:'出国',q:'在日本餐厅，以下哪个行为是不礼貌的？',o:['用筷子插着食物立在饭碗里（类似祭祀的香烛）','用双手拿筷子','把碗端起来靠近嘴巴','喝汤时发出声音（日本认为这是表示好吃的方式）'],a:0,e:'日本餐桌禁忌：①不把筷子插在饭碗里（象征丧葬）②不把食物从筷子传到筷子（也是葬礼习俗）③不用筷子指人。喝面条时发出声音在日本是完全可以接受的，甚至被认为是赞美厨师！'},
  {c:'出国',q:'在印度餐厅吃饭，以下哪项符合当地传统礼仪？',o:['用右手（或餐具）吃饭，用手抓饭在传统家庭和特定餐厅中是正常且被接受的','必须使用刀叉','用左手吃饭也没问题','不能与服务员进行眼神接触'],a:0,e:'印度传统用右手吃饭（左手被认为不洁净，传统上用于如厕清洁）。在传统印度餐厅和家庭，用手抓饭（尤其是南印度的香蕉叶餐）是正常且被鼓励的，表示你真正融入了当地文化。'},
  {c:'出国',q:'"Overtourism"（过度旅游）是什么问题？对旅行者有什么启示？',o:['景点因游客过多导致环境破坏、当地居民生活受损、体验下降；提示旅行者考虑错峰出行、探索冷门目的地','越多游客越好，带动当地经济','只是媒体炒作的概念','和旅行者没有关系，是景区的问题'],a:0,e:'Venice（威尼斯）、Santorini（圣托里尼）、Machu Picchu（马丘比丘）等地正面临Overtourism（过度旅游）问题。作为负责任的旅行者：①避开高峰季②尊重当地社区③不在禁止区域拍照④探索非主流目的地。'},
  {c:'出国',q:'在东南亚国家（如泰国、缅甸、老挝），进入佛教寺庙的着装要求是？',o:['需遮盖肩膀和膝盖，通常需脱鞋；穿吊带/短裤/短裙进入寺庙是不尊重的行为','可以穿任何服装','只有女性需要遮盖','只需要脱帽'],a:0,e:'东南亚寺庙着装规定：①遮肩（no bare shoulders）②遮膝（no shorts/short skirts）③进门脱鞋④进入某些圣地需脱袜⑤女性不能触碰僧侣。很多寺庙门口有出借或出售的纱笼（sarong）供游客使用。'},
  {c:'出国',q:'在巴西，见面的标准问候方式是？',o:['拥抱（abraço）和亲脸颊（beijinho）；巴西人非常热情，肢体接触在社交中很自然','握手','鞠躬','仅点头即可'],a:0,e:'巴西文化极为热情开放，初次见面亲脸颊（通常是右脸一次或两次）和拥抱是常见礼节，不要感到尴尬。"Tudo bem?"（葡语"一切都好吗？"）是常见问候，回答"Tudo bem!"即可。'},
  {c:'出国',q:'"Personal space"（个人空间）的概念在不同文化中有什么差异？',o:['北美/北欧人需要更大的个人空间（约1米），地中海/拉丁美洲/中东人交流距离更近；这在跨文化交流中要注意','所有文化对个人空间要求相同','亚洲人需要最大的个人空间','个人空间在商务场合不重要'],a:0,e:'Personal space（近端距离）文化差异显著：英美需要约1米（arm\'s length）；意大利、巴西、阿拉伯国家的人交流距离更近，经常有肢体接触。跨文化交流时，跟着对方的节奏来，不要表现出明显的不适。'},
  {c:'出国',q:'旅游时拍照的礼仪，以下哪项是不应该做的？',o:['未经许可拍摄当地居民的特写照片','在允许拍照的景点拍照','在博物馆没有禁止摄影的区域拍照','用手机拍摄公共街景'],a:0,e:'拍摄他人时的基本礼仪：①拍特写前征得同意（"May I take your photo?"）②某些文化（如部分原住民社区）认为拍照会夺走灵魂，要绝对尊重③在宗教场所拍照前确认是否允许④不在明显禁止拍照的区域拍照。'}
);

