// 机场补充 ×5
window.QB_EN_AIRPORT.push(
  {c:'出国',q:'"Priority boarding"（优先登机）通常适用于哪些旅客？',o:['商务舱/头等舱旅客、高级常旅客、带幼儿的家庭、有特殊需求的旅客','所有旅客','最后购票的旅客','持有特定信用卡的旅客'],a:0,e:'Priority boarding=优先登机，一般顺序：1.需要协助的旅客 2.头等舱/商务舱 3.高级常旅客会员 4.带幼儿家庭 5.其余旅客按舱位区域分批。'},
  {c:'出国',q:'"Turbulence"（气流颠簸）发生时，最安全的做法是？',o:['回到座位系好安全带（fasten seatbelt），保持镇定，不要站立或走动','站起来抓扶手','立即通知空乘人员','打开舷窗确认飞机状况'],a:0,e:'Turbulence（颠簸）是飞行中的正常现象。机长会打开fasten seatbelt（系安全带）指示灯，此时必须立即坐好系好安全带。即使指示灯未亮，飞行中建议始终系好安全带。'},
  {c:'出国',q:'机票上"PNR"代码（如：XYZABC）是什么？',o:['旅客姓名记录/订单确认号（Passenger Name Record），用于在系统中查找你的订单','飞机型号','座位号','行李条形码'],a:0,e:'PNR（Passenger Name Record）=订单确认号/预订参考码，通常是6位字母数字组合。机场自助值机、网上改签、联系航空公司客服时都需要用到这个号码。'},
  {c:'出国',q:'在候机时，机场广播说"Paging passenger Zhang Wei, please come to gate C8."，这意味着？',o:['张伟旅客被点名，需要立即前往C8登机口（可能是行李问题、证件问题或即将关闭登机口）','张伟旅客的航班被取消','C8登机口更换了','张伟旅客需要办理行李托运'],a:0,e:'被机场广播点名（Paging）通常是紧急情况：忘记办理值机、行李需要确认、证件问题或航班即将关闭。听到自己名字立即前往指定地点！'},
  {c:'出国',q:'"Dry run"和"Stopover"在国际旅行中有什么区别？',o:['Dry run不是旅行术语；Stopover=中途停留（超过24小时可出机场游览）','两者都指转机等候','Dry run指直飞，Stopover指转机','两者含义相同'],a:0,e:'Stopover（中途停留）指转机时在某城市停留超过24小时，很多旅客利用此机会游览第二个城市。如新加坡、迪拜、伊斯坦布尔都支持免签过境游（Free Transit Visa）。'}
);

// 餐厅补充 ×5
window.QB_EN_RESTAURANT.push(
  {c:'出国',q:'"Complimentary"在餐厅中的含义是？',o:['免费赠送的（如餐前面包、开胃小食、餐后薄荷糖）','表示赞美的（这是另一个含义）','含有补充成分的','特别推荐的'],a:0,e:'Complimentary在餐厅中=免费赠送，例如：complimentary bread（免费餐前面包）、complimentary dessert（免费甜点，可能是庆祝生日时餐厅赠送的）。'},
  {c:'出国',q:'你对餐厅的食物和服务非常满意，想给好评，在哪些平台上留评？',o:['Google Maps、TripAdvisor、Yelp（美国）、OpenRice（亚洲）都是常用的餐厅评价平台','只能在餐厅自己的网站留评','只能当面告诉服务员','在Facebook写状态'],a:0,e:'TripAdvisor和Google Maps是全球最通用的旅行/餐厅评价平台。好评对小餐厅意义重大，有很好的体验记得留评！评价时可以说"Highly recommend the seafood pasta!"（强烈推荐海鲜意面！）'},
  {c:'出国',q:'"Prix fixe"菜单（套餐）通常会包括几道菜？',o:['通常是三道菜：前菜（Starter/Appetizer）、主菜（Main Course）、甜点（Dessert）','只有一道主菜','四道菜加酒','五道菜配酒'],a:0,e:'三道菜套餐（Three-course meal）是最常见的Prix fixe格式：Appetizer（前菜/开胃）→ Main course（主菜）→ Dessert（甜点）。有时还包括soup（汤）或cheese course（奶酪）。'},
  {c:'出国',q:'服务员说"Can I interest you in any dessert today?"你不想要甜点，礼貌的回答是？',o:['No, thank you. Just the bill / check, please.','No.','I\'m full.','Maybe next time.'],a:0,e:'"No, thank you. Just the bill, please."是最礼貌完整的拒绝方式，同时告知服务员可以结账。也可以说"I\'ll pass on dessert, thanks. Could we have the check?"'},
  {c:'出国',q:'在美式餐厅，"Free refills"是什么意思？',o:['饮料免费续杯（常见于可乐、咖啡、iced tea等）','免费续餐','免费的小菜','买一赠一'],a:0,e:'Free refills=免费续杯，是美国餐厅（尤其是Diner和连锁餐厅）的常见服务。点一杯汽水，服务员会不断帮你续杯，不另收费。这在欧洲和亚洲非常少见！'}
);

// 词汇补充 ×5
window.QB_EN_VOCAB_TRAVEL.push(
  {c:'词汇',q:'"Guidebook"（旅行指南书）和"Travel blog"（旅行博客）各有什么优缺点？',o:['Guidebook：系统全面，但信息可能过时；Travel blog：即时更新，个人视角丰富，但主观性强，需筛选','Guidebook一定比博客准确','博客比书更权威','两者内容完全相同'],a:0,e:'Lonely Planet、Rough Guides是最著名的纸质旅行指南。现在很多旅行者结合使用：用Guidebook了解背景和必游地点，用Blog/YouTube获取最新实用信息和个人体验。'},
  {c:'词汇',q:'"Peak season"和"Off-season"对旅行预算有什么影响？',o:['旺季（Peak season）价格高、人多；淡季（Off-season）价格低、清静，但部分景点/设施可能关闭','旺季价格更便宜，因为航空公司会打折','淡季是最糟糕的旅行时间','两者价格相同'],a:0,e:'旅行省钱技巧：在Off-season（淡季）或Shoulder season（平季，旺季和淡季之间）出行，机票和酒店价格可比旺季低30-50%。且人少、体验更好，只需接受部分设施关闭的可能。'},
  {c:'词汇',q:'"Airport tax"（机场税）和"Departure tax"（离境税）是旅客需要支付的什么费用？',o:['使用机场设施和离开该国所需支付的税费，通常已包含在机票价格中，有时需在机场现金支付','一种额外购买的服务','仅在特定国家存在的签证费','购买免税商品需要支付的税'],a:0,e:'机场税/离境税是大多数国家对离境旅客收取的费用，现代机票通常already included（已包含）在票价中。少数目的地（如部分加勒比岛国）仍需在机场以现金单独缴纳，出发前要确认！'},
  {c:'词汇',q:'"Cultural immersion"（文化沉浸）旅行是指？',o:['深度融入当地生活（住民宿、学语言、与当地人交流、参与本地活动），而非走马观花的景点打卡','参观多个文化博物馆','在目的地购买文化纪念品','只看歌舞表演'],a:0,e:'Cultural immersion=文化沉浸，是现代旅行的高级形态。可以通过：住当地民宿/Couchsurf、上当地烹饪课、学几句当地语言、参加社区活动、乘坐公共交通等方式实现。'},
  {c:'词汇',q:'"Frequent flyer miles"（常旅客里程）有什么用处？',o:['积累到一定数量可以兑换免费机票、升舱、酒店住宿等奖励','是一种虚拟货币可以换真实人民币','只能在一家航空公司使用','是信用卡积分的另一种说法'],a:0,e:'Frequent flyer miles（常旅客里程）是航空公司的忠诚度计划。经常出差者可以积累大量里程，兑换Business Class（商务舱）或免费机票。中国国际：国航凤凰会、南航明珠，国际：United MileagePlus、Star Alliance。'}
);

// 语法补充 ×5
window.QB_EN_GRAMMAR.push(
  {c:'语法',q:'"I\'d rather..."和"I prefer..."有什么区别？',o:['I\'d rather后接动词原形（I\'d rather walk）；I prefer后接名词或V-ing（I prefer walking）；含义相近','两者语法完全相同','I\'d rather更礼貌','I prefer只用于书面'],a:0,e:'两种表达偏好的方式：I\'d rather walk than take a taxi.（宁愿走路也不坐车）/ I prefer walking to taking a taxi.（更喜欢走路而不是坐车）旅行中表达偏好很常用！'},
  {c:'语法',q:'在餐厅或商店，"for here or to go?"是在问什么？',o:['在这里吃（堂食）还是带走（外带）？','你是从哪里来的？','现在还是稍后？','一份还是两份？'],a:0,e:'"For here or to go?"是美式快餐和咖啡店的常见问句。回答：For here（堂食）/ To go（外带，英式叫takeaway）。英式问法可能是"Eat in or take away?"'},
  {c:'语法',q:'表达"对不起，我没听清楚"的几种方式，哪个最礼貌？',o:['I beg your pardon? / Pardon me? / I\'m sorry, I didn\'t quite catch that.','What?（单字，显得无礼）','Huh?','Speak up!（命令语气，失礼）'],a:0,e:'礼貌程度排序（高到低）："I beg your pardon?"（最正式）>"Pardon?">"I\'m sorry, could you repeat that?">"Could you speak more slowly?">"What?"（太直接，可能显得无礼）'},
  {c:'语法',q:'"Would you like a hand with that?"是什么意思？',o:['我可以帮你吗？（hand=帮助，固定短语）','你手受伤了吗？','你要握手吗？','你需要手套吗？'],a:0,e:'"Give someone a hand"=帮某人忙（与鼓掌的hand意思不同）。"Would you like a hand with your luggage?"=需要我帮你搬行李吗？旅途中遇到需要帮助的人，这句话很实用。'},
  {c:'语法',q:'以下哪个句子表达"我找不到我的护照"是正确的？',o:['I can\'t find my passport. / I seem to have lost my passport.','I have lost passport.','My passport is losing.','I not find my passport.'],a:0,e:'"I can\'t find my passport."=我找不到我的护照（可能还在，只是找不到）/ "I\'ve lost my passport."=我丢了护照（确认丢失）。向警察或大使馆陈述时区分这两种情况很重要。'}
);

window.QB_EN_AIRPORT.push(
  {c:'出国',q:'在值机时，航空公司工作人员说"Your bag is overweight. The excess baggage fee is $50."，意思是？',o:['你的行李超重，需要支付50美元超重费','你的行李需要额外检查','你的行李被没收了','你的行李丢失了'],a:0,e:'overweight=超重，excess baggage fee=超重行李费。出国前务必确认航空公司的免费行李额（free baggage allowance），通常经济舱为20-23kg。'},
  {c:'出国',q:'"Gate change: Flight MU500 now departs from Gate A12."这则广播意味着？',o:['MU500航班登机口变更为A12','MU500航班已经起飞','MU500航班已取消','需要在A12重新值机'],a:0,e:'gate change=登机口变更。在机场候机时要时刻关注显示屏或广播，登机口可能临时更改。更改后要立刻前往新登机口！'},
  {c:'出国',q:'你拿到了一张"boarding pass"，上面显示"Seat 22F"，F代表什么？',o:['靠窗座（F通常是最靠窗的座位字母）','走道座','中间座','头等舱'],a:0,e:'国际航班座位排列通常：A/F=靠窗，C/D=走道，B/E=中间。宽体飞机（如波音777）可能是3-4-3座位，F通常是靠窗。'},
  {c:'出国',q:'在入境卡（Arrival Card/Immigration Form）上，"Occupation"一栏需要填写什么？',o:['你的职业','你的国籍','你的旅行目的','你的居住地址'],a:0,e:'Occupation=职业。常见填写：Student（学生）、Teacher（教师）、Engineer（工程师）、Businessman（商人）、Government Employee（政府职员）。'},
  {c:'出国',q:'海关官员问"Do you have anything to declare?"，如果你有携带超额现金，你应该？',o:['如实申报（Declare it honestly），否则可能面临没收和罚款','说"Nothing to declare"','把现金藏起来','让同行的朋友帮你携带'],a:0,e:'Declare=申报。大多数国家规定：携带超过一定金额的现金（如美国1万美元、中国2万元人民币）必须申报。隐瞒申报属违法行为，后果严重。'},
  {c:'出国',q:'机票上"OW"和"RT"分别代表什么？',o:['One Way（单程）和Round Trip（往返）','Online Waiting和Real Ticket','Overseas和Return','Other Way和Regular Ticket'],a:0,e:'OW=One Way（单程票），RT=Round Trip（往返票）。购票时注意区分，往返票通常比两张单程票便宜，但退改签规则不同。'},
  {c:'出国',q:'你在机场看到"Customs – Red Channel"和"Green Channel"，选择错误通道的后果是？',o:['可能面临检查和罚款：绿色通道是"无需申报"，红色通道是"需要申报"；若有申报物品却走绿色通道属违法','没有任何后果','绿色通道是VIP通道','红色通道是快速通道'],a:0,e:'Green Channel=无需申报（Nothing to Declare），Red Channel=需申报通道。携带超量物品、超额现金、特定食品或动植物必须走红色通道如实申报。'},
  {c:'出国',q:'"Checked baggage"和"carry-on baggage"的主要区别是？',o:['Checked baggage是托运行李（放行李舱）；carry-on是随身行李（带上飞机）','Checked是需要检查的行李，carry-on是免检行李','Checked baggage更贵','Carry-on行李没有重量限制'],a:0,e:'Checked baggage（托运行李）重量限制通常20-23kg；Carry-on（随身行李）限制通常7-10kg且有尺寸要求（如55×40×20cm）。液体类物品随身需符合100ml规定。'},
  {c:'出国',q:'你的航班被取消（cancelled），航空公司应该给你提供哪些权利？',o:['退款（refund）或改签其他航班，可能还有餐食和住宿补偿（视取消原因和当地法律）','什么补偿都没有','只提供改签，不退款','只在航空公司主动联系你时才有权利'],a:0,e:'航班取消的乘客权利：①选择全额退款或改签②若因航空公司原因取消，通常有餐食/住宿补偿③EU261法规规定欧盟航班取消还可获额外赔偿（€250-600）。'},
  {c:'出国',q:'登机牌上显示"Boarding Time: 14:30, Departure: 15:00"，你最晚几点要到登机口？',o:['14:30（登机时间），迟到可能导致无法登机','15:00（起飞时间）前到即可','14:45就行','登机口13:00开放，随时都行'],a:0,e:'Boarding Time（登机时间）≠Departure Time（起飞时间）。最迟要在Boarding Time前到达登机口，通常登机口在起飞前10-15分钟关闭（Gate Closed）。迟到=自动放弃登机！'},
  {c:'出国',q:'"Biometric passport"（生物特征护照）有什么特别之处？',o:['内含芯片，储存持照人面部特征、指纹等生物信息，可快速通过自动出入境通道','只是颜色不同的普通护照','需要特别签证才能使用','只有外交官才有'],a:0,e:'中国第二代电子护照内置芯片，储存个人生物特征数据。使用自助通关（E-gate/Automated border control）时无需人工检查，大幅减少排队时间。很多国家机场设有自助通关通道。'},
  {c:'出国',q:'你在等待行李时，看到了传送带上所有行李都取完了，但你的行李没有出现，第一步应该？',o:['前往行李查询处（Baggage Claim Desk/Lost and Found），填写行李丢失报告','等待下一个航班的行李传送带','打电话给旅行社','回到出发地等通知'],a:0,e:'行李未到要立即（在离开机场前）前往航空公司的行李服务柜台报告，填写Property Irregularity Report（PIR）。如已离开机场再报告，处理难度大幅增加。通常24-48小时内可找回。'},
  {c:'出国',q:'"Non-stop flight"和"Direct flight"有什么区别？',o:['Non-stop=全程不落地直达；Direct=途中可能有中途停靠（停了但不换飞机）；两者经常被混用，购票前要确认','两者完全相同','Non-stop更贵','Direct更快'],a:0,e:'严格来说：Non-stop=一路不停直飞目的地；Direct=飞机可能中途停靠但你不需要换飞机。实际购票时两词常混用，如需确认是否中途停站，看行程单上是否有中间城市。'},
  {c:'出国',q:'你在候机楼看到"Concourse A"的标牌，Concourse是什么意思？',o:['候机区/航站区（机场内连接各登机口的通道区域）','出发大厅','行李提取区','海关检查区'],a:0,e:'Concourse（航站区）=机场内连接各个登机口（Gates）的大型通道区域，通常设有商店、餐厅、休息区。大型机场通常有A、B、C等多个Concourse，要看登机牌上的Gate号确认在哪个区。'},
  {c:'出国',q:'机场免税店（Duty-Free Shop）在哪个区域？中国公民回国时从免税店购买的商品有什么限制？',o:['安检后（国际候机区）；中国居民回国免税限额通常为5000元人民币，超出需缴税','在值机大厅；没有任何限制','在到达出口；限额为1000元','出发前的市区免税店；限额为2000元'],a:0,e:'Duty-Free（免税店）位于安检之后、出境之前的国际候机区，仅对出境旅客开放。中国居民回国时，海关总署规定离境超过24小时可享受5000元人民币个人行李物品免税额。'},
  {c:'出国',q:'"Upgrade"在航空旅行中是什么意思？如何免费获得？',o:['升舱（从经济舱升至商务舱/头等舱）；常见方式：积累高级会员资格、航班超售时自愿接受改签、在柜台礼貌询问是否有空余商务舱位','付费购买更好的餐食','换一个靠窗座位','增加行李额'],a:0,e:'Upgrade=升舱。免费升舱的时机：①高级常旅客会员②航班超售（overbooking）时主动放弃座位换补偿③临近起飞时柜台礼貌询问④使用里程兑换升舱。成功率因航空公司、路线和航班占座率而异。'},
  {c:'出国',q:'你在飞机上，空乘人员说"We are beginning our descent. Please return your seat to the upright position."，你应该做什么？',o:['座椅靠背调回直立位置，收起餐桌板，系好安全带，准备降落','站起来拿行李','关闭所有电子设备','要求空乘给你毯子'],a:0,e:'Descent=下降阶段（飞机开始降落）。标准准备动作：①收起小桌板②调直座椅靠背③打开遮光板④系好安全带⑤确认行李放置妥当。通常在降落前约30分钟开始执行。'},
  {c:'出国',q:'"ESTA"是什么？前往美国旅行需要它吗？',o:['ESTA=电子旅行授权系统（Electronic System for Travel Authorization），仅适用于免签协议国公民（中国公民不可用，需申请B1/B2签证）','ESTA是中国公民赴美专用快速签证','ESTA等同于美国签证','所有人赴美都需要申请ESTA'],a:0,e:'ESTA仅供美国免签计划（VWP）成员国公民使用（如英国、日本、韩国等38个国家）。中国公民不在VWP范围内，赴美需要申请B1（商务）或B2（旅游）签证，在美国大使馆或领事馆预约面签。'},
  {c:'出国',q:'飞机上"Emergency exit row"（紧急出口排）的特殊要求是？',o:['坐该排的乘客需身体健康且愿意在紧急情况下协助打开舱门，通常腿部空间更大但责任更多','该排仅限头等舱乘客','该排禁止携带行李','该排乘客必须懂英语'],a:0,e:'Emergency exit row（紧急出口排）的乘客：①必须年满15岁②身体健康③愿意协助撤离。因此腿部空间更大，但选座时空乘会确认你是否接受相关责任，不符合条件者会被安排其他座位。'},
  {c:'出国',q:'"Aisle"（走道）座和"Middle seat"（中间座）在长途飞行中各有什么优缺点？',o:['走道：方便如厕和走动但会被打扰；中间：两侧都可靠但最不舒适；靠窗最适合睡觉','中间座是最好的座位','走道座没有任何缺点','靠窗座不能关窗'],a:0,e:'长途飞行选座参考：靠窗（A/F）=适合睡觉/不想被打扰；走道（C/D）=方便活动/腿可以伸展；中间（B/E）=最不理想，既要爬过两人又无法依靠。提前在网上选座比登机前现场选好很多！'},
  {c:'出国',q:'"Flight delay compensation"（航班延误赔偿）在哪些情况下可以申请？',o:['因航空公司原因（机械故障、机组原因等）导致延误，欧盟规定延误3小时以上可申请€250-600赔偿；恶劣天气等不可抗力则不赔偿','所有延误都可以申请赔偿','延误1小时即可申请','只在中国境内航班适用'],a:0,e:'EU261法规保护欧盟航班乘客权利最为完善：3小时以上延误且为航空公司原因，可申请€250-600赔偿（视距离而定）。中国国内航班参照民航局规定。购买旅行险后保险公司也会有一定赔偿。'},
  {c:'出国',q:'"I\'d like to request a special meal."在订机票时这句话用于什么目的？',o:['要求特殊餐食，如素食（Vegetarian）、清真（Halal）、儿童餐（Child Meal）等','升舱请求','额外行李申请','选择靠窗座位'],a:0,e:'Special Meal Request=特殊餐食申请，需提前（通常起飞前24小时）向航空公司提交。常见类型：VGML（纯素）、AVML（印式素食）、MOML（清真餐）、HNML（印度餐）、CHML（儿童餐）、GFML（无麸质）。'},
  {c:'出国',q:'你在机场看到"Lost & Found"，这个地方是做什么的？',o:['失物招领处，可以找回在机场遗失的物品','失去行李的投诉处','护照过期处理处','签证临时补办处'],a:0,e:'Lost & Found=失物招领处。在机场或飞机上遗失物品，应立即联系：①所在区域的机场工作人员②航空公司客服（飞机上丢失物品）。建议在旅行App里记录证件和重要物品的照片，以便描述丢失物品。'}
);


// ──────────────────────────────────────────────────────────────
// 【2】酒店入住英语 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_HOTEL.push(
  {c:'出国',q:'前台问"How will you be paying?"，你想用信用卡支付，应该回答？',o:['I\'ll pay by credit card.','I\'ll pay in cash.','I\'ll use Apple Pay.','Can I pay later?'],a:0,e:'支付方式：by credit/debit card（刷卡）、in cash（现金）、by mobile payment（移动支付）。酒店通常会预授权（pre-authorize）你的信用卡，作为入住押金。'},
  {c:'出国',q:'酒店说"We\'ll need a credit card for incidentals."，"incidentals"是指？',o:['杂项费用（如小吧台饮料、损坏赔偿等），酒店要求预授权信用卡作为押金','房间清洁费','提前退房罚款','额外床铺费用'],a:1,e:'Incidentals=杂项/附加费，指入住期间可能产生的额外费用（Mini bar消费、付费电视、打破物品等）。酒店会预先在信用卡上预授权$100-300，退房后若无消费则全额退还。'},
  {c:'出国',q:'"Suite"（套房）和"Standard Room"（标准间）的主要区别是？',o:['价格差别','套房有独立的客厅区域，通常面积更大、设施更豪华；标准间是基本配置的普通客房','套房靠窗，标准间不靠窗','名字不同但实际一样'],a:1,e:'Suite（套房）：客厅+卧室分开，面积通常是标准间的2-3倍，设施更完善（浴缸+淋浴、欧式家具等）。细分有Junior Suite（小套房）、Deluxe Suite、Presidential Suite（总统套房）。'},
  {c:'出国',q:'你到达酒店，但房间还没有准备好（"not ready yet"），你应该怎么做？',o:['把行李寄存在前台（Ask them to store your luggage），先去外面用餐/观光，等房间好了再来','坚持等在大厅直到房间准备好','要求酒店赔偿','取消预订'],a:0,e:'早到时房间未就绪很常见。礼貌询问："Is it possible to store my luggage while I wait?"酒店通常有行李寄存服务（Luggage storage）。也可留下电话号码，请前台room is ready时通知你。'},
  {c:'出国',q:'"Connecting rooms"是指什么类型的房间？',o:['相邻且内部有门相通的两个房间，适合家庭或团队旅行','连接无线网络的房间','带有阳台的相邻房间','标准双人间'],a:0,e:'Connecting rooms（连通房）：两个独立房间之间有内部的连通门，可以互通。家庭旅行非常实用，大人和孩子各有独立卧室，同时可以互通。预订时需要特别申请（Request connecting rooms）。'},
  {c:'出国',q:'"Room service"（客房服务）通常在什么时间段内可以使用？',o:['大多数酒店提供24小时客房服务，但菜单可能在深夜缩减','只在早餐时间','仅限11:00-22:00','只有五星级酒店有'],a:0,e:'Room service=客房送餐服务。四五星级酒店通常24小时提供，菜单在床头桌上或可通过电话拨打内线（通常是"0"或"*0"）点餐。深夜菜单会缩减，而且有额外的服务费和小费。'},
  {c:'出国',q:'你的房间里有小吧台（Minibar），开瓶后喝了一瓶可乐，退房会如何处理？',o:['费用会自动记入你的账单，小吧台消费通常价格很高（是超市的3-5倍）','可以免费享用','需要在前台专门付款','服务员会上门收款'],a:0,e:'Minibar（小吧台/迷你冰箱）里的饮料和零食都是收费的，且价格远高于外面。部分高档酒店提供免费minibar，但要看入住条件。建议到外面超市购买饮料，放入冰箱冷藏。'},
  {c:'出国',q:'"Housekeeping"（客房清洁）服务通常什么时候进行？如何调整？',o:['通常在白天（上午10点-下午4点）进行；可以通过挂"Do Not Disturb"牌或电话通知前台调整时间','每天凌晨进行','住客在场时才能进行','每隔3天进行一次'],a:0,e:'如不希望被打扰，挂上"Do Not Disturb"（请勿打扰）牌或者翻转为"Please Make Up My Room"（请打扫房间）。现代酒店也越来越多提供跳过打扫选项来减少洗涤，获得积分奖励，更环保。'},
  {c:'出国',q:'"Concierge"（礼宾员）在酒店能帮你做什么？',o:['推荐餐厅并订位、订演出票、安排交通（接送机/租车）、提供旅游建议等几乎所有个人服务','只负责搬运行李','只处理账单问题','只安排叫醒服务'],a:0,e:'Concierge（礼宾）是高档酒店提供的高端服务，经验丰富的礼宾员对当地非常熟悉。可以帮你：订难订的餐厅、买演出票、安排私人导游、预约Spa等。他们的建议通常比网络评价更可靠！'},
  {c:'出国',q:'"Bed and Breakfast"（B&B）是什么类型的住宿？',o:['含早餐的家庭旅馆，通常为私人家庭经营，价格介于酒店和青旅之间，体验更地道温馨','五星级酒店的特殊早餐套餐','青年旅舍的一种','度假村的标准配置'],a:0,e:'B&B（Bed and Breakfast）=含早餐的民宿/小旅馆，常见于英国、爱尔兰、欧洲各地。由私人家庭或小老板经营，通常5-10间客房，早餐在公共区域享用，体验非常本地化。'},
  {c:'出国',q:'酒店账单上出现"Resort Fee"，你之前没有被告知，你可以怎么做？',o:['礼貌但坚定地质疑这笔费用，要求说明：许多酒店的Resort Fee是强制收取且合法的，但应在预订时公开透明','无条件支付','拒绝结账离开','报警'],a:0,e:'Resort Fee（度假费/设施费）是美国部分酒店强制收取的额外费用（通常$25-50/晚），覆盖WiFi、健身房、泳池等。虽然合法但争议很大。如预订时未被告知，可以礼貌交涉要求减免，成功率视酒店政策而定。'},
  {c:'出国',q:'"Turndown service"（夜床服务）是什么？',o:['晚间客房整理服务：整理床铺、补充浴室用品、放枕头糖（chocolate）等，通常在傍晚进行','叫醒服务','深夜客房送餐','夜间安保服务'],a:0,e:'Turndown service=夜床服务，是高端酒店的传统礼遇。服务人员在傍晚6-8点会来整理床铺（将床角折叠）、关闭窗帘、放上小礼物（如枕头巧克力或当日天气卡）。如不希望被打扰请挂DND牌。'},
  {c:'出国',q:'以下哪个是"Double room"（双人房）的正确描述？',o:['一张大双人床的房间','两张单人床的房间（Twin room）','两张双人床的房间','大床加单人沙发床'],a:0,e:'Double room=一张双人大床（Double/Queen/King size bed）的房间；Twin room=两张单人床（Single beds）的房间。预订时要确认：很多人误把Twin当作Double预订，对情侣来说区别很重要！'},
  {c:'出国',q:'在欧洲酒店，"Breakfast Continental"和"Full English Breakfast"的区别是？',o:['Continental（欧陆式早餐）=面包/糕点/果汁/咖啡，较清淡；Full English（英式早餐）=培根/香肠/炒蛋/烤豆/烤面包，非常丰盛','两者完全相同','Continental更贵','Full English只在英国才有'],a:0,e:'Continental Breakfast=欧陆式早餐，轻便：牛角包、果酱、奶酪、冷肉、果汁、咖啡。Full English Breakfast（又称"Fry Up"）=英式早餐，丰盛：培根、香肠、炒蛋/煎蛋、烤豆、煎蘑菇、黑布丁、烤面包。'},
  {c:'出国',q:'"Loyalty program"（会员忠诚计划）的好处是什么？推荐给经常旅行的人吗？',o:['积累积分可兑换免费住宿、升舱、优先入住等福利；非常推荐，完全免费注册，对经常出差和旅行的人价值极高','只对商务人士有用','积分会快速过期，意义不大','需要付费会员才能加入'],a:0,e:'酒店忠诚计划（如Marriott Bonvoy、Hilton Honors、IHG Rewards）完全免费注册，通过住宿积分可获得：免费房晚、等级升舱、特别礼遇。适合固定使用某品牌的旅行者，集中消费积分价值更高。'},
  {c:'出国',q:'你在酒店发现床单不干净，应该怎么处理？',o:['立即联系前台，礼貌说明情况并要求更换房间或立即更换床单','自己凑合用','默默忍受','差评了再说'],a:0,e:'发现任何卫生或设备问题，立即（不要等退房后）联系前台："I\'m afraid there\'s a problem with my room. The bed linen doesn\'t look clean. Could you please have it changed or arrange a different room?" 酒店通常会立即处理。'},
  {c:'出国',q:'酒店"Amenities"包括哪些内容？',o:['酒店提供的设施和用品，如泳池、健身房、浴室洗漱包（洗发水/沐浴露/牙刷）等','只有游泳池','仅指餐厅服务','指停车场'],a:0,e:'Amenities（设施/配套）是酒店的特色服务和用品统称：浴室用品（toiletries/bath amenities）、公共设施（健身房/泳池/Spa）、商务中心等。预订时"amenities included"意味着这些是免费提供的。'},
  {c:'出国',q:'"Non-refundable rate"（不可退款价格）和"Flexible rate"（灵活价格）哪个更适合行程不确定的旅行者？',o:['Flexible rate（灵活价格）更适合，虽然价格高一些，但可以免费取消，适合行程可能变化的旅行','Non-refundable更好，因为便宜','两者没有区别','只选最便宜的就对了'],a:0,e:'Non-refundable=不可退款（取消或改期全额收费，通常便宜20-30%）；Flexible/Free Cancellation=可免费取消（通常在入住前24-48小时前取消无损失）。行程不确定建议选Flexible，哪怕贵一点也值得。'},
  {c:'出国',q:'在美国，你入住了5晚酒店，每晚房价$100，通常最终账单会高于$500，为什么？',o:['酒店会加收税费（Hotel Tax/Occupancy Tax），在美国通常为10-18%，部分城市还有额外的城市税','酒店有秘密收费','服务费直接加在房价上','以上说法都是错的，就是$500'],a:0,e:'酒店税（Hotel/Occupancy/Lodging Tax）是美国各州市对酒店住宿征收的税，通常叠加几种税后总税率达10-18%。纽约市可高达20%以上。加上resort fee，实际支出可能比标价高30%。订酒店前要查看含税总价！'},
  {c:'出国',q:'"Dry cleaning service"（干洗服务）在酒店如何使用？',o:['将衣物放入房间提供的洗衣袋，填写洗衣单，挂在门口或告知客房服务，通常次日可取回','只能亲自送到前台','需要提前3天预约','高档酒店才有这项服务'],a:0,e:'酒店Dry Cleaning/Laundry Service=洗衣/干洗服务。价格通常很贵（一件衬衫干洗可达$10-30），适合商务人士应急。也可以找附近的Laundromat（自助洗衣房）或使用酒店Laundry Room自助洗衣（更便宜）。'},
  {c:'出国',q:'"Pet-friendly hotel"意味着什么？',o:['允许携带宠物入住的酒店，通常需要额外支付宠物押金/宠物费','专门为宠物设计的住宿','禁止携带宠物入住','提供宠物寄养服务'],a:0,e:'Pet-friendly hotel=宠物友好酒店。通常：①收取宠物押金（$50-200，用于可能的损坏）②部分楼层/房间允许宠物③提供宠物床、碗、零食等用品④附近可能有宠物活动区域。携带宠物出行前必须提前确认酒店政策。'}
);


// ──────────────────────────────────────────────────────────────
// 【3】交通出行英语 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_TRANSPORT.push(
  {c:'出国',q:'在英国乘坐公共汽车，"Pay as you go"（随用随付）是什么意思？',o:['不购买日票/周票，每次上车刷卡扣费，适合偶尔乘车的旅客','免费乘车','在车上向司机购买单程票','专属于学生的优惠票种'],a:0,e:'Pay as you go=按次计费，使用银行卡/手机Pay/Oyster card（伦敦交通卡）每次上车刷卡。在伦敦公交已全面无现金，必须用非接触式支付（contactless payment）。'},
  {c:'出国',q:'你在巴黎要乘地铁，自动售票机只接受芯片信用卡，你的中国银联卡不被接受，怎么办？',o:['找服务人员窗口用现金购买，或使用支持NFC的手机支付，部分售票机也接受VISA/Mastercard','放弃乘地铁改打车','向当地人借钱','直接跳闸'],a:0,e:'欧洲地铁售票机通常接受欧洲芯片卡。中国游客备用方案：①携带Visa/Mastercard国际卡②准备欧元现金③在窗口购票④提前下载当地公交App（如Paris Visite卡可提前在网上买）。'},
  {c:'出国',q:'"Hop-on Hop-off Bus"（随上随下巴士）在旅游城市有什么特点？',o:['特定路线循环行驶，在主要景点停靠，购买当日票可无限次上下车，非常适合初次到访的游客','只能坐一次的观光巴士','需要提前预约座位','只在周末运营'],a:0,e:'Hop-on Hop-off（通常是双层红色巴士）=随上随下观光巴士，通过热门景点，可以在任意站下车游览后再上下一班。提供耳机语音导览（多种语言）。价格较贵但可以节省交通规划时间。'},
  {c:'出国',q:'在美国，"Jaywalking"是指什么行为？在美国可能面临什么后果？',o:['在不是斑马线或无信号灯处横穿马路；在部分州属违法行为，可能被警察开罚单','在高速公路上行走','逆向骑自行车','在禁止行人的隧道行走'],a:0,e:'Jaywalking（乱穿马路）在美国很多州是违法行为，可能被罚款$1-$200不等（视州而定）。加州2023年放开了部分限制。在美国要严格按信号灯行走，"Walk/Don\'t Walk"信号要认识。'},
  {c:'出国',q:'你在日本，需要从大阪乘新干线去京都，大约需要多少时间？',o:['约14-16分钟（非常近，乘普通特急也只需约30分钟）','约2小时','约1小时','约45分钟'],a:0,e:'大阪（Shin-Osaka站）到京都（Kyoto站）乘新干线仅约14-16分钟！两城市距离很近，普通列车（JR京都线）约30分钟，非常方便。日本持JR Pass可以免费乘坐新干线和JR线列车。'},
  {c:'出国',q:'"Taxi meter"（计程器）和"flat rate"（固定价格）在打车时的区别是？',o:['Meter=按实际行驶距离和时间计费（价格不确定）；Flat rate=预先协商好的固定价格（不管距离）；机场到市区很多地方有flat rate','两者完全相同','Flat rate更贵','Meter更适合长途'],a:0,e:'Flat rate（固定价格）常见于机场到市区的线路，避免绕路和高价。乘车前要确认：是meter计费（Ask "Do you use the meter?"）还是flat rate。若对方说flat rate，上车前要谈好价格并确认！'},
  {c:'出国',q:'在欧洲，"InterRail Pass"适合哪类旅行者？',o:['欧洲居民（持欧洲本地护照/居留证），可购买允许在多个国家无限次乘坐火车的通票（非欧洲居民需购买Eurail Pass）','所有国家旅行者','仅限学生','只在一个国家内有效'],a:0,e:'Eurail Pass（欧铁通票）=非欧洲居民购买，可在30+个欧洲国家坐火车；InterRail Pass=欧洲居民购买。两者都有不同时效的选择（3天/1个月等）。对于跨多国旅行非常划算，但要注意部分高速列车需要额外订座位。'},
  {c:'出国',q:'你在澳大利亚租车，注意到路标显示"110 km/h"，这是指什么？',o:['限速110公里/小时（澳大利亚使用公制，和中国相同）','限速110英里/小时','建议速度','最低速度'],a:0,e:'澳大利亚使用公制（km/h），和中国相同。美国和英国使用英制（mph），注意区分！路牌"110 km/h"在澳大利亚是高速公路的常见限速，澳洲警察测速严格，超速罚款很重且有扣分制度。'},
  {c:'出国',q:'"Ride-sharing"（拼车/共乘服务）和传统出租车（Taxi）的主要区别是？',o:['Ride-sharing（如Uber/Grab）通过App叫车、系统定价、评价双向、无需现金；传统Taxi现场招手、计费器计价、现金或刷卡','没有任何区别','Taxi比Uber安全','Uber没有保险'],a:0,e:'Ride-sharing Apps：Uber（全球）、Grab（东南亚）、Lyft（美国）、Didi（滴滴，部分城市）。优势：价格透明、无需现金、司机信息可追踪、路线可分享给朋友。注意：部分国家的Uber需要当地电话号码注册。'},
  {c:'出国',q:'在英国伦敦，"Oyster Card"是什么？如何使用？',o:['伦敦交通储值卡，可在地铁/公交/轻轨上使用，费率比单次购票便宜；在地铁站充值后每次刷卡上下车','英国的身份证','一种特殊的签证卡','伦敦博物馆联票'],a:0,e:'Oyster Card=伦敦交通卡，在各地铁站和部分超市均可购买（押金£5）和充值。现在也可以直接用任何有非接触式（contactless）功能的银行卡/手机代替，效果相同。每日有封顶收费（Daily Cap）保护旅客不会被过度收费。'},
  {c:'出国',q:'你在美国要去某个地方，朋友说"It\'s about two blocks away."，大概多远？',o:['大约200-300米（一个block=城市街区，长度约100-200m，视城市而定）','约2公里','约2英里','约20分钟步行'],a:0,e:'Block（街区）是美国城市距离的基本单位，指两个路口之间的距离，通常约80-200m，曼哈顿的block约80m。"2 blocks"=走到第2个十字路口，是很短的步行距离。纽约人常用blocks描述距离。'},
  {c:'出国',q:'"Standing room only"在公共交通中意味着什么？',o:['车厢内座位已全部坐满，只能站立乘车','禁止乘车','仅供老人和儿童','需要额外买站票'],a:1,e:'Standing room only（SRO）=座无虚席，只能站立。在繁忙时段的地铁/公交上非常常见。注意在日本、韩国的新干线，无座位票（Non-reserved seat/Standing ticket）是合法的，非高峰时段通常能找到座位。'},
  {c:'出国',q:'乘坐长途大巴时，"Greyhound"在美国是指什么？',o:['美国最大的长途大巴公司，连接大多数美国城市，票价比飞机便宜得多','一种运动员专车','只在纽约运营的公交','美国铁路公司名称'],a:0,e:'Greyhound是美国最大的长途大巴（Intercity bus）公司。优点：票价低（往往比机票便宜50-80%）、覆盖广。缺点：耗时长、设施一般。适合预算有限且不赶时间的旅行者。美国铁路公司叫"Amtrak"。'},
  {c:'出国',q:'"One-way street"（单行道）在驾车时要注意什么？',o:['只能沿规定方向行驶，逆向进入属严重违规，可能被罚款或引发事故','可以双向行驶','只在高峰期单行','行人优先的特殊道路'],a:0,e:'One-way street（单行道）必须严格按规定方向行驶。欧美城市老城区单行道很多，开车前建议提前规划路线或开导航。看到"One Way"路牌和箭头指示方向即为正确行驶方向。'},
  {c:'出国',q:'在东京，"IC Card"（如Suica、Pasmo）的最大优势是什么？',o:['可以在全国（大部分地区）通用，覆盖地铁、公交、JR线，还可以在便利店和自动售货机消费，极其便利','只能在东京使用','只能乘坐地铁','需要每次充值'],a:0,e:'Suica（西瓜卡）/Pasmo是日本的IC储值卡，如同一卡通。支持：①东京及日本全国大部分城市的铁路和公交②7-Eleven、全家、罗森等便利店③部分自动贩卖机和商店。可在机场买卡并充值，极其便利！'},
  {c:'出国',q:'在泰国清迈，"Songthaew"（双条）是什么交通工具？',o:['改装皮卡车，车厢两侧有长椅可坐人，是廉价的共乘小巴，招手即停，类似公交但更灵活','三轮摩托','水上渡轮','旅游大巴'],a:0,e:'Songthaew（双条）="两排"，是东南亚常见的改装皮卡共乘交通。价格非常便宜（通常20-40泰铢），路过时招手示意，说明目的地，司机决定是否顺路。在清迈市区是最便宜的短途交通方式之一。'},
  {c:'出国',q:'在国外驾车，"International Driving Permit"（IDP，国际驾照）有效期是多少年？',o:['1年（IDP有效期固定为1年，需在国内有效驾照基础上申请）','5年','10年','与国内驾照有效期相同'],a:0,e:'IDP（国际驾照）有效期为1年。中国公民可在驾照所在地车管所申请（携带驾照、证件照、费用等）。注意：IDP必须与中国国内驾照同时使用，单独持有IDP无效。部分国家（如日本）不接受中国驾照/IDP，需特别了解。'},
  {c:'出国',q:'"Pedestrian crossing / Crosswalk / Zebra crossing"三者指的是同一设施吗？',o:['是的，都指行人过街横道（人行横道），只是英式/美式/通俗叫法不同','不同，功能各异','Pedestrian crossing只在学校附近','Zebra crossing有斑马值守'],a:0,e:'同一设施，三种叫法：Pedestrian crossing（通用）、Crosswalk（美式）、Zebra crossing（英式，因黑白条纹像斑马得名）。行人横道优先权各国不同：英国斑马线行人绝对优先；美国需先确认车辆停下再通行。'},
  {c:'出国',q:'你在澳大利亚开车，注意到道路靠左行驶（left-hand traffic），以下哪个习惯需要特别注意？',o:['转弯方向、超车方向、视线习惯都与中国相反（右驾变左驾）；在路口"GIVE WAY"标志处需礼让道路优先权的车辆','只需注意车速','加油方式不同','道路标志完全不同'],a:0,e:'澳大利亚、英国、日本、香港等左行国家（Left-hand traffic），驾驶位在右侧。从右行国家换左行国家驾车容易犯错：①转弯时往左而不是右②超车走右道③进环形交叉路时注意优先权。建议初次不要贸然自驾。'},
  {c:'出国',q:'在新加坡，地铁称为？',o:['MRT（Mass Rapid Transit，地铁）','Subway','Underground','Tube'],a:0,e:'新加坡地铁叫MRT（Mass Rapid Transit）。马来西亚KL地铁也叫MRT。香港叫MTR（Mass Transit Railway）。伦敦叫Underground/Tube，美国叫Subway，巴黎叫Métro。不同城市有不同叫法！'},
  {c:'出国',q:'在欧洲旅行，"Tram"（有轨电车）和"Metro"（地铁）的主要区别是？',o:['Tram在地面行驶，经过市区街道，速度较慢但可以欣赏街景；Metro在地下运行，速度更快但看不到风景','Tram更贵','Metro只在大城市有','两者完全相同'],a:0,e:'Tram（有轨电车）=在地面轨道上行驶的电车，是欧洲很多城市（里斯本、阿姆斯特丹、布拉格）的特色交通。Metro（地铁）=地下快速轨道交通。里斯本28路有轨电车本身已成为旅游景点！'},
  {c:'出国',q:'在美国，"Freeway"和"Highway"有什么区别？',o:['Freeway=全封闭高速公路（无红绿灯，通常免费通行）；Highway=泛指公路（可包含收费站和信号灯）；两词常互换','Freeway比Highway更贵','Highway限速更高','两者没有任何区别'],a:0,e:'Freeway（在加州/西部常用）=限制进出的封闭式快速路，通常免费；Expressway/Turnpike/Toll Road=收费高速；Highway=泛指公路。I-（Interstate）开头的是全国高速公路系统。开车时要注意Exit（出口）提前准备变道！'}
);


// ──────────────────────────────────────────────────────────────
// 【4】购物砍价英语 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_SHOPPING.push(
  {c:'出国',q:'商店标签上写"RRP: $80 / Our Price: $55"，"RRP"是什么意思？',o:['Recommended Retail Price（建议零售价），商店标出RRP对比自己的售价，显示"优惠"','Required Regular Payment（固定价格）','Real Reduced Price（真实折扣价）','Return/Refund Policy（退换货政策）'],a:0,e:'RRP=Recommended Retail Price（建议零售价），是厂商建议的标准价格。商店通过对比RRP和自己的售价来显示优惠力度。注意：这是一种营销策略，"优惠"是否真实需要货比三家。'},
  {c:'出国',q:'"Flash sale"（闪购）是什么？',o:['限时折扣活动，时间短（通常几小时到一天）、折扣大，过期即止','每月固定一次的促销','只在线上才有的优惠','仅限会员的秘密折扣'],a:0,e:'Flash sale=闪购，是电商和实体店的限时促销策略：大折扣+短时间（制造紧迫感）。出行前可以关注目的地大型购物节：美国黑色星期五（Black Friday）、泰国米其林购物节等。'},
  {c:'出国',q:'在日本购物，你想询问某件商品是否可以退税（Tax-Free），应该问？',o:['Is this tax-free? / Do you offer tax-free shopping?（可以免税购物吗？）','Can I get a discount?','Is this on sale?','How much is the tax?'],a:0,e:'日本消费税10%，在指定免税商店（标有Tax-Free标志）购买满5000日元的商品可以申请免税（护照）。机场有税退还手续，也可在商店当场免税。全国约50万家商店参与免税计划。'},
  {c:'出国',q:'"What\'s your best price?"（你的最低价是多少？）这种砍价方式在哪些地方更有效？',o:['在市集（Market）、摊贩、小型独立商店；在大型连锁超市/品牌店通常没有效果','在所有地方都有效','在超市购物时最有效','在机场免税店最有效'],a:0,e:'砍价文化因地而异：非常欢迎砍价=土耳其巴扎、摩洛哥市集、东南亚夜市、印度手工市场；不可砍价=日本、北欧（定价文化极强）；部分可砍=欧洲古董市场、电器城（尤其是付现金时）。'},
  {c:'出国',q:'"Buy one get one free"（BOGOF）活动的意思是？',o:['买一送一（购买一件，免费获得另一件相同商品）','买一件打折','买一件可以退款一件','第二件半价'],a:0,e:'BOGOF=Buy One Get One Free（买一送一），是超市和零售店常见促销。变体有：2 for the price of 1（同样意思）；Buy 2 get 1 free（买二送一）。出国购物时看到这些标识要仔细阅读条件。'},
  {c:'出国',q:'你在美国购物，账单上看到"Sales Tax"（消费税），这笔税在哪里缴纳？',o:['在结账时缴纳（与中国的增值税不同，美国商品定价通常不含税，结账时再加）','商品已含税','只有高档商品才有税','可以在机场退税'],a:0,e:'美国大多数州的商品定价不含销售税（Sales Tax），税率5-10%不等（Oregon、Delaware等州无销售税）。结账时才加入。与欧洲不同，欧洲价格通常含VAT（增值税），退税是多退已付的税。'},
  {c:'出国',q:'在泰国或东南亚市场，砍价的基本技巧是什么？',o:['从商贩报价的30-50%开始出价，表现出不急着买的样子，准备好离开，通常会有更好的报价跟来','接受第一个报价','用英语说越流利越有优势','只在下午砍价'],a:0,e:'市场砍价技巧：①不要显示太大兴趣②问完价格装作考虑其他摊位③从报价的一半以下开始出价④微笑保持友好⑤准备好离开（Often the vendor will call you back with a better price）⑥购买多件时整体谈价更有利。'},
  {c:'出国',q:'"Receipt"（收据）在国外购物后为什么重要？',o:['退货/换货时需要出示；在有退税制度的国家（如欧洲）申请VAT退税也需要收据；还可作为支出记录','没有任何用处','只有退税时才需要','可以拿来再次购物打折'],a:0,e:'保留收据（Receipt/Invoice）的理由：①退货换货必须出示②欧洲退税（Tax Refund）必备③记录消费、报销或报税④发现价格错误时的证明。建议有特别购物都拍照备份，避免收据褪色无法读取。'},
  {c:'出国',q:'在英国，"Boxing Day Sale"（节礼日大促销）是哪一天开始的？',o:['12月26日（圣诞节次日），是英国全年最大的折扣日之一，实体店和网店都有疯狂促销','12月25日圣诞节当天','1月1日新年','11月最后一个星期五（美国黑色星期五）'],a:0,e:'Boxing Day（节礼日）=12月26日，是英国、加拿大、澳大利亚等英联邦国家的传统假日。这天各大商场开始大规模年底清仓打折，是圣诞购物季最值得出手的时机。'},
  {c:'出国',q:'在购物时，"Fitting Room"（试衣间）的使用规定通常是什么？',o:['通常需要拿号牌，限制同时试穿的件数（通常5-8件）；部分商店禁止将已试穿的商品带出试衣间前','可以随意进出，无限制','只有高档服装店才有','需要购买后才能试穿'],a:0,e:'试衣间（Fitting Room/Changing Room/Dressing Room）：①店员会给你数量牌（Number Tag）②通常限制每次试穿件数（防盗）③不满意可以出来换其他件④部分国家（如日本）需要带发帽（Hair Cap）防止粉底弄脏衣领。'},
  {c:'出国',q:'你在欧洲看到一件标价"€120"的夹克，申请退税后大约能退多少？',o:['大约€20-22（欧洲VAT税率约20%，退税比例略低于标准税率，需扣除手续费，实际退还15-18%左右）','退还€120全额','退还€50','完全不能退'],a:1,e:'欧洲VAT退税计算：标价通常含税，税率因国家不同（20-27%不等）。实际能退的净额：退税公司会收取一定手续费，最终退还约含税价的12-18%。€120的商品，退税后到手约€15-22，仍然划算！'},
  {c:'出国',q:'"Knock-off"和"Authentic"商品的区别是？',o:['Knock-off=仿冒品（Counterfeit/Fake，非正品）；Authentic=正品（真品）；购买仿品进入中国海关可能被没收','knock-off是限量版','Authentic是二手正品','两者没有区别'],a:0,e:'注意！在某些国家（土耳其、泰国等）买仿冒名牌（knock-offs/counterfeits）带回中国可能在海关被没收，且可能违反知识产权法。商家说"It\'s the real thing"不可轻信，"Authentic"和"Original"需要正规购买渠道。'},
  {c:'出国',q:'在商店看到商品标签"As Is"（原状出售），这意味着什么？',o:['商品以现有状态出售，不保证质量、不可退换（通常用于瑕疵品或展示品特价出售）','商品刚到货很新鲜','商品原装未开封','商品有官方保修'],a:0,e:'"As Is"=按现状出售，意味着商品可能有瑕疵，买家接受现状，通常无退换保证。常见于：家具展示品、瑕疵品清仓、二手商品。价格通常很低，但风险自担，要仔细检查后再购买。'},
  {c:'出国',q:'"Haggle"（讨价还价）文化在哪个地区最普遍？',o:['中东、北非、南亚、东南亚市集；日本、斯堪的纳维亚半岛几乎无法砍价','所有地区都一样','只在亚洲可以砍价','只能在室外市场砍价'],a:0,e:'砍价文化地图：强烈欢迎砍价：摩洛哥集市（Souk）、土耳其大巴扎（Grand Bazaar）、印度集市、埃及、越南夜市。固定价格文化：日本（极少砍价，甚至认为失礼）、北欧国家、德国。其他地区视情况而定。'},
  {c:'出国',q:'在海外网购（如Amazon、ASOS）寄到中国，需要注意哪些问题？',o:['关税（Import Duty）、转运时间、商品是否在中国禁止进口、售后困难等；部分平台不直接发货到中国','没有任何问题，和国内购物完全相同','只有电子产品才有关税','中国海关不检查个人海淘包裹'],a:0,e:'海淘注意事项：①单次进口超过5000元人民币需缴纳关税②食品、化妆品、药品等有进口限制③转运周期较长（通常7-21天）④售后不方便（退货国际运费高）⑤尺码/电压差异（美国服装尺码≠中国）。'},
  {c:'出国',q:'在美国，"Black Friday"（黑色星期五）是什么时候？这个名称的由来是？',o:['感恩节（11月第四个星期四）次日；起源于商家账簿从"赤字（Red）"变为"盈利（Black）"的节点，是美国最大购物日','圣诞节前一天','10月31日万圣节','12月26日'],a:0,e:'Black Friday=每年11月第四个星期五，是美国最大的购物节（相当于中国双11）。原本只有实体店，现已扩展到网店，持续整个感恩节周末（+Cyber Monday网络星期一）。美国大型商场折扣可达30-70%。'},
  {c:'出国',q:'你在商店发现标价牌上价格和收银台实际收费不同，该怎么做？',o:['礼貌指出差异，要求按低价结账：在大多数国家（包括美国、英国），法律要求按标价收费，不能擅自更高价结账','接受较高价格','不购买直接离开','向警察举报'],a:0,e:'价格标示错误：消费者权益保护法规定商家必须按标示价格出售（Misselling不合法）。礼貌说："Excuse me, the tag says $30 but you\'re charging $50. Could you please check?" 通常会按低价处理或解释原因。'},
  {c:'出国',q:'"Complimentary gift wrap"（免费礼品包装）在什么场合最常见？',o:['圣诞节、情人节等节日期间的商场和品牌专卖店，通常会提供免费礼品包装服务','全年所有商店都有','只有高档百货公司','购物中心停车场提供'],a:0,e:'Gift wrap（礼品包装）服务在节日期间（圣诞/情人节/母亲节）很多商场提供，免费或收少量费用。如需要，购买后对收银员说："Could you gift wrap this, please?" 或"Is gift wrapping available?"'},
  {c:'出国',q:'在日本购物，商家接受的主要支付方式有哪些变化趋势？',o:['日本传统上以现金（Cash）为主，但近年来IC卡（Suica/Pasmo）、PayPay、信用卡普及率大幅提升，但许多小商店仍仅接受现金','日本已全面无现金化','日本不接受银联卡','日本只接受日本本地卡'],a:0,e:'在日本旅游的支付建议：①备足日元现金（尤其去小餐厅/神社/农村地区）②Suica/Pasmo可在很多便利店和餐厅使用③VISA/Mastercard信用卡在大城市旅游区基本可用④银联卡接受率也在提升但不如前两者普遍。'},
  {c:'出国',q:'在国外购买电子产品（如iPhone、相机），带回中国需要注意什么？',o:['价值超过5000元的进口商品需向海关申报缴税；要考虑保修是否全球通用；部分产品有区域锁（区域版本）','可以无限量带回不需申报','苹果产品全球统一价格','所有电子产品在中国都可以使用'],a:0,e:'购买海外电子产品注意：①超出免税额需缴税（15-43%关税）②苹果等大牌在美港通常比大陆便宜，但差价可能被关税抵消③区域锁（如美版手机可能无法使用中国频段）④保修是否国内有效⑤电源适配器电压差异。'},
  {c:'出国',q:'你在市场砍价后，商家已经接受了你的出价，但你随后改变主意不想买了，这样做合适吗？',o:['在口头砍价中（未签合同），通常可以不买，但这样做不尊重商家，在文化上是失礼的行为','完全没问题','会被罚款','商家可以强制你购买'],a:0,e:'商业礼仪：口头砍价达成的协议虽然法律上不具约束力（未签合同），但拒绝自己主动出价后被接受的价格在很多文化中被视为严重失礼，可能引发不愉快。建议：没有购买意向就不要开始砍价。'}
);


// ──────────────────────────────────────────────────────────────
// 【5】餐厅点餐英语 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_RESTAURANT.push(
  {c:'出国',q:'服务员说"Would you like still or sparkling water?"，你想要气泡水应该回答？',o:['Sparkling water, please.','Still water, please.','Tap water, please.','I\'ll have juice instead.'],a:0,e:'Still water=无气泡矿泉水（类似普通矿泉水）；Sparkling water=有气泡的矿泉水（类似苏打水）；Tap water=自来水（很多欧美餐厅免费提供）。在意大利/法国等地，开水通常要收费！'},
  {c:'出国',q:'菜单上出现"au gratin"，这道菜是怎么烹饪的？',o:['用奶酪/面包屑覆盖后焗烤（法语烹饪术语，指表面有金黄色奶酪或焦糖外壳）','生食/冷食','蒸制','煮汤'],a:0,e:'"Au gratin"（法语，发音：oh-GRAH-ten）=焗烤，将食材覆盖奶酪或加入奶油烤至表面金黄。常见菜肴：Potato au gratin（焗烤土豆）。旅行中看到法语菜单可以用这些词识别烹饪方式。'},
  {c:'出国',q:'在美国餐厅，标准的用餐小费比例是多少？',o:['15-20%（一般服务15%，好服务18-20%，非常好的服务20%以上）','5-10%','小费完全自愿，给多少都行','已含服务费，不用给'],a:0,e:'美国小费文化：15%=一般服务，18%=不错的服务，20%+=很好的服务。计算方式：账单金额×20%=小费参考。收款机通常会直接提示："15% / 18% / 20%"选择。不给小费在文化上非常失礼，服务员工资很低需要靠小费生活。'},
  {c:'出国',q:'"Sommelier"（侍酒师）在餐厅的职责是什么？',o:['负责葡萄酒（和其他饮料）的选择、推荐和服务，可以根据你的菜肴和预算推荐合适的葡萄酒','负责调制鸡尾酒（调酒师叫Bartender/Mixologist）','负责所有食物的烹饪','只在法国餐厅才有'],a:0,e:'Sommelier（发音：som-el-YAY）=侍酒师，是专业的葡萄酒顾问。如果点了葡萄酒，可以请他推荐："Could you recommend a wine that pairs well with the lamb?" 侍酒师的建议通常非常专业。'},
  {c:'出国',q:'"Set menu"（套餐）和"À la carte"（单点）在价格上通常有什么区别？',o:['Set menu通常比单点便宜（商家给整套折扣）；À la carte每道菜单独计价，可以更灵活选择','À la carte更便宜','两者价格完全相同','Set menu只有午餐才有'],a:0,e:'À la carte（法语，"按菜单点"）=每道菜分别点单、分别计价；Set menu/Prix fixe=固定套餐价格，通常包括前菜+主菜+甜点。Set menu通常更划算，适合不挑食的旅行者。'},
  {c:'出国',q:'你想告诉服务员食物不够咸，应该说？',o:['Could I have some salt, please? / This needs a bit more seasoning.','This is too spicy.','I\'m allergic to this.','This tastes wrong.'],a:0,e:'表达口味不足：Could I have some salt/pepper/sauce?（可以给我盐/胡椒/酱料吗？）This is a bit bland for my taste.（对我来说有点淡）。在日本提出这类要求可能被视为对厨师的批评，要注意文化场合。'},
  {c:'出国',q:'"Aperitif"（开胃酒）和"Digestif"（餐后酒）分别在何时饮用？',o:['Aperitif在餐前饮用（刺激食欲）；Digestif在餐后饮用（促进消化）','两者都在餐中饮用','Aperitif是餐后酒','只有法国餐厅才有这个传统'],a:0,e:'高档餐厅的完整用餐流程：Aperitif（餐前酒，如香槟、金巴利）→面包→前菜→主菜→奶酪→甜点→Digestif（餐后酒，如白兰地、格拉帕）→咖啡/茶。了解这些让你在高档餐厅更自在。'},
  {c:'出国',q:'在英国餐厅，"Pudding"不一定是布丁，它还常指什么？',o:['甜点/甜食（Dessert的英式说法，不特指布丁这种食物）','一种特定的英式蛋糕','含有布丁粉的所有食品','只是Christmas Pudding'],a:0,e:'英式英语中"Pudding"=甜点（Dessert）的通称。服务员问"Would you like any pudding?"=你要甜点吗？而不是专门问要不要吃布丁。同样，英国人说"Afters"也是甜点的意思。'},
  {c:'出国',q:'在法国餐厅，正确的面包食用礼仪是什么？',o:['用手撕小块面包蘸食物（不要整个面包咬），面包用来蘸酱汁而非代替餐具','用刀切面包','把面包放在盘子里','先吃完面包再点餐'],a:0,e:'法国餐桌礼仪：面包（Bread/Pain）通常放在左边小盘或直接放桌布上（不是餐盘上），用手撕成小块后吃，可以用来蘸盘底的酱汁（这被认为是对厨师的赞美，叫faire la saucer）。'},
  {c:'出国',q:'在日本寿司店，"Omakase"是什么意思？',o:['把选择权交给厨师（"我交给你决定"），厨师会根据当天新鲜食材和你的预算提供最好的搭配，通常价格较高','任何都吃（表示没有禁忌）','外带寿司的术语','寿司套餐的固定名称'],a:0,e:'Omakase（お任せ）=日语"交给你"，是最高级的日本餐饮体验之一。厨师会根据当日最新鲜食材、季节和客人喜好创作一套菜肴。在日本高端寿司餐厅（银座、六本木），Omakase一人消费可达3-5万日元。'},
  {c:'出国',q:'"Happy Hour"（欢乐时光）在酒吧/餐厅通常指什么？',o:['特定时段（通常下午4-7点）饮料或小食半价或特价，吸引下班人流','只有节假日才有','全天24小时打折','只限会员享受'],a:0,e:'Happy Hour=欢乐时光，通常在工作日下班前的时段（4pm-7pm），酒吧提供买一送一、半价饮料、特价小食等优惠。是以较低价格体验当地酒吧文化的好机会，旅行中一定要留意！'},
  {c:'出国',q:'餐厅菜单上的"Contains nuts"警示标识对哪类顾客最重要？',o:['对坚果过敏的顾客（Nut allergy），严重过敏者摄入坚果可能导致危及生命的过敏性休克','对素食主义者','对麸质过敏者','对乳糖不耐者'],a:0,e:'食物过敏（Food Allergy）标识：Contains nuts（含坚果）、Contains gluten（含麸质）、Contains dairy（含乳制品）等。如有过敏，点餐时一定要主动告知服务员。欧盟法规要求餐厅必须标注14种主要过敏原。'},
  {c:'出国',q:'在美国，"Brunch"（早午餐）通常在什么时间？包括哪些特色食物？',o:['周末上午10点到下午2点；包括鸡蛋本尼迪克特（Eggs Benedict）、松饼（Pancakes）、含酒精的鸡尾酒（如Bloody Mary/Mimosa）等','周一到周五的商务早餐','只在高档酒店','中午12点到下午3点'],a:0,e:'Brunch（Breakfast+Lunch）=周末特色，通常周六日10am-2pm供应。特色：Eggs Benedict（荷兰酱水波蛋）、French Toast（法式吐司）、Avocado Toast（牛油果吐司）、Mimosa（香槟加橙汁）。周末去餐厅可能需要排队等位！'},
  {c:'出国',q:'"Tasting menu"（品鉴菜单）有什么特点？适合什么场合？',o:['多道小份量菜肴（通常5-12道）展示厨师的烹饪技巧和创意，价格通常很高，适合庆祝特殊场合','只有两道菜的简化套餐','学生特价套餐','外卖专属套餐'],a:0,e:'Tasting menu=品鉴菜单，在米其林餐厅和创意餐厅常见。优点：体验厨师多种菜肴风格；缺点：价格高（可能每人$150-500+）、用时长（2-4小时）、份量小。通常需要提前预约，并告知饮食限制。'},
  {c:'出国',q:'在澳大利亚餐厅，"BYO"（Bring Your Own）是什么意思？',o:['自带酒水（餐厅不提供酒精饮料或提供有限，允许客人自带葡萄酒/啤酒，通常收少量开瓶费Corkage Fee）','自带食物','自带餐具','自带甜点'],a:0,e:'BYO=Bring Your Own，是澳大利亚和新西兰部分餐厅（通常是中小型本地餐厅）的特殊许可。自带葡萄酒可省下餐厅加价（Restaurant markup通常是进货价3-4倍）。Corkage Fee（开瓶服务费）通常$5-15每瓶。'},
  {c:'出国',q:'服务员问"How was everything?"用餐结束时，礼貌的回答是？',o:['It was delicious, thank you!（非常好吃，谢谢）/ Everything was wonderful.','Just fine.','Nothing special.','The food was cold.（如果确实有问题才说）'],a:0,e:'用餐结束，服务员询问体验感受时，若整体满意应给予正面反馈，这是基本礼貌。如有问题（食物不新鲜/错误等），可以礼貌但直接地说明，给餐厅改进机会，而不是默默忍受后只是不留小费。'},
  {c:'出国',q:'在泰国/越南街头食摊（Street Food），以下哪项注意事项最重要？',o:['选择人流量大（说明食物新鲜、翻台率高）、当地人也在吃的摊位；注意饮食卫生（生食、冰块可能不安全）','避开所有街头食物','只吃连锁餐厅','价格越贵越安全'],a:0,e:'Street Food选择指南：①人多=食物新鲜（高turnover）②当地人光顾=口味地道③观察是否使用一次性餐具或清洁餐具④避免生食（沙拉、生肉刺身）和当地制冰⑤果汁现榨且用当地水制冰要谨慎。'},
  {c:'出国',q:'在意大利餐厅，"Antipasto"是什么？什么时候吃？',o:['开胃菜（餐前小食，意大利语"在主食之前"），包括橄榄、腌肉、奶酪、烤蔬菜等','意大利面','主菜','甜点'],a:0,e:'意大利传统用餐顺序：Antipasto（开胃菜）→Primo（第一道，通常是意面/汤/烩饭）→Secondo（第二道，肉类或鱼）→Contorno（配菜）→Dolce（甜点）→Caffè（咖啡）。正式意式晚餐可能长达2-3小时！'},
  {c:'出国',q:'在西餐餐具摆放中，叉子放在哪侧，刀和勺放在哪侧？',o:['叉子在左侧，刀和勺在右侧（记忆法：Fork和Left都有4个字母）','叉子在右侧','全部放在右侧','放在盘子上方'],a:0,e:'Western table setting（西餐餐具）：Fork（叉）在Left（左）侧，Knife（刀）在右侧（刀刃朝盘子方向），Spoon（汤匙）在刀的外侧。餐具从外到内按用餐顺序使用（最外侧的先用）。记忆诀窍：FORKS=5字母，LEFT=4字母，从左用右。'},
  {c:'出国',q:'"Gluten-free"（无麸质）饮食是指不含什么成分的食物？',o:['不含麸质蛋白（Gluten，存在于小麦、大麦、黑麦等谷物中）；患乳糜泻（Celiac Disease）的人必须严格避免麸质','不含糖','不含脂肪','不含盐'],a:0,e:'Gluten=麸质，是小麦、大麦、黑麦等谷物中的蛋白质。乳糜泻（Celiac Disease）和麸质敏感者需要避免含麸质食物（面包/意面/啤酒等）。点餐时说"I have a gluten intolerance/I\'m Celiac, does this contain gluten?"'},
  {c:'出国',q:'在美国点外卖（Takeout）时，"ETA"是什么意思？',o:['Estimated Time of Arrival（预计到达/送达时间）','External Tax Added（额外税费）','Express Takeout Allowed（允许快速外带）','Every Time Available（随时可以）'],a:0,e:'ETA=Estimated Time of Arrival（预计到达时间），广泛用于外卖（Delivery）、包裹追踪、导航等场合。"ETA: 30 mins"=预计30分钟到达。类似的：ETD=Estimated Time of Departure（预计出发时间）。'},
  {c:'出国',q:'你在餐厅点了"Medium-rare"牛排，上来后发现太生了，应该怎么处理？',o:['礼貌告知服务员，请厨房重新处理："Excuse me, the steak is more rare than I expected. Could I have it cooked a bit more?"','直接吃掉算了','大声抱怨','直接离开不付款'],a:0,e:'食物不符合要求要及时（趁热）反馈，不要等吃完再抱怨。礼貌但明确地表达：服务员/厨房通常会乐意重新处理。用餐结束后只在账单或小费上表达不满并不能真正改善问题，也给不了餐厅改进机会。'}
);


// ──────────────────────────────────────────────────────────────
// 【6】紧急情况英语 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_EMERGENCY.push(
  {c:'出国',q:'在美国遇到紧急情况拨打911，你需要告诉调度员哪些关键信息？',o:['你的精确位置、紧急情况类型（医疗/火警/犯罪）、相关人员状况，保持通话直到被告知可以挂断','只说"Help"','只报你的名字','只说要求什么服务'],a:0,e:'911报警要点：①说明位置（Location）②描述紧急情况（What happened）③人员状况（是否有人受伤/处于危险）④按调度员指示行动，不要轻易挂断电话。调度员会全程引导你直到救援到达。'},
  {c:'出国',q:'如果你在国外目击了一场车祸，应该怎么做？',o:['拨打当地紧急电话，确保自身安全，不要随意移动受伤人员（防止二次伤害），拍照记录，等待警方','立即拍照发社交媒体','尝试自行救治伤者','快速离开现场'],a:0,e:'目击事故处理：①确保自身安全②拨打紧急电话（不同国家号码不同）③不随意移动受伤者（可能有颈椎损伤）④保持现场④提供目击证词⑤不要拍摄并传播血腥内容（在某些国家传播意外现场视频是违法的）。'},
  {c:'出国',q:'你在国外需要紧急医疗帮助，最快找到医疗设施的方法是？',o:['告知周围任何人"I need a hospital / Call an ambulance!"或拨打当地急救电话；也可对任意智能手机说"Emergency"唤起紧急功能','在网上搜索最近医院后再去','先打电话给旅行社','先联系中国大使馆'],a:0,e:'医疗紧急情况处理优先级：①大声呼救②拨打当地急救电话③接受急救治疗（先治后费，旅行保险可报销）。iPhone长按侧键或Android连续按电源键可触发SOS紧急模式，自动拨打当地急救电话！'},
  {c:'出国',q:'"Anaphylaxis"（过敏性休克）的紧急症状有哪些？',o:['喉咙肿胀/呼吸困难、皮疹、心跳加速、血压下降、意识模糊——需立即注射肾上腺素（EpiPen）并拨打急救电话','轻微的皮肤瘙痒','流鼻涕和打喷嚏','轻微的胃部不适'],a:0,e:'Anaphylaxis（过敏性休克）是危及生命的紧急情况。严重食物/昆虫叮咬过敏者应随身携带EpiPen（肾上腺素自动注射器）。第一时间注射后必须立即就医，注射后症状可能反弹！如在国外：Call 911/112/999，说"Anaphylaxis/Allergic reaction/Life-threatening emergency!"'},
  {c:'出国',q:'你在国外丢失了信用卡，应该做的第一件事是？',o:['立即致电银行紧急客服挂失（Freeze/Cancel the card）；银行国际紧急电话通常印在卡背面（24小时）','等回国再处理','去当地警察局','打电话给家人'],a:0,e:'信用卡丢失：立即挂失！大多数银行提供24小时国际客服（如招行400-888-7777境外拨打时需去掉前缀）。挂失后可申请紧急补卡（Emergency Card Replacement）或紧急现金（Emergency Cash Advance）。同时在网银App冻结该卡。'},
  {c:'出国',q:'你被人抢劫（Mugged/Robbed），犯人已经逃跑，正确的做法是？',o:['确保自身安全，记录犯罪特征（外貌、方向、时间），立即报警并获取警察报告号（Police Report Number）——这是保险理赔必需的文件','追上去自己解决','立刻飞回中国','默默接受'],a:0,e:'遭遇抢劫后：①不要追击（personal safety first）②寻找安全地点③拨打报警电话④索取Police Report（警察报案证明）——保险理赔必须有这份文件⑤联系中国大使馆（如护照一并被抢）⑥通知银行挂失所有被盗卡。'},
  {c:'出国',q:'"CPR"（心肺复苏）的全称是？在什么情况下实施？',o:['Cardiopulmonary Resuscitation（心肺复苏），在人员失去意识、没有脉搏/呼吸时实施（等待急救到来期间）','Counter Police Report（警方报告）','Common Public Response（公共应急响应）','Critical Person Rescue（危重人员救援）'],a:0,e:'CPR（心肺复苏）=胸外按压+人工呼吸（现代指南倾向只做胸外按压）。发现有人倒地无意识：①确认安全②拍肩呼唤③拨打急救电话④开始CPR直到救援到来。建议旅行前学习基础急救知识！'},
  {c:'出国',q:'你在国外遇到自然灾害（地震/台风/洪水），应该怎么做？',o:['遵从当地官方指示，通过使馆网站/官方App获取最新安全信息，联系家人报平安，保留紧急联系号码','继续旅游计划','独自寻找出路不理官方指示','等候旅行社安排'],a:0,e:'海外遇灾应对：①关注中国驻当地大使馆公告（官网或微信公众号）②注册驻外中国公民信息（领事保护App）③与家人保持联系（发短信比打电话更可靠，基站受损时）④准备3天自救物资⑤熟悉酒店的紧急疏散路线。'},
  {c:'出国',q:'"Travel Insurance"（旅行保险）的"Medical Evacuation"（紧急医疗撤离）条款是什么？',o:['当地医疗条件不能满足治疗需求时，保险公司负责将被保险人转运到能提供适当治疗的地方（包括回国），这项保额通常需要达到$100万以上才够','只涵盖在医院里的费用','转运到任意国家均需自费','只在欧美国家有效'],a:0,e:'Medical Evacuation（紧急医疗撤离）是旅行险中最重要但最被忽视的条款。东南亚/非洲部分地区医疗条件有限，危重病人可能需要转运到新加坡/曼谷/香港等医疗中心，费用可达数万至数十万美元。购买保险时确认此条款的保额！'},
  {c:'出国',q:'你在国外手机没电、网络中断，如何找到中国大使馆的联系方式？',o:['向当地警察求助（他们通常有各国使馆的联系方式）；或找到有联网设备的人搜索"Chinese Embassy in [城市名]"；或借用酒店前台的电话（大使馆号码全球24小时）','等手机充电后再查','去机场等候','放弃，自己解决'],a:0,e:'中国领事保护专线：12308（国内）境外拨打+86-10-12308，24小时为海外中国公民提供领事协助。出行前建议：①下载"领事直通车"App②将大使馆电话存入手机③把大使馆地址写在纸条上备份。'},
  {c:'出国',q:'"Dehydration"（脱水）在旅行中常见，主要症状是什么？如何预防？',o:['口渴、头晕、尿液颜色深黄（正常应为淡黄/浅色）、疲劳；预防：多喝水、避免在高温下长时间活动、随身携带水瓶','只有在沙漠才会脱水','喝果汁不如喝酒精饮料补水','症状不严重，不需要处理'],a:0,e:'旅行脱水风险高：①长途飞行（机舱湿度极低）②高温目的地（中东/东南亚）③大量步行出汗。预防：每天喝8杯水（约2升），少喝咖啡因和酒精（加速脱水）。严重脱水需补充电解质（Oral Rehydration Salts）。'},
  {c:'出国',q:'你在海外生病，旅行保险理赔时需要提供哪些文件？',o:['医疗费用收据、诊断证明（Medical Certificate）、保险公司报案号、相关药品收据；部分险种还需提前致电保险公司获取授权（Pre-authorization）','只需要收据','只需要护照复印件','口头告知保险公司就够了'],a:0,e:'旅行险理赔准备：①就医前/后尽快通知保险公司（部分保险需要Pre-authorization）②保留所有原始收据（发票/收据，不接受复印件）③获取诊断证明（英文或当地语言+翻译）④记录就医时间地点⑤回国后在规定时间内提交理赔（通常30-60天内）。'},
  {c:'出国',q:'在飞机上，如果有乘客突然昏迷，空乘会首先做什么？',o:['询问机舱内是否有医生或医疗专业人员（"Is there a doctor on board?"），联系地面医疗支持，并取出机载医疗设备（包括AED和急救箱）','继续飞行不做处理','立即让飞机降落','只给乘客水喝'],a:0,e:'航班医疗紧急情况：所有商业航班必须配备急救箱（First Aid Kit）和AED（自动体外除颤器）。机组接受过基础急救训练。严重情况下机长可宣布医疗紧急情况（Medical Emergency），就近降落。通常会请求机上医疗专业人员协助。'},
  {c:'出国',q:'你的旅行同伴突然受伤流血，包扎前应该首先做什么？',o:['戴上手套（如有）保护自身，评估伤口严重程度，保持冷静；严重出血直接用干净布料施压（Direct Pressure）止血','立即清洗伤口（可能刺激伤口）','先找药店买药','先拍照记录'],a:0,e:'基础急救：严重出血处理原则是Direct Pressure（直接加压）——用干净布料（或徒手）持续用力按压伤口，不要移开查看（会破坏血凝块）。如出血不止，在专业医疗到来前继续加压。不要尝试取出深处的嵌入异物！'},
  {c:'出国',q:'在国外，你应该如何事先准备以应对医疗紧急情况？',o:['准备英文版病历摘要（包含血型、过敏史、慢性病、长期用药）、购买足额旅行医疗险、知道目的地的急救电话和最近医院位置','不需要提前准备','只需要带上常用药','完全依赖当地的急救系统'],a:0,e:'出发前医疗准备：①英文版医疗信息卡（ICE Card，含血型/过敏/既往病史/用药）放在钱包②购买含医疗和撤离的旅行险③检查目的地疫苗要求（黄热病/疟疾等）④带足够量的处方药（+处方复印件）⑤记录目的地急救电话。'},
  {c:'出国',q:'"SOS"是什么意思？国际上通用的求救信号还有哪些？',o:['SOS是国际通用的求救信号（摩尔斯电码：···—··· ），其他通用求救信号：用石头/旗子或手势做出"X"形、连续吹口哨三声、生火发烟（白天）或燃烧明火（夜晚）','SOS只用于海上','SOS=Save Our Ship（救救我们的船），仅在轮船上使用','SOS是密码，普通人不能使用'],a:0,e:'SOS（···—···）是国际通用求救信号，无特定含义（不是缩写的首字母）。野外求救信号：①数字3原则（3声响/3次闪光）②反光镜（镜面）传递信号③大型字母X（标在地面）⑤明显颜色布料或物品。'},
  {c:'出国',q:'你在国外骑共享单车摔倒受伤，共享单车公司的保险能覆盖你的医疗费用吗？',o:['视当地法律和共享单车公司政策而定，通常有限制；最可靠的是自购旅行险（含个人意外险和医疗险）','共享单车公司必须全额赔偿','中国社保在国外有效','不需要任何保险'],a:0,e:'旅行中的意外（骑车/行走受伤等）：①共享单车保险通常非常有限（可能只赔自行车损坏）②中国社保不适用于国外③旅行险的Personal Accident（个人意外）和Medical Expense（医疗费用）是你的主要保障④注意保险是否涵盖摩托车/自行车活动（部分险种明确排除）。'},
  {c:'出国',q:'你在国外发现有人掉入水中溺水（Drowning），你不擅长游泳，应该怎么做？',o:['大声呼救，拨打急救电话，寻找救生圈/绳子/棍子等抛给落水者，不要贸然跳入水中（非专业救援者自身也可能溺亡）','立刻跳入水中救人','只呼救，其他什么也不做','录制视频发送给救援人员'],a:0,e:'溺水救援黄金原则："Reach, Throw, Don\'t Go!"——①用棍子/绳子/救生圈等延伸工具施救②抛出可漂浮物③非专业人员不要直接跳水（落水者可能在恐慌中将救援者按入水中）。岸边高声呼救的同时拨打急救电话。'},
  {c:'出国',q:'在国外迷路且完全没有手机信号，你应该怎么办？',o:['保持镇定，停在原地不要乱走（更容易被找到），寻找地标，向附近居民求助，必要时等候并保持体温和体力','继续随便走以期找到出路','在夜间大声呼喊','独自在野外过夜不寻求帮助'],a:0,e:'野外迷路原则：STOP=Stop（停下）→Think（思考你从哪里来）→Observe（观察周围地形）→Plan（制定行动计划）。在人口稀少地区，等待救援比无目的游走更安全。出行前告知他人你的行程和预计返回时间！'},
  {c:'出国',q:'在国外发现你的旅行伴侣出现高烧（Temperature over 39°C）并意识模糊，正确处置是？',o:['立即拨打急救电话，尝试物理降温（凉湿毛巾擦身），不要给予大量冰水，保持侧卧位防止呕吐窒息，等待医疗救援','先给退烧药等待观察','继续旅行计划，到目的地再看医生','给予大量冰水饮用'],a:0,e:'高烧+意识模糊=医疗紧急情况！可能是严重感染（如脑膜炎、疟疾）。处置：①立即急救（Emergency）②降温（物理降温，不要冰水浸泡）③侧卧位（防止呕吐物堵塞气道）④不要延误等待。在东南亚出现这种症状要立即检查是否患疟疾（Malaria）。'},
  {c:'出国',q:'旅行保险中的"24小时紧急热线"有什么用？',o:['全天候提供：紧急医疗指导、协助就医、语言翻译、紧急撤离安排、法律援助推荐等综合服务','只用于查询保险条款','只提供电话导航','仅在保险公司工作时间有效'],a:0,e:'旅行险紧急热线（如平安保险全球救援：400-818-0100 / 阳光保险：00-86-10-5589-7678）提供：①24小时紧急协助②医院推荐及预授权③翻译协助④索赔指导⑤紧急撤离安排。出行前把这个号码存入手机，紧急时刻非常重要！'}
);


// ──────────────────────────────────────────────────────────────
// 【7】亚洲热门目的地 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_ASIA.push(
  {c:'旅游',q:'以下哪个不是日本的世界遗产（UNESCO World Heritage Site）？',o:['东京迪士尼乐园','京都的历史古迹（Historic Monuments of Ancient Kyoto）','奈良的历史古迹','广岛原爆纪念碑（Hiroshima Peace Memorial）'],a:0,e:'东京迪士尼不是世界遗产。日本现有25个世界遗产（2024年）。著名的有：富士山、京都古迹群、姬路城、广岛原爆纪念碑（Genbaku Dome）、屋久岛等。'},
  {c:'旅游',q:'印度的"Taj Mahal"（泰姬陵）建于何时？为什么而建？',o:['17世纪（1632-1653年），由莫卧儿皇帝沙贾汗为纪念其爱妃慕塔芝·玛哈尔而建','15世纪，作为皇宫','19世纪，英国殖民地时期建造','20世纪，现代纪念碑'],a:0,e:'泰姬陵（Taj Mahal）是世界七大奇迹之一，位于印度阿格拉（Agra）。由沙贾汗（Shah Jahan）为悼念爱妻慕塔芝（Mumtaz Mahal）所建，历时22年。是伊斯兰建筑的杰作，已被列为UNESCO世界遗产。'},
  {c:'旅游',q:'香港"Ocean Park"（海洋公园）和"Disneyland"（迪士尼乐园）各有什么特色？',o:['Ocean Park以海洋生物、主题游乐设施和中国文化为特色；Disneyland以迪士尼IP、经典游乐项目和奇幻王国主题为特色','两者完全相同','Ocean Park更适合成人','Disneyland没有游乐设施'],a:0,e:'香港Ocean Park（海洋公园）：大熊猫、海豚表演、特色缆车、香港文化展示，价格较迪士尼便宜。香港迪士尼：全球最小的迪士尼（正在扩建），适合喜爱迪士尼IP的家庭。根据旅行目的选择！'},
  {c:'旅游',q:'去柬埔寨吴哥窟（Angkor Wat）旅游，最佳观看日出的位置是？',o:['在吴哥窟主神庙的倒影池前（Reflection Pond），日出时神庙倒映水中，是最经典的摄影构图位置','在热气球上','在主神庙顶部（游客不允许登顶）','在暹粒市区'],a:0,e:'吴哥窟日出是世界最美日出之一。最佳位置：神庙西侧的倒影池前（需天黑前入场），可拍到神庙倒影。要注意旺季人山人海，需要提前占位。门票3天证约$72，包含吴哥窟、巴戎寺（Bayon）、塔普伦寺（Ta Prohm）等。'},
  {c:'旅游',q:'缅甸蒲甘（Bagan）以什么著名？',o:['数千座佛塔（Pagodas/Stupas）组成的古代佛教遗址，乘热气球俯瞰是最著名的旅游体验之一','以现代高楼大厦著名','以热带雨林著名','以冰川湖泊著名'],a:0,e:'蒲甘（Bagan）平原上有超过2000座古代佛塔（建于9-13世纪），是东南亚最壮观的古迹群之一。黎明时分乘热气球（Hot Air Balloon）俯瞰数千座佛塔和日出，是很多旅行者心目中的终极体验。旅行前注意缅甸局势。'},
  {c:'旅游',q:'去日本旅游，"JR Pass"（日本铁路周游券）的主要适用人群是？',o:['主要适用于外国游客（非日本居民），需要在出日本前在海外购买；持Pass可在规定时间内无限次乘坐JR线（包含大部分新干线）','日本本地居民','只适用于老年人和学生','在日本任何售票处都可购买'],a:0,e:'JR Pass（日本铁路周游券）=专为外国游客设计，需在日本境外购买（现在也允许在日本境内购买但价格更高）。有7天/14天/21天版本。如果行程跨越多个城市（如东京→京都→广岛→大阪），JR Pass通常比单程票划算。'},
  {c:'旅游',q:'台湾的"Night Market"（夜市）最著名的有哪些？有什么必吃食物？',o:['台北士林夜市（Shilin）、饶河街夜市等；必吃：臭豆腐（Stinky Tofu）、大肠包小肠、珍珠奶茶、蚵仔煎、胡椒饼','台湾没有著名夜市','夜市只卖非食品商品','夜市只在冬季开放'],a:1,e:'台湾夜市是台湾旅游必体验项目！士林夜市（Shilin Night Market）是最大最有名的，营业时间通常晚上6点到凌晨。珍珠奶茶（Bubble Tea）发源于台湾，在全球风靡。夜市小吃价格实惠（一般50-150台币）。'},
  {c:'旅游',q:'韩国的"K-pop"文化旅游包括哪些体验？',o:['SM、YG等大型娱乐公司的COEX/弘大等地参观、K-pop主题咖啡馆、明星手印（星光大道）、首尔东大门潮流购物等','K-pop只是音乐，与旅游无关','只有韩国人才能参与K-pop活动','K-pop旅游只在釜山'],a:0,e:'韩国首尔已成为重要的K-pop文化旅游目的地：明洞（购物/街头小吃）、弘大（年轻人文化/地下音乐）、江南（K-pop公司聚集地）、北村韩屋村（传统文化）。景福宫门卫换岗也是必看项目。'},
  {c:'旅游',q:'越南河内（Hanoi）和胡志明市（Ho Chi Minh City）分别位于越南的哪个部分？',o:['河内在越南北部（首都）；胡志明市在越南南部（最大城市，旧称西贡Saigon）','两者都在南部','河内在南部，胡志明在北部','两者都在中部'],a:0,e:'越南南北差异明显：北部（河内）=政治中心，气候较凉，文化传统；南部（胡志明/西贡）=商业中心，气候热带，国际化程度高。中部有顺化（Hue，古都）、会安（Hoi An，古镇）、岘港（Da Nang，海滩）。'},
  {c:'旅游',q:'斯里兰卡的"Ceylon Tea"（锡兰红茶）享誉全球，以下说法正确的是？',o:['斯里兰卡原名Ceylon，是世界三大茶产区之一（另两个是中国和印度），其高地茶园是重要旅游景点','Ceylon是印度的一个省','锡兰红茶产自非洲','锡兰红茶是中国独有品牌'],a:0,e:'斯里兰卡（Sri Lanka）殖民地时代名称为Ceylon，其高地茶园（如努沃勒埃利耶Nuwara Eliya地区）是世界著名红茶产地。参观茶园、品茶是来斯里兰卡的必选体验。斯里兰卡还有古迹锡吉里耶（Sigiriya，狮子岩）等世界遗产。'},
  {c:'旅游',q:'以下哪个国家的首都不在字母A或B开头？',o:['马来西亚（首都：吉隆坡Kuala Lumpur，以K开头）','阿富汗（首都：喀布尔Kabul）','孟加拉国（首都：达卡Dhaka）','阿拉伯联合酋长国（首都：阿布扎比Abu Dhabi）'],a:0,e:'记忆亚洲首都：Kuala Lumpur（吉隆坡）是马来西亚首都，KL是常用缩写。其他亚洲首都：Tokyo（日本）、Seoul（韩国）、Bangkok/Krung Thep（泰国）、Manila（菲律宾）、Jakarta（印尼，正在迁至Nusantara）。'},
  {c:'旅游',q:'在菲律宾，"Jeepney"（吉普尼）是什么？',o:['当地最具代表性的公共交通工具，由二战时美军遗留吉普车改装，色彩鲜艳，是菲律宾文化符号之一','一种菲律宾传统食物','菲律宾军队的一种','一种海岛旅游活动'],a:0,e:'Jeepney（吉普尼）=菲律宾最有特色的交通工具，由二战美军吉普改装，车身绘有华丽彩绘和装饰，是菲律宾国家形象的象征。费用极低（约10-20菲律宾比索），是当地人主要通勤工具，但路线复杂，外地游客需要指引。'},
  {c:'旅游',q:'去不丹（Bhutan）旅游有什么独特的要求？',o:['外国游客（除印度/孟加拉/马尔代夫公民）必须通过认证旅行社预订，且每天需支付固定旅游税（Sustainable Development Fee，每天约$100）','不丹禁止外国游客入境','不丹只接受中国游客','不需要任何特殊手续'],a:0,e:'不丹以"高价值、低游量"（High Value, Low Volume）旅游政策闻名，限制游客数量以保护文化和环境。外国游客需要：①通过认证旅行社预订②支付SDF（可持续发展费）③所有行程必须预先规划。但体验非常独特，被称为"雷龙之国"。'},
  {c:'旅游',q:'以下关于新加坡的说法，哪个是错误的？',o:['新加坡是东南亚最大的国家（面积最大）','新加坡是全球最重要的金融中心之一','新加坡的"Hawker Centre"（小贩中心）是体验当地饮食文化的最佳场所','新加坡有两位米其林一星的小贩（Hawker）—— 是世界上最便宜的米其林星级美食'],a:0,e:'新加坡面积仅约733平方公里，是东南亚面积最小的国家（但人均GDP最高）。新加坡Hawker Centre（熟食中心）的美食极具特色，多元民族融合（中式/马来/印度/峇峇娘惹等），且价格亲民（约$3-5新元/份）。'},
  {c:'旅游',q:'尼泊尔的"Everest Base Camp Trek"（珠峰大本营徒步）的起点通常是哪里？',o:['卢克拉（Lukla），需乘坐小型飞机从加德满都抵达（Tenzing-Hillary Airport，全球最危险机场之一）','直接从加德满都徒步出发','从中国西藏入境','从印度边境进入'],a:0,e:'EBC（Everest Base Camp Trek）经典路线：加德满都→卢克拉（飞行约35分钟）→南崎巴扎（Namche Bazaar）→珠峰大本营（海拔5364米），全程约14-21天。徒步前建议进行高原适应训练，出发前购买旅行险（含高原医疗）。'},
  {c:'旅游',q:'马尔代夫（Maldives）的"Water Villa"（水上别墅）有什么特点？',o:['建于海面上的独立别墅，有独立泳池/楼梯可直接入海，通常价格昂贵（每晚500-3000美元）但体验顶级','马尔代夫没有水上别墅','只有最贵的岛才有','水上别墅没有私人泳池'],a:0,e:'Water Villa（水上别墅/Overwater Bungalow）是马尔代夫最具代表性的住宿体验。推荐时间：1月-4月（旱季，海水清澈、阳光明媚）。预订要点：①注意是否在礁湖（Lagoon）内（更平静清澈）②餐食是否包含（全包Meal Plan更划算）③转机快艇/水上飞机费用。'},
  {c:'旅游',q:'以下哪项不是去日本旅游的最佳时间？',o:['8月盂兰盆节期间（Obon，国内旅游高峰，景区人满为患、价格昂贵）','3-4月樱花季（Cherry Blossom Season）','10-11月红叶季（Autumn Foliage）','11月下旬-12月（较为宁静，光明节前的淡季）'],a:0,e:'日本旅游旺季：3-4月（樱花）和10-11月（红叶）最受外国游客欢迎。日本人国内旅游高峰：黄金周（4月底-5月初）、盂兰盆节（8月中）、年末年初。这些时期机票酒店价格高且景区拥挤，建议避开。'},
  {c:'旅游',q:'印度尼西亚的科莫多岛（Komodo Island）以什么著名？',o:['科莫多巨蜥（Komodo Dragon），世界上最大的蜥蜴，体长可达3米，是当地的濒危保护动物','热带珊瑚礁潜水','沙滩冲浪','活火山徒步'],a:0,e:'Komodo Dragon（科莫多龙）是仅存于印尼科莫多群岛的巨蜥，是地球上现存最大的蜥蜴。前往科莫多国家公园需要持有指定许可证，且必须有向导陪同（科莫多龙具有危险性）。'},
  {c:'旅游',q:'在中国（大陆）旅游，外国游客常遇到的不便是什么？',o:['许多国际App（Google、WhatsApp、Facebook等）被屏蔽，需要提前安装VPN；支付宝/微信支付需要中国手机号码才能正常使用','外国人不能在中国消费','中国不接受外国人旅游','外国游客需要特殊签证'],a:0,e:'来中国旅游外国人注意：①Google/Gmail/WhatsApp在大陆不可用，需提前安装VPN②支付宝/微信支付现已支持外国信用卡绑定（境外游客版）③Booking.com/Expedia等国际订房平台可用④大城市（北京/上海/广州）英语环境较好。'},
  {c:'旅游',q:'哈萨克斯坦的阿拉木图（Almaty）到首都阿斯塔纳（Astana）的最快交通方式是？',o:['飞机（约2小时，两城市相距约1100公里）','高铁（约3小时）','乘车（约15小时）','骑马（传统交通方式）'],a:2,e:'阿拉木图（Almaty）是哈萨克斯坦最大城市（前首都），阿斯塔纳（旧名努尔苏丹Nur-Sultan）是现首都。两城相距约1100公里，飞机最快（2小时）。哈萨克斯坦是中亚面积最大国家，中国公民现可免签入境（根据最新政策，请出行前核实）。'},
  {c:'旅游',q:'去泰国旅游，"Muay Thai"（泰拳）体验包括哪些活动？',o:['在拳馆学习泰拳基本动作（课程通常1-2小时）；或观看职业泰拳比赛（曼谷Rajadamnern Stadium/Lumpinee Stadium）','泰拳是秘密运动，外国人不能参与','只能在清迈才能体验','泰拳是饮食文化，不是武术'],a:0,e:'Muay Thai（泰拳）体验在泰国各地都有：曼谷、清迈、华欣等地都有拳馆提供外国游客的入门课程（Muay Thai Class）。曼谷的Rajadamnern Stadium和Lumpinee Stadium是观看职业比赛的最佳场所。'},
  {c:'旅游',q:'以下关于"Angkor Wat"（吴哥窟）的说法，哪个是正确的？',o:['吴哥窟是世界上最大的宗教建筑群，最初建于12世纪，是印度教（后改为佛教）神庙，印在柬埔寨国旗上','吴哥窟建于20世纪','吴哥窟是清真寺','吴哥窟位于泰国'],a:0,e:'Angkor Wat：①建于12世纪（约1113-1150年），苏利耶跋摩二世（Suryavarman II）建造②最初为印度教神庙（供奉毗湿奴），后转变为佛教寺庙③是全球面积最大的宗教建筑群（约162公顷）④印在柬埔寨国旗上。'}
);


// ──────────────────────────────────────────────────────────────
// 【8】欧洲经典目的地 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_EUROPE.push(
  {c:'旅游',q:'葡萄牙里斯本（Lisbon）著名的"Pastéis de Nata"是什么？',o:['葡式蛋挞（Custard Tart），外皮酥脆，内馅奶油蛋黄，是葡萄牙最著名的传统甜点，也是中国蛋挞的原型之一','一种葡萄牙传统面包','一种海鲜烹饪方式','里斯本著名的古堡'],a:0,e:'Pastéis de Nata（葡式蛋挞）发源于里斯本贝伦区（Belém）的Pastéis de Belém糕点店，自1837年起营业至今。据说澳门蛋挞（和香港蛋挞）都是葡式蛋挞的后代。里斯本必吃！'},
  {c:'旅游',q:'瑞士（Switzerland）最著名的旅游活动是什么？它属于欧盟吗？',o:['瑞士不属于欧盟（也不是申根区正式成员，但实行申根协议）；最著名的是滑雪（少女峰/策马特）、徒步、钟表珠宝购物、巧克力和奶酪','瑞士属于欧盟','瑞士最著名的是海滩','瑞士首都是苏黎世'],a:0,e:'瑞士特殊地位：①不属于EU（欧盟）②签署了申根协议（持申根签证可入境）③货币是瑞士法郎CHF而非欧元④首都是伯尔尼（Bern），苏黎世（Zurich）是最大城市。旅游亮点：少女峰（Jungfrau）、策马特（Zermatt）/马特洪峰（Matterhorn）、日内瓦湖。'},
  {c:'旅游',q:'冰岛（Iceland）的"Northern Lights"（北极光）最佳观看月份是？',o:['9月至翌年3月（需要黑暗天空，冰岛夏季白夜几乎全天有光，无法看到北极光）','6-8月夏季','全年任何时间','只有12月25日圣诞节'],a:0,e:'Northern Lights（Aurora Borealis，北极光）观看条件：①黑暗天空（冬季，9月-3月）②晴朗无云③远离城市灯光④KP指数（地磁活动指数）≥3。冰岛最佳观光地点：雷克雅未克郊外、黑沙滩、斯奈山半岛。'},
  {c:'旅游',q:'捷克共和国的"Prague"（布拉格）有什么著名景点？',o:['布拉格城堡（Prague Castle，世界最大古堡建筑群）、查理大桥（Charles Bridge）、老城广场（Old Town Square）和天文钟（Astronomical Clock）','只有啤酒厂','布拉格没有历史建筑','布拉格在斯洛伐克'],a:0,e:'布拉格（Prague/Praha）：捷克首都，被称为"欧洲最美城市"之一。布拉格城堡（Hradčany）是世界面积最大的古堡建筑群。著名的老城区（Staré Město）于1992年被列为世界遗产。捷克现已加入申根区，货币仍为捷克克朗（CZK）非欧元。'},
  {c:'旅游',q:'土耳其的"Cappadocia"（卡帕多西亚）有什么独特的旅游体验？',o:['乘坐热气球（Hot Air Balloon）俯瞰奇特的"仙人烟囱"（Fairy Chimneys）地貌；住在凿岩而成的洞穴酒店（Cave Hotel）','冲浪和海滩度假','参观现代化都市风光','极地探险'],a:0,e:'卡帕多西亚（Cappadocia）位于土耳其中部，以独特的火山地貌（奇石柱"仙人烟囱"）和早期基督教洞穴教堂著名。热气球飞行（Black Balloon Ride）是最受欢迎的旅游体验。住洞穴酒店也是必体验之一！'},
  {c:'旅游',q:'挪威的"Fjord"（峡湾）是如何形成的？',o:['由古代冰川侵蚀岩石后，冰川融化海水倒灌形成的深而窄的海湾，两侧是陡峭的山壁','由火山喷发形成','由河流冲积形成','由地壳运动地震形成'],a:0,e:'Fjord（峡湾）=挪威最具代表性的自然景观。冰川时代，巨大冰川沿着河谷不断侵蚀，留下深达数百米的U形谷地，冰川消退后海水涌入形成峡湾。盖朗格峡湾（Geirangerfjord）和奈罗峡湾（Nærøyfjord）是UNESCO世界遗产。'},
  {c:'旅游',q:'到"Vatican City"（梵蒂冈）旅游，参观西斯廷礼拜堂（Sistine Chapel）的注意事项是？',o:['着装要保守（遮肩遮膝），禁止拍照（正式规定，虽然很多人违规），礼拜堂内要保持安静，建议提前网上购票避免长队','可以随意拍照','无需事先购票直接入场','梵蒂冈不开放参观'],a:0,e:'梵蒂冈（Vatican City）是世界最小国家，位于罗马城内。西斯廷礼拜堂（Sistine Chapel）有米开朗基罗的著名穹顶壁画《创世纪》。参观梵蒂冈博物馆需要提前在官网预订门票，旺季现场排队可达数小时。'},
  {c:'旅游',q:'西班牙巴塞罗那的"Sagrada Família"（圣家族大教堂）由谁设计？预计何时完工？',o:['由建筑师安东尼·高迪（Antoni Gaudí）设计，1882年开始建造，预计2026年或稍后完工（建造时间超过140年）','由毕加索设计','1950年代开始建造','早已于1950年完工'],a:0,e:'Sagrada Família是高迪（Gaudí）最伟大的作品，以独特的有机曲线风格著称，是UNESCO世界遗产。高迪1926年去世时仅完成约25%，之后靠门票收入和捐款继续建造。建筑融合了Gothic和Art Nouveau风格，每一面都有不同的宗教主题。'},
  {c:'旅游',q:'波兰的"Auschwitz-Birkenau"（奥斯维辛-比克瑙集中营）是什么历史遗址？参观时应该注意什么？',o:['二战期间纳粹德国的灭绝营，约110万人（主要是犹太人）在此遇难；参观时应保持严肃庄重，不要拍不尊重的照片','一座中世纪城堡','波兰王室的宫殿','一个主题公园'],a:0,e:'奥斯维辛集中营是二战最著名的纳粹大屠杀遗址，1979年被列为UNESCO世界遗产。参观礼仪极为重要：保持安静庄重，不在遇难者遗物前摆拍，门票免费但需提前预约，英语导览非常推荐，需要有心理准备——参观体验非常沉重。'},
  {c:'旅游',q:'匈牙利布达佩斯（Budapest）的"Thermal Baths"（温泉浴场）最著名的是哪个？',o:['塞切尼温泉浴场（Széchenyi Baths），是欧洲最大的温泉浴场之一，在新文艺复兴风格的建筑内，可室外泡温泉','盖勒特浴场（Gellért Baths）也非常著名（两者都是正确答案）','布达佩斯没有温泉','温泉只在匈牙利乡村'],a:0,e:'布达佩斯以"温泉之都"著称。最著名的两个：①塞切尼浴场（Széchenyi）=城市公园内，最热闹最大型，室外大池非常有拍照效果②盖勒特浴场（Gellért）=宏伟Art Nouveau建筑内，更精致典雅。浴场通常全天开放，含泳衣租借服务。'},
  {c:'旅游',q:'爱尔兰（Ireland）和英国的北爱尔兰（Northern Ireland）有什么区别？',o:['爱尔兰（Republic of Ireland）是独立国家，货币为欧元，首都都柏林；北爱尔兰是英国的一部分，使用英镑，首都贝尔法斯特','两者是同一个国家','北爱尔兰已独立','两者都使用欧元'],a:0,e:'爱尔兰岛分为两个政治实体：①爱尔兰共和国（Republic of Ireland）=独立国家，欧盟成员，货币€，首都Dublin②北爱尔兰（Northern Ireland）=英国（UK）的一部分，货币£，首都Belfast。两者之间曾有边境但现已实现基本自由通行（Good Friday Agreement）。'},
  {c:'旅游',q:'德国慕尼黑的"Oktoberfest"（啤酒节）实际上在几月份举行？',o:['主要在9月下旬到10月初（传统上在9月下旬开始，约持续16-18天，最后一天在10月第一个周日）','10月全月','8月','11月'],a:0,e:'Oktoberfest（慕尼黑啤酒节）：世界上最大的民间节日，每年吸引约600万游客。传统上9月下旬开幕（约9月第三个周六），10月初结束。啤酒帐篷（Beer Tent）需要提前很多个月预约桌位。穿传统服装Dirndl（女）和Lederhosen（男）增添气氛！'},
  {c:'旅游',q:'丹麦（Denmark）的"Hygge"文化是什么？',o:['一种以舒适温馨、与亲友共处、享受简单生活为核心的生活哲学（发音：HYU-guh），影响全球生活方式潮流','丹麦的官方语言','一种传统舞蹈','丹麦最著名的建筑风格'],a:0,e:'Hygge（丹麦/挪威语）=舒适惬意的生活哲学，包含：烛光、温暖室内、好友相聚、美食、无手机的宁静时光。丹麦连续多年被评为全球幸福指数最高国家之一，Hygge被认为是重要原因。在丹麦旅行体验Hygge：咖啡馆里捧着热可可、乘游船游览运河。'},
  {c:'旅游',q:'波罗的海三国是哪三个？它们各自的首都是什么？',o:['爱沙尼亚（塔林Tallinn）、拉脱维亚（里加Riga）、立陶宛（维尔纽斯Vilnius）','波兰、芬兰、瑞典','挪威、丹麦、冰岛','俄罗斯、乌克兰、白俄罗斯'],a:0,e:'波罗的海三国（Baltic States）：Estonia（爱沙尼亚）、Latvia（拉脱维亚）、Lithuania（立陶宛）。三国首都的老城区均为UNESCO世界遗产，保存了精美的中世纪建筑，且物价比西欧低，是欧洲的隐藏宝石旅游目的地。'},
  {c:'旅游',q:'到意大利旅游，"Colosseum"（斗兽场）建于何时？最多可容纳多少人？',o:['建于公元72-80年（罗马帝国时期），最多可容纳约50,000-80,000名观众','建于中世纪','最多容纳1000人','是现代建造的旅游景点'],a:0,e:'Colosseum（罗马斗兽场）=世界上最大的古代竞技场，建于公元72-80年。原用于角斗士（Gladiator）比赛、动物猎捕表演等。是罗马（和意大利）最具代表性的地标。购票建议提前网上预订，可跳过长队。'},
  {c:'旅游',q:'去英国爱丁堡（Edinburgh）旅游，"Edinburgh Fringe Festival"是什么？',o:['世界上最大的艺术节（每年8月举办），包含数千场喜剧、戏剧、舞蹈等演出，很多节目是免费的','苏格兰传统音乐节','威士忌品鉴活动','皇室巡游庆典'],a:0,e:'Edinburgh Festival Fringe（爱丁堡边缘艺术节）：每年8月在爱丁堡举行，是全球最大的艺术节，持续约3周，有超过3000台演出。涵盖喜剧（Comedy）、戏剧（Theatre）、音乐、舞蹈等，部分演出免费，是体验英国当代艺术的绝佳机会。'},
  {c:'旅游',q:'以下哪个欧洲国家不使用欧元（€）作为官方货币？',o:['瑞典（使用瑞典克朗SEK，已于2024年投票暂不加入欧元区）','法国','德国','意大利'],a:0,e:'欧盟成员国不一定使用欧元：目前使用自有货币的EU国家（非欧元区）：瑞典（克朗SEK）、匈牙利（福林HUF）、捷克（克朗CZK）、波兰（兹罗提PLN）、罗马尼亚（列伊RON）等。非EU国家：瑞士（法郎CHF）、英国（英镑GBP）、挪威（克朗NOK）。'},
  {c:'旅游',q:'希腊雅典的"Acropolis"（卫城）有哪些主要建筑？',o:['帕台农神庙（Parthenon）是主体，还有厄瑞克忒翁神庙（Erechtheion）、胜利女神庙（Temple of Athena Nike）、山门（Propylaea）','只有帕台农神庙一座','卫城只有废墟','都是现代仿古建筑'],a:0,e:'雅典卫城（Acropolis of Athens）是建于山顶的古代希腊神庙建筑群，已有2500年历史，是世界古典建筑的杰作。帕台农（Parthenon）供奉雅典娜女神。注意：大部分精美的大理石雕刻（Elgin Marbles）现存于大英博物馆，希腊持续要求归还。'},
  {c:'旅游',q:'去俄罗斯莫斯科旅游，"Red Square"（红场）附近有哪些著名景点？',o:['克里姆林宫（Kremlin）、圣巴西尔大教堂（St Basil\'s Cathedral，彩色洋葱顶）、国家历史博物馆、列宁墓（Lenin\'s Mausoleum）','红场只是一个空旷广场','红场在圣彼得堡','红场只有军事阅兵时才开放'],a:0,e:'Red Square（Красная площадь）是莫斯科的心脏地带，虽名为"红场"但"Красная"在古俄语中原意是"美丽"。圣巴西尔大教堂（St Basil\'s Cathedral）是俄罗斯最具代表性的建筑，建于1555-1561年，伊凡雷帝时代。'},
  {c:'旅游',q:'去法国巴黎，"Musée d\'Orsay"（奥赛博物馆）收藏什么类型的艺术品？',o:['主要是印象派（Impressionist）和后印象派（Post-Impressionist）绘画（如莫奈、雷诺阿、梵高、高更），建筑本身是旧火车站改建','古埃及文物（那是卢浮宫）','现代当代艺术（那是蓬皮杜中心）','雕塑只（那是罗丹博物馆）'],a:0,e:'巴黎三大博物馆定位：①卢浮宫（Louvre）=古代到19世纪初（《蒙娜丽莎》《米洛的维纳斯》）②奥赛博物馆（Orsay）=印象派（莫奈睡莲、梵高自画像）③蓬皮杜中心（Pompidou）=现代当代艺术（毕加索等）。'},
  {c:'旅游',q:'在荷兰，"Windmills"（风车）最集中的地区是？风车最初用来做什么？',o:['小孩堤坝（Kinderdijk），是UNESCO世界遗产；风车最初用来排水抽水（荷兰大面积土地低于海平面，靠风车抽水防洪）','阿姆斯特丹市中心','鹿特丹港口区','荷兰没有保存完好的风车'],a:0,e:'荷兰风车（Windmill）：Kinderdijk（小孩堤坝，Rotterdam附近）有19座完整保存的风车，是UNESCO遗产。风车最早用于抽水（水力管理），让低于海平面的土地（Polder）保持干燥。现代荷兰也大量使用风力发电机（Wind Turbine）。'},
  );


// ──────────────────────────────────────────────────────────────
// 【9】美洲及大洋洲 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_AMERICAS.push(
  {c:'旅游',q:'美国"National Parks"（国家公园）系统有什么特点？如何进入？',o:['美国拥有63个国家公园（如黄石/大峡谷/优胜美地），可购买"America the Beautiful Pass"（$80/年）无限进入所有国家公园','所有国家公园免费进入','国家公园不需要提前预约','只有本国公民可以进入'],a:0,e:'美国国家公园：①63个NPS（National Park Service）管理的国家公园②收费通常$15-35/车③"Annual Pass"（$80/年）无限进入所有国家公园，超2次就回本④黄石/冰川/拱门等热门公园需要提前网上预约停车证（Timed Entry Permit）。'},
  {c:'旅游',q:'加拿大的魁北克省（Quebec）有什么独特的文化特色？',o:['以法语文化为主（唯一以法语为官方语言的省份），蒙特利尔（Montreal）和魁北克城（Quebec City）保留了大量法国殖民地历史建筑','魁北克以英语文化为主','是加拿大唯一的英语省份','没有任何独特文化特色'],a:0,e:'Quebec（魁北克）是加拿大唯一以法语为官方语言的省份。魁北克城（Quebec City）旧城区是北美唯一保存完好的城墙城市，已被列为UNESCO世界遗产。冬季嘉年华（Winter Carnival）是世界上最大的冬季节庆之一。'},
  {c:'旅游',q:'巴西亚马逊雨林（Amazon Rainforest）有什么生态意义？',o:['被称为"地球之肺"，产生全球约20%的氧气，拥有全球最高生物多样性（约10%的物种），是全球重要的碳汇和气候调节器','亚马逊雨林不产生氧气','亚马逊雨林已完全消失','亚马逊雨林只在巴西境内'],a:0,e:'Amazon Rainforest跨越9个国家（巴西占60%），是世界最大的热带雨林。生态重要性：①全球约10%的物种生活于此②调节全球气候和水循环③储存大量碳④为数百万原住民提供家园。近年来由于砍伐和气候变化面临严峻威胁。'},
  {c:'旅游',q:'"Galapagos Islands"（加拉帕戈斯群岛）在哪个国家？为什么在科学上著名？',o:['属于厄瓜多尔（Ecuador）；达尔文在此观察独特动物物种，启发了进化论（Theory of Evolution by Natural Selection）的提出','属于秘鲁','属于智利','属于哥伦比亚'],a:0,e:'加拉帕戈斯群岛（Galápagos）：位于太平洋，属厄瓜多尔领土。1835年达尔文（Charles Darwin）乘"小猎犬号"（HMS Beagle）到访，观察到不同岛屿间物种的差异，启发了自然选择进化论。当地特有动物：加拉帕戈斯象龟、海鬣蜥、达尔文雀。'},
  {c:'旅游',q:'秘鲁的"Machu Picchu"（马丘比丘）有什么特点？如何到达？',o:['15世纪印加帝国的石造城市，位于海拔约2430米山顶，现为UNESCO世界遗产；可从库斯科（Cusco）乘火车+巴士到达，或徒步印加古道（Inca Trail）4天','马丘比丘在玻利维亚','乘飞机直达','是现代建造的旅游景点'],a:0,e:'Machu Picchu（马丘比丘）：建于约1450年，印加帝国的"失落之城"，1911年被美国探险家重新发现。到达方式：库斯科→乘Vistadome/Expedition列车到Aguas Calientes→乘巴士上山。也可徒步Inca Trail（需提前数月预约，每日限额500人）。'},
  {c:'旅游',q:'美国的"Times Square"（时代广场）在哪个城市？以什么著名？',o:['纽约市（曼哈顿）；以巨型LED广告牌、百老汇剧院区、新年倒计时降球（Ball Drop）著名','洛杉矶','芝加哥','旧金山'],a:0,e:'Times Square（时代广场）位于曼哈顿中城，是全球游客最多的地区之一。著名：①百老汇剧院区（Broadway）②大型LED/霓虹广告牌③新年倒计时（New Year\'s Eve Ball Drop）每年吸引百万人⑤24小时都热闹非凡。周边有许多旅游景点：洛克菲勒中心、MoMA、帝国大厦。'},
  {c:'旅游',q:'澳大利亚的"Great Barrier Reef"（大堡礁）面临的最大威胁是什么？',o:['气候变化导致的海水升温和珊瑚白化（Coral Bleaching），以及海洋酸化（Ocean Acidification）','过度捕鱼','石油泄漏','旅游活动本身'],a:0,e:'Great Barrier Reef（大堡礁）是全球最大的珊瑚礁系统，也是UNESCO世界遗产。自1980年代以来，约50%的珊瑚已因珊瑚白化（Coral Bleaching，由海水升温引起珊瑚排出藻类）而死亡。可在凯恩斯（Cairns）或汉密尔顿岛（Hamilton Island）参加潜水/浮潜观光。'},
  {c:'旅游',q:'新西兰的"Hobbiton"（霍比特村）在哪里？这是什么景点？',o:['位于新西兰马塔马塔（Matamata）附近的私人农场，是《指环王》（Lord of the Rings）和《霍比特人》（The Hobbit）电影中霍比屯的实景拍摄地','只存在于电影中','在威灵顿市内','在南岛基督城'],a:0,e:'Hobbiton Movie Set（霍比特村电影取景地）：彼得·杰克逊（Peter Jackson）在当地农场建造了真实霍比屯布景。现为重要旅游景点，提供导览游（约2.5小时），包含参观地洞小屋、绿龙酒馆（Green Dragon Inn）和试喝特色饮料。'},
  {c:'旅游',q:'智利的"Atacama Desert"（阿塔卡马沙漠）有什么特别之处？',o:['是地球上最干旱的非极地沙漠，年均降雨量不到1毫米；以壮观的星空（全球最佳天文观测地之一）和盐湖（如阿塔卡马盐湖）著名','是世界最大的沙漠','以热带植被著名','位于巴西'],a:0,e:'Atacama Desert（阿塔卡马沙漠）：南美洲西海岸，跨越智利和秘鲁。特点：①世界最干旱沙漠（部分地区数十年无降雨）②高海拔（多在2400-4800米）③全球最佳天文观测地（无光污染，空气透明度极高）④月亮谷（Valle de la Luna）的奇特地貌。'},
  {c:'旅游',q:'哥伦比亚的卡塔赫纳（Cartagena）因为什么著名？',o:['保存完好的西班牙殖民地时代城墙老城（Walled City），色彩鲜艳的建筑，是UNESCO世界遗产','以毒品旅游著名（这是负面刻板印象，不代表现实的卡塔赫纳）','以丛林探险为主','是哥伦比亚首都'],a:0,e:'Cartagena de Indias（卡塔赫纳）：哥伦比亚加勒比海岸的殖民地古城，城墙老城（Ciudad Amurallada）已被列为UNESCO世界遗产，以粉色、黄色等鲜艳的建筑和热带风情著称。近年来哥伦比亚旅游业快速复苏，是南美洲越来越受欢迎的目的地。'},
  {c:'旅游',q:'美国"Las Vegas"（拉斯维加斯）著名的"Strip"（赌场大道）位于哪个州？',o:['内华达州（Nevada）；"The Strip"是拉斯维加斯大道南段，聚集了世界上最大最豪华的赌场酒店（如Bellagio、MGM Grand、Caesars Palace）','加利福尼亚州','亚利桑那州','犹他州'],a:0,e:'Las Vegas Strip（拉斯维加斯大道）：内华达州，约6.7公里长，聚集了全球最奢华的赌场酒店。著名景观：贝拉吉奥喷泉秀（Bellagio Fountains）、威尼斯人运河（The Venetian）、自由女神仿制品（New York-New York）。即使不赌博也有很多娱乐可以体验。'},
  {c:'旅游',q:'古巴（Cuba）首都哈瓦那（Havana）对中国游客来说有什么特别之处？',o:['保存了大量1950年代的美国老爷车（Classic American Cars），殖民地时代建筑，加勒比海文化，且中国公民可相对较容易地申请签证','古巴对中国游客完全开放无需签证','古巴禁止外国人旅游','哈瓦那是现代化都市'],a:1,e:'古巴（Cuba）特点：①1950年代美国老爷车是标志性街景（1961年禁运后无法进口新车）②生动的拉丁音乐文化③哈瓦那老城（Habana Vieja）为UNESCO遗产④中国公民需提前申请签证⑤信用卡在古巴可能无法使用，建议携带现金（欧元或加拿大元）。'},
  {c:'旅游',q:'厄瓜多尔首都基多（Quito）有什么地理上的特殊之处？',o:['位于赤道附近的安第斯山脉上，海拔约2850米，是世界上距离赤道最近的首都之一，也是海拔最高的首都之一','是世界上海拔最低的首都','位于海边','是世界上最热的首都'],a:0,e:'Quito（基多）：位于南纬0°13\'，海拔2850米，是世界上距赤道最近且海拔最高的首都之一。附近有"赤道纪念碑"（Mitad del Mundo），但实际赤道线位置与纪念碑稍有偏差（GPS测量的实际位置在北边约240米）。'},
  {c:'旅游',q:'澳大利亚原住民（Aboriginal Australians）最著名的艺术形式和文化传统是什么？',o:['点画艺术（Dot Painting）、梦幻时代（Dreamtime）神话体系、迪吉里杜管（Didgeridoo，管乐器）和回旋镖（Boomerang）','制作陶瓷','建造石头城市','以农业闻名'],a:0,e:'澳大利亚原住民文化是世界上最古老的持续存在的文化之一（历史超过65,000年）。Dreamtime（梦幻时代）=原住民宇宙观和创世神话体系。乌鲁鲁（Uluru/Ayers Rock）是原住民圣地，现已禁止攀登（2019年起）以示尊重。'},
  {c:'旅游',q:'巴西的"Carnival"（嘉年华）最著名的城市是哪里？通常在几月举行？',o:['里约热内卢（Rio de Janeiro），通常在2-3月（大斋期前的星期二，Fat Tuesday/Mardi Gras前后），持续5天','圣保罗（圣保罗也有嘉年华，但里约最著名）','巴西利亚','亚马逊雨林中'],a:0,e:'Rio Carnival（里约嘉年华）：全球最大的狂欢节，每年吸引超过200万人参与街头庆典。桑巴舞学校在桑巴大道（Sambódromo）的大游行是最壮观的活动。购票参观正式游行需提前很久（1年以上）。'},
  {c:'旅游',q:'加拿大班夫国家公园（Banff National Park）位于哪个省？以什么著名？',o:['艾伯塔省（Alberta）；以洛基山脉（Rocky Mountains）、路易斯湖（Lake Louise）的蓝绿色湖水、冰川（如哥伦比亚冰原）和野生动物（黑熊/麋鹿）著名','不列颠哥伦比亚省（BC）','安大略省','魁北克省'],a:0,e:'Banff National Park（班夫国家公园）：1885年建立，是加拿大第一个国家公园。路易斯湖（Lake Louise）的蓝绿色湖水（由冰川粉末形成）是经典明信片风景。夏季徒步、冬季滑雪都非常受欢迎。班夫小镇Banff Town是旅游服务中心。'},
  {c:'旅游',q:'阿根廷（Argentina）的"Patagonia"（巴塔哥尼亚）以什么旅游体验著名？',o:['徒步（Trekking）世界级冰川和山峰（如托雷斯德尔潘恩国家公园/Torres del Paine），莫雷诺冰川（Perito Moreno Glacier），以及南美特有野生动物','热带雨林探险','现代都市购物','沙漠骆驼骑行'],a:0,e:'Patagonia（巴塔哥尼亚）横跨阿根廷和智利南端，是地球上最后的荒野之一。Perito Moreno Glacier（莫雷诺冰川）是世界上少数仍在增长的冰川，可近距离观看冰块崩落入湖（Calving）的壮观景象。'},
  {c:'旅游',q:'波多黎各（Puerto Rico）对美国公民来说有什么特殊之处？',o:['波多黎各是美国领土（US Territory），美国公民无需护照即可前往，当地货币为美元，官方语言为西班牙语和英语','波多黎各是独立国家','需要签证','官方语言只有西班牙语'],a:0,e:'Puerto Rico（波多黎各）=美国自由邦（US Commonwealth），美国公民出行如同国内旅行（不需护照）。首都圣胡安（San Juan）的老城区（Old San Juan）有保存完好的西班牙殖民地城堡和彩色建筑，是加勒比海最受欢迎的目的地之一。'},
  {c:'旅游',q:'美国"Hawaii"（夏威夷）与美国大陆的时间差是多少？',o:['夏威夷使用HST（Hawaii Standard Time），比美国东部时间（EST）早5-6小时，比中国（CST）晚18-19小时（夏令时期间有差异）','和大陆时间相同','比大陆早2小时','比大陆晚2小时'],a:0,e:'夏威夷时区HST（UTC-10）：冬季比纽约早5小时，比加州早2-3小时（加州采用夏令时时差有变化，夏威夷不实行夏令时）。从中国飞往夏威夷约9-10小时，需要穿越日期线（International Date Line），注意日期变化！'},
  {c:'旅游',q:'巴拿马运河（Panama Canal）在世界地理和贸易中的重要性是什么？',o:['连接太平洋（Pacific Ocean）和大西洋（Atlantic Ocean/Caribbean Sea），使船只避免绕行南美洲最南端（Cape Horn），将航程缩短约15000公里','只对巴拿马有经济意义','是一条铁路，不是运河','运河已废弃不用'],a:0,e:'Panama Canal（巴拿马运河）：建于1904-1914年，全长约82公里，通过船闸系统（Locks）提升船只穿越分水岭。每年通过约14000艘船只，占全球海运贸易约5%。已于1999年由美国移交巴拿马管理。可在观景平台观看船只过闸。'},
  {c:'旅游',q:'玻利维亚（Bolivia）的"Salar de Uyuni"（乌尤尼盐沼）有什么特别的旅游体验？',o:['世界最大的盐沼（约10582平方公里），雨季（12-3月）积水后形成完美反射天空的"天空之镜"（Mirror Effect），是全球最受追捧的摄影地之一','是一片普通的海滩','位于海平面以下','夏季才有盐沼'],a:0,e:'Salar de Uyuni（乌尤尼盐沼）：位于玻利维亚西南高原（海拔约3656米），由干涸的史前湖泊形成。旱季（6-10月）：白茫茫盐漠，可见六边形盐结晶；雨季（11-4月）：薄薄的水层创造完美镜面效果，与天空连成一片，是户外摄影的圣地。'},
  {c:'旅游',q:'美国波士顿（Boston）在美国历史上的重要地位是什么？',o:['是美国独立革命的发源地之一，有波士顿倾茶事件（Boston Tea Party, 1773）、邦克山战役等重要历史地点，也是美国最古老的大学城（哈佛、MIT均在波士顿地区）','是美国最大的城市','是美国的首都（实际上首都是华盛顿DC）','是第一个建立的美国城市'],a:0,e:'Boston（波士顿）：美国历史文化重镇。"自由之路"（Freedom Trail）是串联16个历史景点的步行路线。哈佛大学（Harvard，1636年建立，美国最古老大学）和麻省理工学院（MIT）均在附近的剑桥市（Cambridge）。波士顿还以海鲜浓汤（Clam Chowder）和红袜队（Red Sox）著名。'}
);


// ──────────────────────────────────────────────────────────────
// 【10】旅行高频词汇 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_TRAVEL.push(
  {c:'词汇',q:'"Wanderlust"是什么意思？这个词源自哪种语言？',o:['强烈的旅行渴望/漫游欲望；源自德语（Wandern=徒步旅行+Lust=渴望/激情）','害怕旅行的心理','旅行疲劳综合症','对异国文化的好奇心'],a:0,e:'"Wanderlust"=旅行欲（德语原词），形容对探索世界的强烈渴望，已成为英语中广泛使用的词汇，常见于旅行博客和社交媒体标签（#wanderlust）。'},
  {c:'词汇',q:'"Off the beaten track/path"是什么意思？',o:['远离热门旅游路线，探索冷门/非主流目的地','走在普通道路上','跑步锻炼的路线','飞机航线'],a:0,e:'"Off the beaten track"=偏离主流旅游路线，指去冷门的、游客较少的地方旅行。如："We went off the beaten path and discovered this amazing hidden village."（我们偏离主路，发现了这个很棒的隐秘村落）'},
  {c:'词汇',q:'"Bucket list"（遗愿清单/愿望清单）在旅行中是什么意思？',o:['生前想完成的旅行体验/想去的地方清单（"Kick the bucket"=死去，Bucket list=死前必做的事）','装行李的清单','购物清单','退款申请清单'],a:0,e:'"Bucket list"=遗愿清单，列出生前必须完成的事情和体验。"This hike was on my bucket list!"=这次徒步在我的愿望清单上！用作旅行语境时=毕生必去的旅行目的地清单。'},
  {c:'词汇',q:'"Couchsurfing"是什么旅行方式？',o:['通过CouchSurfing平台免费借住当地人家中（睡沙发/客房），与主人交流文化，是深度体验当地生活的方式','在汽车后备箱里睡觉','一种冲浪运动','付费民宿平台'],a:0,e:'CouchSurfing（沙发客）=旅行者与当地人互换接待的免费住宿文化。通过官方App/网站联系愿意接待的"主人"，住在他们家中，零住宿费用但需要真正的文化交流。适合预算有限且社交开放的旅行者。'},
  {c:'词汇',q:'"Digital nomad"是什么类型的旅行者/生活方式？',o:['利用互联网远程工作、同时在世界各地旅居的生活方式（不固定在某个城市，边工作边旅行）','只用数字地图的旅行者','不使用任何电子设备的旅行者','专门研究数字文化的学者'],a:0,e:'"Digital Nomad"（数字游民）=利用互联网和远程工作技术，在全球各地旅居工作的人。受COVID-19推动，远程工作普及后这种生活方式迅速增加。部分国家（如葡萄牙、爱沙尼亚、巴厘岛）已推出专门的数字游民签证。'},
  {c:'词汇',q:'"Slow travel"（慢旅行）的理念是什么？',o:['在一个地方停留更长时间，深度体验当地生活，而不是走马观花打卡式旅行；更环保（减少飞行次数）且通常花费更少','旅行过程中开车很慢','只乘火车不坐飞机','每天只参观一个景点'],a:0,e:'"Slow travel"与"Fast tourism"相对，强调：①在一个地点停留1周或更长②融入当地生活节奏（买菜/逛市场/学语言）③减少奔波和交通费用④更深刻的旅行体验。一个地方住1个月比30个地方各住1天收获更深。'},
  {c:'词汇',q:'"Hidden gem"在旅行语境中是什么意思？',o:['不为大众所知但非常值得一游的地方或体验（"宝藏目的地"）','宝石博物馆','珠宝商店','地下洞穴景点'],a:0,e:'"Hidden gem"=隐藏的珍宝，旅行语境中指鲜为人知但极具价值的目的地/餐厅/体验。"This tiny café is a real hidden gem!"=这家小咖啡馆真的是个宝藏！是旅行博主和旅游指南最常用的表达之一。'},
  {c:'词汇',q:'"Jet-setter"是什么类型的人？',o:['经常乘飞机旅行的富裕社会名流，过着奢华旅行生活的人','飞行员','旅行博主','航空公司员工'],a:0,e:'"Jet-setter"（时髦旅行族）=经常进行豪华国际旅行的富有人士，生活方式以飞行和奢华体验为特色。"She\'s a true jet-setter, spending her summers in Saint-Tropez and winters in Aspen."（她是真正的时髦旅行族，夏天在圣特罗佩，冬天在阿斯彭）。'},
  {c:'词汇',q:'"Gap year"（间隔年）在西方文化中指什么？',o:['在高中毕业后、大学开始前（或其他人生阶段转换时）花一年时间旅行、工作或体验生活，暂停传统学业/职业轨道','放弃学业的一年','专门学语言的一年','退休后的旅行生活'],a:0,e:'"Gap Year"=间隔年，在英国、澳大利亚等国是相当普遍的文化实践。内容可以包括：环球旅行、志愿工作（volunteer work）、语言学习、打工旅游（Working Holiday Visa）等。近年来在中国年轻人中也越来越流行。'},
  {c:'词汇',q:'"Overlanding"（越野长途自驾）是什么旅行方式？',o:['驾驶越野车（通常是4WD/Land Rover/Jeep）进行长途自驾旅行，露营途中，探索人迹罕至的地方，通常包括非铺装路面和野外生存技能','普通高速公路长途驾车','在沙漠骑骆驼','参加有导游的越野车游览'],a:0,e:'"Overlanding"=越野远征，以4WD越野车（Land Cruiser/Defender/Tacoma等）为载体，通常携带帐篷、炊具、备用燃料等在荒野中长途旅行。经典路线：非洲开罗到开普敦、泛美公路（Pan-American Highway）等。'},
  {c:'词汇',q:'"Travel hack"（旅行技巧/骚操作）包括哪些常见例子？',o:['使用里程/积分升舱、利用航班价格规律找最便宜的出发日期（周二/三通常更便宜）、在机场拿免费行李袋、订有免费取消政策的酒店等','违法绕过边境检查','作弊使用他人的优惠票','以上所有都是不道德行为'],a:0,e:'"Travel hacks"=旅行省钱/升级小技巧（合法且聪明的策略）：①清除浏览器Cookie再搜索机票（某些网站会对反复搜索的用户提高价格）②比较含税总价而非基础票价③红眼航班（overnight flight）更便宜且节省酒店费④Airbnb长租比按天算更便宜。'},
  {c:'词汇',q:'"Visa on arrival"（落地签）和"Visa-free"（免签）的区别是？',o:['Visa on arrival=到达目的地后在机场/口岸办理签证（通常需要付费）；Visa-free=无需签证直接入境，完全免办理手续','两者完全相同','Visa on arrival比Visa-free更麻烦但更安全','Visa-free=免费签证'],a:0,e:'中国公民出行签证分类：①免签（Visa-free）=无需任何签证手续直接入境②落地签（VOA/Visa on Arrival）=到机场后办理，需要准备材料和费用③电子签（eVisa）=提前网上申请④传统签证=需要预约面签。出行前务必查询最新政策！'},
  {c:'词汇',q:'"Travel advisory"（旅行警告）是什么？应该关注哪些来源？',o:['政府发出的安全警示，告知本国公民目的地国家的安全风险（政治局势/自然灾害/疾病等），建议旅行者注意或避免前往','旅行社的营销广告','景点的开放时间通知','签证申请指南'],a:0,e:'旅行安全警告发布来源：①中国外交部"领事服务网"（www.csm.mfa.gov.cn）②中国领事服务App（"领事直通车"）③目的地国家自己的外交部网站④世卫组织（WHO）的健康旅行建议。出行前必须查看，特别是前往局势不稳定地区。'},
  {c:'词汇',q:'"Biking tour"、"Hiking tour"、"Walking tour"在旅游中有什么区别？',o:['Biking=骑自行车游览；Hiking=在自然环境中步行（通常有一定坡度/难度）；Walking tour=城市中的徒步参观（通常由导游带领介绍历史文化）','三者完全相同','Hiking只能在山上进行','Walking tour是开车游览'],a:0,e:'城市旅行推荐：Free Walking Tour（免费城市步行导览）——在许多欧洲和南美城市，当地导游免费带你游览（导览结束后按满意度自愿给小费）。是了解城市历史文化和结识旅友的最佳方式，通常评价很高！'},
  {c:'词汇',q:'"Airbnb"和传统酒店相比，有哪些主要优缺点？',o:['Airbnb优点：价格通常更低（尤其长租）、更本地化体验、厨房设施可自炊；缺点：清洁费有时很高、服务不稳定、无法24小时前台、某些城市有法规限制','Airbnb比酒店贵','Airbnb没有缺点','酒店总是比Airbnb好'],a:0,e:'Airbnb（爱彼迎）vs 酒店：①Airbnb适合长租（1周以上）、多人旅行（整租比多间酒店便宜）、注重本地生活体验②酒店适合短住、需要稳定服务和位置便利③中间选项：Boutique Hotel（精品酒店）或Guesthouse（民宿）平衡了两者优点。'},
  {c:'词汇',q:'"Over-packing"（过度打包）是很多旅行者的常见问题，解决方法是什么？',o:['采用胶囊衣橱策略（Capsule Wardrobe），选择可以相互搭配的基础款；遵循"铺开所有你要带的东西，然后去掉一半"的原则；选择快干衣物','带越多越好','把所有衣服都带上以防万一','不用解决，行李可以超重'],a:0,e:'聪明打包技巧：①Rule of three（三件原则）：3件上衣/2条裤子/1双正式鞋/1双运动鞋②卷叠衣物（Rolling）比折叠更省空间③压缩袋（Compression Bags）减小体积④随身带的比托运更安全（行李丢失风险）⑤目的地洗衣比多带衣服更明智。'},
  {c:'词汇',q:'"Responsible tourism"（负责任旅游）的核心原则是？',o:['在享受旅行的同时，减少对当地环境和社区的负面影响，支持当地经济（选择本地商家/餐厅），尊重当地文化和习俗','以最低价格旅行','只参加官方旅游团','不拍任何照片'],a:0,e:'Responsible Tourism（负责任旅游）= Sustainable Tourism（可持续旅游）核心：①购买本地产品支持当地经济②减少塑料垃圾（带可重复使用水瓶）③选择环保交通④不购买野生动物制品⑤尊重当地文化和宗教传统⑥减少拍照骚扰当地人。'},
  {c:'词汇',q:'"Travel fatigue"（旅行疲劳）的主要症状是什么？',o:['对旅行感到倦怠、失去对新事物的兴奋感、思乡、做决策困难；通常在长途旅行2-3个月后出现','身体上的极度疲惫','对旅行的恐惧','对航空公司的不满'],a:0,e:'Travel fatigue（旅行疲劳/旅行倦怠）=长期旅行后出现的心理疲劳状态。症状：①不再对新地方感到兴奋②总想着"下一个目的地"而无法享受当下③决策疲劳（吃什么/去哪里）④极度思念家人和日常生活。解决方法：放慢节奏、在一处停留更长时间、建立日常规律。'},
  {c:'词汇',q:'"Ecotourism"（生态旅游）的定义和目的是什么？',o:['前往自然环境的负责任旅行，以欣赏和保护自然为目的，同时支持当地社区（通常包括环境教育），最小化旅行对生态的影响','在丛林里砍树','拍摄濒危动物的秘密活动','专门研究气候变化的科学旅行'],a:0,e:'Ecotourism（生态旅游）代表案例：哥斯达黎加（Costa Rica）是全球生态旅游的标杆国家，50%的国土是保护区，旅游收入用于保护热带雨林。坦桑尼亚（Tanzania）的保护区野生动物园（Safari）也是典型的生态旅游产品，门票费用用于野生动物保护。'},
  {c:'词汇',q:'"House-sitting"是什么样的旅行方式？',o:['在别人出门旅行时帮他们照看房子（通常包括照顾宠物），作为交换可以免费居住在该房子里，大幅节省住宿费用','付费住在别人家','租用整栋别墅','在别人家门口露营'],a:0,e:'House-sitting=代看房，通过平台（TrustedHousesitters/HouseCarers等）匹配：房主出行期间需要人照看房子和宠物→旅行者免费住宿换取照看服务。对旅行者：免费住宿+体验本地生活；对房主：安心出游+宠物得到照料。是双赢的旅行方式。'},
  {c:'词汇',q:'"Round-the-world"（RTW）机票是什么？适合哪类旅行者？',o:['联合多家航空公司的全球环绕行程机票，通常限制特定里程或城市数量，价格通常在$2000-5000不等；适合计划环球旅行的人','普通的往返机票','包含所有费用的旅游套餐','无限制随时飞的通票'],a:0,e:'RTW（Round-the-World）机票由Star Alliance、Oneworld等航空联盟发售，通常限制在12个月内完成，可在联盟成员航空公司的网络内选择多个城市（通常限制里程或城市数）。性价比评估：如果行程超过3-4个大洲，RTW通常比单独购买更划算。'},
  {c:'词汇',q:'"Timeshare"（分时酒店）是什么？有什么常见陷阱？',o:['购买特定度假地点特定时间段的使用权（如每年在某海边度假村2周），通常通过高压推销售出，有很多陷阱（难以转售/管理费持续上涨/灵活性差）','按小时租用酒店房间','酒店的会员积分计划','豪华游艇租赁'],a:0,e:'Timeshare警告：在旅游景点常被邀请"免费早餐"参加"信息发布会"，实际是高压销售Timeshare。特点：①一次性购买费用高②年度管理费（maintenance fee）持续上涨③极难转售（市场流动性差）④出行时间和地点不灵活。全球知名的消费者陷阱之一，请谨慎！'}
);


// ──────────────────────────────────────────────────────────────
// 【11】日常生活词汇 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_DAILY.push(
  {c:'词汇',q:'"Expat"（外派人员/海外侨民）和"Immigrant"（移民）有什么区别？',o:['Expat通常指由公司派驻或选择暂时居住在国外的专业人士（经常回国/有明确意图）；Immigrant通常指永久移居另一国家的人（通常来自发展中国家移往发达国家）','两者完全相同','Expat比Immigrant更正式','Immigrant比Expat有更高的社会地位'],a:0,e:'Expat（Expatriate的缩写）=暂居海外者，常用于描述来自发达国家在别处工作生活的专业人士。社会学者指出，同样是移居海外，来自发达国家的人常被称为"expat"，来自发展中国家的人则被称为"immigrant"，这反映了一定的文化偏见。'},
  {c:'词汇',q:'"Gentrification"（绅士化/高档化）是什么城市现象？',o:['原来低收入社区因吸引高收入居民和高档商业入驻而转型，原有低收入居民可能因租金上涨被迫迁走','城市绿化美化工程','政府将郊区改造成市中心','建设更多公共设施'],a:0,e:'Gentrification（绅士化）在旅游语境中很重要：曾经"有趣"的艺术家社区（如柏林米特、纽约布鲁克林）因旅游者涌入和租金上涨，逐渐失去原有特色和原住民。作为旅行者，意识到这个现象，选择本地经营的小餐厅而非大型连锁，有助于减缓这一进程。'},
  {c:'词汇',q:'"Carbon footprint"（碳足迹）在旅行中是什么意思？如何减少？',o:['旅行产生的二氧化碳排放量；减少方法：选择陆路（火车/大巴）代替飞行、乘经济舱（商务舱人均排放更高）、购买碳补偿（Carbon Offset）','旅行者留在景区的脚印','旅行中使用的燃料量','旅行照片的数量'],a:0,e:'旅行碳排放：一次从中国到欧洲的往返飞行大约排放2-4吨CO₂，相当于一个欧洲人约半年的日常碳排放量。减少措施：①尽量乘火车（特别是欧洲高铁）②选择直飞（起降阶段排放最多）③少坐飞机多深度旅行④购买认证的碳抵消项目。'},
  {c:'词汇',q:'在英语国家，"Toilet"、"Restroom"、"Bathroom"、"Loo"分别在什么场合使用？',o:['Toilet=厕所（英式，最直接）；Restroom=洗手间（美式，更委婉）；Bathroom=浴室（美式也用于指公厕）；Loo=厕所（英式俚语，很口语）','四者不能互换使用','Bathroom只指有浴缸的房间','Restroom只在餐厅使用'],a:0,e:'找厕所的表达因地区而异：美国公共场所说"Restroom"；英国说"Toilet"或"Loo"（口语）；餐厅/商场说"Where are the facilities?"（最委婉）。在他人家里说"May I use your bathroom?"最常见。注意：在英国问"Bathroom?"主人可能带你去真正的浴室！'},
  {c:'词汇',q:'"Homesick"（思乡）的英语表达有哪些？',o:['I miss home. / I\'m homesick. / I\'m longing to be back home.（这是正常情绪，长途旅行和旅居海外都常见）','I want to be here.','I love traveling.','I need a holiday.'],a:0,e:'Homesick（思乡）是旅行，尤其是长期旅居海外时非常常见的情绪。缓解方法：①建立本地社群②烹饪家乡食物③定期与家人视频④加入当地的华人社区。"Home is where the heart is."（心在哪里，家就在哪里）是常用安慰语。'},
  {c:'词汇',q:'"FOMO"是什么意思？在旅行中如何影响旅行者的决策？',o:['Fear Of Missing Out（错过恐惧症）；旅行中表现为：看到太多推荐景点，担心每个都必须去，反而无法放松享受当下','Fly Over Mid-Ocean（过洋飞行）','First-class Or Multiple Options（头等舱选择）','Free On Mobile Order（移动端免费订单）'],a:0,e:'FOMO（错过恐惧症）在旅行中极为常见：社交媒体上看到别人去的"网红打卡地"都想去，结果行程排满了却感觉很疲劳。对治FOMO的方法："JOMO"（Joy of Missing Out，享受错过的快乐）——有意识地放慢节奏，深度体验少数几个地方，比走马观花更有满足感。'},
  {c:'词汇',q:'"Souvenir"（纪念品）购买时应该注意哪些问题？',o:['避免购买象牙/玳瑁/珊瑚等濒危生物制品（违反CITES公约，进关可能被没收并罚款）；辨别是否为当地制造（Made in China的"本地特色纪念品"很常见）','什么都可以买，没有限制','所有纪念品都有海关限制','只能在机场免税店买纪念品'],a:0,e:'购买纪念品注意：①CITES（《濒危野生动植物种国际贸易公约》）严格限制象牙、老虎制品、熊胆、犀牛角等制品的购买和携带②部分植物种子在某些国家也受管制③"100% Local"或"Handmade by artisans"标识更可信④亲自逛当地市场比机场买到的更有特色且更便宜。'},
  {c:'词汇',q:'"Street art"（街头艺术）和"Graffiti"（涂鸦）有什么区别？',o:['Street art通常是获得许可的、有艺术意图的大型壁画；Graffiti通常是未经授权在公共设施上的涂写（在很多地方属违法行为）；但两者界限有时模糊','两者完全相同，只是名称不同','Street art是非法的','Graffiti受法律保护'],a:0,e:'街头艺术作为旅游体验越来越受欢迎：柏林（East Side Gallery，保存的柏林墙段）、墨尔本（Hosier Lane）、里斯本（Intendente广场）、波哥大等城市都有著名街头艺术区。Banksy是全球最著名的街头艺术家，其作品出没地点成为旅游热点。'},
  {c:'词汇',q:'"Midnight sun"（极昼）和"Polar night"（极夜）是什么现象？发生在哪里？',o:['极昼=夏季太阳全天不落（北极圈/南极圈地区夏季24小时日照）；极夜=冬季太阳全天不升（同区域冬季24小时黑夜）','是一种气候异常现象','只有在赤道地区才有','全球所有地方都有极昼极夜'],a:0,e:'Midnight Sun（极昼）体验：挪威北部、冰岛、芬兰、瑞典北部的夏季（6月前后）可以体验全天候白昼——凌晨太阳仍在地平线上。但这也意味着需要遮光眼罩才能入睡！Polar Night（极夜）：同一地区冬季（12月前后）则全天黑暗，但这是观看极光的最佳时机。'},
  {c:'词汇',q:'"Altitude sickness"（高原反应/高海拔反应）的症状和预防措施是什么？',o:['症状：头痛、恶心、疲劳、呼吸急促；预防：缓慢上升（适应海拔）、多休息多喝水、避免剧烈活动、必要时服用乙酰唑胺（Acetazolamide）','只在珠穆朗玛峰才会出现','喝咖啡可以预防','运动越多适应越快'],a:0,e:'高原反应易发地：西藏（拉萨海拔3650m）、秘鲁库斯科（Cusco，3400m）、玻利维亚拉巴斯（La Paz，3640m）、尼泊尔（徒步区域）。预防重于治疗：①到高海拔地区后先休息1-2天再活动②避免剧烈运动③不要立即饮酒④严重时立即下降海拔。'},
  {c:'词汇',q:'"Culture shock"（文化冲击）分几个阶段？',o:['通常分为4个阶段：蜜月期（Honeymoon，新奇兴奋）→挫折期（Frustration，负面情绪）→适应期（Adjustment，开始理解）→融入期（Adaptation，双文化能力）','只有一个阶段','文化冲击不会发生在长途旅行者身上','文化冲击只影响永久移民'],a:0,e:'文化冲击曲线（U-curve）：第1阶段（蜜月期）：觉得一切都很新奇有趣→第2阶段（沮丧期）：开始觉得很多东西不如家里好，更像home sick→第3阶段（调整期）：开始适应，找到规律→第4阶段（融入/双文化期）：能从两种文化视角看问题。短期旅行者通常只经历1-2阶段。'},
  {c:'词汇',q:'"Haggling"（砍价）在什么文化背景中被认为是失礼的行为？',o:['在日本、斯堪的纳维亚国家、德国等地，商品均有明码标价，砍价被认为是对商家不尊重甚至侮辱的行为','在所有国家砍价都被欢迎','只在土耳其才能砍价','只有外国人才能砍价'],a:0,e:'砍价文化禁忌：日本的店铺定价是最终价格，尝试砍价会让双方都非常不舒服。同样，在北欧、德国、英国等地，商店定价不容置疑。相比之下，中东巴扎、东南亚市集、印度路边摊则是强烈欢迎甚至期待砍价的文化。'},
  {c:'词汇',q:'"Body language"（肢体语言）中，以下哪个手势在不同文化中有不同含义？',o:['竖起大拇指（Thumbs up）：在多数西方国家表示"好/赞"，但在伊朗、部分中东地区是侮辱性手势（类似竖中指）','握手在所有文化都相同','点头在所有文化都表示赞同','微笑在所有文化含义相同'],a:0,e:'手势文化差异：①OK手势（拇指食指圈圈）：西方=OK/好，巴西=侮辱，日本=表示"钱"②竖拇指：多数地方=好，伊朗/西非=侮辱③点头：大多数文化=是，部分巴尔干国家（保加利亚）=否。出国前了解目的地的手势文化，避免误会！'},
  {c:'词汇',q:'"Local SIM card"（本地SIM卡）和"eSIM"有什么区别？',o:['Local SIM=实体卡，需要换出原手机卡；eSIM=嵌入式数字SIM，可以在手机设置中直接激活，不需要物理换卡，部分手机支持同时使用多个号码','两者完全相同','eSIM比实体SIM贵很多','eSIM只适用于苹果手机'],a:0,e:'eSIM（嵌入式SIM）优势：①无需物理换卡②可以保留原号码同时使用本地流量③支持多号码（iPhone 14以后双eSIM）。下载eSIM方式：购买后扫描QR码激活。已支持eSIM的运营商：Airalo、Holafly（流量套餐）。注意：出行前确认手机是否解锁（Unlocked）和是否支持eSIM。'},
  {c:'词汇',q:'"VPN"在出境旅行中有什么作用？',o:['VPN（Virtual Private Network）=虚拟私人网络，可以使你的网络流量通过其他国家的服务器路由，在中国境外可用于访问部分受地理限制的服务（如Netflix当地内容）；在中国境内使用VPN访问被封锁网站属于法律灰色地带','VPN是一种杀毒软件','VPN只用于企业办公','VPN可以完全隐藏身份保证绝对安全'],a:0,e:'VPN使用注意：①在中国境外（如日本/欧美）使用VPN访问Netflix等地区内容是合法的②中国境内使用未经许可VPN访问境外网站在法律上属灰色地带，且技术上屡遭封锁③VPN不能保证100%匿名，不要在VPN下做违法行为④出行前下载好VPN（到中国后可能连VPN官网都无法访问）。'},
  {c:'词汇',q:'"Language barrier"（语言障碍）旅行中如何克服？',o:['使用翻译App（Google Translate、DeepL）、学习当地基础短语、肢体语言和图片、寻找会说英语或普通话的当地人帮助','只能去英语国家','必须流利掌握当地语言才能旅行','不可能克服，只能放弃旅行'],a:0,e:'克服语言障碍实用工具：①Google Translate即时摄像头翻译（拍菜单/路牌自动翻译）②DeepL（书面翻译质量更高）③iPhone/Android离线语言包（无网络可用）④普通话在东南亚华人社区（新加坡/马来西亚/泰国/越南）有一定覆盖⑤学会用数字计算器砍价（超越语言的沟通方式）。'},
  {c:'词汇',q:'"Dress code"（着装规范）在旅行中有哪几种常见级别？',o:['Casual（休闲）→Smart Casual（商务休闲）→Business Casual（正式商务休闲）→Formal/Black Tie（正式礼服/黑领结）→White Tie（最高级晚礼服）','只有两种：正式和休闲','所有场合可以穿同样的衣服','Dress code只适用于宴会'],a:0,e:'旅行中着装等级应用：①普通观光：Casual②米其林餐厅晚餐：Smart Casual-Business Casual（男士需要长裤，不能穿运动鞋）③剧院/音乐会：Smart Casual④高档Gala晚宴：Black Tie（男士燕尾服/领结）。提前查看活动/餐厅的Dress Code要求，穿错了可能被拒绝入场！'},
  {c:'词汇',q:'"Public transportation card"（公共交通卡）在全球各城市有不同名称，以下哪个是正确匹配？',o:['伦敦=Oyster Card；东京=Suica/Pasmo；香港=Octopus Card（八达通）；新加坡=EZ-Link Card','纽约=Oyster Card','东京=Oyster Card','香港=Suica'],a:0,e:'全球著名交通卡：Oyster（伦敦）、Suica/Pasmo（东京/日本大部分城市）、Octopus八达通（香港）、T-money（首尔）、EZ-Link（新加坡）、Opal（悉尼）、Charlie Card（波士顿）、Clipper（旧金山湾区）。到达一个新城市先买当地交通卡是最省事的做法！'},
  {c:'词汇',q:'"Emergency landing"（紧急降落）通常由什么原因引起？',o:['医疗紧急情况（机上乘客病情危重）、机械故障、自然灾害（雷击/鸟击）、安全威胁（如炸弹威胁）等；任何危及飞行安全的情况都可能触发','飞机油耗过低（会提前规划备降）','旅客太多座位不够','飞行员想在某地观光'],a:0,e:'Emergency Landing（紧急/备降）：①Medical Emergency（医疗紧急）=机上乘客严重病情②Technical Failure（机械故障）=发动机/液压系统故障③Diversion（改降）=目的地机场天气/关闭，改降备用机场。遇到紧急降落要保持冷静，听从空乘指示。'},
  {c:'词汇',q:'"Hitchhiking"（搭便车）旅行有哪些优缺点和注意事项？',o:['优点：免费、可遇见有趣的当地人、灵活；缺点：安全风险（尤其对单身女性）、时间不可控；注意：大多数发达国家已很少人搭便车，在某些国家是普遍现象（如冰岛、古巴）','搭便车完全安全无风险','所有国家都鼓励搭便车','搭便车比所有交通方式都慢'],a:0,e:'搭便车（Hitchhiking）：冰岛、古巴、新西兰相对较常见且安全；在大多数国家较少见且风险较高。安全建议（如决定搭便车）：①不要单独行动②在光天化日下②告知亲友位置③上车前观察司机是否有异常④不要透露个人信息。现代旅行中，Ridesharing App（Uber/Grab）已取代了搭便车的大部分需求。'}
);


// ──────────────────────────────────────────────────────────────
// 【12】旅行实用语法 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_GRAMMAR.push(
  {c:'语法',q:'以下哪个句子使用了正确的被动语态（Passive Voice）？',o:['The wallet was stolen from my bag.（钱包被从我包里偷走了）','Someone stolen my wallet.','My wallet is steal.','The thief stole wallet my.'],a:0,e:'被动语态结构：be + 过去分词（Past Participle）。"Was stolen"=was（过去式be动词）+stolen（steal的过去分词）。旅行中描述被盗、行李丢失等情况时被动语态非常有用：My luggage was lost. / My passport has been taken.'},
  {c:'语法',q:'"Neither A nor B"和"Either A or B"有什么区别？在旅行点餐时如何使用？',o:['Either A or B=A或B之一（选择其一）；Neither A nor B=A和B都不要（否定两者）','意思完全相同','Either表示否定','Neither用于肯定句'],a:0,e:'使用场景：点餐时服务员问"Beef or chicken?"=Either beef or chicken（随便哪个）。"I\'d like neither the beef nor the chicken—do you have any vegetarian options?"=牛肉和鸡肉我都不要，请问有素食选项吗？Neither-nor后面的动词与最近的名词一致。'},
  {c:'语法',q:'"Despite"和"Although"在表达转折时有什么语法区别？',o:['Despite后接名词/名词短语（Despite the rain）；Although后接完整的从句（Although it was raining）；两者表达相同的转折含义','Despite后接从句','Although后接名词','两者可完全互换，没有任何区别'],a:0,e:'对比：Despite the bad weather, we visited the museum.（尽管天气不好）= Although the weather was bad, we visited the museum.（虽然天气不好）。Notwithstanding/In spite of也与Despite用法相同。旅行中描述克服困难时这些表达很常用。'},
  {c:'语法',q:'表达"一旦我们到了巴黎，我们就会去卢浮宫"，哪个句子语法正确？',o:['Once we arrive in Paris, we will visit the Louvre.（时间从句用一般现在时，主句用将来时）','Once we will arrive in Paris, we will visit the Louvre.（错误：时间从句不能用will）','Once we arrived in Paris, we will visit the Louvre.（时态不一致）','Once we arrive in Paris, we would visit the Louvre.（条件语气不当）'],a:0,e:'英语规则：在时间从句（when/once/as soon as/after等引导）中，即使表达未来，也要用一般现在时（Simple Present），主句才用将来时（will）。错误：Once we WILL arrive... 正确：Once we ARRIVE...'},
  {c:'语法',q:'区分"Since"和"For"在现在完成时中的用法？',o:['Since + 时间点（从某个具体时间开始）；For + 时间段（持续了多长时间）；两者都与现在完成时搭配','Since和For可以互换','For后接时间点','Since后接时间段'],a:0,e:'I have been traveling for three months.（我旅行了三个月）→ For + 持续时间段。I have been traveling since January.（我从一月起就一直在旅行）→ Since + 开始时间点。记忆：For=时间的长度，Since=时间的起点。'},
  {c:'语法',q:'表达建议时，"You should"和"You must"有什么语气强度差异？',o:['Must比Should强烈得多：Should=建议（可以不做）；Must=必须（非做不可）；Ought to强度介于两者之间','两者完全相同','Should比Must更强烈','Must表示禁止'],a:0,e:'语气强度排序（弱→强）：Could（可以考虑）→ Might（也许）→ Should（应该）→ Ought to（应当）→ Must/Have to（必须）。旅行建议中："You should try the local food."（应该尝尝当地食物）; "You must carry your passport at all times."（必须随时携带护照）。'},
  {c:'语法',q:'"Whose"和"Who\'s"有什么区别？',o:['"Whose"=谁的（所有格）；"Who\'s"是"Who is"或"Who has"的缩写；拼写不同，不能混用','两者完全相同','Whose是复数形式','Who\'s只用于书面语'],a:0,e:'"Whose bag is this?"=这是谁的包？（Whose=所有格）。"Who\'s coming with me?"=谁要跟我一起去？（Who\'s=Who is）。这是一个常见的拼写错误，旅行中填写表格或发邮件时需要注意区分。'},
  {c:'语法',q:'在餐厅要求"something"时，"I want something spicy"和"I want anything spicy"有什么区别？',o:['Something用于肯定句（表示期望有某物）；Anything通常用于否定句或疑问句，也可用于肯定句表示"无论什么都行"','两者完全相同','Anything比Something更礼貌','Something只用于食物'],a:0,e:'Something vs Anything：I want something spicy.（我想要辣的东西，期望有）✓；Is there anything spicy?（有没有辣的东西？）✓；I don\'t want anything with nuts.（我不想要任何含坚果的）✓；I\'ll eat anything.（什么都行）✓。规律：anything在否定句/疑问句或表示"无所谓"时使用。'},
  {c:'语法',q:'"Would you mind if I sat here?"中为什么用过去式"sat"而不是"sit"？',o:['这是虚拟语气（Subjunctive mood）的用法，Would you mind if...后接过去时表示礼貌的假设，并非表示过去时间','这是语法错误，应该用sit','表示这是过去发生的事情','只是一种固定搭配，没有逻辑原因'],a:0,e:'礼貌请求中的虚拟语气（Subjunctive）："Would you mind if I + 过去时动词?"=你介意我…吗？如：Would you mind if I opened the window?=我可以开窗吗？这是一种"距离感"用法，越"不真实"（使用过去时）越礼貌。也可说：Do you mind if I sit here?（现在时，较直接但也可接受）。'},
  {c:'语法',q:'区分"Bring"和"Take"的用法？',o:['Bring=向说话者靠近的方向移动（带来）；Take=远离说话者的方向移动（带走）；方向决定用哪个词','两者可以随意互换','Bring只用于物品','Take只用于人'],a:0,e:'"Can you bring me the menu?"（向我靠近=拿来）"Shall I take your luggage to your room?"（向说话者之外的地方=带走）。在旅行语境：餐厅点餐说"Could you bring me some water?"（向我拿来）；告别时说"Take care"（祝你走好，远离这里的方向）。'},
  {c:'语法',q:'以下哪个句子正确表达了"如果我有更多钱，我会住在更好的酒店"？',o:['If I had more money, I would stay in a better hotel.（虚拟条件句，与现实相反）','If I have more money, I will stay in a better hotel.（真实条件句，表示真正可能发生的条件）','If I would have more money, I would stay in a better hotel.（错误：条件从句不用would）','If I had more money, I will stay in a better hotel.（时态不一致）'],a:0,e:'条件句区分：第一条件句（真实可能）：If + 现在时，will + 动词；第二条件句（假设，与现实相反）：If + 过去时，would + 动词原形。题目中说话者实际上没有更多钱（假设），所以用第二条件句。'},
  {c:'语法',q:'如何礼貌地说"这个价格太贵了"？',o:['This is a bit pricey for my budget.（这对我的预算来说有点贵）/ It\'s slightly out of my price range.（稍微超出我的预算）','This is too expensive! Ridiculous!','I won\'t pay that much.（可以说但较强硬）','Are you crazy?（太失礼）'],a:0,e:'"Pricey"（有点贵）是"expensive"的较委婉说法。礼貌表达价格接受度："That\'s a bit more than I\'d hoped to spend."（比我预期的多一点）/ "Is there anything in a lower price range?"（有没有价格低一些的选择？）这类表达即表达了限制又不显得失礼。'},
  {c:'语法',q:'在正式信件/邮件开头，以下哪个称呼最为正式？',o:['Dear Sir/Madam,（不知道对方性别/姓名时最正式的称呼）','Hey there,','Hi friend,','To whom it may concern,（也非常正式，用于不知道收件人身份时）'],a:0,e:'正式程度排序：Dear [Name]（认识对方时最佳）> Dear Sir/Madam / To Whom It May Concern（不知道对方时）> Dear [Job title]（如Dear Manager）> Hi / Hello。旅行前联系酒店/航空公司时用Dear Sir/Madam or Dear [酒店名] Team开头。'},
  {c:'语法',q:'表达"从北京飞到东京要多久？"最自然的问法是？',o:['How long does it take to fly from Beijing to Tokyo?','How much time is needed for Beijing to Tokyo flight?','What is the duration time for Beijing Tokyo flight?','How many hours flies from Beijing to Tokyo?'],a:0,e:'"How long does it take to + 动词?"=做某事需要多长时间？这是询问时间最自然的英语表达。其他选项虽然可以理解，但不够地道。回答格式："It takes about 3 hours."（大约需要3小时）。'},
  {c:'语法',q:'"Used to"和"Was/Were used to"有什么本质区别？',o:['"Used to do"=过去习惯做（现在已经不再）；"Be used to doing"=习惯于做某件事（已经适应了，可以是现在）','两者完全相同','Used to只用于过去时','Were used to只用于英国英语'],a:0,e:'"I used to eat spicy food."=我过去常吃辣的（现在不吃了）。"I\'m used to eating spicy food."=我习惯吃辣的（已经适应了）。旅行语境："I\'m getting used to the local food."（我正在适应当地食物）/ "I used to get homesick often."（我以前常常思乡）。'},
  {c:'语法',q:'区分"Say"和"Tell"的用法？',o:['Tell必须跟"人"（Tell someone something）；Say后直接跟说的内容（Say something），不直接跟人作宾语','Say和Tell可以随意互换','Tell后面必须跟that从句','Say只用于直接引语'],a:0,e:'Tell总是跟"人"：Tell me / Tell the receptionist / Tell your friend. Say不跟人作直接宾语（要加to）：Say something / Say to me（不是Say me）。错误：He told "goodbye"（应该是said）/ She said me she was lost（应该是told me）。旅行中常用：Tell the taxi driver your hotel address. Say "thank you" in the local language.'},
  {c:'语法',q:'以下哪种表达最恰当地表示"我刚刚才到达"？',o:['I\'ve just arrived.（现在完成时，刚刚发生）','I just arrived.（一般过去时，也可接受但不如现在完成时精确）','I am just arriving.','I have been arriving.'],a:1,e:'两种都可以接受！"I\'ve just arrived."（现在完成时）更强调"刚发生，与现在有关联"；"I just arrived."（一般过去时）在美式英语中非常常见且地道。区别：英式英语倾向用现在完成时表示"just done"，美式英语两者均可。'},
  {c:'语法',q:'"Excuse me"和"I\'m sorry"有什么使用场景上的区别？',o:['Excuse me=用于请求别人注意/路过时（打扰一下，请让一让）；Sorry=用于已经犯了错误后的道歉','两者可以完全互换','Sorry比Excuse me更礼貌','Excuse me只在餐厅使用'],a:0,e:'区分：Excuse me=引起注意或请求通过（"Excuse me, can you help me?"；路过拥挤人群时说"Excuse me"）。Sorry=表达对已发生事情的歉意（踩到别人的脚说"I\'m sorry!"）。碰到别人：英国人倾向说"Sorry"，美国人倾向说"Excuse me"或"Pardon me"。'},
  {c:'语法',q:'表达询问某人的意见时，哪个表达最礼貌且正式？',o:['What do you think about/of...? / Could I have your opinion on...?','What you think?','How you feel about this?','Tell me what you like.'],a:0,e:'"What do you think about/of X?"（你觉得X怎么样？）是常见的征求意见表达。更正式："Could I ask for your opinion on this matter?"。在旅行语境向服务员/当地人询问建议：What would you recommend?（你推荐什么？）/ What do you think is the best option?（你觉得哪个选择最好？）'},
  {c:'语法',q:'以下句子哪个使用了正确的比较级？',o:['This hotel is more expensive than the last one.','This hotel is expensiver than the last one.','This hotel is more expensiver than the last one.','This hotel is expensive more than the last one.'],a:0,e:'形容词比较级规则：①短词（1-2音节）直接加-er：cheaper, bigger, nicer②长词（2个以上音节）用more + 形容词：more expensive, more comfortable③不规则：good→better, bad→worse, far→further。"expensiver"是错误形式。'},
  {c:'语法',q:'如何礼貌地要求别人帮你做一件事？以下哪个表达最正式？',o:['I was wondering if you could possibly help me with...','Help me.','Do this for me.','You must help me.'],a:0,e:'"I was wondering if you could possibly..."是超级礼貌的请求格式（过去进行时+could+possibly三重礼貌化处理）。礼貌程度：Do this（命令）< Help me.（直接）< Can you...?（较随意）< Could you...?（有礼貌）< I was wondering if you could possibly...（非常委婉正式）。高级礼貌请求时使用！'},
  {c:'语法',q:'"Much"和"Many"分别用于什么类型的名词？',o:['Much用于不可数名词（much water, much time, much money）；Many用于可数名词的复数（many hotels, many people, many places）','两者可完全互换','Much只用于疑问句','Many只用于否定句'],a:0,e:'数量词规则：可数名词（countable）：many hotels / a few days / fewer mistakes；不可数名词（uncountable）：much luggage / a little time / less money。常见错误：many luggage（×，行李是不可数名词）→ much luggage / several pieces of luggage（✓）。旅行中："How much time do we have?" "How many bags can I bring?"'}
);


// ──────────────────────────────────────────────────────────────
// 【13】文化礼仪常识 新增 ×22
// ──────────────────────────────────────────────────────────────
window.QB_EN_CULTURE.push(
  {c:'出国',q:'在英国，与陌生人谈话时，哪个话题是最安全的开场白？',o:['天气（Weather）——英国人对天气非常热衷，这是打破沉默、避免争议的完美话题','政治立场','个人收入','宗教信仰'],a:0,e:'英国人以喜欢聊天气著称，这不是笑话而是文化事实。"Lovely weather, isn\'t it?"是英式对话的经典开场。英国的社交禁忌话题：个人收入/财富、政治（尤其Brexit）、宗教。'},
  {c:'出国',q:'在日本，给对方名片（Business Card/名刺）时应该注意什么？',o:['双手递上，面朝对方，鞠躬致意；接收时双手接，认真阅读，妥善放置（不要随意塞进口袋或在上面写字）','单手递交就可以','可以随意放在桌上当杯垫','在名片上写字表示重视'],a:0,e:'名刺（Meishi）交换是日本商务礼仪的重要一环：①双手递交②面朝对方（文字朝向接收者）③接收时双手承接④立刻认真阅读（表示尊重）⑤放入名片夹（不随意折叠或在上面乱画）。旅游时较少交换名片，但了解这个礼节能体现对日本文化的尊重。'},
  {c:'出国',q:'在穆斯林文化的国家（如土耳其、马来西亚、埃及），以下哪个行为是对当地文化尊重的表现？',o:['在斋月（Ramadan）期间，在公共场所避免当着封斋的穆斯林面前饮食，进入清真寺前脱鞋并适当着装','在清真寺内大声交谈','用左手接递食物','向陌生的穆斯林询问是否在封斋'],a:0,e:'伊斯兰文化礼仪：①斋月期间（约一个月，日期每年变化）在公共场所应尊重封斋者②进入清真寺：脱鞋、安静、禁止在礼拜时间入内参观③左手在伊斯兰文化中被视为不洁净，用右手传递食物/物品④女性在某些保守地区需要戴头巾（视当地规定）。'},
 );
