window.QB_EN_AIRPORT.push(
  {c:'出国',q:'"Aisle"这个词在机场/飞机上指的是？',o:['靠窗的位置','走道/通道（座位间的过道）','头顶行李舱','紧急出口'],a:1,e:'aisle（发音：I-ul）=走道、通道。"Aisle seat"=靠走道座位，方便起身上厕所或早下飞机。Aisle也指超市货架间的走道。'},
  {c:'出国',q:'你在值机柜台，工作人员说"Your baggage is overweight by 3kg"，正确的理解是？',o:['你的行李箱坏了','你的行李需要重新包装','你的行李超重了3公斤','你需要换大一号的行李箱'],a:2,e:'overweight=超重，by 3kg=超出了3公斤。此时你可以选择付超重费（excess baggage fee），或者把东西转移到随身行李里。'},
  {c:'出国',q:'"Jet bridge / jetway"是指机场里的什么设施？',o:['跑道上的飞机通道','机场内的小火车','连接航站楼与飞机舱门的登机廊桥','行李传送带'],a:2,e:'Jet bridge / jetway / boarding bridge=登机廊桥，就是你从候机室直接走进飞机的那条封闭通道。没有廊桥时需要走到停机坪乘摆渡车（shuttle bus）。'},
  {c:'出国',q:'值机时工作人员问"Do you have any liquids over 100ml in your carry-on?"，这是在问？',o:['你的随身行李是否超重','你是否携带了活体动植物','你的随身行李里是否有超过100毫升的液体','你是否需要托运行李'],a:2,e:'国际航班安全规定：随身行李（carry-on）中液体必须≤100ml，且装入可密封的透明袋（规格约1升）。超过100ml的液体必须托运。'},
  {c:'出国',q:'你在机场买了免税品，工作人员给你一个密封袋并说"Don\'t open until you\'re on the plane."，这是因为？',o:['袋子里有防伪码需要在机上验证','购买的商品需要冷藏保存','某些国家规定免税品在过境转机时仍须密封，防止被认定为已使用','这只是包装习惯，没有实际意义'],a:2,e:'这是国际免税品转机规定（STEB=Secure Tamper-Evident Bag）。转机时如被要求查验，密封完好的袋子可证明商品是合规免税购买的，否则可能被没收或补税。'},
  {c:'出国',q:'机场指示牌上"Domestic"和"International"分别指什么？',o:['头等舱区和经济舱区','出发区和到达区','国内航班区和国际航班区','商务区和休闲区'],a:2,e:'Domestic=国内（境内）；International=国际（出境/入境）。在大型机场这两个区域通常分开，安检和登机流程也有所不同。'},
  {c:'出国',q:'你刚过安检，想知道自己的登机口，最快的方法是？',o:['问每一位路过的旅客','返回到值机柜台重新询问','查看登机牌上的Gate号并找对应的出发大屏','直接坐下等广播'],a:2,e:'登机牌（boarding pass）上会印有Gate号码（有时是暂定的，可能会临时更换）。最好结合候机楼的出发信息大屏（Departure Board）确认最终登机口。'},
  {c:'出国',q:'你的护照有效期只剩5个月，申请去某国旅游签证时被拒，原因最可能是？',o:['护照颜色不符合该国要求','你之前去过某个国家留下记录','大多数国家要求护照有效期至少超过签证期限6个月','护照照片不够清晰'],a:2,e:'"6个月护照有效期规定"是国际通用惯例：大多数国家要求入境时护照有效期须在6个月以上。出行前必须检查护照有效期！'},
  {c:'出国',q:'航班信息显示"ETD 14:30 / ATD 15:10"，这说明什么？',o:['预计到达14:30，实际到达15:10','预计出发14:30，实际出发15:10，延误了40分钟','预计出发14:30，已于15:10取消','出发门14号，出发时间15:10'],a:1,e:'ETD=Estimated Time of Departure（预计出发时间），ATD=Actual Time of Departure（实际出发时间）。两者相差40分钟，说明航班延误了40分钟。'},
  {c:'出国',q:'"Priority boarding"（优先登机）通常适用于哪些旅客？',o:['所有持有登机牌的旅客','已通过安检的旅客','头等舱/商务舱、航空公司高级会员、特殊需求旅客（老人/残障/携婴旅客）','最先到达登机口的旅客'],a:2,e:'优先登机权通常属于：头等舱/商务舱旅客、常旅客计划高等级会员、携婴旅客、行动不便旅客。部分低成本航空也会向购买"优先登机"服务的普通旅客开放。'},
  {c:'出国',q:'机场"Duty Free"商品与普通商品的主要区别是？',o:['质量更好','品牌更多','免除进口关税和消费税，因此价格通常更低','只有高端品牌才有免税资格'],a:2,e:'Duty Free=免税，意味着该商品已免去进口关税（import duty）和消费税（sales tax / VAT），因此通常比市价便宜。但并不是所有商品都必然比外面便宜，买之前可以对比一下。'},
  {c:'出国',q:'你在英国希思罗机场转机前往澳大利亚，中转时间只有1.5小时，你最应该担心什么？',o:['机场免税店是否开门','转机时间是否足够通过安检、护照检查并找到下一个登机口','航空公司是否提供中转餐食','行李是否需要自己搬运'],a:1,e:'短暂中转时间（尤其在大型机场如希思罗）是风险所在。需要考虑：过安检的时间、步行距离（航站楼可能很大）、护照检查（国际转国际需过移民局）等。一般建议国际转机至少保留2小时。'},
  {c:'出国',q:'在机场，"Unaccompanied minor（UM）"服务是为谁准备的？',o:['没有购票的儿童','独自乘机的未成年人（通常5-14岁）','残疾儿童旅客','未成年背包客'],a:1,e:'Unaccompanied Minor（UM）=无人陪伴的未成年旅客服务。航空公司安排专人从登机到接机全程陪同，确保孩子安全。通常需要在购票时提前申请，并额外收费。'},
  {c:'出国',q:'"Codeshare flight"（代码共享航班）是指？',o:['两架飞机同时起飞的联合航班','由多家航空公司共同运营同一架飞机','由一家航空公司运营，但同时以多家航空公司名义销售的航班','两家航空公司共用同一航站楼'],a:2,e:'代码共享（Codeshare）=一家航空公司（运营商）的航班，由多家航空公司使用各自航班代码共同销售。你买的可能是A公司的票，但实际乘坐的是B公司的飞机。登机时注意认准实际运营航班号。'},
  {c:'出国',q:'如果你的座位旁有紧急出口（Emergency Exit Row），通常会被要求？',o:['额外付费购买更好的服务','提前20分钟到达登机口','能够协助开启紧急出口，且不能携带婴儿就座','必须是头等舱旅客'],a:2,e:'坐在紧急出口排（Emergency Exit Row）的旅客需具备开启出口的体力和能力，并且座位旁不能有婴儿或行动不便者。通常腿部空间更大，但责任也更大。登机时空乘会确认你是否愿意承担此责任。'}
);

// ──────────────────────────────────────────────────────────────
// 【2】酒店英语 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_HOTEL.push(
  {c:'出国',q:'酒店前台说"I\'m sorry, we\'re fully booked tonight."，意思是？',o:['今晚酒店特价优惠','今晚酒店客满，没有空房','今晚只有套房可用','你的预订没有记录'],a:1,e:'fully booked=客满，no vacancies也是同义表达。遇到这种情况可以问"Do you know any nearby hotels that might have rooms?"（你知道附近哪家酒店可能有空房吗？）'},
  {c:'出国',q:'"Minibar"是酒店房间里的什么设施？',o:['小型冰箱（通常免费）','小型冰箱里存放饮料零食（通常额外收费）','免费的茶水咖啡机','房间内的小型酒柜（免费畅饮）'],a:1,e:'Minibar=房间内的小冰箱，里面有饮料、零食、酒水，通常价格远高于外面，且会被自动计入账单。如果不确定是否收费，退房前先询问前台。'},
  {c:'出国',q:'办理退房（Check-out）时，前台问"Did you use anything from the minibar?"，你应该如何回应？',o:['直接说Yes就行，不用细说','如实回答，列出消费的物品','说No然后快点离开','不用回答，账单已经自动生成'],a:1,e:'如实回答是最重要的，因为Minibar通常有自动计费系统或人工检查。账单错误时（如你没用过但被计费）也可以说："I don\'t think I used the minibar. Could you double-check?"'},
  {c:'出国',q:'你预订了一间"Twin room"，入住后发现是什么？',o:['一张超大双人床的房间','两张单人床的房间','带起居室的套房','顶楼景观房'],a:1,e:'Twin room=有两张单人床（single beds）的房间，适合两位朋友或不想同床的旅伴。与之对应的是Double room=一张大双人床。订房时要注意区分！'},
  {c:'出国',q:'酒店账单上出现"City tax / Tourist tax"，这是？',o:['城市停车税','当地政府向住客征收的旅游税，通常每人每晚几欧元','酒店额外收取的城市服务费','升舱费用'],a:1,e:'许多欧洲城市（如巴黎、阿姆斯特丹、罗马）向游客征收"旅游税"（Tourist/City tax），通常每人每晚1-7欧元不等，部分酒店在预订时注明，有些在退房时现付。'},
  {c:'出国',q:'你打电话给前台说"The shower is not draining properly."，你在反映什么问题？',o:['热水不够热','淋浴间排水不畅（水积在地上）','莲蓬头坏了','浴室灯不亮'],a:1,e:'drain=排水，not draining properly=排水不畅。这是酒店常见问题，可以要求维修或换房。其他浴室问题：no hot water=没热水；the toilet is clogged=马桶堵了。'},
  {c:'出国',q:'你想把贵重物品锁起来，应该使用酒店房间里的哪个设施？',o:['床头柜抽屉','衣柜里的保险箱（In-room safe）','行李箱','前台的寄存服务'],a:1,e:'In-room safe=房内保险箱，通常在衣柜里，可设置自定义密码。用来存放护照、现金、贵重珠宝。前台也提供贵重物品寄存（Safe deposit box），需要凭证取回。'},
  {c:'出国',q:'早餐时服务员问"How would you like your eggs?"，以下哪个不是鸡蛋的常见做法？',o:['Scrambled（炒蛋）','Poached（水波蛋）','Sunny side up（单面煎蛋）','Marinated（腌制蛋）'],a:3,e:'常见西式早餐鸡蛋做法：Scrambled eggs（炒蛋）、Poached（水波蛋）、Sunny side up（单面不翻煎蛋）、Over easy（双面嫩煎）、Boiled（白煮蛋）、Fried（煎蛋）。Marinated是腌制，不属于早餐点单选项。'},
  {c:'出国',q:'"Housekeeping"在酒店语境中是指？',o:['前台接待服务','客房清洁和整理服务（打扫房间的人员和部门）','行李搬运服务','酒店保安部门'],a:1,e:'Housekeeping=客房部，负责打扫、整理房间，更换床单、毛巾等。如不想被打扰可挂"Do Not Disturb"牌，如需打扫可挂"Please Make Up Room"牌。'},
  {c:'出国',q:'酒店说"We offer complimentary airport transfer for stays over 3 nights."，意思是？',o:['入住超过3晚的客人须额外支付机场接送费','入住超过3晚可享受免费机场接送','机场接送需提前3天预约','只有3晚的套餐包含机场接送'],a:1,e:'complimentary=免费赠送。"Complimentary airport transfer"=免费机场接送服务。"For stays over 3 nights"=入住超过3晚时。'},
  {c:'出国',q:'你在酒店游泳池旁，工作人员说"Pool towels are available at the towel station."，意思是？',o:['游泳池明天才开放','游泳池毛巾需要在前台借用','泳池专用毛巾可以在毛巾站自取','游泳必须自带毛巾'],a:2,e:'towel station=毛巾站，池边设有专门存放毛巾的区域可以自取。有些酒店收取毛巾押金，归还时退还。别把泳池毛巾带回房间哦！'},
  {c:'出国',q:'你想要一间能看到海景的房间，预订时应选择哪个类型？',o:['Garden view room','Mountain view room','Ocean view / Sea view room','Courtyard room'],a:2,e:'Ocean view / Sea view room=海景房。Garden view=花园景，Mountain view=山景，Pool view=泳池景，City view=城市景，Courtyard view=庭院景。预订时仔细选择！'},
  {c:'出国',q:'酒店标注"Self-catering accommodation"，这意味着？',o:['酒店提供三餐服务','房间配有厨房设施，旅客可自行烹饪','每天提供一次清洁服务','酒店提供自助早餐'],a:1,e:'Self-catering=自炊式住宿，即房间配备厨房（kitchen）或小厨台，旅客可以自己买菜做饭。常见于公寓式酒店（Apartment hotel）和度假屋（Holiday cottage）。'},
  {c:'出国',q:'前台说"We\'ve upgraded you to a suite at no extra charge."，你应该怎么回应？',o:['拒绝，说自己不需要','要求改回普通房间','道谢，接受升级','要求写成书面确认'],a:2,e:'免费升级是酒店给旅客的福利！一般说"Thank you so much, I really appreciate it!"愉快接受就好。这种情况多发生在：生日/纪念日、入住率低、高级会员资格等情况下。'},
  {c:'出国',q:'酒店早餐区的标识"Continental Breakfast"是指什么类型的早餐？',o:['包含煎蛋、培根、香肠的英式早餐','以面包、咖啡/茶、果汁、果酱为主的欧陆式早餐','中式粥饭点心','美式全套早餐'],a:1,e:'Continental Breakfast（欧陆式早餐）=面包/羊角包、黄油、果酱、咖啡或茶、果汁。与之对比：Full English Breakfast（英式早餐）包含煎蛋、培根、香肠、烤豆、烤番茄等，更丰盛。'}
);

// ──────────────────────────────────────────────────────────────
// 【3】交通出行英语 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_TRANSPORT.push(
  {c:'出国',q:'你拦下一辆出租车，司机问"Where to?"，你应该怎么回答？',o:['Yes, please.','To the Hilton Hotel on Fifth Avenue, please.','I need a taxi.','How much is the fare?'],a:1,e:'"Where to?"=去哪里？直接告诉司机目的地名称和地址即可。也可以展示手机地图或写下地址给司机看，非常实用。'},
  {c:'出国',q:'在英国，"Give way"标志的意思等同于美国的哪个标志？',o:['Stop（停车让行）','Yield（让行）','No Entry（禁止进入）','Speed Limit（限速）'],a:1,e:'"Give way"是英式英语，意思等同于美式英语的"Yield"，都是指让对方先行。英美驾车用语有很多差异，了解当地用语很重要！'},
  {c:'出国',q:'你在纽约，想乘坐地铁（Metro）应该买？',o:['Oyster Card','MetroCard','EZ-Link Card','Octopus Card'],a:1,e:'纽约地铁使用MetroCard（现在逐步过渡到OMNY感应支付）。英国伦敦用Oyster Card，新加坡用EZ-Link Card，香港用八达通（Octopus Card）。'},
  {c:'出国',q:'"Roundabout"在英国道路上是什么？',o:['高速公路收费站','环形交叉路口（环岛）','停车场','人行横道'],a:1,e:'Roundabout=环形交叉路口，就是圆形的交叉路口，车辆顺时针方向行驶（英国靠左行驶）。美国叫traffic circle，在欧洲非常普遍。进入环岛的车要让环岛内的车先行。'},
  {c:'出国',q:'在火车站你看到"Platform 9"，这是什么意思？',o:['第9节车厢','第9号站台（乘火车的站台）','火车9号出口','第9列火车'],a:1,e:'Platform=站台/月台。在英国、澳大利亚等国，"Platform"用来指乘车的站台。"Which platform does the train to Edinburgh depart from?"=去爱丁堡的火车从几号站台出发？'},
  {c:'出国',q:'你在日本租车，需要注意当地是靠哪侧行驶？',o:['靠右行驶（和中国一样）','靠左行驶（方向盘在右侧）','高速靠右，市区靠左','无固定规定'],a:1,e:'日本、英国、澳大利亚、新西兰等国靠左行驶（Left-hand traffic），方向盘在右侧（Right-hand drive）。和中国、美国、欧洲大陆的靠右行驶（Right-hand traffic）相反，租车前务必确认！'},
  {c:'出国',q:'你要坐巴士去市区，售票员说"Exact change only."，这是什么意思？',o:['只能刷卡，不收现金','请准备好零钱（不找零）','票价固定，不能砍价','只有月票才能上车'],a:1,e:'"Exact change only"=只收零钱/不找零。很多国家的公交车司机不找零，需要提前准备好正确金额的零钱，或使用交通卡（transit card）付款。'},
  {c:'出国',q:'你在美国租车时被问到"Would you like to add GPS navigation?"，这是？',o:['询问是否需要全险','询问是否要加购GPS导航设备','询问是否需要额外驾驶员','询问是否要升级车型'],a:1,e:'GPS navigation=导航设备，租车公司会提供车载GPS，但通常额外收费（每天约10-15美元）。大多数旅行者直接用手机Google Maps或Apple Maps，更经济实用。'},
  {c:'出国',q:'地铁广播说"Mind the gap between the train and the platform."，这句话的目的是？',o:['提醒你确认座位号','提醒你注意列车与站台之间的空隙，防止踩空','提醒你不要忘记行李','提醒你准备好车票'],a:1,e:'"Mind the gap"是伦敦地铁（The Tube）的标志性提醒广播，意思是注意列车与站台之间的缝隙，小心脚踩空。"Mind"在这里是动词，意为"注意/当心"。'},
  {c:'出国',q:'乘坐欧洲城际火车（如法国TGV、德国ICE），你的座位上显示"Reserviert"（德语）或"Réservé"（法语），这意味着？',o:['此座位免费可坐','此座位已被预订，不能随便坐','请购买座位预订票','此节车厢无人可乘坐'],a:1,e:'Reserviert/Réservé=已预订。欧洲很多高铁座位需要单独预订（reservation），即使持有通行证（Eurail Pass）也需额外付预约费。看到此标志说明该座位已有人预订。'},
  {c:'出国',q:'你在悉尼，想了解最近的火车站，应该如何问路人？',o:['Can you help me?','Do you know where the nearest train station is?','I need transport.','Where bus?'],a:1,e:'"Do you know where the nearest...is?"是问路的礼貌句型。也可以说"Excuse me, is there a train station nearby?"。澳大利亚火车叫train，不叫subway或tube。'},
  {c:'出国',q:'"One-way ticket"和"Round-trip ticket"，哪个通常更便宜？',o:['一定是one-way ticket更便宜','通常round-trip ticket按比例更划算（每程价格较低）','两者价格完全相同','取决于距离，没有规律'],a:1,e:'通常往返票（Round-trip/Return ticket）的每程单价比单程（One-way）便宜。但在某些廉价航空或特殊情况下，买两张单程票反而更灵活便宜，需要实际比较。'},
  {c:'出国',q:'你要搭乘渡轮（Ferry），工作人员说"Last boarding in 10 minutes."，你应该？',o:['继续在附近逛，等下一班','立刻前往登船口准备上船','去售票处重新购票','询问是否可以改签'],a:1,e:'"Last boarding"=最后登船时间。和飞机"Final boarding call"一样，意味着这是最后机会上船。10分钟后渡轮就会关闭舷梯出发，必须立刻上船！'},
  {c:'出国',q:'你在国外驾车，GPS显示"Make a U-turn."，你应该做什么？',o:['靠边停车等待','掉头（180°转向）往反方向行驶','绕过下一个街区','继续直行'],a:1,e:'U-turn=掉头。Make a U-turn=请掉头。注意：很多路口标有"No U-turn"（禁止掉头）标志，必须遵守。在允许掉头的地方，确认无车后再操作。'},
  {c:'出国',q:'你在伦敦看到"Bus Stop（Compulsory）"和"Bus Stop（Request）"两种站牌，有什么区别？',o:['前者是快速巴士，后者是普通巴士','前者是每班必停的站，后者需要你挥手示意或按铃才停','前者在市中心，后者在郊区','两者没有区别，都会停'],a:1,e:'Compulsory（强制停靠）=每班都停；Request（按需停靠）=乘客需要在车站挥手示意司机停车，或在车上按下"Stop"按钮请求在此站下车。英国很多公交站是Request Stop。'}
);

// ──────────────────────────────────────────────────────────────
// 【4】购物砍价英语 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_SHOPPING.push(
  {c:'出国',q:'你拿着一件衣服问店员"Does this come in other colors?"，你是在问什么？',o:['这件衣服是否能洗？','这件衣服还有没有其他颜色？','这件衣服有没有更小的尺码？','这件衣服是什么材质？'],a:1,e:'"Come in other colors"=有没有其他颜色款式。"Do you have this in blue / in a larger size / in other styles?"是购物中非常实用的句型。'},
  {c:'出国',q:'收银台旁有标牌"No refunds on sale items."，这说明？',o:['特价商品享有双倍退款保障','特价/打折商品不可退款','所有商品都可以退款','退款需要在30天内申请'],a:1,e:'"No refunds on sale items"=特卖商品不可退款。这在许多国家很常见，购买前要确认商品是否符合你的需求。Sale=打折促销，sale item=折扣商品。'},
  {c:'出国',q:'你在市场上看中一件工艺品，想砍价，最自然的开场白是？',o:['This is too cheap, I\'ll take it!','That\'s a little more than I was hoping to spend. Is there any flexibility?','Discount! Now!','I don\'t have money.'],a:1,e:'礼貌砍价的开场白："That\'s a little more than I was hoping to spend."（比我预期的稍贵一点）或"Is there any flexibility on the price?"（价格有没有商量余地？）态度友好，成功率更高！'},
  {c:'出国',q:'店员说"This is our best price."（这是我们的最低价），你还想再砍一刀，可以说？',o:['OK, I won\'t buy it then.（走开，通常店员会叫你回来）','What if I buy two? Can you do better?（买两件的话能再优惠吗？）','Give me for free.','Is this fake?'],a:1,e:'砍价小技巧："What if I buy two / pay in cash?"（如果我买两件/付现金，能不能再优惠？）。走开策略（"I\'ll think about it"）有时也奏效，但不一定每次都管用！'},
  {c:'出国',q:'你在日本购物，想申请消费税退税（Tax Free），需要准备什么？',o:['信用卡和消费账单','护照（Passport）和购物小票','旅游签证和银行流水','酒店入住确认单'],a:1,e:'日本Tax Free退税需出示护照（Passport），店员会在护照上粘贴退税凭证。购物金额通常需满5000日元以上，且商品须在日本境内未使用（离日时在机场海关盖章）。'},
  {c:'出国',q:'你买了一件商品，想知道是否可以用信用卡分期付款，应该问？',o:['Can I get a receipt?','Do you offer installment payments?','Can I get a gift receipt?','Is there a warranty?'],a:1,e:'"Installment payments"=分期付款（也叫installment plan）。有些国家大型消费支持分期（buy now pay later）。"Do you offer 0% installment?"=有没有免息分期？'},
  {c:'出国',q:'在超市结账时，收银员说"Paper or plastic?"，这是在问你什么？',o:['你要付现金还是刷卡？','你要纸袋还是塑料袋？','你要纸质收据还是电子收据？','你要普通装还是礼品包装？'],a:1,e:'"Paper or plastic?"=要纸袋还是塑料袋？这是美国超市的传统问法。如今很多地方鼓励自带购物袋（reusable bag），塑料袋有时需付费（bag fee）。'},
  {c:'出国',q:'"This item is out of stock."的意思是？',o:['这件商品即将涨价','这件商品已售罄/缺货','这件商品不在促销范围内','这件商品是最后一件'],a:1,e:'"Out of stock"=缺货/售罄。类似表达："Sold out"=已售完，"Not available"=暂时无货。可以问"When will it be back in stock?"（什么时候补货？）或"Do you have it in another store?"'},
  {c:'出国',q:'在欧洲旅游，"VAT Refund"（增值税退税）的英文全称是？',o:['Value Added Transportation Refund','Value Added Tax Refund','Visa And Travel Refund','Valid Amount Tax Refund'],a:1,e:'VAT=Value Added Tax（增值税）。欧洲许多国家VAT税率高达20%以上，游客购物后可在离境时申请退税。找贴有Global Blue或Premier Tax Free标志的商店购物，保留收据和退税单。'},
  {c:'出国',q:'店员问"Would you like to sign up for our loyalty program?"，这是在邀请你？',o:['购买额外延保计划','加入会员积分计划','参加抽奖活动','申请信用卡'],a:1,e:'Loyalty program=会员忠诚度计划（积分计划）。在超市、连锁店、航空公司等地常见，消费累积积分可兑换折扣或礼品。短期旅行一般不值得办，但常去的话可以考虑。'},
  {c:'出国',q:'"Fitting room is on your left."这句话是什么意思？',o:['服务台在你左边','试衣间在你左边','收银台在你左边','特价区在你左边'],a:1,e:'Fitting room=试衣间，也叫changing room（英式）或dressing room（美式）。进试衣间前通常店员会数你拿了几件衣服，有最大件数限制。'},
  {c:'出国',q:'你在跳蚤市场（Flea market）购物，商家说"Take it or leave it."，意思是？',o:['你可以带走商品，回家后再决定是否购买','就这个价，爱买不买，没有商量余地','商品可以试用一段时间','价格还有商量余地'],a:1,e:'"Take it or leave it"=就这个价了，爱买不买（没有商量余地的最终报价）。在跳蚤市场这是卖家结束议价的常见说法。如果真的喜欢，可以假装走开，对方可能会主动降价！'},
  {c:'出国',q:'商场广播说"Our store will be closing in 15 minutes. Please bring your final selections to the register."，你应该？',o:['继续悠闲地逛','马上把要买的东西拿去结账','在店里等工作人员引导离开','放下商品直接离开'],a:1,e:'Register=收银台。这句话告诉你：商场还有15分钟关门，请把最终要购买的商品拿到收银台结账。听到这个广播要赶快去结账！'},
  {c:'出国',q:'你想问这件商品是否有质量保证，应该说？',o:['Is this on sale?','Does this come with a warranty?','Can I return this?','Is this waterproof?'],a:1,e:'Warranty=质量保证/保修。"Does it come with a warranty?"=有保修吗？"How long is the warranty?"=保修期多长？购买电子产品时尤其要问。'},
  {c:'出国',q:'"Cash back"在购物结账时是什么意思？',o:['返利给信用卡账户的消费奖励','在超市结账时用借记卡多付一些钱，余额以现金形式取回（部分国家超市提供此服务）','购物退款','现金折扣'],a:1,e:'Cash back有两层意思：①信用卡消费返现（奖励计划）②在英国/澳大利亚等地的超市，刷借记卡结账时可以顺便取现，省去找ATM。"Can I get £20 cash back?"=我可以顺便取20英镑现金吗？'}
);

// ──────────────────────────────────────────────────────────────
// 【5】餐厅点餐英语 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_RESTAURANT.push(
  {c:'出国',q:'服务员说"Tonight\'s special is pan-seared salmon with asparagus."，这句话说明？',o:['三文鱼已经售完','今晚的特供菜是香煎三文鱼配芦笋','三文鱼是本餐厅的招牌菜','今晚的菜单已更换'],a:1,e:'Tonight\'s special=今晚特供菜，通常是当天根据新鲜食材临时准备的菜肴。pan-seared=香煎，salmon=三文鱼，asparagus=芦笋。'},
  {c:'出国',q:'菜单上"Gluten-free options available"的意思是？',o:['菜单上所有菜都没有小麦成分','可以提供不含麸质（小麦蛋白）的菜品选择','本餐厅专门服务素食者','菜单上没有面食类菜品'],a:1,e:'Gluten=麸质（小麦、大麦、黑麦中的蛋白质）。Gluten-free=无麸质，适合乳糜泻（Celiac disease）患者。越来越多餐厅提供无麸质选项，点单时告诉服务员即可。'},
  {c:'出国',q:'你点了一份牛排，说"Medium rare, please."，你期待的熟度是？',o:['全熟（Well done）','三分熟（外层烤熟，内部粉红偏红，多汁）','五分熟（Medium）','一分熟（Rare）'],a:1,e:'熟度对照：Rare=一分熟（内部血红）；Medium Rare=三分熟（内部粉红偏红）；Medium=五分熟（内部粉红）；Medium Well=七分熟；Well Done=全熟。Medium rare被很多老饕认为是最佳熟度！'},
  {c:'出国',q:'服务员问"Would you like still or sparkling water?"，如果你想要普通水（不含气泡），应该说？',o:['Sparkling, please.','Still water, please.','No water.','Tap water.'],a:1,e:'Still water=不含气泡的普通水；Sparkling water=含气泡的碳酸水（气泡水）。在很多欧洲餐厅，你必须明确说still或sparkling，否则可能默认上瓶装水（收费）。'},
  {c:'出国',q:'"Al dente"这个意思在意大利餐厅描述什么？',o:['非常软烂的意大利面','煮到稍微有点嚼劲（有弹性）的意大利面','加了香料的意大利面','意大利传统手工面食'],a:1,e:'"Al dente"是意大利语，字面意思是"对牙齿"，指面食或米饭煮到稍有嚼劲、不完全软烂的状态。这是意大利烹饪的黄金标准。在意大利餐厅，你可以说"I\'d like my pasta al dente."'},
  {c:'出国',q:'账单上显示"Gratuity of 18% is included for parties of 6 or more."，这说明？',o:['用餐人数超过6人不需要额外给小费，18%小费已计入账单','6人以上用餐享有18%折扣','超过6人需要额外支付18%的用餐税','18%的服务费是可选的'],a:1,e:'Gratuity=小费，automatically included=已自动计入。美国很多餐厅对大桌（通常6人以上）自动收取18%-20%的小费。看到这句话说明你不需要再额外给小费了，否则会重复付！'},
  {c:'出国',q:'服务员问"Are you ready to order, or do you need a few more minutes?"，你还没想好，应该说？',o:['I\'ll have the salmon.','I\'m not ready yet. Could we have a few more minutes, please?','We don\'t want anything.','The menu is confusing.'],a:1,e:'还没决定时礼貌说法："Could we have a few more minutes?"或"We\'d like a little more time, please."非常常用，服务员会给你时间，不会催你。'},
  {c:'出国',q:'你发现菜里有一根头发，应该怎么告知服务员？',o:['大声呼叫让全餐厅的人都知道','Excuse me, I found a hair in my dish. Could I have a replacement?','直接吃掉，不要在意','要求免单，威胁要投诉'],a:1,e:'礼貌但直接地告知："Excuse me, I found a hair in my dish."（我的菜里发现了一根头发）然后说"Could I have a replacement?"（能换一份吗？）正规餐厅会立即更换并道歉，严重时可能免费。'},
  {c:'出国',q:'菜单上"House wine"是指？',o:['用餐厅自家葡萄园酿制的高档红酒','由餐厅选定的性价比较高的自选酒水','只在酒吧区供应的酒','本餐厅限量版特供酒'],a:1,e:'"House wine"=本店自选酒，通常是餐厅精选的经济实惠款葡萄酒，有红/白/桃红之分。比点知名品牌酒款便宜，适合随意搭配餐食。"I\'ll just have the house red, please."'},
  {c:'出国',q:'你想要一杯不加糖的美式咖啡，应该怎么点？',o:['I\'d like a coffee with lots of sugar.','An Americano, black, no sugar, please.','One sweet latte, please.','Coffee with milk and three sugars.'],a:1,e:'Americano=美式咖啡（浓缩咖啡+热水），black=不加奶，no sugar=不加糖。黑咖啡就是"black coffee"。如要加奶：with milk；加奶泡：with foam；不加糖：no sugar / unsweetened。'},
  {c:'出国',q:'"Tapas"是哪个国家的特色饮食文化？',o:['意大利（意式小吃文化）','西班牙（多种小份前菜共享式进餐）','希腊（地中海风格小食）','法国（法式小点心）'],a:1,e:'Tapas=西班牙特色小食文化，指一小份一小份的各式冷热前菜，多人共享。源于西班牙南部安达卢西亚地区，如今在全球广泛流行。去西班牙必须体验"ir de tapas"（吃tapas之旅）！'},
  {c:'出国',q:'你在点餐时说"I\'d like the set menu."，这是点了什么？',o:['按照自己喜好单点各道菜','套餐（通常包含前菜+主菜+甜点，固定价格）','素食套餐','只点一道主菜'],a:1,e:'"Set menu"=套餐，通常是固定价格包含多道菜（前菜/汤+主菜+甜点+饮料）。也叫"Table d\'hôte"（法式套餐）或"Prix fixe menu"。比单点（à la carte）通常更划算。'},
  {c:'出国',q:'服务员说"We\'re out of the cod today."，你理解为？',o:['今天的鳕鱼特别新鲜，值得推荐','今天鳕鱼售完了','鳕鱼菜今天要额外加收费用','鳕鱼菜需要等待30分钟'],a:1,e:'"We\'re out of..."=……卖完了/没有了。Cod=鳕鱼。如果你正好想点鳕鱼，可以问"What fish do you have today?"（今天有什么鱼？）'},
  {c:'出国',q:'在美国餐厅，吃剩的食物打包带走，通常可以向服务员说？',o:['I\'d like another serving, please.','Could I get a box for this?（能给我一个打包盒吗？）/ Can I take this to go?','The food was terrible.','Please throw this away.'],a:1,e:'在美国，把剩菜打包带走完全正常，常称为"doggy bag"（打包袋）。问法："Can I get this to go?"或"Could I have a box?"非常常用。在日本或某些亚洲国家，打包文化不那么普遍。'},
  {c:'出国',q:'菜单上标注"V"或"VG"通常代表什么？',o:['Very Good（评级很好）和Very Great（非常棒）','V=Vegetarian（素食），VG=Vegan（纯素食，不含任何动物产品）','Vitamin丰富、Vegetable base','V=半份，VG=全份'],a:1,e:'菜单标注：V=Vegetarian（素食，不含肉但可含奶蛋）；VG=Vegan（纯素，不含任何动物产品）；GF=Gluten-Free（无麸质）；N=Contains Nuts（含坚果）。有饮食限制的人需关注这些标注。'}
);

// ──────────────────────────────────────────────────────────────
// 【6】紧急情况英语 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_EMERGENCY.push(
  {c:'出国',q:'你在英国遇到紧急情况，应该拨打哪个号码？',o:['911','999（英国紧急电话）','112','110'],a:1,e:'英国紧急电话是999，适用于警察（Police）、消防（Fire）、急救（Ambulance）。欧盟通用112在英国也可使用。美国是911，澳大利亚是000，日本警察是110、急救是119。'},
  {c:'出国',q:'你的护照丢失后，联系中国驻外领事馆，他们会为你办理的临时证件叫什么？',o:['临时旅行证（Temporary Travel Document / Emergency Travel Document）','旅行通行证','临时护照（Temporary Passport）','入境许可证（Entry Permit）'],a:0,e:'中国驻外领事馆可以为在海外丢失护照的中国公民签发"旅行证"（Travel Document / Emergency Travel Document），可用于返回中国。这个过程需要几个工作日，建议携带护照复印件或手机拍照备份。'},
  {c:'出国',q:'你看到有人在街上晕倒，应该先做什么？',o:['搜查晕倒者的随身物品','呼叫当地急救（拨打紧急电话），不要随意搬动伤者','立刻给晕倒者喂水','围观拍照记录现场'],a:1,e:'遇到有人晕倒：①大声呼救让周围人注意②拨打急救电话（告知位置和伤者状况）③不要随意搬动④如有必要且你会急救，进行心肺复苏（CPR）。不会急救不要贸然处理，防止加重伤情。'},
  {c:'出国',q:'你在国外遇到抢劫，劫匪已经离开，你首先应该做什么？',o:['立刻追赶歹徒','前往最近的警察局报警（或拨打紧急电话）并记录损失','自己在网上发布寻人启事','等到明天再报警'],a:1,e:'遭遇抢劫后：①确认自身安全②拨打110/999/911或前往最近警察局③如实描述歹徒外貌、事发地点和时间④列清被盗物品清单（护照、手机、现金等）⑤报案回执（police report）用于向保险公司索赔。'},
  {c:'出国',q:'你在国外突发心脏病需要急救，告诉急救人员最关键的信息是？',o:['你的护照号码','你的名字、当前位置（地址/附近地标）、症状','你的酒店预订号','你的行程安排'],a:1,e:'拨打急救电话时最关键的信息：①你的位置（Location）——这是救护车找到你的关键！②症状（Symptoms）——"Chest pain/Chest tightness"=胸痛/胸闷③你的名字。其他信息（过敏史、药物）之后再补充。'},
  {c:'出国',q:'你在海外丢失了信用卡，第一步应该？',o:['向酒店前台借钱','立刻致电银行挂失并冻结卡片，然后考虑补办或临时用备用卡','在社交媒体发布寻卡启示','等回国后再处理'],a:1,e:'信用卡丢失第一步是立即挂失（cancel/report lost card）！大多数银行提供24小时电话服务，卡背面有客服号码。出行前建议：①记下银行紧急联系号码②带两张卡备用③开通手机支付（Apple Pay等）。'},
  {c:'出国',q:'"I need an interpreter."在紧急情况下是什么意思？',o:['我需要一张地图','我需要翻译（因为语言不通）','我需要文件证明','我需要签证帮助'],a:1,e:'interpreter=口译员/翻译。语言不通时可以向警察、医院等说"I need an interpreter."或"Do you have a Chinese interpreter?"很多国家的警察局和医院有多语种服务。'},
  {c:'出国',q:'你在旅途中丢了钱包，身上没有任何现金，急需用钱，有哪种服务可以帮到你？',o:['向路人借钱','联系家人通过Western Union等国际汇款服务紧急转账','找中国大使馆借钱','联系当地银行免费借款'],a:1,e:'西联汇款（Western Union）、速汇金（MoneyGram）等国际汇款服务可以让家人在国内汇款，你在海外几分钟内即可取现。需要知道取款密码和汇款人信息。大使馆在极端情况下也可提供紧急借款（需归还）。'},
  {c:'出国',q:'你的旅伴在登山时扭伤了脚踝，步行困难，你应该说？',o:['Hurry up, we need to continue.','My friend has sprained their ankle and needs medical assistance. Can you help?','Let\'s wait here until it gets better.','Don\'t worry, just walk slowly.'],a:1,e:'Sprained ankle=扭伤脚踝。向当地人或救援人员求助时说清楚情况。在山区可以拨打山地救援（Mountain Rescue）。出行前了解目的地急救号码，登山建议购买含紧急撤离的旅行保险。'},
  {c:'出国',q:'你在泰国发生了交通事故，对方司机说是你的责任，你应该？',o:['立刻向对方道歉并赔钱','保持冷静，拨打当地警察，等警察来做记录，不要轻易签任何文件','逃离现场','和对方私下解决，不报警'],a:1,e:'海外交通事故处理：①不要在情绪激动时做任何承诺或签署文件②拨打当地警察③拍照记录现场（车牌、损坏情况）④联系租车公司和旅行保险公司⑤必要时联系中国大使馆寻求协助。'},
  {c:'出国',q:'你在国外遇到地震，在室内应该怎么做？',o:['立刻往外跑，寻找空旷地方','就地躲在坚固桌子下，保护头部，等震动停止再有序撤离','躲进电梯','站在窗边等待救援'],a:1,e:'地震室内避险原则：Drop（趴下）Cover（遮掩头部，躲到坚固桌下）Hold on（抓紧不动）。不要在震动时跑动，玻璃和掉落物品是主要危险。震动停止后，关闭燃气，有序从楼梯（不是电梯）撤离。'},
  {c:'出国',q:'"Travel Advisory Level 3"（美国国务院旅行建议第三级）意味着？',o:['安全，建议旅行','正常注意，可以旅行','建议重新考虑是否旅行（Reconsider Travel）','禁止旅行（Do Not Travel）'],a:2,e:'美国国务院旅行建议分4级：Level 1=正常预防（Normal Precautions）；Level 2=增加注意（Exercise Increased Caution）；Level 3=建议重新考虑（Reconsider Travel）；Level 4=不要旅行（Do Not Travel）。中国外交部也有类似安全提示，出行前要查阅！'},
  {c:'出国',q:'你的旅行保险不包含"Pre-existing medical conditions"，这意味着？',o:['所有医疗费用都会被报销','保险不承保你出发前已有的既往病症相关的医疗费用','只承保意外事故','所有慢性病都被排除在外'],a:1,e:'"Pre-existing condition"=既往症/已有病症（如高血压、糖尿病、哮喘等）。购买旅行保险时要仔细阅读条款，了解哪些情况被排除在外。有慢性病的旅客应选择包含既往症的保险计划（通常保费更高）。'},
  {c:'出国',q:'你在餐厅发现食物中有异物，导致你肠胃不适，这在英文里叫什么？',o:['Heat stroke（中暑）','Food poisoning（食物中毒）','Altitude sickness（高原反应）','Motion sickness（晕车/晕船/晕机）'],a:1,e:'Food poisoning=食物中毒，症状包括恶心（nausea）、呕吐（vomiting）、腹泻（diarrhea）。如症状严重应立即就医说"I think I have food poisoning."。其他旅行常见病：Heat stroke=中暑；Altitude sickness=高原反应；Motion sickness=晕动症。'},
  {c:'出国',q:'你在酒店房间发现火灾烟雾，正确的应对是？',o:['打开窗户通风，等待自行消失','按房间内的火警按钮，拨打消防电话，从消防通道（不是电梯）撤离','立刻乘电梯下楼','先收拾贵重物品再撤离'],a:1,e:'火灾应对：①按火警按钮（Fire Alarm）②拨打当地火警电话③从消防楼梯（Fire Exit / Emergency Stairwell）撤离，绝对不坐电梯④逃生前用手背触碰门把手——如烫就不要开门⑤生命第一，贵重物品可以不要。'}
);

// ──────────────────────────────────────────────────────────────
// 【7】亚洲热门目的地 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_ASIA.push(
  {c:'旅游',q:'日本的"新宿御苑"（Shinjuku Gyoen）最著名的是什么？',o:['大型购物中心','每年春季的赏樱胜地（Cherry Blossom Viewing）','全球最忙碌的地铁站','世界第一高的观景台'],a:1,e:'新宿御苑是东京最受欢迎的赏樱（Cherry Blossom）场所之一，每年3-4月樱花盛开时吸引大量游客。公园内有约1100棵樱花树，风景绝美。'},
  {c:'旅游',q:'泰国的"泼水节"（Songkran）是什么时候举行的？',o:['1月1日（新年）','每年4月13-15日（泰国传统新年）','12月25日（圣诞节）','春分当天'],a:1,e:'Songkran（宋干节/泼水节）是泰国的传统新年，通常在4月13-15日举行。人们互相泼水以示祝福和洗去厄运。清迈（Chiang Mai）的泼水节是全球最著名的节日之一！'},
  {c:'旅游',q:'新加坡著名的"滨海湾金沙酒店"（Marina Bay Sands）顶部有什么特色设施？',o:['全球最高的旋转餐厅','世界最大的屋顶无边际游泳池（Infinity Pool）','东南亚最大的赌场','亚洲最高的观景台'],a:1,e:'Marina Bay Sands的屋顶有著名的Infinity Pool（无边际泳池），从57层俯瞰新加坡全景，是全球最受追捧的"打卡"泳池之一。注意：只有酒店住客才能使用泳池！'},
  {c:'旅游',q:'韩国最受欢迎的购物街"明洞"（Myeongdong）以什么著名？',o:['韩国传统工艺品市场','美妆（K-Beauty）、时尚、街头小吃，是首尔购物和美食的核心区','韩国最大的传统市场','韩剧取景的宫殿建筑群'],a:1,e:'Myeongdong（明洞）是首尔最繁华的购物街，以韩国美妆品牌（K-Beauty）、时尚服饰和街头小吃著名。各大化妆品牌旗舰店云集，是购买K-Beauty产品的最佳地点！'},
  {c:'旅游',q:'"Angkor Wat"（吴哥窟）位于哪个国家？',o:['泰国','柬埔寨（Cambodia）','越南','老挝'],a:1,e:'Angkor Wat（吴哥窟）位于柬埔寨（Cambodia）暹粒市（Siem Reap），建于12世纪，是世界上最大的宗教建筑之一，也是柬埔寨的国家象征（出现在国旗上）。'},
  {c:'旅游',q:'印度的"泰姬陵"（Taj Mahal）是由谁建造的，为了纪念谁？',o:['阿克巴大帝为庆祝帝国建立','莫卧儿皇帝沙贾汉为纪念亡妻慕塔兹·玛哈尔','英国殖民政府为庆祝统治印度','拉贾斯坦国王为供奉神灵'],a:1,e:'Taj Mahal（泰姬陵）由莫卧儿帝国皇帝沙贾汉（Shah Jahan）下令建造，以纪念他深爱的妻子慕塔兹·玛哈尔（Mumtaz Mahal），建于1632-1653年，是世界七大奇迹之一。'},
  {c:'旅游',q:'香港的"维多利亚港"（Victoria Harbour）最壮观的景色在何时欣赏？',o:['清晨日出时分','每晚8点的"幻彩咏香江"灯光秀（Symphony of Lights）期间','正午阳光照射时','台风来临前夕'],a:1,e:'"Symphony of Lights"=幻彩咏香江，是每天晚上8点在维多利亚港举行的灯光音乐汇演，两岸大厦同步亮灯，已被吉尼斯世界纪录认定为全球最大的灯光音响表演。'},
  {c:'旅游',q:'去日本旅行，"JR Pass"（日本铁路通票）最适合哪类旅客？',o:['只在东京市内游玩的旅客','计划跨城市旅行（如东京-京都-大阪-广岛）的外国旅客','日本本地居民','只乘坐地铁的旅客'],a:1,e:'JR Pass=日本铁路通票，适合在多个城市间移动的外国旅客，可无限次乘坐JR线（包括大部分新干线）。如果只在一个城市游玩，单独购票反而更便宜。出日本前在海外购买，比在日本购买便宜。'},
  {c:'旅游',q:'越南"会安古镇"（Hoi An Ancient Town）以什么闻名？',o:['现代艺术博物馆','保存完好的15-19世纪贸易港口古镇，以灯笼和古建筑著名','全越南最大的海鲜市场','越南最高的摩天大楼'],a:1,e:'Hoi An（会安）是UNESCO世界遗产，15世纪的古老贸易港口，保存有中国、日本、欧洲建筑风格混合的古建筑。最著名的是每月农历十五的灯笼节（Lantern Festival），整个古镇灯火辉煌。'},
  {c:'旅游',q:'马来西亚的"双子塔"（Petronas Twin Towers）位于哪个城市？',o:['槟城（Penang）','吉隆坡（Kuala Lumpur）','新山（Johor Bahru）','古晋（Kuching）'],a:1,e:'Petronas Twin Towers（双峰塔/双子塔）位于马来西亚首都吉隆坡（Kuala Lumpur），高452米，于1998年建成时是世界最高的双子楼。88层的Skybridge（天桥）是热门参观项目。'},
  {c:'旅游',q:'菲律宾的"巧克力山"（Chocolate Hills）位于哪个岛？',o:['吕宋岛（Luzon）','薄荷岛（Bohol）','宿务岛（Cebu）','巴拉望岛（Palawan）'],a:1,e:'Chocolate Hills（巧克力山）是菲律宾薄荷岛（Bohol Island）的著名地标，由超过1000个圆锥形山丘组成，旱季时草地枯黄呈巧克力色而得名。'},
  {c:'旅游',q:'斯里兰卡的"狮子岩"（Sigiriya Rock Fortress）有什么历史意义？',o:['古代海盗的藏宝地','5世纪卡塞亚帕国王建造的宫殿要塞，已被列为世界遗产','印度洋最古老的灯塔','佛教高僧修行的圣山'],a:1,e:'Sigiriya（狮子岩）是斯里兰卡最著名的古迹，建于公元5世纪，是国王卡塞亚帕一世的宫殿和要塞。200米高的花岗岩上有保存完好的壁画和水景花园，被联合国教科文组织列为世界遗产。'},
  {c:'旅游',q:'去尼泊尔（Nepal）的主要目的之一是？',o:['参观古埃及文明遗址','徒步（Trekking）前往珠穆朗玛峰大本营或安纳普尔纳地区','游览热带海滩','体验赌场文化'],a:1,e:'尼泊尔是世界著名的徒步和登山目的地，拥有世界十四座8000米以上高峰中的八座（包括珠穆朗玛峰/Everest）。Everest Base Camp Trek（EBC大本营徒步）是全球最受欢迎的徒步线路之一。'},
  {c:'旅游',q:'台湾夜市中，"臭豆腐"用英文怎么向外国朋友介绍？',o:['Sweet tofu dessert（甜豆腐甜品）','Stinky tofu - fermented tofu with a pungent smell but crispy outside（臭豆腐-发酵豆腐，气味刺鼻但外皮酥脆）','Fresh tofu snack（新鲜豆腐小食）','Grilled tofu skewer（烤豆腐串）'],a:1,e:'"Stinky tofu"=臭豆腐，是台湾最具代表性的夜市小吃。向外国朋友介绍时可以说："It smells strong but tastes amazing! The outside is crispy and the inside is soft."（闻起来很刺鼻但超级好吃！外皮酥脆内里软嫩）'},
  {c:'旅游',q:'日本的"富士山"一年四季都可以攀登吗？',o:['是的，全年开放，任何季节都可以攀登','不是，登山季通常只有7-8月（约两个月），其余时间因积雪和恶劣天气关闭','只有冬天开放','春秋两季开放，夏冬关闭'],a:1,e:'富士山正式登山季是每年7月初到9月初（约两个月）。其余时间山道封闭，主要因为积雪、结冰和恶劣天气。旺季（8月）需要提前预约！富士山一共有4条登山路线，其中吉田口（Yoshida Trail）最受欢迎。'}
);

// ──────────────────────────────────────────────────────────────
// 【8】欧洲经典目的地 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_EUROPE.push(
  {c:'旅游',q:'意大利"科洛塞姆"（Colosseum）是哪个时代建造的？',o:['文艺复兴时期（14-17世纪）','古罗马帝国时期（公元70-80年）','中世纪（公元1000年前后）','现代（19世纪重建）'],a:1,e:'Colosseum（斗兽场）建于公元70-80年，由维斯帕先皇帝下令建造，弗拉维安皇帝时期完工。可容纳约50000-80000名观众，是罗马角斗士和野兽搏斗的场所。'},
  {c:'旅游',q:'西班牙"圣家堂"（Sagrada Família）有什么特别之处？',o:['它是世界上最古老的教堂','由建筑师高迪设计，开工140余年至今仍在建设中','它是伊斯兰风格的清真寺','它是世界上最大的无梁教堂'],a:1,e:'Sagrada Família（圣家堂）是西班牙建筑师安东尼奥·高迪（Antoni Gaudí）的代表作，1882年开工，预计2026年前后完工，是世界上持续建设时间最长的建筑之一。已被列为UNESCO世界遗产。'},
  {c:'旅游',q:'去布拉格（Prague）旅游，著名的"查理大桥"（Charles Bridge）横跨哪条河？',o:['莱茵河（Rhine）','伏尔塔瓦河（Vltava River）','多瑙河（Danube）','易北河（Elbe）'],a:1,e:'查理大桥（Charles Bridge）横跨伏尔塔瓦河（Vltava），连接布拉格老城和小城区。建于14世纪，桥上有30座圣人雕像，是布拉格最具代表性的地标。'},
  {c:'旅游',q:'"Northern Lights"（北极光）最容易在哪里看到？',o:['西班牙南部（马拉加）','挪威特罗姆瑟、冰岛、芬兰北部等极圈附近地区','法国阿尔卑斯山','英国苏格兰'],a:1,e:'Northern Lights（Auroral Borealis，北极光）在极圈附近最容易看到，最佳目的地包括：挪威特罗姆瑟（Tromsø）、冰岛（Iceland）、芬兰拉普兰（Lapland）、瑞典基律纳（Kiruna）。最佳观测季节是9月到次年3月，需要晴朗无光污染的夜晚。'},
  {c:'旅游',q:'克罗地亚的"杜布罗夫尼克"（Dubrovnik）以什么著名？',o:['最大的葡萄酒产区','"亚得里亚海明珠"，红色屋顶古城墙，《权力的游戏》取景地','欧洲最大的渔港','最古老的哥特式大教堂'],a:1,e:'Dubrovnik是克罗地亚最著名的旅游城市，以保存完好的中世纪城墙、红色屋顶和亚得里亚海景著名。也是美剧《权力的游戏》（Game of Thrones）中"君临城"（King\'s Landing）的主要取景地。'},
  {c:'旅游',q:'在荷兰，"风车"（Windmill）历史上的主要功能是什么？',o:['发电，为城市提供电力','排水、磨粉、锯木等，用来对抗低于海平面的地理条件','作为灯塔指引船只','纯粹作为装饰地标'],a:1,e:'荷兰低于海平面的土地占全国约26%，风车（Windmill）历史上用于排水（防洪）、磨粉（面粉加工）、锯木等。小孩堤坝（Kinderdijk）有19座历史风车群，是UNESCO世界遗产。'},
  {c:'旅游',q:'去冰岛（Iceland）旅游，什么是"Golden Circle"（黄金圈）？',o:['冰岛首都的主要购物街','包含辛格韦利尔国家公园、盖歇尔间歇泉和黄金瀑布的三大景点路线','北极光最佳观测区域','冰岛的火山地热区集合'],a:1,e:'Golden Circle（黄金圈）是冰岛最经典的一日游路线，包含：①Þingvellir National Park（辛格韦利尔，美洲板块和欧亚板块交汇处）②Geysir（盖歇尔间歇泉区）③Gullfoss（黄金瀑布）。从首都雷克雅未克出发约300公里环线。'},
  {c:'旅游',q:'法国的"卢浮宫"（Louvre Museum）中最著名的艺术品是？',o:['梵高的《星夜》','达芬奇的《蒙娜丽莎》（Mona Lisa）','米开朗基罗的《创造亚当》','毕加索的《格尔尼卡》'],a:1,e:'《蒙娜丽莎》（Mona Lisa）由意大利文艺复兴大师达·芬奇（Leonardo da Vinci）创作，是卢浮宫乃至全世界最著名的画作。注意：卢浮宫非常大，建议提前规划参观路线！'},
  {c:'旅游',q:'瑞士最著名的山峰"马特宏峰"（Matterhorn）有什么特点？',o:['是阿尔卑斯山脉中最高的山峰','以其独特的三角形锥状山峰著名，位于瑞意边境，高4478米','以年均积雪量最大著名','是世界上唯一一座无法攀登的山峰'],a:1,e:'Matterhorn（马特宏峰）以其完美的金字塔形锥状轮廓著称，是世界上最具辨识度的山峰之一。位于瑞士采尔马特（Zermatt）和意大利边境，4478米高。采尔马特是无汽车城镇，以环保著名。'},
  {c:'旅游',q:'苏格兰"威士忌"（Scotch Whisky）和普通威士忌的区别是？',o:['苏格兰威士忌完全不含酒精','必须在苏格兰酿造、在橡木桶中陈年至少3年（法律规定）、酒精度≥40%','只有在高地（Highlands）酿造才能叫Scotch','苏格兰威士忌不用谷物，只用泥炭'],a:1,e:'Scotch Whisky有严格法律定义：①必须在苏格兰制造②必须在橡木桶陈年至少3年③酒精度40%以上。分为五大产区：Highlands、Lowlands、Speyside、Islay（以泥炭味著名）、Campbeltown。'},
  {c:'旅游',q:'在希腊旅游，雅典卫城（Acropolis）上最著名的建筑是？',o:['奥林匹亚宙斯神庙（Temple of Olympian Zeus）','帕台农神庙（Parthenon）','阿波罗神庙','赫淮斯托斯神庙'],a:1,e:'Parthenon（帕台农神庙）建于公元前447-432年，供奉雅典娜女神（Athena），是古希腊黄金时代的代表建筑。尽管经历了数千年的风雨和战争，雄伟的大理石柱廊至今仍部分保存完好。'},
  {c:'旅游',q:'波兰的"奥斯维辛集中营"（Auschwitz-Birkenau）现在是什么？',o:['已被拆除，原地建了纪念公园','已成为博物馆和UNESCO世界遗产，作为二战暴行的历史纪念地','已改建成军事博物馆','仅限学者研究，不向公众开放'],a:1,e:'Auschwitz-Birkenau（奥斯维辛-比克瑙）是二战中纳粹德国最大的集中营，约110万人（主要是犹太人）在此被杀害。现为博物馆和UNESCO世界遗产，每年有约200万游客前来悼念和学习历史。'},
  {c:'旅游',q:'挪威的"峡湾"（Fjord）是如何形成的？',o:['海底火山喷发形成','由冰川侵蚀而成，海水倒灌形成的狭长深邃海湾','河流冲刷形成的峡谷','地震导致的地壳断裂'],a:1,e:'Fjord（峡湾）是冰河时期冰川侵蚀形成的深谷，冰川融化后海水灌入，形成狭长深邃的海湾。挪威拥有世界上最著名的峡湾，盖朗厄尔峡湾（Geiranger fjord）和纳柔依峡湾（Nærøyfjord）均为UNESCO世界遗产。'},
  {c:'旅游',q:'去爱尔兰旅游，"莫赫悬崖"（Cliffs of Moher）位于哪个省？',o:['伦斯特省（Leinster）','芒斯特省（Munster）/康诺特省（Connacht）边界，位于克莱尔郡（County Clare）','阿尔斯特省（Ulster）','唯一在北爱尔兰'],a:1,e:'Cliffs of Moher（莫赫悬崖）位于爱尔兰西部克莱尔郡（County Clare），高达214米，长约8公里，俯瞰大西洋，是爱尔兰最受欢迎的自然景观之一，每年吸引超过150万游客。'},
  {c:'旅游',q:'德国的"新天鹅堡"（Neuschwanstein Castle）是哪位国王下令建造的？',o:['神圣罗马帝国皇帝腓特烈一世','巴伐利亚国王路德维希二世（Ludwig II）','德意志皇帝威廉一世','普鲁士国王腓特烈大帝'],a:1,e:'Neuschwanstein Castle（新天鹅堡）由巴伐利亚"童话国王"路德维希二世（Ludwig II）下令建造，始建于1869年。这座浪漫主义城堡是迪士尼睡美人城堡的原型，是全球最受欢迎的旅游地之一。'}
);

// ──────────────────────────────────────────────────────────────
// 【9】美洲及大洋洲 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_AMERICAS.push(
  {c:'旅游',q:'去美国旅游，入境时须填写的"I-94表格"记录了什么？',o:['你在美国的购物清单','你的入境/出境记录和允许停留时间','你的酒店预订信息','你的旅行保险信息'],a:1,e:'I-94（Arrival/Departure Record）=美国入境记录，电子化后自动生成，记录你入境日期和允许停留的最长时间。旅游签证一般允许停留180天以内。可在CBP官网查询I-94记录。'},
  {c:'旅游',q:'加拿大的"班夫国家公园"（Banff National Park）位于哪个省？',o:['不列颠哥伦比亚省（British Columbia）','艾伯塔省（Alberta）','安大略省（Ontario）','魁北克省（Quebec）'],a:1,e:'Banff National Park（班夫国家公园）是加拿大最古老的国家公园（1885年建立），位于艾伯塔省（Alberta）落基山脉中，以路易斯湖（Lake Louise）的碧绿湖水和雪山倒影著名。'},
  {c:'旅游',q:'巴西的"里约热内卢狂欢节"（Rio Carnival）通常在什么时间举行？',o:['7月（巴西冬季）','通常在2月或3月（复活节前的40天，大斋期开始前）','12月（圣诞节期间）','10月（巴西国庆节前后）'],a:1,e:'Rio Carnival（里约狂欢节）是世界上最大的狂欢节，通常在2月或3月举行（具体日期根据复活节变化）。各桑巴学校竞相表演，全城狂欢四天五夜，被誉为"地球上最盛大的演出"。'},
  {c:'旅游',q:'秘鲁的"马丘比丘"（Machu Picchu）是什么文明的遗址？',o:['玛雅文明（Maya civilization）','印加文明（Inca civilization）','阿兹特克文明（Aztec civilization）','殖民时期西班牙建筑群'],a:1,e:'Machu Picchu（马丘比丘）是印加帝国（Inca Empire）15世纪建造的古城遗址，位于秘鲁安第斯山脉（Andes）2430米高处。1911年被美国历史学家发现，现为UNESCO世界遗产和新世界七大奇迹之一。'},
  {c:'旅游',q:'澳大利亚的"大堡礁"（Great Barrier Reef）面临的最大威胁是？',o:['过度捕鱼导致渔业枯竭','气候变化引起的海水升温导致珊瑚白化（Coral Bleaching）','海洋污染（塑料垃圾）','旅游开发过度'],a:1,e:'Coral bleaching（珊瑚白化）是大堡礁面临的最大威胁。海水温度升高导致珊瑚排出共生藻类，变白并死亡。近年来大堡礁经历了多次大规模白化事件，科学家正竭力保护这一世界遗产。'},
  {c:'旅游',q:'新西兰著名的"霍比特人村"（Hobbiton）位于哪个城市附近？',o:['奥克兰（Auckland）','马塔马塔（Matamata）','惠灵顿（Wellington）','皇后镇（Queenstown）'],a:1,e:'Hobbiton Movie Set（霍比特人村）是《指环王》和《霍比特人》电影的拍摄地，位于新西兰北岛马塔马塔（Matamata）附近的亚历山大牧场。是新西兰最受欢迎的旅游景点之一。'},
  {c:'旅游',q:'墨西哥"玛雅文明"的"奇琴伊察"（Chichen Itza）最著名的建筑是？',o:['特奥蒂瓦坎太阳金字塔（Pyramid of the Sun）','库库尔坎神庙（El Castillo/Temple of Kukulcan），即羽蛇神金字塔','玛雅人头像','玛雅壁画神殿'],a:1,e:'El Castillo（也叫Kukulcan Temple/羽蛇神神庙）是奇琴伊察的标志建筑，高达30米的阶梯金字塔，每逢春分秋分日落时，阶梯侧面会出现"蛇形"阴影奇观（Shadow Snake Phenomenon）。是新世界七大奇迹之一。'},
  {c:'旅游',q:'美国夏威夷（Hawaii）属于太平洋哪类岛屿？',o:['大陆架岛屿（与大陆相连的岛）','火山岛（由海底火山活动形成）','珊瑚礁岛','冰川岛'],a:1,e:'夏威夷群岛是由海底火山喷发形成的火山岛（Volcanic islands）。大岛（Hawaii Island）上的基拉韦厄火山（Kilauea）是世界上最活跃的活火山之一，熔岩至今仍在不断扩大岛屿面积。'},
  {c:'旅游',q:'"Patagonia"（巴塔哥尼亚）指的是哪个地区？',o:['巴西亚马逊丛林南部','阿根廷和智利南端的广阔荒野地区，以壮阔冰川和国家公园著名','秘鲁沿海地区','哥伦比亚高原地区'],a:1,e:'巴塔哥尼亚（Patagonia）是南美洲最南端的荒野地区，跨越阿根廷和智利。以托雷斯德尔潘纳国家公园（Torres del Paine）、菲茨罗伊山（Mount Fitz Roy）和巨大的冰川著名，是户外探险爱好者的圣地。'},
  {c:'旅游',q:'去加勒比海旅游，"All-inclusive resort"（全包式度假村）包含什么？',o:['只包含住宿和早餐','通常包含住宿、三餐、饮料（含酒水）、非机动水上运动和部分娱乐活动','包含所有旅游活动和机票','只包含住宿，其他自费'],a:1,e:'"All-inclusive"=全包式，通常包含：住宿、三餐（buffet）、全天候饮品（含无限量酒水）、基础水上活动（浮潜、皮划艇）、娱乐表演等。各度假村具体包含内容有所不同，预订前要仔细阅读说明。'},
  {c:'旅游',q:'阿根廷首都布宜诺斯艾利斯（Buenos Aires）最著名的舞蹈是？',o:['桑巴（Samba）','探戈（Tango）','弗拉门戈（Flamenco）','伦巴（Rumba）'],a:1,e:'Tango（探戈）起源于阿根廷布宜诺斯艾利斯的贫民区，是19世纪末非洲、欧洲和拉丁美洲文化融合的产物，已被UNESCO列为非物质文化遗产。圣特尔莫区（San Telmo）是体验探戈的最佳地点。'},
  {c:'旅游',q:'澳大利亚土著居民（Aboriginal Australians）创作的艺术特点是？',o:['以华丽的油画为主，风格写实','以"X射线画"和"点画"（Dot Painting）著名，有着丰富的精神文化含义','以西方现代抽象艺术为主','以瓷器和陶器艺术见长'],a:1,e:'澳大利亚原住民艺术是世界上最古老的艺术传统之一（超过6万年）。点画（Dot Painting）和梦境故事（Dreamtime stories）是其最具代表性的形式，充满精神和文化含义。购买原住民艺术品时，选择有原住民认证的店铺。'},
  {c:'旅游',q:'哥伦比亚的"卡塔赫纳"（Cartagena）以什么著名？',o:['世界上最大的咖啡农场','色彩缤纷的西班牙殖民时期古城和加勒比海滩','哥伦比亚最大的现代都市','雨林中的亚马逊生态旅游基地'],a:1,e:'Cartagena（卡塔赫纳）是哥伦比亚的加勒比海港口城市，以保存完好的西班牙殖民时期彩色老城区著名。16世纪的城墙（The Walls）保存完好，是UNESCO世界遗产。与美丽的海滩相邻，是哥伦比亚最浪漫的城市。'},
  {c:'旅游',q:'游览美国"大沼泽地国家公园"（Everglades）最可能看到哪种动物？',o:['棕熊（Brown Bear）','美洲短吻鳄（American Alligator）和佛罗里达美洲豹','麋鹿（Elk）','加州海狮（California Sea Lion）'],a:1,e:'Everglades National Park（大沼泽地）位于佛罗里达州，是北美洲最大的热带地区国家公园。以美洲短吻鳄（Alligator）、珍稀的佛罗里达美洲豹（Florida Panther）和多种热带鸟类著名。'},
  {c:'旅游',q:'去阿根廷/巴西交界的"伊瓜苏瀑布"（Iguazu Falls），哪侧观景被认为最壮观？',o:['巴西侧（可看到全景，是最佳拍摄角度）','阿根廷侧（可以近距离走到瀑布边缘，体验感更强）','两侧完全相同，没有差别','只有直升机视角才能看到全貌'],a:0,e:'实际上两侧各有优势！巴西侧（Brazil side）可以看到瀑布全景，适合拍照；阿根廷侧（Argentina side）可以深入瀑布内部近距离感受，有多条栈道直达瀑布边缘。建议有时间的话两侧都游览！'}
);

// ──────────────────────────────────────────────────────────────
// 【10】旅行高频词汇 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_TRAVEL.push(
  {c:'词汇',q:'"Wanderlust"这个词的意思是？',o:['对旅行的恐惧或焦虑','对旅行和探索未知地方的强烈渴望','旅行疲劳综合症','迷路时的无助感'],a:1,e:'"Wanderlust"来源于德语，意为对旅行和探索的强烈渴望。它已成为社交媒体上的热门旅行词汇："My wanderlust has been killing me – I need to book a flight ASAP!"'},
  {c:'词汇',q:'"Bucket list"是什么意思？',o:['行李清单（行李箱里要带的东西）','生前愿望清单（希望在死前完成的事情清单）','旅行预算表','签证申请材料清单'],a:1,e:'"Bucket list"来自"kick the bucket"（死亡的俚语），意为你希望在有生之年完成的愿望清单。"Visiting all 7 continents is on my bucket list."（游遍七大洲是我的人生愿望之一）'},
  {c:'词汇',q:'"Off the beaten path"在旅行中是什么意思？',o:['走错路了，需要返回','非主流旅游路线，避开大众景点，探索不为人知的地方','快捷路线，可以节省时间','危险区域，不建议前往'],a:1,e:'"Off the beaten path/track"=非主流路线，指那些不在普通旅游线路上的、较少游客光顾的地方。爱好这类旅行的人也叫"off the beaten track traveler"。"Let\'s skip the touristy spots and go somewhere off the beaten path."'},
  {c:'词汇',q:'"Souvenirs"（纪念品）和"Collectibles"（收藏品）有什么区别？',o:['两者完全相同','Souvenirs通常是普通的旅游商品，Collectibles是具有较高价值或珍稀性的收藏品','Souvenirs是食物，Collectibles是艺术品','Souvenirs比Collectibles贵'],a:1,e:'Souvenir=旅游纪念品（如冰箱贴、明信片、钥匙扣），通常批量生产，价格亲民。Collectible=收藏品，指有特定价值、有限量版或艺术价值的物品。当然它们有时候会重叠。'},
  {c:'词汇',q:'"Visa on arrival"（落地签）是指？',o:['提前在大使馆申请的签证','在抵达目的地机场时当场申请和获取的签证','电子签证（在线申请的签证）','不需要签证即可入境'],a:1,e:'Visa on Arrival（VOA）=落地签，无需提前申请，在抵达该国机场时直接办理。常见于泰国、印度尼西亚、土耳其等国。注意：需准备好护照照片、填写的表格和签证费（通常只收美元或当地货币）。'},
  {c:'词汇',q:'"Long-haul flight"是指什么？',o:['国内短途航班（1小时内）','长途飞行（通常指飞行时间超过6-7小时的航班）','过境航班','包机（Charter flight）'],a:1,e:'Long-haul flight=长途飞行，通常指6小时以上的航班，如北京飞伦敦约11小时，北京飞洛杉矶约13小时。长途飞行中要注意：多走动防血栓、多喝水、带颈枕耳塞等。'},
  {c:'词汇',q:'"Overland travel"（陆路旅行）是指什么？',o:['在城市内部的旅行','通过陆地交通方式（火车/巴士/自驾）横越地区，而非乘坐飞机','沿海岸线的旅行','徒步旅行'],a:1,e:'Overland travel=陆路旅行，指使用地面交通（火车、长途巴士、自驾等）进行的旅行，区别于飞行（air travel）和海运（sea travel）。在欧洲和东南亚非常流行，可以欣赏沿途风景。'},
  {c:'词汇',q:'"Homestay"和"Airbnb"分别是什么住宿方式？',o:['Homestay是高档民宿，Airbnb是廉价旅馆','Homestay是住在当地人家中（常含餐食）的文化沉浸式住宿；Airbnb是整租或合租的民宿平台','两者完全相同，都是共享短租住宿','Homestay是长期租住，Airbnb是酒店预订平台'],a:1,e:'Homestay=住宿家庭，通常住在当地居民家中，包含一日两到三餐，是深入体验当地文化的方式，常见于语言交流项目。Airbnb=网络短租平台，整租或合租当地人的房子，更独立。'},
  {c:'词汇',q:'"Couchsurfing"是什么旅行方式？',o:['一种豪华游艇旅行','通过网络社区免费借住陌生人家中沙发/房间的旅行方式','乘坐沙发车旅行','带着折叠沙发去野营的旅行'],a:1,e:'Couchsurfing=沙发冲浪，是一种通过Couchsurfing.com等平台联系愿意免费提供住宿的当地人（host），住在他们家沙发或空房间的旅行方式。以文化交流为核心，完全基于互信和互惠。'},
  {c:'词汇',q:'"Frequent flyer miles"（常旅客里程）可以用来做什么？',o:['兑换现金返还到银行账户','兑换免费或打折机票、升舱、酒店住宿等奖励','用于减免签证费用','在免税店购物时使用'],a:1,e:'Frequent Flyer Miles（里程）是航空公司忠诚度计划（Loyalty Program）的积分，可以兑换：免费机票、舱位升级（Upgrade）、酒店住宿、租车等。如果经常出行，绑定常旅客号码积累里程非常值得！'},
  {c:'词汇',q:'"Carbon offset"（碳抵消）在旅行中是什么概念？',o:['航班上的碳酸饮料配额','通过捐款支持植树造林等项目来抵消飞行产生的碳排放，减少对环境的影响','减少行李重量从而降低油耗','购买电动旅游车服务'],a:1,e:'Carbon offset（碳抵消/碳补偿）=通过购买碳信用（捐款支持植树、可再生能源等项目）来抵消旅行产生的碳排放。很多航空公司（如国泰航空、新加坡航空）提供购票时自愿选择碳抵消的选项。'},
  {c:'词汇',q:'"Gap year"在旅行语境中是指？',o:['签证审批期间的等待时间','在人生阶段转换之间（如毕业后、工作转型时）花一年时间旅行和体验不同生活','两次旅行之间的休息期','超过一年的长期旅居生活'],a:1,e:'"Gap year"=间隔年，源于英国和澳大利亚，指在完成学业进入大学或职场之前，花一年时间旅行、义工或自我探索。现在也泛指任何人生阶段的"暂停一年"进行旅行探索。'},
  {c:'词汇',q:'"Digital nomad"（数字游牧民族）是指什么类型的人？',o:['没有护照的无国籍旅行者','使用互联网和技术远程工作、同时在世界各地旅行生活的人','专门研究游牧文化的学者','只使用数字地图旅行的人'],a:1,e:'"Digital nomad"=数字游民，指通过远程办公（remote work）、自由职业或在线创业实现位置独立，同时在不同城市或国家旅行生活的现代人。Bali、Chiang Mai、Lisbon、Medellin是全球著名的数字游民聚集地。'},
  {c:'词汇',q:'"Excursion"（旅行中的小型游览活动）通常是指？',o:['长达数周的远程旅行','从主要目的地出发的一日或半日短途参观活动','需要特殊装备的极限运动','旅行社安排的全程包团游'],a:1,e:'"Excursion"=短程游览，通常是从你所在的城市出发，一日或半日往返的观光活动。如在巴塞罗那住几天，可以去蒙特塞拉特山（Montserrat）一日游——这就是一次excursion。'},
  {c:'词汇',q:'"Transit hotel"（过境酒店）适合哪类旅客使用？',o:['长期居住在机场附近的当地居民','在机场附近短暂休息（6-12小时）等待转机的旅客','只接待商务旅客的高端酒店','机场工作人员专用酒店'],a:1,e:'Transit hotel=过境酒店，通常位于机场内或附近，专为中转旅客提供短时（数小时）或一晚的住宿。如果转机时间超过6小时，可以考虑入住过境酒店休息，比在候机楼的椅子上熬夜舒服多了！'}
);

// ──────────────────────────────────────────────────────────────
// 【11】日常生活词汇 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_DAILY.push(
  {c:'词汇',q:'"Laundromat"（美式）/ "Laundrette"（英式）是指什么地方？',o:['干洗店（专业干洗服务）','自助洗衣店（投币式洗衣机和烘干机供公众使用）','酒店洗衣服务','服装修改店'],a:1,e:'Laundromat/Laundrette=自助洗衣店，通常有投币式洗衣机（washing machine）和烘干机（dryer）。长途旅行时非常实用，可以自己洗衣服，费用比酒店洗衣便宜很多。'},
  {c:'词汇',q:'在国外超市，"Sell-by date"和"Best before date"有什么区别？',o:['两者完全相同，都表示产品不能在该日期后食用','Sell-by=商店应在此日期前售出；Best before=最佳食用期（此后口感下降但通常仍安全）；两者不同于Expiry date（有效期，过期须扔掉）','Best before是强制性的，Sell-by只是建议','两者都表示危险过期日期'],a:1,e:'"Sell-by date"是给商店看的补货提示；"Best before date"是最佳口味期限；"Expiry/Use-by date"才是真正的安全有效期，必须在此日期前食用。奶制品、肉类要严格注意Use-by date。'},
  {c:'词汇',q:'在英国，"Chemist"（药剂师/药店）等同于美国的哪个词？',o:['Physician（医生）','Pharmacy / Drugstore（药店）','Supermarket（超市）','GP（家庭医生）'],a:1,e:'"Chemist"在英国指药店（pharmacist=药剂师，工作的地方叫chemist\'s/pharmacy）。Boots和Superdrug是英国最大的连锁药店。美国叫pharmacy或drugstore（如CVS、Walgreens）。'},
  {c:'词汇',q:'"Tap water"（自来水）在哪些国家可以直接饮用？',o:['全球所有发达国家和大多数发展中国家','英国、德国、美国、澳大利亚、日本、北欧等发达国家（大多数地区），但发展中国家通常建议喝瓶装水','只有欧洲国家','只有有过滤系统的地区'],a:1,e:'发达国家（英、美、德、法、日、澳等）自来水通常可以直接饮用且水质优良。前往发展中国家（部分东南亚、非洲、印度、墨西哥等）建议喝瓶装水或已煮沸的水，以防旅行者腹泻（Traveler\'s diarrhea）。'},
  {c:'词汇',q:'"Sunscreen"（防晒霜）上的"SPF 50"代表什么？',o:['防晒产品在市场上的编号','可将皮肤遭受紫外线灼伤的时间延长50倍的防护系数（UVB防护）','50%的紫外线防护率','适合50岁以上人群使用的配方'],a:1,e:'SPF（Sun Protection Factor）=防晒系数，代表对UVB的防护强度。SPF 50=可延长皮肤遭受晒伤时间的50倍。SPF 30已提供97%的UVB防护，SPF 50提供98%。热带地区和雪山旅行建议使用SPF 50+。'},
  {c:'词汇',q:'在国外超市，"Aisle 7"是什么意思？',o:['超市的第7个收银台','超市的第7条货架走廊','超市7号停车场入口','超市7号特卖区'],a:1,e:'Aisle（走廊）在超市指货架之间的走道，并按编号排列。"The cereal is in Aisle 7."=麦片在7号货架走廊。和机场一样，aisle发音是"I-ul"。'},
  {c:'词汇',q:'"Hostel dorm"（青年旅舍宿舍）通常是什么形式？',o:['一个人的私人房间（有独立卫浴）','多人共享一个房间（4-12张床），卫浴共用，价格较低','夫妻或家庭专属房间','青年旅舍的餐厅'],a:1,e:'Dorm（dormitory）=多人宿舍，是青年旅舍（hostel）最便宜的选择，通常6-10人同住一室，有上下铺（bunk beds）。优点：价格低廉，认识来自世界各地的旅行者；缺点：隐私少，噪音可能较大。'},
  {c:'词汇',q:'"Public holiday"在旅行时需要特别注意什么？',o:['公众假日期间，景点通常会全天开放更长时间','很多商店、博物馆、政府机构可能会关门或营业时间缩短','所有交通工具都会停运','外国游客不受公众假日影响'],a:1,e:'Public holiday（公众假日/法定节假日）期间：很多商店可能关门或营业时间缩短；博物馆可能关闭或免费开放；交通（尤其是公交）班次减少；某些景点反而人更多。出行前查好目的地的公众假日！'},
  {c:'词汇',q:'你在国外使用ATM时，机器问"Do you want to proceed with this exchange rate?"（是否使用此汇率换算？），通常建议你？',o:['选择Yes，同意ATM提供的汇率（更方便）','选择No，让你的银行进行汇率换算（通常汇率更好，手续费更低）','无论哪个选择，结果完全相同','选择Yes只适用于有旅行信用卡的人'],a:1,e:'这是"动态货币换算"（Dynamic Currency Conversion / DCC）陷阱！ATM提供的汇率通常比银行汇率差5-10%。应该选择以本地货币计费（"No" / "Charge in local currency"），由你的银行按更好的汇率换算。'},
  {c:'词汇',q:'"Luggage storage"（行李寄存）服务通常在哪些地方提供？',o:['只有豪华酒店才提供','火车站、机场、青年旅舍、酒店前台，以及部分城市中心的商业寄存点（如Stasher, Bounce等App）','只有官方旅游中心','仅在目的地抵达后第一天可用'],a:1,e:'行李寄存（Luggage Storage）到处都有：①火车站/地铁站（有自动储物柜）②机场③大多数酒店（免费或收费）④共享储存App（Stasher、Bounce、Bounce等可预约附近商店寄存）。退房后不需要拖着行李游玩！'},
  {c:'词汇',q:'"Roaming charges"（国际漫游费）是指什么费用？',o:['国内地区间通话费','在境外使用手机时，运营商收取的通话、短信和数据费用（通常很贵）','超出套餐流量的国内费用','国际长途电话费'],a:1,e:'Roaming charges=国际漫游费，使用中国手机在国外时产生的费用（通话/短信/数据），可能非常昂贵。避免方法：①开通运营商的境外流量包②购买目的地SIM卡③关闭数据漫游，只用WiFi。'},
  {c:'词汇',q:'"Jet bridge etiquette"中，登机时应该遵守哪些礼仪？',o:['尽量快速插队，早点进入飞机','按区域登机顺序有序等候，不插队，在通道中迅速找到座位并收拾好行李','在登机廊桥上做热身运动','在通道中花大量时间整理行李箱'],a:1,e:'登机礼仪：①按照广播叫到的区域（Zone/Group）再去排队②到达座位后迅速把行李放入头顶舱，坐好③不要堵在过道整理行李（先坐下再整理）④头顶舱先放随身行李箱，小包放脚下。这些习惯能大大提高登机速度！'},
  {c:'词汇',q:'"Dehydration"（脱水）在旅行中的常见表现和预防方法是什么？',o:['脱水只发生在沙漠旅行中，城市旅行无需担心','头痛、疲劳、深黄色尿液是脱水迹象；在热带/高海拔地区旅行要主动多喝水（每天至少2-3升）','多喝运动饮料（含大量糖分）比水更有效','只要不感到口渴就不需要喝水'],a:1,e:'旅行中容易脱水（尤其在热带气候、高海拔或大量运动时）。脱水症状：口渴、头痛、疲倦、深色尿液。预防：随时携带水瓶，主动补水不要等感到口渴才喝。在高原还需防高原反应（Altitude Sickness）。'},
  {c:'词汇',q:'在国外餐厅看到菜单标注"GF"，代表什么？',o:['Genuine Food（正宗食品）','Gluten-Free（不含麸质，适合乳糜泻患者或麸质不耐受人群）','Great Flavor（口味极佳）','Grown Fresh（新鲜种植）'],a:1,e:'GF=Gluten-Free（无麸质）。麸质（Gluten）存在于小麦、大麦、黑麦中。乳糜泻（Celiac Disease）患者食用后会引发严重肠胃反应。其他常见菜单标注：V=素食，VG=纯素，N=含坚果，DF=无乳制品。'}
);

// ──────────────────────────────────────────────────────────────
// 【12】旅行实用语法 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GRAMMAR.push(
  {c:'语法',q:'"I\'ve been traveling for 3 weeks."用的是哪种时态，强调什么？',o:['一般过去时，强调旅行已结束','现在完成进行时（Present Perfect Continuous），强调动作从过去开始持续到现在，且可能还在继续','一般现在时，描述习惯','过去完成时，表示旅行在某个过去时刻之前完成'],a:1,e:'现在完成进行时结构：have/has + been + 现在分词（-ing）。强调：①动作从过去某时开始②一直持续到现在③可能还在继续。"I\'ve been waiting here for two hours."（我已经在这里等了两小时了）—— 还在等！'},
  {c:'语法',q:'"The hotel where we stayed was amazing."中"where"的作用是？',o:['疑问词（问在哪里）','关系副词，引导定语从句（替代"in which"），修饰名词"hotel"','地点介词','连词（连接两个句子）'],a:1,e:'关系副词where引导定语从句，用来修饰表示地点的名词："The city where I was born"（我出生的城市）/ "The restaurant where we had dinner"（我们吃晚饭的餐厅）。等同于"The hotel in which we stayed..."'},
  {c:'语法',q:'表达"我宁愿吃当地食物也不愿去快餐店"，正确结构是？',o:['I prefer to going local restaurants than fast food.','I\'d rather eat local food than go to a fast food restaurant.','I like more the local food but not fast food.','I prefer local food comparing fast food.'],a:1,e:'"I\'d rather A than B"=我宁愿A而不是B。结构：I\'d rather + 动词原形 + than + 动词原形。也可以说"I prefer A to B"（prefer + 名词/动名词 + to + 名词/动名词）：I prefer local food to fast food.'},
  {c:'语法',q:'"By the time we reached the station, the train had already left."使用了什么时态？',o:['两句都是一般过去时','主句一般过去时 + 从句过去完成时（Past Perfect），表示从句动作在主句动作发生前已完成','主句过去完成时 + 从句一般过去时','两句都是过去完成时'],a:1,e:'过去完成时（Past Perfect = had + 过去分词）用于描述在过去某个时刻之前已经完成的动作。"By the time我们到站时（过去），火车已经离开了（更早的过去）"。这是过去完成时的经典使用场景。'},
  {c:'语法',q:'以下哪个问句用于询问建议，语法最正确？',o:['What do you suggest me visiting?','What would you suggest visiting? / What do you recommend I visit?','What should I visit, can you tell me?','Where is the good place for me?'],a:1,e:'"What would you suggest visiting?"=你建议去参观什么？suggest后面的用法：suggest + V-ing（recommend + V-ing）或suggest + (that) + 主语 + 动词。错误："suggest me visiting"——suggest不像tell那样直接跟人作间接宾语。'},
  {c:'语法',q:'区分"Fewer"和"Less"的用法，哪个句子是正确的？',o:['There is less tourists in January.','There are fewer tourists in January. / We have less time than I expected.','There is fewer traffic today.','There is less cars on the road.'],a:1,e:'Fewer用于可数名词（fewer tourists, fewer days）；Less用于不可数名词（less time, less traffic, less water）。常见错误："10 items or less"（超市快速通道标语，严格来说应该是"10 items or fewer"）。'},
  {c:'语法',q:'"The tour guide, who speaks five languages, is very knowledgeable."句子中的逗号有什么作用？',o:['表示错误，逗号不应该用在这里','将"who speaks five languages"变成非限定性定语从句（提供额外信息，去掉也不影响主句含义）','表示停顿，没有语法意义','将句子分成两个独立的句子'],a:1,e:'非限定性定语从句（Non-restrictive Relative Clause）用逗号分隔，提供补充信息而非限定范围。对比：限定性："The guide who speaks Chinese was helpful."（特指说中文的那位导游）；非限定性："The guide, who speaks Chinese, was helpful."（提供额外信息）。'},
  {c:'语法',q:'"Do you speak any English?"和"Do you speak some English?"有什么区别？',o:['两者完全相同，可以互换','Any通常用于疑问句和否定句；Some通常用于肯定句或期待肯定回答的礼貌请求（"Do you have some water?"暗示期望有）','Any比Some更正式','Some只用于书面语'],a:1,e:'"Do you speak any English?"是中性问句（不预设答案）；"Do you speak some English?"语气更柔和，隐含希望对方有一点英语基础。在旅行中向不确定会不会英语的人询问，用any更自然。'},
  {c:'语法',q:'在英语中，"Would you mind if I opened the window?"这句话真正想表达的意思是？',o:['你是否已经打开了窗户？','你介意我打开窗户吗？（礼貌请求许可）','你今天打开过窗户吗？','窗户是否应该打开？'],a:1,e:'"Would you mind if I + 过去时动词?"=你介意我……吗？（非常礼貌的许可请求）。回答：如果不介意（同意）说"No, not at all."（一点也不介意）；如果介意（拒绝）说"Actually, I\'d prefer if you didn\'t."。注意："No"代表"我不介意（可以）"！'},
  {c:'语法',q:'"It\'s worth visiting."和"It\'s worth a visit."哪个语法正确？',o:['只有"It\'s worth visiting."正确','两者都正确！worth + V-ing 和 worth + 名词都是正确的','只有"It\'s worth a visit."正确','两者都不正确，应该说"It is worthing to visit"'],a:1,e:'worth的正确用法：①worth + V-ing: "This museum is worth visiting."②worth + 名词: "This museum is worth a visit."；worth it=值得。错误用法："It\'s worth to visit"（×）。旅行推荐时常用："The view is absolutely worth the hike."（这个景色绝对值得爬山）'},
  {c:'语法',q:'以下哪个句子表达了"如果明天天气好，我们就去参观古堡"？',o:['If tomorrow is fine weather, we would go to the castle.','If the weather is fine tomorrow, we\'ll visit the castle.','If the weather will be fine tomorrow, we will visit the castle.','If the weather would be fine tomorrow, we will go to the castle.'],a:1,e:'第一条件句（真实可能的条件）：If + 一般现在时，主句 + will/can/may + 动词原形。时间从句（if/when/as soon as）中不能用will，用一般现在时代替将来。正确：If the weather IS fine...we\'ll visit（不是"will be fine"）。'},
  {c:'语法',q:'"Excuse me, I\'m looking for the cathedral."这句话中"I\'m looking for"用的是哪种时态，为什么？',o:['一般现在时，表示日常习惯','现在进行时，强调此刻正在寻找（当前动作）','现在完成时，表示已经找到','将来进行时，表示计划要找'],a:1,e:'现在进行时（am/is/are + V-ing）用于描述此刻正在发生的动作。"I\'m looking for"=我正在找（此刻的动作）。对比一般现在时：I look for = 我经常找（习惯）。在问路场景中，进行时准确表达了"此时此刻在寻找"的意思。'},
  {c:'语法',q:'"The more you travel, the more open-minded you become."用了哪种语法结构？',o:['假设从句（If-then）','The + 比较级..., the + 比较级...（越……越……）固定结构','让步状语从句','因果关系从句'],a:1,e:'"The + 比较级, the + 比较级"是英语中的固定结构，表示"越……越……"。例：The sooner, the better.（越快越好）/ The longer you stay, the more you\'ll see.（待得越久，看得越多）。在旅行建议中经常用到！'},
  {c:'语法',q:'"I wish I had booked the tickets earlier."这句话表达的含义是？',o:['我很高兴提前订了票','我希望我之前早点订票（但实际上没有，对过去的遗憾）','我打算提前订票','我建议你提前订票'],a:1,e:'"I wish + 过去完成时"表示对过去事实的遗憾（与过去事实相反的虚拟语气）。"I wish I had booked..."=我当时要是早点订票就好了（暗示：我没有早点订，现在后悔）。对比："I wish I had more time."（对现在的遗憾，用过去时）'},
  {c:'语法',q:'在向陌生人道别时，以下哪个表达最地道自然？',o:['Goodbye forever.','Take care! / Safe travels! / It was lovely meeting you!','See you never.','I am leaving now, goodbye to you.'],a:1,e:'与旅途中认识的陌生人道别常用语：Take care!（保重）、Safe travels!（一路平安）、It was lovely/great meeting you!（很高兴认识你）、Have a wonderful trip!（祝旅途愉快）。这些表达友善自然，给人留下好印象。'}
);

// ──────────────────────────────────────────────────────────────
// 【13】文化礼仪常识 追加 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_CULTURE.push(
  {c:'出国',q:'在法国，进入别人家中或在正式场合初次见面，法国人通常用什么方式打招呼？',o:['用力握手','贴面礼（La Bise，脸颊轻触加飞吻，通常2-4次，各地区不同）','90度鞠躬','拥抱'],a:1,e:'La Bise（贴面礼）是法国社交标配，见到朋友或熟人时互相贴脸颊并发出亲吻的声音。次数因地区而异（巴黎通常2次，南法可能4次）。初次见面陌生人之间通常握手。'},
  {c:'出国',q:'在中东国家（如沙特阿拉伯、伊朗），女性旅行者需要特别注意什么着装规定？',o:['只需避免穿短裙即可','在许多中东国家，女性需要遮住头发（戴头巾Hijab）和身体曲线，穿着宽松保守的服装；在沙特，公共场所须穿阿巴雅（Abaya）','女性禁止在任何公共场所出现','只有进入清真寺时才需要遮头'],a:1,e:'着装规定因国而异：沙特阿拉伯公共场所女性（外国游客也包括）需穿阿巴雅（Abaya，宽松长袍）；伊朗需戴头巾；阿联酋（迪拜）相对开放但需着装保守（盖肩盖膝）。在任何伊斯兰国家参观清真寺女性必须遮头。'},
  {c:'出国',q:'在日本料理店，以下哪个行为是不礼貌的？',o:['用双手接饮料或食物','把筷子竖着插在米饭上（这是葬礼仪式中的做法）','用手拿起饭碗把脸凑近喝汤','向服务员说"Itadakimasu"（开动前的感谢语）'],a:1,e:'日本饮食禁忌：①不要把筷子垂直插进米饭（这是供奉死者的方式）②不要用筷子传递食物给别人的筷子（也是葬礼习俗）③不要在菜肴上方挥舞筷子犹豫不决（NG行为）。用手拿饭碗喝汤在日本是正常的。'},
  {c:'出国',q:'在印度，访客进入有神灵供奉的家庭或寺庙时，正确的做法是？',o:['用左手接受供品以示吉祥','脱鞋后进入，接受供品时用右手或双手，不用左手','保留鞋子，因为地板很脏','戴手套进入'],a:1,e:'印度文化：①进入寺庙或传统家庭须脱鞋②左手在印度传统文化中被视为不洁，接受食物、礼物或用右手③如果被邀请参加宗教仪式，遵从主人指引。接受任何东西都用右手，这在南亚和东南亚都适用。'},
  {c:'出国',q:'在澳大利亚，当地人叫你"mate"，这是什么意思？',o:['这是一种侮辱性称呼','这是朋友/哥们儿的意思，是非常友好亲切的称呼','这表示对方想要你的帮助','这是一种正式的问候方式'],a:1,e:'"Mate"在澳大利亚（和英国）是"朋友"的意思，非常口语化和亲切。无论是否认识，澳大利亚人都可能叫你mate。"G\'day, mate!"=你好，朋友！这是澳大利亚人的经典打招呼方式。'},
  {c:'出国',q:'在西方国家（如美国、英国），餐厅里的小费文化中，下列哪种情况通常小费最多？',o:['超市收银','餐厅坐下用餐（Sit-down restaurant）服务（通常15-20%）','快餐店（Fast food）','自助餐（Buffet）'],a:1,e:'小费比例指南（美国）：坐下用餐=15-20%（这是服务员主要收入来源）；酒吧=每杯$1-2；外卖（Delivery）=10-15%；快餐=不需要或可选；美发=15-20%；出租车=10-15%。"Is 20% a good tip?"=给20%小费合适吗？'},
  {c:'出国',q:'在新加坡，哪项行为可能面临高额罚款？',o:['在地铁上使用手机（没有罚款）','在公共场所随地吐痰、乱扔垃圾、进食/饮水（地铁内禁止）；携带榴莲乘坐公共交通','在购物中心大声说话','在户外打电话'],a:1,e:'新加坡以严格法律著名：①地铁内禁止饮食（罚款500新元）②随地吐痰罚款③随地乱扔垃圾罚款④携带榴莲乘坐公共交通是被明令禁止的（因气味）⑤口香糖只允许医疗用途⑥万圣节活动须事先申请许可。'},
  {c:'出国',q:'在俄罗斯，送花给主人时需要注意什么？',o:['最好送白色花，代表纯洁','送花束时要送单数（奇数），偶数花束（如12支）在俄罗斯文化中是葬礼专用','颜色越多越好，代表热情','黄色花是最吉祥的颜色'],a:1,e:'俄罗斯（及很多东欧斯拉夫国家）的送花文化：奇数（单数）花=喜庆场合；偶数（双数）花=葬礼/悼念。所以生日、拜访主人要送1、3、5、7支等奇数束花。另外，黄色花在某些东欧文化中代表分离。'},
  {c:'出国',q:'参观梵蒂冈博物馆和圣彼得大教堂时，对旅客着装有什么要求？',o:['须穿西装和正装鞋','须遮住肩膀和膝盖（禁止穿短裤、无袖衣服进入），否则将被拒绝入场','须穿戴天主教宗教服饰','没有着装要求'],a:1,e:'梵蒂冈（Vatican）是天主教圣地，入场着装要求严格：①必须遮肩（肩膀以下）②必须遮膝（膝盖以下）③禁止穿短裤、背心、无袖裙。可以用丝巾或围巾临时遮盖。不符合要求将被门卫拒绝入场。'},
  {c:'出国',q:'在巴西，拇指和食指连成圆圈的手势（OK手势）是什么含义？',o:['好的/没问题（和大多数西方国家一样）','在巴西（及部分拉丁美洲国家）这是一个粗鄙的侮辱性手势','代表钱','代表"零"或"没有"'],a:1,e:'手势因文化差异巨大！OK手势（☞）：在美国=好；在巴西/希腊=侮辱性手势；在日本=钱；在法国=零。旅行前了解目的地手势禁忌非常重要。大拇指向上（👍）在全球大多数地方表示好，但在伊朗和部分中东地区是侮辱性手势。'},
  {c:'出国',q:'在北欧国家（如挪威、瑞典、芬兰），社交时应该注意什么？',o:['北欧人热情好客，会主动找陌生人聊天','北欧人普遍较为内敛安静，珍视个人空间，不喜欢在公共场所与陌生人闲聊；但一旦成为朋友，关系非常真诚','北欧文化要求在任何场合都要大声问好','北欧人非常注重等级，见人须先鞠躬行礼'],a:1,e:'北欧文化特点：高度重视个人空间（personal space）和隐私；不习惯与陌生人闲聊（特别是在公交车上）；直接坦率不喜欢客套话；非常平等主义，不喜欢炫耀财富。这不是冷漠，而是不同的文化价值观。'},
  {c:'出国',q:'"Gestures can be misleading across cultures."这句话对旅行者有什么启示？',o:['旅行时最好只说话，完全不用手势','某些在本国正常的手势，在其他文化中可能有完全不同甚至侮辱性的含义，出行前应了解当地手势禁忌','所有手势在全球都有统一的含义','只有肢体语言，语言反而不重要'],a:1,e:'"手势因文化而异"的旅行忠告：出行前了解目的地的手势禁忌，避免意外冒犯。重要禁忌：左手（中东/印度）、鞋底朝人（泰国/中东）、头顶（泰国）、OK手势（巴西/中东）、竖大拇指（伊朗/部分中东）都可能是侮辱性的！'},
  {c:'出国',q:'在非洲东部国家（如肯尼亚、坦桑尼亚），Safari旅游时应遵守什么行为规范？',o:['可以随意下车与野生动物互动，拍照更方便','必须留在车内不得下车（除非导游明确表示安全），保持安静，不要用食物喂食野生动物','大声呼喊动物名字可以帮助辨认','穿鲜艳颜色服装方便被同伴找到'],a:1,e:'Safari礼仪和安全规范：①不得在未经许可的区域下车（野生动物威胁）②保持安静（大声说话会吓跑动物）③不喂食野生动物（破坏生态且危险）④着装建议大地色（卡其、棕、绿），鲜艳颜色会吸引昆虫和影响动物行为⑤不使用闪光灯拍照。'},
  {c:'出国',q:'在中国台湾、香港等地，当你收到别人用双手递来的名片时，正确的做法是？',o:['单手接过，迅速收入口袋','用双手接住，花几秒钟认真看一下内容再妥善放置，不要当场在名片上写字','随手放到桌上继续聊天','将名片折叠方便收纳'],a:1,e:'东亚商务名片礼仪：双手接收，认真阅读（表示尊重对方），放入名片夹或桌面右上方（不要随意塞入口袋或放在名片上压东西）。在名片上写字或折叠在日本文化中是极不礼貌的行为，台湾和香港也类似。'},
  {c:'出国',q:'"Culture shock"（文化冲击）通常经历哪几个阶段？',o:['兴奋期→适应期→结束','蜜月期（Honeymoon）→挫折期（Frustration）→调整期（Adjustment）→适应期（Adaptation）','恐惧期→适应期→结束','拒绝期→融合期→独立期'],a:1,e:'文化冲击四阶段：①蜜月期=到达初期，对一切感到新奇兴奋②挫折期=语言障碍、文化差异引起挫败感③调整期=开始理解和适应当地文化④适应/双文化期=融入当地同时保留本文化。了解这个过程有助于更好地应对长期海外生活。'}
);
