// 【1】机场英语 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_AIRPORT.push(
  {c:'出国',q:'机场"Fast Track"通道是为哪类旅客设置的？',o:['所有旅客均可使用','头等舱、商务舱或购买快速通道服务的旅客，可以跳过普通安检长队','持有外交护照的旅客专属','只有机场工作人员使用'],a:1,e:'Fast Track=快速通道，允许持有特定资质（商务舱/头等舱票、高级会员资格、付费购买）的旅客走专属安检通道，节省排队时间。部分机场App可以单独购买此服务。'},
  {c:'出国',q:'"Tarmac"在机场语境里是指？',o:['机场内部的候机大厅','飞机停放和滑行的地面跑道及停机坪区域','机场行李传送带','登机廊桥内部'],a:1,e:'Tarmac（柏油停机坪）=飞机在地面上滑行和停放的区域。"Stuck on the tarmac"=飞机停在跑道上迟迟不能起飞（旅客的噩梦之一）。Runway=起飞降落用的跑道，Taxiway=滑行道。'},
  {c:'出国',q:'登机牌上的"Boarding time"与"Departure time"有什么区别？',o:['两者含义完全相同','Boarding time=登机开始时间（通常比起飞早30-60分钟）；Departure time=飞机预计起飞时间，两者不同，要看清楚','Departure time比Boarding time早','只有国际航班才区分这两个时间'],a:1,e:'Boarding time（登机开始时间）通常在Departure time（起飞时间）前30-60分钟。很多旅客把起飞时间当成登机时间，结果错过了航班！看清楚登机牌上的Gate Closes时间，那才是登机截止时刻。'},
  {c:'出国',q:'你在机场听到广播"Paging Mr. Zhang Wei, please come to the information desk."，这意味着？',o:['机场安保在找一位安全威胁者','有人在广播寻找张伟先生，请他前往服务台','张伟先生的航班被取消了','这是一条测试广播'],a:1,e:'"Paging"=通过广播寻找某人。在机场被广播寻找，通常是：有人（家人/同伴）在服务台找你、有遗留物品需要认领、航班信息有变更需要通知。听到自己名字立刻前往Information Desk。'},
  {c:'出国',q:'"Biometric passport"（生物识别护照）中包含什么信息？',o:['只有普通的文字个人信息','内嵌芯片，存储持照人的照片、指纹等生物特征信息，可用于快速自动通关','存储旅行记录的电子标签','具有防伪墨水的特殊护照'],a:1,e:'生物识别护照（也叫电子护照/e-Passport）内嵌RFID芯片，存储面部图像和指纹数据，可以在自助通关闸机（e-gate / ABC gate）使用，速度大大快于人工检查。中国护照自2012年起陆续换发生物识别护照。'},
  {c:'出国',q:'机场"Transfer Desk"（中转服务台）的作用是？',o:['为所有旅客提供旅游咨询','专为转机旅客服务，帮助确认转机登机牌、获取转机信息或处理短暂中转期间的问题','只为头等舱旅客服务','处理行李赔偿申请'],a:1,e:'到达转机机场后，如有问题（找不到下一个航班的登机口、需要重新值机、转机信息有变），前往"Transfer Desk"或"Transit Help Desk"寻求帮助，工作人员专门协助中转旅客。'},
  {c:'出国',q:'你的托运行李在传送带上出现了破损，应该在哪里处理？',o:['向航空公司发送电子邮件投诉','在行李领取区找"Baggage Claims"或"Lost & Damaged Baggage"服务台，当场填写损坏报告（PIR）','回到值机柜台报告','联系机场保安部门'],a:1,e:'行李损坏必须在离开行李领取区前报告！找航空公司的行李服务台，填写PIR（Property Irregularity Report，不正常行李报告），要求赔偿。出机场后再报告通常不被受理。出行建议给行李拍照留证。'},
  {c:'出国',q:'"ESTA"是什么，适用于哪个国家的入境？',o:['欧洲申根区的电子旅行许可证','美国的免签证电子旅行授权（Electronic System for Travel Authorization），适用于符合免签计划的国家公民','加拿大的电子旅行授权（eTA）','澳大利亚的电子签证'],a:1,e:'ESTA（电子旅行授权）是美国免签计划（Visa Waiver Program）国家公民访美所需申请的电子授权，不是签证但也需要申请，通常在几分钟内获批，有效期2年。中国公民需申请正式签证，不适用ESTA。'},
  {c:'出国',q:'"Excess baggage"费用可以通过哪些方式避免或减少？',o:['向工作人员哭诉，博取同情','网上提前购买额外行李额度（通常比机场现付便宜30-50%）；将重物转移到随身行李；穿上最重的衣服；使用行李秤提前称重','购买商务舱升级','更换航空公司'],a:1,e:'超重行李费（Excess Baggage Fee）避免技巧：①出发前在航空公司官网预购额外行李额度（比机场便宜很多）②穿最重的衣服和鞋子登机③把重物如书、充电宝放随身行李④出发前用行李秤称好重量。'},
  {c:'出国',q:'机场的"Sterile transit"（免签中转）区域是什么？',o:['为生病旅客设置的隔离区域','允许旅客在不过边境/移民检查的情况下，在机场内转机的区域（无需目的地转机签证）','专为VIP旅客设置的候机区','专门用于危险品检查的区域'],a:1,e:'Sterile transit（无签证中转）=旅客不需离开国际候机区（不接触当地移民控制）即可完成转机的区域。是否允许无签证中转因国而异——美国不允许，大多数欧洲枢纽允许。转机前必须核查！'},
  {c:'出国',q:'在机场购买的免税酒类，上飞机后有什么规定？',o:['可以立即在机上饮用','通常须装在原始密封袋中，不能在飞行中擅自开封饮用机上提供的餐饮服务之外的个人购买酒类','必须托运，不能随身携带','只有商务舱旅客可以携带免税酒类登机'],a:1,e:'机上饮酒规定：航空公司通常禁止乘客饮用自带酒类（只能喝机上提供的）。免税酒类须保持STEB密封袋完好。在某些国家（如澳大利亚、新西兰），入境时对酒精有严格限额（通常2.25升），超过须申报并缴税。'},
  {c:'出国',q:'"Aerobridges are not available for this flight."广播说这句话，旅客应预期什么？',o:['这次航班被取消了','旅客需要走到停机坪，乘坐摆渡车（bus）或步行登机，没有廊桥连接','这次航班改变了登机口','这次航班将会延误'],a:1,e:'Aerobridge=廊桥（登机桥）。没有廊桥时旅客需要步行下到停机坪，乘坐摆渡车（shuttle bus）到飞机旁，再爬舷梯（airstairs）登机。这在小型机场、低成本航空或停机位不足时很常见。'},
  {c:'出国',q:'你想在出发前把行李暂存在机场，应该寻找什么设施？',o:['机场安检处','Left Luggage / Luggage Lockers（行李寄存处/储物柜）','行李传送带','机场酒店的行李室'],a:1,e:'Left Luggage（英式）/ Bag Storage（美式）=机场行李寄存服务，通常按小时或天数收费。大型机场还有自助储物柜（Luggage Lockers）。适合早到机场需要等候或想轻装游览市区的旅客。'},
  {c:'出国',q:'"Non-revenue passenger"（非付费旅客）通常是指？',o:['购买了特价机票的旅客','以员工福利或优惠资格免费/低价乘坐的航空公司员工及其家属','持里程兑换票的旅客','乘坐包机的旅客'],a:1,e:'Non-revenue passenger（非收益旅客）=不购买正常机票的旅客，通常是航空公司员工或其家属使用员工福利乘机（空位才能登机，优先级最低），也叫"standby passenger"（候补旅客）。'},
  {c:'出国',q:'你在候机室发现座位全满，又不想站着等，可以去哪里休息？',o:['直接坐在地板上','寻找机场贵宾室（Lounge）——持商务舱票、高级会员卡或付费（部分允许散客付费进入）；或寻找非高峰区域的空座','要求机场工作人员给你安排座位','回到值机柜台要求换早一班的飞机'],a:1,e:'候机室座位紧张时：①持Priority Pass卡或商务舱票可进入Lounge（有舒适座椅、免费饮食）②部分机场的Lounge接受散客付费入场（约30-50美元/次）③可以去餐厅/咖啡馆买杯东西坐着等④走到候机室的远端，人通常少一些。'}
);

// ──────────────────────────────────────────────────────────────
// 【2】酒店英语 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_HOTEL.push(
  {c:'出国',q:'酒店前台说"We have a room available with a partial ocean view."，这意味着什么？',o:['房间完全面向大海，视野极佳','从房间某个角度可以看到部分海景，但不是全景海景房','房间在大海旁边但看不到海','房间完全看不到海'],a:1,e:'Partial ocean view（部分海景）=从房间能看到一部分海，但不是完整的海景。介于No view（无景）和Full ocean view（全海景）之间。预订时要认清：ocean view（海景）≠ oceanfront（紧临海边）≠ partial ocean view。'},
  {c:'出国',q:'"B&B"（Bed and Breakfast）是什么类型的住宿？',o:['一种青年旅舍，只提供床和早餐','提供住宿和早餐的小型家庭式旅馆，通常由家庭经营，更有人情味','提供全套餐食的度假村','只在英国存在的一种酒店类型'],a:1,e:'Bed and Breakfast（B&B）=提供床位和早餐的小型民宿，通常由家庭经营，房间数量少（3-10间），早餐是自制的家庭风格餐食。在英国、爱尔兰、美国乡村等地非常普遍，比酒店更有家的感觉，价格适中。'},
  {c:'出国',q:'你入住时前台说"Your room won\'t be ready for another hour. Would you like to wait in our lobby?"，你最好怎么回应？',o:['直接离开，去别的酒店','感谢前台，并可以询问是否能寄存行李，然后去附近游览一会儿再回来','要求立即退款','要求前台给你一个折扣补偿'],a:1,e:'等房间是正常情况（特别是早到时）。可以说"No problem. Could I leave my luggage here while I wait?"（没关系，我可以把行李寄存在这里吗？）然后轻装去附近转转，比坐在大厅等更愉快。'},
  {c:'出国',q:'"Turndown service"是酒店提供的什么服务？',o:['协助旅客延迟退房的服务','晚间将床铺整理好（折叠床角、放置巧克力或鲜花）并关闭窗帘的服务','将行李从大厅送到房间的服务','叫醒服务'],a:1,e:'Turndown service=夜床服务，通常在晚6-9点提供。服务员进入房间：折好床角（方便入睡）、关上窗帘、放上枕边巧克力或鲜花、调暗灯光。是高档酒店的特色服务，象征细致入微的关怀。'},
  {c:'出国',q:'酒店收据上显示"Incidentals hold $200"，这$200是什么意思？',o:['你已经消费了$200的额外服务','酒店预授权冻结在你信用卡上的押金，用于可能产生的额外费用（迷你吧、损坏等），退房结算后若无消费会退还','这是强制收取的服务费','押金已被收取且不会退还'],a:1,e:'Incidentals hold（押金预授权）=酒店在你信用卡上冻结一笔金额作为押金，防范可能的额外消费（Minibar、损坏、延迟退房等）。退房结清账目后，多余的冻结金额会在几个工作日内解冻退回。建议使用信用卡而非借记卡，以避免影响现金流。'},
  {c:'出国',q:'你在酒店看到"Valet parking"服务，这是什么？',o:['免费自助停车场','代客泊车服务——将车钥匙交给服务员，他们帮你停车；取车时需要给小费','仅限酒店员工使用的停车场','仅接受预约的长期停车服务'],a:1,e:'Valet parking（代客泊车）=把车钥匙交给酒店停车员（valet），他们帮你把车停好，需要时再把车开到门口。比自己找停车位方便，但通常收费较贵，还需额外给小费（$2-5）。'},
  {c:'出国',q:'你在热带地区的酒店发现房间里有小型爬行动物（壁虎），你应该？',o:['立刻要求退房，这是严重的卫生问题','无需过于紧张，壁虎在热带地区很常见且无害，会捕食蚊虫；如实在不适可联系前台处理','拍照投诉到网上给差评','打死壁虎'],a:1,e:'热带/亚热带地区（泰国、巴厘岛、东南亚等）酒店常见壁虎（Gecko），它们无毒无害，还会帮忙消灭蚊虫，是当地生态的一部分。当地人视之为吉祥动物。如果真的很介意，可以联系前台，大部分酒店会尽力处理。'},
  {c:'出国',q:'办理入住时，前台问"How will you be settling your bill?"，你应该回答什么？',o:['我会用中文支付','I\'d like to pay by credit card. / I\'ll settle in cash.（我要用信用卡/现金结账）','我要明天再付','我已经在网上付款了所以不需要再付'],a:1,e:'"How will you be settling your bill?"=你打算怎么结账？这是标准入住问题，用于确认支付方式。常见回答："By credit card"（信用卡）/ "In cash"（现金）/ "The company is paying"（公司付款）/ "It\'s prepaid online"（已在网上预付）。'},
  {c:'出国',q:'"The hotel is fully ADA compliant."对于残障旅客意味着什么？',o:['酒店只接受美国旅客','酒店符合美国残疾人法案标准，提供轮椅坡道、无障碍卫浴、电梯等无障碍设施','酒店所有服务都可以用英语沟通','酒店的价格比标准价格高'],a:1,e:'ADA（Americans with Disabilities Act）=美国残疾人法案。ADA compliant=符合无障碍标准，包括：轮椅坡道、加宽走廊和门、无障碍浴室（grab bars扶手）、点字标识、视觉报警系统等。在美国境内旅行的残障人士可以要求ADA无障碍房间。'},
  {c:'出国',q:'酒店游泳池旁边的标志"No diving"是什么意思？',o:['游泳池今天关闭','禁止跳水/跳入泳池（因为水浅，跳水有受伤风险）','禁止穿潜水装备','禁止带水下摄像机'],a:1,e:'"No diving"=禁止跳水（head first into the pool）。酒店泳池通常较浅（1-1.5米），跳水很容易头碰池底受伤。相关标志：No running（禁止奔跑）、No glass（禁止带玻璃器皿）、Shower before entering（入池前请淋浴）。'},
  {c:'出国',q:'"The hotel has a 48-hour cancellation policy."说明什么？',o:['你必须在入住前48小时办理入住手续','如果在入住日期前48小时内取消预订，将被收取取消费（通常为1晚房费）','你需要提前48小时告知预计到达时间','预订后48小时内可以免费取消'],a:1,e:'取消政策（Cancellation Policy）48小时=需在入住日期前至少48小时取消，否则收取罚金（通常1晚房费）。订房前务必阅读取消政策！"Free cancellation"=免费取消（在指定时间内）。旅行不确定时建议订可免费取消的房型。'},
  {c:'出国',q:'你在某国高档酒店结账，账单金额明显偏高，应该怎么做？',o:['直接全额支付，反正保险会报销','礼貌地要求前台逐项解释账单，核实每一项费用是否准确，对有疑问的项目提出质疑','在网上发差评','拒绝支付并离开'],a:1,e:'收到账单时养成逐项核查的好习惯！可以说"Could you go through the bill with me, please?"（能帮我逐项过一下账单吗？）或"I don\'t think I used the minibar."（我不记得用过迷你吧）。酒店账单错误时有发生，礼貌质疑是你的权利。'},
  {c:'出国',q:'在日本传统旅馆（Ryokan）住宿，通常会有什么特色体验？',o:['与普通国际酒店完全相同','睡在榻榻米（Tatami）上的传统铺盖（Futon）、穿着浴衣（Yukata）、享用多道日本传统料理（Kaiseki）和温泉（Onsen）','只提供西式早餐','不提供餐食服务'],a:1,e:'Ryokan（旅馆）是日本传统住宿形式：铺着榻榻米的房间、使用蒲团睡床、着浴衣（Yukata）在馆内活动、享用精致的日本怀石料理（Kaiseki）、泡温泉（Onsen）。是体验日本传统文化的最佳方式，但通常价格较高。'},
  {c:'出国',q:'你在欧洲入住一家标榜"Eco-friendly"（环保）的酒店，你预期会有什么特点？',o:['价格比普通酒店贵一倍以上','使用太阳能、减少一次性塑料、鼓励旅客重复使用毛巾床单、当地有机食材早餐、节能灯和低流量淋浴头等可持续措施','装修非常老旧，设施落后','禁止旅客使用空调'],a:1,e:'Eco-friendly hotel（环保酒店）常见特点：①可再生能源（太阳能板）②减少一次性塑料（不提供一次性洗漱用品）③鼓励旅客不每天换洗毛巾和床单④当地采购食材⑤节水节电设施⑥部分提供电动车充电桩。住环保酒店也是旅行者减少碳足迹的方式之一。'},
  {c:'出国',q:'你在酒店使用了健身房（Gym/Fitness Center），账单上出现了$15的费用。这说明？',o:['所有酒店健身房都免费','这家酒店的健身房需要额外付费，不是免费包含在房价内的','这是一个账单错误，可以要求取消','健身房只对会员免费'],a:1,e:'并非所有酒店设施都免费！入住前最好确认：游泳池、健身房、Spa、停车、WiFi是否包含在房价内（complimentary）或需额外付费。部分酒店度假费（Resort Fee）或城市费（Facility Fee）每天固定收取，包含这些设施。'}
);

// ──────────────────────────────────────────────────────────────
// 【3】交通出行英语 ×15（答案在B/C/D）
