window.QB_EN_TRANSPORT.push(
  {c:'出国',q:'在美国，"Freeway"和"Highway"有什么区别？',o:['两者完全相同，可互换使用','Freeway=没有红绿灯的全封闭式高速公路，不收费；Highway=泛指公路，包括有红绿灯的主干道（部分收费）','Freeway更快，Highway更安全','Highway专指城市内道路，Freeway仅在郊区'],a:1,e:'Freeway（高速公路）=出入口受控、无红绿灯、通常免费；Highway（公路）是更广义的词，包括各种主干道，可能有收费站（Toll）和红绿灯。Turnpike/Toll road=收费高速。在加州，freeway非常普遍且多数免费。'},
  {c:'出国',q:'在英国乘坐出租车，"Black cab"（黑色出租车）和普通Uber有什么主要区别？',o:['Black cab比Uber贵，但服务完全相同','Black cab是持牌的传统伦敦出租车，司机须通过"知识考试"（The Knowledge，熟记所有伦敦街道），起步价更高但无需网络预约；Uber需要App预约、价格随需求浮动','Uber在伦敦是非法的','Black cab不接受信用卡支付'],a:1,e:'伦敦Black Cab（黑色出租车）的司机须通过严苛的"The Knowledge"考试——熟记伦敦25000多条街道和地标，平均需2-4年准备。可在路边直接拦停（Hail）。Uber通过App叫车，价格通常更便宜但高峰期会溢价（Surge pricing）。'},
  {c:'出国',q:'你在澳大利亚驾车，看到标志"Give way to merging traffic from right"，你应该？',o:['保持车速不变，有优先通行权','让右侧汇入车道的车辆先行，减速或停车待避','加速超过汇入车辆','靠左变道避让'],a:1,e:'澳大利亚靠左行驶，部分道路规则与中国不同。"Give way"=让行（等同于"Yield"）。在环形交叉口（Roundabout），已在环内的车辆有优先权。靠右行驶的国家逻辑相反，驾车前务必了解当地规则！'},
  {c:'出国',q:'"Interrail"和"Eurail Pass"有什么区别？',o:['两者完全相同，是同一产品的两个名字','Interrail适用于欧洲居民；Eurail Pass适用于欧洲以外的游客（如中国旅客）；两者都是欧洲多国火车通票','Interrail更便宜，适用范围更广','Eurail Pass只在法国和德国有效'],a:1,e:'简单区分：你是欧洲人→买Interrail；你是来欧洲旅游的外国人（如中国旅客）→买Eurail Pass。两者功能类似，都可以在欧洲多国坐火车，但部分热门路线（如TGV、ICE）还需额外预约座位（Seat reservation）。'},
  {c:'出国',q:'在日本乘坐地铁，"Priority seat"（优先座）的规定是什么？',o:['任何人都必须使用优先座，普通座位禁止坐','优先座通常为老人、残障人士、孕妇、抱小孩的旅客保留；在日本，坐优先座时须关闭手机信号，且当相关人士出现时应主动让座','优先座只限残障人士，有专门标记','外国游客禁止坐优先座'],a:1,e:'日本地铁优先座（Silver seat / Priority seat）文化：即使座位空着，健康的年轻人也往往会刻意回避就坐，以防止需要让座的尴尬。在优先座区域须关闭手机，不能打电话。这体现了日本对老弱群体的尊重文化。'},
  {c:'出国',q:'"Ridesharing"（拼车）服务和普通出租车最大的区别是什么？',o:['拼车只能坐一个人，出租车可以多人','拼车通过App预约、价格透明、使用私人车辆（非职业出租车），司机评分机制让双方互相评价；出租车是持牌专业运营车辆','拼车在所有国家都合法','出租车必须使用计价器，拼车不需要'],a:1,e:'Uber、Grab、Lyft、DiDi等都是Ridesharing平台，利用私人车辆和司机提供服务，通过App预约和支付，价格算法动态定价（高峰期涨价），双方互评机制（星级评分）。与传统出租车（Taxi）相比，方便性高但监管规定各国不同。'},
  {c:'出国',q:'"Park and Ride"停车换乘是什么意思？',o:['在公园里停车，然后骑自行车游览','在市郊停车场停好私家车，换乘公共交通（巴士、地铁）进入市中心，减少市中心拥堵','一种儿童游乐设施','公共停车场与出租车的联合服务'],a:1,e:'Park and Ride（P&R）=停车换乘，在城市外围设置大型停车场，旅客把车停在那里，再换乘公共交通进城。欧洲很多城市（如牛津、剑桥、爱丁堡）有这个系统，大大缓解市中心交通压力，对游客非常实用。'},
  {c:'出国',q:'在欧洲乘火车，"Open ticket"（开放票）和"Fixed ticket"（固定票）哪个更灵活？',o:['固定票更灵活，因为你已经有了确定的座位','开放票（或Flex票）更灵活，可以乘坐当天或某日期内的任意一班次，但通常价格更贵；固定票只能乘坐特定时间的特定班次','两者灵活性完全相同','欧洲火车只有固定票，没有开放票'],a:1,e:'Open/Flex ticket=弹性票，可以在有效期内乘任意班次，适合行程不固定的旅客，价格较贵。Fixed ticket=固定时间票，只能坐特定班次，价格便宜很多但无法更改。提前确定行程买fixed ticket最划算！'},
  {c:'出国',q:'在美国，"HOV lane"（高承载车道）需要什么条件才能使用？',o:['支付额外通行费','车内乘客人数达到规定数量（通常2人以上或3人以上）才能使用，单人驾驶禁止进入','拥有特定车牌','仅允许出租车和公共巴士使用'],a:1,e:'HOV（High Occupancy Vehicle）Lane=高承载车道（也叫Carpool Lane）。规定车内必须有特定人数（通常2+或3+人），以鼓励拼车出行。部分HOV车道允许电动车单人使用。单人驾驶进入HOV车道会被罚款。'},
  {c:'出国',q:'"Coach"在英国的交通语境中通常指什么？',o:['马车（历史用词）','长途大巴车（类似中国的高速客运巴士），与市内公交Bus区分使用','火车的餐车厢','一种小型私人轿车'],a:1,e:'在英国，Coach=长途大巴（Intercity bus），如National Express、Megabus。Bus=市内公共汽车（City bus）。乘坐Coach需要提前预订座位，类似坐火车，适合在城市间经济出行。Coach站和火车站有时在同一地点（Victoria Station in London）。'},
  {c:'出国',q:'你在德国租车，看到"Autobahn"（高速公路）上某些路段没有速度限制，这是否意味着可以无限制飙车？',o:['是的，完全无限制，可以随意开多快','德国Autobahn部分路段确实没有法定最高速度，但有推荐速度（130km/h），且在坏天气、交通拥堵等情况下必须减速；超速行驶若发生事故，驾驶者需承担更大法律责任','整条Autobahn全程都无限速','只有德国人驾驶证才能在无限速段行驶'],a:1,e:'德国Autobahn约30%的路段没有强制限速（Keine Geschwindigkeitsbegrenzung），但推荐速度为130km/h。重要！：雨天、雾天或施工区域有临时限速；无限速不代表无责任，发生超速相关事故承担更多法律责任；且近年来越来越多路段设定了限速，出行前留意实时标志。'},
  {c:'出国',q:'"Scenic route"（风景路线）和"Fastest route"（最快路线）在驾车导航中有什么区别？',o:['风景路线更安全，最快路线更危险','风景路线绕道经过自然风光或名胜景点，路程更长但体验更佳；最快路线通常是直线高速公路，省时但可能错过沿途美景','导航软件中这两个选项是一样的','风景路线只适用于骑行，不适用于驾车'],a:1,e:'自驾旅行中"走Scenic Route"是一种享受旅途的态度。著名的风景驾车路线：美国一号公路（Pacific Coast Highway）、新西兰皇后镇公路、挪威峡湾路（Fjord Road）、苏格兰北部500英里（NC500）。不赶时间时，选择风景路线往往是旅途中最美好的部分！'},
  {c:'出国',q:'在东南亚（如泰国、越南），"Tuk-tuk"是什么交通工具？',o:['一种传统帆船','三轮摩托出租车，是当地特色交通工具','双层观光巴士','一种水上摩托艇'],a:1,e:'Tuk-tuk=三轮摩托出租车，是东南亚（泰国曼谷、印度、斯里兰卡等）的标志性交通工具。上车前务必谈好价格（或要求使用计价器），是体验当地文化的有趣方式，但注意防骗——有些司机会绕路或带你去合作商店。'},
  {c:'出国',q:'你在荷兰阿姆斯特丹旅游，当地人推荐你骑自行车游览，需要注意什么？',o:['荷兰禁止游客骑自行车','荷兰有专用自行车道（Fietspad），自行车拥有路权，但要遵守交通规则、走自行车道、不闯红灯；小心行人和其他自行车，别在自行车道上行走（非常危险）','荷兰自行车是单向通行的','游客租自行车需要荷兰驾照'],a:1,e:'阿姆斯特丹是全球最自行车友好的城市，有超过800公里的自行车道。注意：自行车道（红色路面或Fietspad标志）优先；不要走在自行车道上（当地人会生气地按铃）；停车要锁好（自行车失窃率很高）。租车推荐MacBike或Star Bikes等知名租车店。'},
  {c:'出国',q:'在美国，"Toll road"（收费公路）通常如何支付费用？',o:['只能在出发前在网上支付','可以在收费站投硬币（Cash）、使用E-ZPass等电子通行卡，或通过车牌识别（License plate billing）事后网络支付','只接受信用卡支付','全程免费，"Toll"是装饰标志'],a:1,e:'美国收费公路付费方式：①Cash（投硬币/纸币）—传统方式但很多已取消②E-ZPass / SunPass等电子通行证（ETC）—快速无须停车③免费通道（Open Road Tolling）—车牌识别系统，事后通过邮件账单或网上支付。租车时询问是否有E-ZPass，避免收费公路麻烦。'}
);

// ──────────────────────────────────────────────────────────────
// 【4】购物砍价英语 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_SHOPPING.push(
  {c:'出国',q:'你在美国超市，结账时收银员问"Paper or plastic bag? That\'ll be 10 cents."，这说明？',o:['所有包装都免费提供','购物袋需要收费（无论纸袋还是塑料袋），这是很多美国城市/州的环保政策','10美分是额外的包装服务费','这家超市是私人收费','这只是一个建议，可以拒绝'],a:1,e:'很多美国城市（加州、纽约等）和欧洲国家对一次性购物袋收费，以减少塑料污染。建议出行时自带一个可折叠的购物袋（Reusable bag / Tote bag），既环保又省钱。'},
  {c:'出国',q:'"Consignment shop"（寄卖店）和普通二手商店有什么区别？',o:['寄卖店只卖新品，二手商店卖旧货','寄卖店是原物主委托店铺代卖，售出后双方分成（通常40-60%给原主）；二手店是店铺直接买断再出售','寄卖店比二手商店更便宜','两者完全相同'],a:1,e:'Consignment shop=寄卖店：货主把物品交给店铺代卖，卖出后货主和店铺按比例分钱，卖不出去退还货主。比如The RealReal（奢侈品寄卖）。Thrift store（二手店）=商店直接买断旧物，价格更低。二手购物在欧美是主流文化的一部分！'},
  {c:'出国',q:'在美国，"Black Friday"（黑色星期五）是什么？',o:['美国的全国哀悼日，商店不营业','感恩节后的第一个星期五，是美国一年中打折力度最大的购物节，很多商家提供30-70%的折扣','专门出售黑色服装的促销活动','每月最后一个星期五的固定打折日'],a:1,e:'Black Friday（黑色星期五）是美国感恩节后的传统大促，每年11月最后一个星期五。历史上人们天不亮排队等候开门，现在已蔓延到网上购物（Cyber Monday=周一网络促销）。这一传统已传播到全球多个国家。'},
  {c:'出国',q:'在奢侈品店，"Duty free"和"Tax refund"有什么区别？',o:['两者是同一回事，只是叫法不同','Duty free=在机场免税区销售（商品本身就不含税）；Tax refund=在普通店铺购物后凭小票在出境时申请退税，两个概念不同','Tax refund只适用于欧洲','Duty free商品不能出境'],a:1,e:'区别很重要：Duty Free（免税店）=商品直接免税销售，主要在机场内；Tax Refund（退税）=在免税店以外的普通商店购物，含税购买，离境时凭单据在机场退税窗口拿回部分税款。后者需要保留小票和退税单。'},
  {c:'出国',q:'你在商场看到"3 for 2"的标签，这是什么促销方式？',o:['买3件只需付1件的价格','买3件只需付2件的价格（第3件免费）','每件商品打3折','买2件送1件赠品'],a:1,e:'"3 for 2"=买3付2（第3件最低价那件免费）。类似的：BOGOF（Buy One Get One Free）=买一送一；2 for 1=花1件的钱买2件；BOGO 50% off=买一件第二件半价。注意看清楚条款！'},
  {c:'出国',q:'在英国，"Primark"类型的店铺以什么著名？',o:['售卖英国皇室御用奢侈品','以极低价格出售快时尚服装，不提供网上购物服务','专售高质量环保有机服装','英国最大的奢侈品寄卖店'],a:1,e:'Primark是爱尔兰起源的快时尚连锁，以极低价格著名（T恤2英镑，牛仔裤10英镑），没有网上商店（只能去实体店购物）。伦敦牛津街的Primark旗舰店是全球最大的Primark店之一，是很多旅客的购物首选！'},
  {c:'出国',q:'你在跳蚤市场，发现一件标价$50的古董，你认为值$30，你开始砍价的合理出价是？',o:['直接还$30（目标价）','出$20-25（比目标价低一些），给双方留下协商空间','出$1，看看卖家反应','直接说"这不值$50，最多$30"'],a:1,e:'砍价策略：出低于心理价格的价格，留出协商空间。如果心理价格$30，先出$20-25，经过来回协商双方在$28-32左右成交。出太低（$1）显得不真诚；直接说最高价会失去谈判筹码。微笑、友好、坚持是砍价三要素！'},
  {c:'出国',q:'在超市，"Self-checkout"（自助结账）通道适合什么情况使用？',o:['购买大量商品时，因为机器更快','购买商品较少（通常标有"15 items or fewer"）、或需要快速结账时；操作：扫条形码→放秤台→付款（刷卡/手机）','只适合会英语的旅客','自助通道只接受现金'],a:1,e:'Self-checkout（自助结账）=自己扫描商品、自己付款的通道，适合商品少的快速结账。不熟悉操作时：①扫描条形码②放到称重区（不要移走）③选择付款方式④如有疑问按"Help"键叫店员协助。部分商品（酒类）需要店员验证年龄。'},
  {c:'出国',q:'在国外商店，导购主动热情地向你介绍商品，你想礼貌地表示不需要帮助，应该说什么？',o:['请离我远点，我不需要你的帮助','Thank you, I\'m just browsing / I\'m just looking around. I\'ll let you know if I need help.（谢谢，我只是随便看看，需要时我会找你的）','我不买任何东西','我不说英语'],a:1,e:'"I\'m just browsing"或"I\'m just looking around"=我只是随便逛逛看看，是礼貌拒绝导购跟随的标准说法。加上"I\'ll let you know if I need anything"（如果需要我会告诉你）更完整有礼。这句话之后导购通常就会给你私人空间了。'},
  {c:'出国',q:'"Buy online, pick up in store"（BOPIS）是什么购物方式？',o:['在实体店买货，快递到家','在网上下单付款，直接去实体店取货（节省运费，且可以当天取到）','先在店里试穿，再回家网上订购','只支持会员使用的服务'],a:1,e:'BOPIS（Buy Online Pick Up In Store）=网购店取，是零售业的热门服务。优点：①节省运费②可当天取货（比快递快）③可以在店内当场检查商品是否满意，不满意直接退换。在Target、Best Buy等美国大型零售商非常普遍。'},
  {c:'出国',q:'在国外，信用卡被刷卡机提示"Declined"（被拒绝），最可能的原因是？',o:['这个国家不接受外国信用卡','可能是银行的海外交易安全拦截（未提前通知银行出行）、额度不足、磁条损坏或芯片问题','你的信用卡已过期并且你不知道','商家系统出现故障'],a:1,e:'信用卡在国外被拒原因：①未提前告知银行出行，被系统误判为欺诈交易→解决：出行前致电银行开通境外消费②额度不足③磁条/芯片损坏→换一张卡试试④商家POS机故障。建议出行时带两张不同银行的卡！'},
  {c:'出国',q:'在美国，商品标签价格和最终结账价格可能不同，这是因为？',o:['美国商家喜欢在最后时刻涨价','美国大多数州的价格标签不含销售税（Sales Tax），结账时才加上税金（通常4-10%不等）','标价是批发价，零售价需要加价','这是一种促销套路'],a:1,e:'美国Sales Tax（销售税）=类似增值税，但通常不在标签价格中显示，结账时才加上。各州税率不同：俄勒冈州、蒙大拿州等无销售税；纽约市合计约8.875%；加州最高可达10.25%。这是外国旅客常常没预料到的价格差。'},
  {c:'出国',q:'你买了一件衣服，洗标（Care label）上标有"Dry clean only"，意思是？',o:['只能用干布擦拭','只能送专业干洗店清洁，不能水洗（否则可能缩水、变形或褪色）','可以用冷水手洗','可以机洗但要用冷水模式'],a:1,e:'"Dry clean only"=只能干洗，禁止水洗。常见洗标符号：①圆圈=干洗②波浪桶=水洗③三角形=漂白④正方形=烘干⑤熨斗=熨烫。出国买了高档服装，回国后记得按洗标护理，否则可能毁掉一件昂贵的衣服！'},
  {c:'出国',q:'在奢侈品店购买高档手袋，导购说"This comes with a Certificate of Authenticity."，这意味着？',o:['这个包是仿制品，所以需要证明真实性','这个包附有正品保证书，证明是品牌正品，有助于日后转售保值','这个证书可以用来申请保险','持有证书可以享受终身维修服务'],a:1,e:'Certificate of Authenticity（正品证书/真品证书）=证明商品是正品的官方文件，常见于奢侈品（包、手表、珠宝）购买时附带。对于日后转售（Resale）非常重要，有证书的二手奢侈品价格更高。购买奢侈品时要保存好所有包装、证书和收据。'}
);

// ──────────────────────────────────────────────────────────────
// 【5】餐厅点餐英语 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_RESTAURANT.push(
  {c:'出国',q:'在美国，"Brunch"是什么？通常在几点供应？',o:['午餐和晚餐之间的加餐（下午3点左右）','介于早餐（Breakfast）和午餐（Lunch）之间的一餐，通常在上午10点至下午2点供应，周末最为流行','一种特殊的早餐套餐','只在特定节假日供应'],a:1,e:'Brunch（早午餐）=Breakfast+Lunch的合成词，是周末的重要社交活动。常见Brunch食物：Eggs Benedict（班尼迪克蛋）、Avocado Toast（牛油果吐司）、Pancakes（松饼）、Mimosa（香槟橙汁鸡尾酒）。"Let\'s do brunch on Sunday!"是美式周末邀约的经典方式。'},
  {c:'出国',q:'服务员说"The kitchen is closing in 20 minutes."，你应该？',o:['悠闲地继续看菜单，不用着急','尽快决定并下单，因为20分钟后厨房将停止接受点单','立刻结账离开','询问厨房为什么要关闭'],a:1,e:'"The kitchen is closing"=厨房即将停止接受订单（但餐厅可能还在营业，饮料仍可点）。这与餐厅关门不同！听到这句话要立刻决定是否点餐，否则只能喝酒水了。Last orders!是另一种常见说法，在英国pub里尤其常见。'},
  {c:'出国',q:'菜单上"Antipasto"（意大利语）是一道什么类型的菜？',o:['意大利的甜点','前菜/开胃拼盘（通常包括腌肉、奶酪、橄榄等），在正式意大利餐前供应','意大利的主食（面食类）','一种意大利酱汁'],a:1,e:'Antipasto=意大利餐的前菜（字面意思是"面食之前"），通常是冷盘拼盘：Prosciutto（意式火腿）、Bruschetta（烤面包片）、Olives（橄榄）、Mozzarella（马苏里拉）等。正式意大利大餐顺序：Antipasto→Primo（面食/汤）→Secondo（主菜肉类）→Dolce（甜点）→Caffè（咖啡）。'},
  {c:'出国',q:'在法国餐厅，你点了"Crème brûlée"，端上来是什么？',o:['一种法式薄饼','一种焦糖脆皮奶冻（法式烤布蕾），是法国经典甜点','一种法式炖菜','一种法式浓汤'],a:1,e:'Crème brûlée（法语，发音：krem bru-LEY）=法式焦糖布丁：底层是香草奶冻，表面撒上一层糖，用火枪或烤炉将糖烤成脆焦糖壳。用勺子敲破焦糖壳的那一刻是法式甜点的经典仪式感！'},
  {c:'出国',q:'"Farm-to-table"餐厅有什么特点？',o:['食材来自世界各地的农场，新鲜进口','食材直接来自本地农场，减少运输链，强调新鲜、当季和可持续农业','提供在农场里用餐的体验','只供应有机认证食材'],a:1,e:'"Farm-to-table"（农场直供）=餐厅直接从本地农场采购食材，去除中间商，强调本地、当季、新鲜。这一餐饮理念在美国、澳大利亚、欧洲日益流行，代表了对可持续食物系统的追求。菜单通常随季节变化。'},
  {c:'出国',q:'在日本料理中，"Omakase"是什么意思？',o:['日语中"自助餐"的意思','由厨师全权决定菜单（"交给您了"），客人不点菜，享受厨师当日最佳食材和创意的精致料理体验','一种特定的日本传统套餐形式','只在午餐供应的特惠套餐'],a:1,e:'Omakase（お任せ）=日语"交给您了/随您决定"，是一种高端日本料理体验，完全由厨师根据当天最好的食材决定菜单。通常是寿司店的最高规格用餐方式，价格较高但体验独特。须提前预约，并告知过敏或饮食限制。'},
  {c:'出国',q:'你在餐厅对服务员说"Can you box this up for me?"，你的意思是？',o:['请给我换一个干净的餐盒盛饭','请帮我把剩余的食物打包带走','请把我的餐点装进一个礼盒','请帮我叫一辆外卖配送'],a:1,e:'"Box this up"=把剩余食物装盒打包带走（与"Can I get a box?"或"Doggy bag"意思相同）。在美国打包剩菜是非常普遍和被接受的行为。在日本或部分欧洲国家，打包文化不那么普遍，但也越来越被接受。'},
  {c:'出国',q:'在美国餐厅，服务员问"Do you need change?"（需要找零吗），如果你说"No, keep it."，意味着什么？',o:['你表示不想继续用餐了','你让服务员保留零钱作为小费（这是给小费的常见方式之一）','你拒绝结账','你表示价格有问题'],a:1,e:'"Keep the change"（找零不用了/零钱给你）是美国给小费（Tip）的一种常见方式。例如账单$18，你给$20，说"Keep the change"，即给了$2小费。另一种常见方式是在信用卡收据上的"Tip"栏填写金额。'},
  {c:'出国',q:'在菜单上看到"Locally sourced ingredients"（本地食材），这说明？',o:['这家餐厅只雇用本地员工','食材来自餐厅所在地的周边地区，更新鲜、支持本地农业、碳排放更低','这家餐厅禁止使用进口调料','所有食材都是有机认证的'],a:1,e:'Locally sourced（本地采购）=食材来自餐厅周边一定范围内（通常100-200公里）的农场或供应商。好处：更新鲜（运输时间短）、支持当地经济、减少运输碳排放、菜单跟随当地季节变化。这是现代餐饮的重要趋势。'},
  {c:'出国',q:'在英国酒吧（Pub），"Last orders!"是什么信号？',o:['最后一轮赠饮，免费！','酒吧即将停止接受新订单（通常是打烊前约20分钟），这是你最后一次点酒的机会','客人被要求离开','酒吧推出了限时特供酒'],a:1,e:'"Last orders!"（最后点单！）是英国酒吧打烊前的传统广播，通常在打烊前20-30分钟。在酒吧结束时，酒保还会喊"Time, please!"或"Finish your drinks!"表示营业时间结束，需要把手中的酒喝完并离开。'},
  {c:'出国',q:'在餐厅点餐时，"On the side"是什么意思？',o:['请靠窗边的座位用餐','将配菜或酱汁单独放在旁边的小碟里，不混合在主菜中','只点一种菜','站在桌旁用餐'],a:1,e:'"On the side"=单独放在旁边。"I\'d like the dressing on the side."（沙拉酱请单独放）是沙拉点单时常见说法，让你自行控制酱的用量。"Can I have the sauce on the side?"同理——不要把酱淋在菜上，单独盛放。'},
  {c:'出国',q:'在泰国街头，摊贩问"Spicy or not spicy?"，如果你不太能吃辣，最好说什么？',o:['Spicy!（辣的）','Not spicy please, or just a little.（不辣/微辣）','Very spicy!（非常辣）','Same as usual.（和平常一样）'],a:1,e:'泰国料理的辣度通常远超中国标准！如果点了spicy往往真的很辣。不能吃辣：说"Mai phet"（泰语"不辣"）或"Not spicy please"。微辣："A little spicy"。泰餐的辣椒是真正的辣椒，不是中国的红油，量要谨慎！'},
  {c:'出国',q:'在西班牙，"Tapas"和"Pintxos"有什么区别？',o:['两者完全相同，只是不同地区的叫法','两者都是西班牙小食，Tapas主要在安达卢西亚和全国流行；Pintxos（或Pinchos）是巴斯克地区的特色，通常是把各种食材插在面包片上用牙签固定','Pintxos比Tapas更贵','Tapas是冷食，Pintxos是热食'],a:1,e:'Pintxos（发音：PEEN-chos）是巴斯克地区（Bilbao, San Sebastián）的特色小食，通常把丰富食材放在一片面包（baguette）上，用牙签固定。有时按牙签数量结账（每根牙签代表一份Pintxo）。San Sebastián是西班牙米其林星餐厅密度最高的城市！'},
  {c:'出国',q:'你在意大利点了"Risotto"，端上来是什么？',o:['一种意大利面条','用特殊短粒米（如Arborio米）慢慢搅拌烹制的意大利奶油炖饭，质地浓稠细腻','一种意大利薄饼（类似Pizza）','一种意大利炸饭团'],a:1,e:'Risotto（意式烩饭）是以高淀粉含量的Arborio米为原料，用高汤（broth）一勺一勺慢慢加入翻炒，直到米粒吸收汤汁并释放淀粉，形成浓郁奶滑的质地。经典款有：Risotto ai funghi（菌菇）、Risotto alla Milanese（藏红花）。'}
);

// ──────────────────────────────────────────────────────────────
// 【6】紧急情况英语 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_EMERGENCY.push(
  {c:'出国',q:'你在国外遭遇突发洪水，当地政府发布"Evacuation order"（撤离令），你应该？',o:['留在原地等洪水退去','立刻按指定路线撤离，不要返回取财物，前往指定避难中心（Evacuation shelter）','搬到更高楼层等待救援','拒绝撤离，保护自己的财产'],a:1,e:'"Evacuation order"=强制撤离令，必须立刻执行。撤离要点：①不要返回取财物，生命第一②带上护照、手机、药品等最关键物品③按指定路线走（避开洪水区）④前往政府指定的避难场所（Evacuation center / Emergency shelter）⑤到达后登记，方便家人联络。'},
  {c:'出国',q:'你在国外突发急性阑尾炎，需要紧急手术，但语言不通，最应该告知医生哪个部位的疼痛？',o:['用手指向喉咙','用手指向腹部右下方——这是阑尾的位置；说"I have severe pain in my lower right abdomen"（我右下腹剧烈疼痛）','指向心脏位置','指向整个腹部'],a:1,e:'阑尾（Appendix）位于右下腹（lower right abdomen）。急性阑尾炎（Appendicitis）的典型症状：右下腹持续剧痛、发烧、恶心。这是医疗急症，需要立刻就医。记住身体部位的英语表达：Abdomen（腹部）、Chest（胸部）、Lower back（腰部）、Shoulder（肩膀）。'},
  {c:'出国',q:'你的旅行证件在国外被小偷偷走，在联系中国大使馆之前，哪个步骤最应该先做？',o:['立刻购买回国机票','向当地警察报案并取得报案证明（Police Report / Crime Report Number）','给家人打电话','联系旅行社'],a:1,e:'护照失窃处理顺序：①向当地警察报案，取得报案证明（Police Report）——中国大使馆申请临时证件需要这份文件②联系中国大使馆或领事馆（提供：照片、身份证明材料、报案证明）③联系家人告知情况④联系旅行保险公司。报案证明是后续所有申请的基础文件！'},
  {c:'出国',q:'在海外，你突然感到胸口剧痛、左臂麻木，这可能是什么紧急情况，应该怎么做？',o:['可能是肌肉拉伤，休息一下就好','可能是心脏病发作（Heart attack）的典型症状，应立刻拨打急救电话，不要自行驾车前往医院','可能是消化不良，服用胃药观察','可能是脱水，多喝水即可'],a:1,e:'心脏病发作（Heart attack）典型症状：胸口压迫感/剧痛（Chest pain/pressure）、左臂或下颌放射痛、出汗、恶心、呼吸困难。处理：立刻拨打120/999/911，让患者坐下休息（不要让其站立或移动），如有阿司匹林且患者不过敏，给服1片。每分钟都是黄金时间！'},
  {c:'出国',q:'你在街上目睹一场暴力事件，最安全的做法是什么？',o:['立刻冲上去制止暴力行为','迅速离开现场到安全距离，拨打当地警察电话（不要自己介入，这可能使自己陷入危险），描述暴力事件的位置、人数和情况','大声呼救吸引人群围观','录像后发到社交媒体'],a:1,e:'遭遇暴力事件：自身安全第一，不要贸然干预！正确步骤：①快速远离现场到安全地点②拨打110/999/911报警③如实描述：地点（准确地址或附近地标）、涉事人数、是否有武器、是否有人受伤。不要让自己成为第二个受害者。'},
  {c:'出国',q:'你在山区徒步时迷路，手机信号极弱，这时最应该做什么？',o:['继续往前走，寻找下山路','停在原地等待救援（如已激活紧急卫星通讯功能则发出求救信号），节约体力和物资，保持可见性（使用口哨、反光物等），有信号时立刻联系救援','攀登到最高点寻找手机信号','在原地生火等待飞机发现'],a:1,e:'山野迷路生存原则："STOP"法：Stop（停下不乱跑）、Think（冷静思考）、Observe（观察环境、判断方向）、Plan（制定行动）。保存体力，留在原地更容易被救援发现；发出求救信号：三声口哨（国际求救信号）、反光镜或手电筒、布置SOS字样；保存手机电量等待信号。'},
  {c:'出国',q:'在泰国旅游时，你被海边行驶的快艇螺旋桨割伤，出血较严重，最紧急的处置是什么？',o:['立刻游回岸上再处理','用手或干净布料用力按压伤口止血（Direct pressure），在手边可用材料包扎，立即寻求医疗救助','用海水冲洗伤口（海水含细菌，实际上不建议）','喝大量水防止失血性休克'],a:1,e:'严重出血急救：用力直接压迫（Direct Pressure）是最重要的止血措施——用干净布料（如衣物）压住伤口，持续用力至少10分钟不松开。若包扎后血液渗出，在原来的敷料上继续加压包扎，不要取下原有敷料。同时立刻呼救/叫人拨打急救电话。'},
  {c:'出国',q:'"SOS"信号的三种常见发出方式分别是什么？',o:['大声呼喊、挥舞手臂、发短信','三短三长三短的声音（口哨/敲击）、三短三长三短的光信号（手电筒/镜子反光）、在地面用石头或树枝摆出"SOS"字样','拨打112、发邮件、发社交媒体求救','连续大喊三声、烧三堆火（三堆火是求救信号！）、做十字架标志'],a:1,e:'SOS（···---···）是国际通用求救信号（摩尔斯电码）。三种发出方式：①声音：三短三长三短（口哨/敲击）②视觉：三短三长三短闪光，或镜面/反光物向空中/远处闪光③地面：用石块、树枝、衣物摆出大型"SOS"字样（便于飞机发现）。烧三堆火（三角形排列）也是国际求救信号。'},
  {c:'出国',q:'你的旅行保险有"Emergency Medical Evacuation"（紧急医疗转运）保障，什么情况下会用到？',o:['当你需要乘坐飞机回国时的普通机票费用','当你在当地医疗条件不足以治疗病情时，保险公司安排专用医疗飞机或其他方式将你转运到可以接受适当治疗的地方（如转回国内）','当你旅行途中想临时提前回国','所有医疗费用都包含在内'],a:1,e:'紧急医疗转运（Emergency Medical Evacuation）=在当地医院无法处理的危重情况下，保险公司安排专业医疗飞机（带医护人员和医疗设备）将你转运到合适的医院。费用极高（可达数十万美元），这是旅行保险最重要的保障之一！尤其前往医疗设施落后地区时必备。'},
  {c:'出国',q:'在东南亚旅行，突遇海啸预警，你在海滩上，应该立刻做什么？',o:['留在海边观察海浪','立刻向内陆高地跑（越快越远越好），不要驻足拍照；注意：如果看到海水突然退潮（海水大量后退）是海啸前兆，这是最后的逃跑时机','游向海里避免被海浪卷走','待在酒店房间里等待广播'],a:1,e:'海啸逃生：海水突然大量后退（异常退潮）是最重要的海啸前兆，此时须立刻逃往高地（Evacuate to higher ground），不要驻足观看！向距海岸至少1-2公里的内陆或30米以上高地撤离。跑向高处，远离海岸线、河道和低洼地带。海啸波可以多次涌来，第一波退去后不可立刻返回。'},
  {c:'出国',q:'在欧洲旅行，出现高烧（38.5°C以上）并伴有颈项僵硬和畏光，最可能是什么情况，应该如何处理？',o:['这是普通感冒，买退烧药即可','这可能是细菌性脑膜炎（Bacterial meningitis）的症状，是危及生命的急症，须立刻拨打急救电话或前往急诊','这可能是高原反应，下山就好','这是普通中暑，补充水分即可'],a:1,e:'细菌性脑膜炎（Bacterial Meningitis）症状：高烧、剧烈头痛、颈项僵硬（不能低头）、畏光、身上可能出现不褪色的红色皮疹（脑膜炎球菌败血症特征）。这是医疗紧急情况，致死率高，必须立刻就医！脑膜炎的皮疹测试：用玻璃杯压住皮疹，不褪色则高度危险。'},
  {c:'出国',q:'在酒店发生火灾时，为什么不应该使用电梯（Elevator）逃生？',o:['电梯太慢，浪费时间','火灾中电梯可能因停电或火势影响而关闭，将人困在里面；电梯井道也可能成为烟雾快速扩散的通道','这只是一个建议，不是强制规定','老人和残障人士可以使用电梯'],a:1,e:'火灾中禁止使用电梯的原因：①电梯可能因停电失控，将人困在电梯间内②电梯井是烟雾和热气的扩散通道，打开电梯门时可能受到伤害③消防电梯（Firefighter\'s lift）是预留给消防员使用的。正确做法：走消防楼梯（Emergency Stairwell），低姿前进，避开烟雾。'},
  {c:'出国',q:'你在海外被抢劫时，歹徒要求交出钱包，面对此情况最安全的做法是？',o:['拼命抵抗，保护财物','冷静配合，交出财物，保留人身安全——财物可以补，命只有一条；事后尽快前往安全区域报警','大声呼救吸引人群来帮助','逃跑，让歹徒无法得逞'],a:1,e:'遭遇抢劫的生存原则：不要抵抗！财物可以补，受伤可能无法弥补。建议：①保持冷静②交出财物时缓慢动作③不要直视歹徒眼睛（被认为是挑衅）④歹徒离开后立刻前往安全区域（商店、酒店）⑤拨打报警电话。出行时建议带少量现金，大额现金和贵重物品锁在酒店保险箱。'},
  {c:'出国',q:'你在旅途中发现旅伴出现疑似"中暑"（Heat stroke）症状：体温极高、皮肤热而干燥、神志不清，应该如何处置？',o:['让他喝冰水，静卧休息','这是医疗急症！立刻拨打急救电话；将伤者移到阴凉处、脱去多余衣物、用冷水或冰块降温（颈部、腋下、腹股沟）、用湿布擦拭皮肤，等待医疗救援','让他继续走动以出汗散热','给他服用退烧药'],a:1,e:'中暑（Heat Stroke，非Heat Exhaustion热衰竭）=医疗急症！特点：体温>40°C、皮肤热而干燥（不出汗）、神志混乱。处置：①立刻急救并叫救护车②快速降温是关键：移至阴凉处、冷水浸湿衣物、冰袋置于颈腋腹股沟③不要让其独处④给清醒的人补充水分（不清醒的人不要喂水）。'},
  {c:'出国',q:'在国外药店购买药品，"Prescription only"（处方药）和"OTC"有什么区别？',o:['处方药比OTC药更便宜','处方药需要医生开具处方才能购买（用于治疗严重疾病）；OTC（Over The Counter，非处方药）无需处方可直接购买（用于轻微症状）','OTC药效果更强，处方药更温和','处方药可以自行在网上购买'],a:1,e:'关键区别：Prescription Drug（处方药）=须医生开处方，用于严重或复杂病症（抗生素、强效止痛药等）。OTC Drug（非处方药）=可直接购买，用于轻微症状（头痛药、感冒药、消化药等）。如果需要处方药，在海外须先看医生（可去诊所/急诊）获取处方。出行时最好带上国内常用药品。'}
);

// ──────────────────────────────────────────────────────────────
// 【7】亚洲热门目的地 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_ASIA.push(
  {c:'旅游',q:'印度尼西亚巴厘岛最著名的"乌布"（Ubud）以什么著名？',o:['以海滩度假著名，是冲浪胜地','以艺术文化、传统舞蹈、梯田景观和冥想养生（Wellness）著名，被称为巴厘岛的文化心脏','以购物中心和现代都市著名','以赌场和夜生活著名'],a:1,e:'Ubud（乌布）=巴厘岛内陆的文化艺术中心。著名景点：Tegalalang梯田（UNESCO景观）、Monkey Forest（猴子森林）、传统巴厘舞蹈（Kecak fire dance）、各种瑜伽和冥想中心。与巴厘岛海滩度假区（Seminyak, Nusa Dua）形成鲜明对比。'},
  {c:'旅游',q:'前往缅甸（Myanmar/Burma），"蒲甘"（Bagan）以什么著名？',o:['以现代城市建筑和购物著名','以平原上数以千计的古代佛塔（Pagoda）群著名，气球观光是热门体验','以热带雨林和野生动物著名','以海边白沙滩著名'],a:1,e:'Bagan（蒲甘）是缅甸最著名的旅游目的地，伊洛瓦底江平原上分布着超过2000座古佛塔（建于11-13世纪）。乘坐热气球（Hot air balloon）俯瞰佛塔群是许多旅客的梦想体验，通常在11月至2月（旱季）进行。'},
  {c:'旅游',q:'老挝的"琅勃拉邦"（Luang Prabang）最著名的清晨景象是什么？',o:['世界上最大的早市','每天清晨僧侣沿街化缘（Alms Giving Ceremony，布施仪式），信众跪在路边捐献糯米饭等食物','清晨的湄公河日出船游','每天举行的传统舞蹈表演'],a:1,e:'布施仪式（Tak Bat）是琅勃拉邦最著名的文化景象，每天日出前约5-6点，数百名穿橘红色袈裟的僧侣列队沿街化缘，信众虔诚地双膝跪地奉上糯米饭和食物。参观时须保持距离和安静，不要打闪光灯，尊重这一神圣仪式。'},
  {c:'旅游',q:'"Great Wall of China"（中国长城）中，哪个地段是最受外国游客欢迎的？',o:['嘉峪关（最西端终点）','慕田峪（Mutianyu）和八达岭（Badaling），两者都在北京附近，距市区约1-2小时','山海关（最东端起点）','西安段长城'],a:1,e:'慕田峪长城（Mutianyu）被很多旅行者评为最佳体验地：保存完好、游客相对少于八达岭（Badaling）、有缆车（Cable Car）和滑道（Toboggan）、景色优美。八达岭是国家重点开放段，基础设施最好但游客最多。'},
  {c:'旅游',q:'中国西藏（Tibet）的"布达拉宫"（Potala Palace）有什么历史意义？',o:['是中国最大的佛教寺庙','曾是历代达赖喇嘛的冬宫（Winter Palace），海拔3700米，是世界上最高的宫殿建筑群之一，已被列为UNESCO世界遗产','是清朝皇帝的行宫','是现任班禅喇嘛的居所'],a:1,e:'布达拉宫（Potala Palace）建于7世纪（现建筑主体建于17世纪），是历代达赖喇嘛的居所和西藏政治中心。如今作为博物馆开放，需提前预约（每日限制参观人数）。进入西藏须办理西藏旅行许可证（Tibet Travel Permit）。'},
  {c:'旅游',q:'日本"奈良"（Nara）以什么特别著名？',o:['全球最大的海洋水族馆','公园里的鹿可以自由行走，接受游客喂食（用官方鹿饼），鹿在奈良是神圣动物','世界最密集的地铁系统','全日本最高的摩天大楼'],a:1,e:'奈良公园里约有1200只自由奔跑的鹿，被视为神灵使者（神鹿）。游客可购买"鹿饼"（Shika-senbei）喂食，但鹿非常聪明，如果你有吃的它们会主动接近！参观东大寺（Todai-ji）是奈良的必游项目——其大佛（Daibutsu）是日本最大的铜铸佛像。'},
  {c:'旅游',q:'印度"斋浦尔"（Jaipur）被称为"粉红之城"（Pink City），这个颜色有什么历史背景？',o:['斋浦尔的土壤是粉红色的，使建筑呈现粉色','1876年为迎接英国威尔士亲王访问，国王下令将城市建筑涂成粉色（代表热情好客），这一传统延续至今','斋浦尔的砂岩本来就是粉色的','这是一种营销噱头，实际上城市并不是粉色的'],a:1,e:'斋浦尔（Jaipur）=拉贾斯坦邦首府，1876年为欢迎英国威尔士亲王（后来的爱德华七世），摩诃拉贾下令将旧城建筑涂成代表热情好客的玫瑰粉色，此后成为传统。风之宫殿（Hawa Mahal）和城市宫殿（City Palace）是必游景点。'},
  {c:'旅游',q:'斯里兰卡"高跷渔夫"最常见于哪个城市附近？',o:['科伦坡（Colombo，首都）','高勒（Galle）和科加拉（Koggala）附近的海岸','康提（Kandy）佛牙寺附近','亚拉国家公园附近'],a:1,e:'高跷渔夫（Stilt Fishermen）是斯里兰卡南部海岸（高勒附近）的标志性文化景象：渔民坐在插入浅水中的木桩上钓鱼，是传统捕鱼方式。注意：现在很多高跷渔夫是为游客表演收费拍照，真正传统意义上的渔业捕鱼已减少。'},
  {c:'旅游',q:'泰国清迈（Chiang Mai）最著名的传统手工艺是什么？',o:['以机器纺织的现代面料著名','以精美的手工艺品著名，包括伞（Umbrella）制作、漆器（Lacquerware）、银饰（Silverware）和丝绸织造（Silk weaving）','以高科技电子产品制造著名','以玻璃吹制工艺著名'],a:1,e:'清迈（Chiang Mai）是泰国最重要的手工艺中心，周边有"手工艺品村"（Craft villages）：柏桑村（Bo Sang）以手绘伞著名；清迈古城附近的银匠村（Wualai Road）以银器著名；周末夜市（Weekend Night Bazaar）是购买手工艺品的最佳地点。'},
  {c:'旅游',q:'马尔代夫（Maldives）的旅游特色是什么？',o:['以丛林徒步和野生动物著名','以水上屋（Water Bungalow/Overwater Villa）、清澈珊瑚礁和奢华度假著名，同时面临气候变化海平面上升的威胁','以古代文明遗址著名','以高山滑雪度假著名'],a:1,e:'马尔代夫是印度洋上的岛国，以世界级的白沙滩、清澈碧蓝的海水、珊瑚礁潜水和著名的水上木屋（Overwater Bungalow）著称。平均海拔仅1.5米，是全球最受气候变化海平面上升威胁的国家之一。"One island, one resort"是马尔代夫独特的度假模式。'},
  {c:'旅游',q:'菲律宾巴拉望岛（Palawan）被多次评为世界最佳岛屿，以什么著名？',o:['以世界最大的赌场度假村著名','以地下河（Puerto Princesa Subterranean River，UNESCO世界遗产）、埃尔尼多（El Nido）的石灰岩岛屿和世界级的潜水胜地著名','以现代购物和美食著名','以火山景观和温泉著名'],a:1,e:'巴拉望岛（Palawan）被CNN Travel评为全球最佳岛屿之一。Puerto Princesa地下河是UNESCO世界遗产，全长超过8公里的地下河流穿过石灰岩洞穴。El Nido和科隆（Coron）以翡翠绿海水、岩礁潜水（尤其是二战沉船潜水）著名。'},
  {c:'旅游',q:'中国"九寨沟"（Jiuzhaigou）在四川省，以什么自然景观著名？',o:['以世界最大的温泉著名','以色彩斑斓的多层湖泊和瀑布著名（湖水因矿物质和藻类呈现翠绿、宝蓝、翡翠等颜色），是UNESCO世界遗产','以雪山攀登著名','以热带丛林和珍稀动物著名'],a:1,e:'九寨沟（Jiuzhaigou Valley）=藏语"九个藏族寨子的沟"，以海拔2000-3000米的多彩湖泊（Five Flower Lake五花海、Long Lake长海等）和瀑布著名。湖水颜色因矿物质、藻类和水深而异，呈现绝美色彩。秋天（9-10月）是最佳游览时间，枫叶倒映湖中极为壮美。'},
  {c:'旅游',q:'韩国济州岛（Jeju Island）最著名的自然景观是什么？',o:['以著名的海底温泉著名','以汉拿山（Hallasan，韩国最高峰）火山地貌和海女（Haenyeo）文化著名，已被列为UNESCO世界遗产','以世界最大的人工瀑布著名','以北极熊观测著名'],a:1,e:'济州岛（Jeju-do）是韩国最大的岛屿，独特之处：①汉拿山（Hallasan，1950米）是韩国最高峰，火山地貌②海女（Haenyeo）文化——潜水采集海鲜的中老年女性，已列入UNESCO非物质文化遗产③城山日出峰（Seongsan Ilchulbong）是壮观的火山口。'},
  {c:'旅游',q:'在越南旅行，"奥黛"（Áo Dài）是什么？',o:['越南传统美食（一种米粉汤）','越南传统服装，是一种修身长衫配宽腿裤，通常以丝绸制成，是越南的国服','越南传统乐器','越南传统建筑风格'],a:1,e:'Áo Dài（奥黛）=越南国服，是一种修身立领长衫，通常配白色宽腿裤（女款更为流行），常见于节庆、婚礼和学校制服。以丝绸、雪纺等面料制成，优雅飘逸。在会安（Hoi An）有很多店铺可以量身定制，是购买手信的热门选择！'},
  {c:'旅游',q:'"Trans-Siberian Railway"（西伯利亚大铁路）是指什么？',o:['中国西部的高速铁路网','连接莫斯科和俄罗斯远东（符拉迪沃斯托克）的世界最长铁路，全程约9258公里，穿越西伯利亚大陆','中亚地区的历史古丝绸之路铁路','连接北京和西伯利亚的高铁线路'],a:1,e:'西伯利亚大铁路（Trans-Siberian Railway）是世界上最长的铁路，全程约9258公里，从莫斯科到符拉迪沃斯托克（Vladivostok），横跨7个时区，全程约7天。有三条主要路线：①经典西伯利亚线②蒙古线（途经乌兰巴托）③满洲里线（途经中国东北）。是终极铁路旅行体验！'}
);

// ──────────────────────────────────────────────────────────────
// 【8】欧洲经典目的地 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_EUROPE.push(
  {c:'旅游',q:'英国的"温布尔登"（Wimbledon）以什么著名？',o:['英国最古老的板球场','世界上最著名的草地网球赛事（Wimbledon Championships），每年6月底至7月初举行，是大满贯之一','英国最大的马术比赛场','英国最古老的橄榄球俱乐部'],a:1,e:'The Championships Wimbledon（温布尔登网球赛）是全球历史最悠久（1877年首届）和最有声望的网球大满贯之一，以全草地球场著名。观赛必吃：草莓配奶油（Strawberries and cream）是温布尔登的传统美食！'},
  {c:'旅游',q:'葡萄牙里斯本（Lisbon）以什么音乐类型著名？',o:['以弗拉门戈（Flamenco）著名（实为西班牙的）','以法朵（Fado）著名——一种忧郁的葡萄牙传统歌曲，表达对过去的思念与乡愁（Saudade）','以古典交响乐著名','以现代电子音乐著名'],a:1,e:'Fado（法朵）是葡萄牙的传统音乐，发源于里斯本19世纪初，表达葡萄牙文化中独特的情感——"Saudade"（乡愁/对美好事物逝去的感伤）。Fado已被UNESCO列为非物质文化遗产。阿尔法玛区（Alfama）的Fado餐厅是体验这种音乐的最佳地点。'},
  {c:'旅游',q:'德国的"慕尼黑啤酒节"（Oktoberfest）实际上通常在什么时间举行？',o:['10月1日至31日整个十月份','大多数从9月下旬开始，持续约16-18天，在10月第一个周末结束（并非整个十月）','整个9月份','每年冬季12月'],a:1,e:'尽管名字叫Oktoberfest，但大部分时间实际上在9月！通常从9月中旬的周六开始，到10月第一或第二个周日结束，共约16-18天。在慕尼黑（Munich）的特蕾西娅广场（Theresienwiese）举行，是全球规模最大的啤酒节，每年吸引超过600万游客。'},
  {c:'旅游',q:'波兰的"克拉科夫"（Kraków）与哪个重要历史事件密切相关？',o:['法国大革命的发源地','二战期间离奥斯维辛集中营最近的主要城市，纳粹德国占领期间曾是德国总督府所在地，城市本身在战争中受损较少而保存完好','一战后《凡尔赛条约》的签署地','拿破仑军队的最后战役地点'],a:1,e:'克拉科夫（Kraków）是波兰第二大城市，中世纪旧城区保存完好（UNESCO世界遗产）。其历史与二战密切相关：距奥斯维辛集中营约70公里；德国占领时期是总督府（General Government）首府；辛德勒工厂（Schindler\'s Factory）就在城内，现为博物馆。旧城广场（Main Market Square）是欧洲最大的中世纪广场之一。'},
  {c:'旅游',q:'芬兰"圣诞老人村"（Santa Claus Village）位于哪个城市？',o:['赫尔辛基（Helsinki，首都）','罗瓦涅米（Rovaniemi）——位于北极圈（Arctic Circle）上，是芬兰官方认定的圣诞老人故乡','坦佩雷（Tampere）','奥卢（Oulu）'],a:1,e:'Santa Claus Village位于罗瓦涅米（Rovaniemi），横跨北极圈线（Arctic Circle），是芬兰拉普兰地区的热门旅游目的地。提供：拜访圣诞老人、驯鹿雪橇、哈士奇体验、冰屋住宿（Ice hotel）和北极光观测。每年圣诞期间吸引大量家庭游客。'},
  {c:'旅游',q:'奥地利维也纳（Vienna）被誉为什么城市？',o:['欧洲的金融之都','音乐之都（City of Music）——贝多芬、莫扎特、舒伯特、施特劳斯等众多音乐大师在此生活和创作','欧洲的时装之都','现代建筑的中心'],a:1,e:'维也纳被称为"音乐之都"（City of Music），曾是贝多芬（Beethoven）、莫扎特（Mozart，少年时期）、舒伯特（Schubert）、勃拉姆斯（Brahms）等古典音乐大师的活动中心。维也纳金色大厅（Musikverein）和国家歌剧院（State Opera）是全球音乐爱好者的朝圣地。'},
  {c:'旅游',q:'土耳其伊斯坦布尔（Istanbul）的"圣索菲亚大教堂"（Hagia Sophia）有什么特殊的历史背景？',o:['一直是基督教教堂，从未改变过用途','最初是拜占庭帝国的东正教大教堂（537年建成），后被奥斯曼帝国改为清真寺，20世纪成为博物馆，2020年再次改回清真寺','从建成之初就是伊斯兰清真寺','是现代建筑师设计的仿古建筑'],a:1,e:'圣索菲亚（Hagia Sophia）是建筑史上的奇迹（公元537年建成，穹顶直径31米），历经多次功能变迁：①东罗马（拜占庭）帝国东正教大教堂（537-1453）②奥斯曼帝国伊斯兰清真寺（1453-1934）③世俗博物馆（1934-2020）④重新成为清真寺（2020至今）。现在开放参观，进入时女性须遮头。'},
  {c:'旅游',q:'冰岛（Iceland）有什么特殊的地理现象，使其成为旅行目的地？',o:['冰岛冬天气温极低，约-50°C，无法旅行','冰岛是欧洲最活跃的火山地区之一，拥有冰川（Glacier）和火山同时存在（"冰与火之国"）、地热温泉、夏季极昼和冬季北极光等罕见自然现象','冰岛没有任何自然景点，只有城市观光','冰岛全年被冰雪覆盖无法旅行'],a:1,e:'冰岛（Land of Ice and Fire）：①全球地热活动最活跃地区之一（火山、间歇泉、地热温泉）②拥有大面积冰川（Vatnajökull是欧洲最大冰川）③夏季午夜太阳（Midnight Sun，6月日不落）④冬季北极光（Aurora Borealis，9-3月）⑤蓝湖地热温泉（Blue Lagoon）。独一无二的旅行目的地！'},
  {c:'旅游',q:'捷克布拉格（Prague）的"克鲁姆洛夫"（Český Krumlov）以什么著名？',o:['全捷克最大的工业城市','保存极为完好的中世纪小城，以蜿蜒河流环绕的城堡和彩色巴洛克式建筑著名，已被列为UNESCO世界遗产','捷克的科技和创新中心','以葡萄酒庄园著名的农业小镇'],a:1,e:'Český Krumlov（克鲁姆洛夫）是波西米亚南部的童话般小城，伏尔塔瓦河在此绕了一个大弯，将城堡山与老城分开，形成独特景观。城堡（Ceský Krumlov Castle）是捷克第二大城堡建筑群，整个历史中心已被列为UNESCO世界遗产。适合布拉格的一日游。'},
  {c:'旅游',q:'比利时布鲁日（Bruges）被称为什么？',o:['比利时的首都','北方的威尼斯（Venice of the North）——以密集的运河网络和保存完好的中世纪砖石建筑著名','欧洲最重要的钻石交易中心（安特卫普才是）','比利时巧克力的发源地（布鲁塞尔更出名）'],a:1,e:'布鲁日（Bruges）=北方威尼斯，城内有密集的运河，中世纪建筑保存极为完好（UNESCO世界遗产），是比利时最美丽的城市之一。以手工巧克力（Belgian chocolate）、花边（Lace）工艺和运河游船著名。从布鲁塞尔乘火车约1小时可到达。'},
  {c:'旅游',q:'西班牙马德里（Madrid）的"普拉多博物馆"（Museo del Prado）以收藏哪些艺术家的作品著名？',o:['以印象派（法国莫奈、雷诺阿等）作品为主','以西班牙和欧洲大师作品为主，包括委拉斯开兹（Velázquez）、哥雅（Goya）、鲁本斯（Rubens）、博斯（Hieronymus Bosch）等','以现代抽象艺术（毕加索、达利）为主','以中世纪宗教艺术为主'],a:1,e:'普拉多博物馆（Museo Nacional del Prado）是世界最重要的博物馆之一，收藏超过8000件画作和雕塑。必看作品：委拉斯开兹的《宫娥》（Las Meninas）、哥雅的《裸体的马哈》（La maja desnuda）。毕加索和达利的作品分别在马德里的"王后索菲亚艺术中心"和巴塞罗那展出。'},
  {c:'旅游',q:'匈牙利布达佩斯（Budapest）的"温泉文化"有什么独特之处？',o:['布达佩斯没有任何温泉设施','布达佩斯建在地热温泉上，是欧洲唯一一座拥有超过百年历史温泉浴池（如塞切尼温泉浴场Széchenyi Baths）的首都城市，温泉文化深入日常生活','布达佩斯温泉只对住宿游客开放','温泉在布达佩斯是需要提前数周预约的稀缺体验'],a:1,e:'布达佩斯被称为"温泉之都"（Spa City），地下有丰富的地热水资源，全市有超过80个温泉浴场。Széchenyi Baths（塞切尼温泉）是欧洲最大的温泉浴场之一，建于1913年，可容纳数千人，在黄色巴洛克宫殿建筑内泡温泉的体验独一无二！'},
  {c:'旅游',q:'前往挪威卑尔根（Bergen），乘坐"弗洛伊班"（Fløibanen）缆车可以到达什么？',o:['一家山顶赌场','弗洛伊恩山顶（Fløyen），俯瞰卑尔根老城和峡湾的绝美景观台','挪威最大的滑雪场','通往峡湾的起点站'],a:1,e:'Fløibanen（弗洛伊班尼）是卑尔根的登山缆车（Funicular），从市中心出发，8分钟内到达弗洛伊恩山（Fløyen，320米）山顶。从山顶可以俯瞰卑尔根老城（Bryggen，UNESCO世界遗产）、海湾和四周的山峰，是卑尔根最受欢迎的旅游体验之一。'},
  {c:'旅游',q:'爱沙尼亚塔林（Tallinn）最著名的特色是什么？',o:['全球最繁忙的港口之一','欧洲保存最完好的中世纪旧城（Old Town），城墙和塔楼基本完好，整个旧城区已列为UNESCO世界遗产','全球最先进的电子政务系统所在地（这是事实但不是主要旅游特色）','以桑拿文化著名（芬兰才是）'],a:1,e:'塔林（Tallinn）是爱沙尼亚首都，旧城（Vanalinn）是欧洲保存最完好的中世纪城市之一，1997年被列为UNESCO世界遗产。中世纪城墙、塔楼（Toompea Castle）、汉萨同盟时期的商人建筑保存完好，是波罗的海三国旅游的必访城市。'}
);

// ──────────────────────────────────────────────────────────────
// 【9】美洲及大洋洲 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GEO_AMERICAS.push(
  {c:'旅游',q:'"Route 66"（66号公路）在美国有什么文化意义？',o:['是美国最繁忙的现代高速公路','是美国历史上著名的公路（1926-1985年）——从芝加哥延伸至洛杉矶，全程约4000公里，象征美国公路旅行和自由精神，仍是自驾游热门路线','是美国最危险的公路，不建议旅行','只有在加利福尼亚州境内的部分路段保留了下来'],a:1,e:'Route 66（母亲之路/美国主街）是美国最具历史文化意义的公路，1926年建立，横跨8个州（Illinois、Missouri、Kansas、Oklahoma、Texas、New Mexico、Arizona、California），全程约3940公里。代表了美国大移民时代和公路文化，如今是最受欢迎的自驾游路线之一。'},
  {c:'旅游',q:'哥斯达黎加（Costa Rica）以什么旅游特色著名？',o:['以现代城市和购物著名','以生态旅游（Ecotourism）著名——热带雨林、火山、野生动物（蜘蛛猴、巨嘴鸟、蝴蝶）、冲浪和可持续旅游理念','以奢华海滩度假和赌场著名','以古代玛雅文明遗址著名'],a:1,e:'哥斯达黎加是世界生态旅游的标杆国家，面积虽小（约51000平方公里）却拥有全球约5%的生物多样性。口号"Pura Vida"（纯净生活）是国家精神。热门体验：雨林徒步、蒙特维德云雾森林（Monteverde Cloud Forest）、阿雷纳尔火山（Arenal Volcano）和太平洋海岸冲浪。'},
  {c:'旅游',q:'美国阿拉斯加（Alaska）最著名的野生动物观察体验是什么？',o:['观看北极熊在雪地奔跑','在卡特迈国家公园（Katmai National Park）观看棕熊在河中捕捞鲑鱼（尤其是7-9月鲑鱼洄游季节）','观看座头鲸和白鲸','在育空河畔观看麋鹿'],a:1,e:'Katmai National Park（卡特迈）的Brooks Falls是全球最著名的棕熊观察地，每年7-9月鲑鱼洄游时，棕熊站在瀑布旁捕食跳跃的鲑鱼，场景壮观。国家公园局甚至提供网络直播（Bear Cam）！阿拉斯加还有著名的"Denali（德纳利峰）"——北美最高峰（6190米）。'},
  {c:'旅游',q:'厄瓜多尔的"加拉帕戈斯群岛"（Galápagos Islands）为什么对科学家和旅行者都具有特殊意义？',o:['是全球最大的珊瑚礁群","是达尔文（Charles Darwin）1835年访问后，受当地独特生物进化现象启发而提出进化论的地方；岛上至今生活着不怕人的野生动物（海鬣蜥、蓝脚鲣鸟等）','是世界上氧气含量最高的地方','是南美洲最大的钻石矿区'],a:1,e:'加拉帕戈斯群岛（Galápagos Islands）是UNESCO世界遗产和世界遗址，查尔斯·达尔文1835年在此观察到独特物种（加拉帕戈斯雀、海鬣蜥、象龟等），启发了《物种起源》中的自然选择理论。岛上动物未经人类捕猎，完全不怕人，可以近距离接触，是自然旅游的极致体验。'},
  {c:'旅游',q:'玻利维亚的"乌尤尼盐沼"（Salar de Uyuni）的独特景观是什么？',o:['世界最大的熔岩地貌','世界最大的盐滩，旱季时是白色的盐晶平原，雨季时积水形成天空之镜（Mirror of the Sky），可以清晰倒映天空','世界最大的沙漠地带','世界上海拔最低的咸水湖'],a:1,e:'Salar de Uyuni（乌尤尼盐沼）是世界上最大的盐滩（约10582平方公里），位于玻利维亚海拔约3656米的高原。旱季（5-10月）：蓝白色盐晶平原，可以拍创意透视照；雨季（11-4月）：薄薄的积水形成完美的"天空之镜"（Mirror Effect），是全球最受追捧的摄影目的地之一。'},
  {c:'旅游',q:'澳大利亚"艾尔斯岩"（Uluru/Ayers Rock）对当地原住民有何重要意义？',o:['是澳大利亚历史上第一个欧洲移民定居点','是阿南古人（Anangu Aboriginal people）的神圣地，有着数万年的文化和精神意义；攀爬被视为对当地文化的不尊重，现已被正式禁止','是澳大利亚最高峰','仅仅是一块著名的红色大岩石，没有特别文化含义'],a:1,e:'乌鲁鲁（Uluru/Ayers Rock）是澳大利亚红色中心的地标性巨岩，对安纳谷（Anangu）原住民有深远的精神和文化意义。攀岩在2019年10月正式被禁止，以尊重原住民文化。岩石日出日落时呈现的橙红色变化是观赏亮点。周围的原住民文化中心值得参观。'},
  {c:'旅游',q:'加拿大不列颠哥伦比亚省的"维多利亚"（Victoria）以什么著名？',o:['以全球最大的科技公司总部著名','以浓厚的英式文化气息著名——维多利亚式建筑、下午茶（High Tea）传统、精心打理的花园（尤其是Butchart Gardens宝翠花园）','以加拿大最繁忙的港口著名','以全球最重要的钻石交易中心著名'],a:1,e:'维多利亚（Victoria）是不列颠哥伦比亚省省会，位于温哥华岛南端，保留了浓郁的英式殖民风情。必游：宝翠花园（Butchart Gardens）——废弃石灰岩矿改造而成的世界著名花园；议会大厦（Parliament Building）夜晚亮灯极美；下午茶文化是维多利亚的骄傲（Fairmont Empress酒店是圣地）。'},
  {c:'旅游',q:'巴西的"亚马逊雨林"（Amazon Rainforest）覆盖了哪些主要国家？',o:['只有巴西','主要分布在巴西（约60%），另延伸至秘鲁、哥伦比亚、委内瑞拉、厄瓜多尔、玻利维亚等9个南美国家','主要分布在哥伦比亚和委内瑞拉','只分布在南美洲东部沿海'],a:1,e:'亚马逊雨林（Amazon Rainforest）是世界最大的热带雨林，总面积约550万平方公里，横跨巴西（约60%）、秘鲁、哥伦比亚、委内瑞拉、厄瓜多尔、玻利维亚、圭亚那、苏里南和法属圭亚那。亚马逊河（Amazon River）是全球流量最大的河流。'},
  {c:'旅游',q:'新西兰"皇后镇"（Queenstown）以什么旅游特色著名？',o:['以奢华购物和艺术画廊著名','以极限运动（Adventure Sports）著名——蹦极（Bungee jumping，这里是世界商业蹦极的发源地）、跳伞、喷射快艇、高山滑雪等，被称为"世界冒险之都"','以毛利文化体验著名','以葡萄酒庄园参观著名'],a:1,e:'皇后镇（Queenstown）位于新西兰南岛，是全球知名的极限运动天堂：①世界第一个商业蹦极（AJ Hackett Bungy，1988年）②喷射快艇（Shotover Jet，在惊险峡谷中极速穿梭）③跳伞（Skydive）④冬季高山滑雪（Coronet Peak, The Remarkables）。背靠壮阔的雷马克布尔山脉，景色令人叹为观止。'},
  {c:'旅游',q:'智利的"阿塔卡马沙漠"（Atacama Desert）有什么特别之处？',o:['是世界上最热的沙漠','是世界上最干燥的非极地沙漠，年降水量近乎为零，同时海拔高（4000+米），是地球上最佳的天文观测地之一','是世界上面积最大的沙漠','以古代沙漠岩画著名'],a:1,e:'阿塔卡马沙漠（Atacama Desert）=世界上最干燥的沙漠（部分地区数十年无降雨记录）。旅游亮点：①月谷（Valle de la Luna）——火星般的地貌②间歇泉（El Tatio Geysers）③焰湖（Laguna Colorada）④世界顶级天文台（ALMA射电望远镜）——高海拔、极干燥的大气使星空清晰度无与伦比。'},
  {c:'旅游',q:'在加拿大魁北克（Quebec）旅行，需要注意什么语言特点？',o:['魁北克的官方语言是英语','魁北克以法语为官方语言（法裔加拿大人占多数），街道标识全法语，英语在部分旅游区可用但当地人日常使用法语','魁北克同时使用法语和英语，街道标识是双语的','魁北克已完全使用英语，法语只在少数乡村使用'],a:1,e:'魁北克是北美洲唯一法语为主要官方语言的省份，首府魁北克城（Quebec City）和最大城市蒙特利尔（Montréal）都以法语为主。旅行提示：学几句法语问候（Bonjour=你好，Merci=谢谢，Parlez-vous anglais?=您说英语吗？）会受到热情对待！'},
  {c:'旅游',q:'阿根廷的"伊瓜苏瀑布"（Iguazu Falls）由多少条瀑布组成？',o:['约20条瀑布','约275条独立瀑布，宽约2700米，被誉为世界上最宽的瀑布群','约50条瀑布','只有一条主瀑布，但极为壮观'],a:1,e:'伊瓜苏瀑布（Iguazu Falls）由约275条大小瀑布组成，总宽度约2700米，是世界上最宽的瀑布群（尼亚加拉瀑布宽约1200米）。最壮观的部分叫"魔鬼喉"（Devil\'s Throat/Garganta del Diablo），在此水声震耳欲聋，水雾弥漫。罗斯福夫人参观后曾感叹："可怜的尼亚加拉！"'},
  {c:'旅游',q:'南极洲（Antarctica）旅游有哪些独特的体验？',o:['可以在南极自由住宿和野营，无需任何许可证','通常以邮轮为基地，提供橡皮艇（Zodiac boat）登陆参观，可近距离接触企鹅、海豹、鲸鱼，体验极昼，但须遵守严格的南极环境保护规定','南极旅游完全禁止，只有科学家可以前往','可以随意带走南极岩石和冰块作为纪念品'],a:1,e:'南极旅游（通常从阿根廷乌斯怀亚Ushuaia或智利蓬塔阿雷纳斯Punta Arenas出发）：以探险邮轮为基地，通过橡皮艇登陆，时间约10-20天。体验：零距离接触帝企鹅（Emperor Penguin）等野生动物、冰山壮观景色、极昼。严格遵守《南极条约》：不能触碰野生动物、不能带走任何东西、不能留下任何垃圾。费用较高（通常$5000+）。'},
  {c:'旅游',q:'前往古巴（Cuba）旅游，哪种交通工具是当地最具特色的体验之一？',o:['现代磁悬浮列车','经典老爷车（Classic American Cars，1950-60年代美国汽车）——美国禁运后古巴人维修保养数十年的彩色老爷车仍在街上跑','高科技电动出租车','双层观光巴士'],a:1,e:'古巴（Cuba）的经典老爷车（Yank tanks / Classic cars）是最独特的旅行体验之一。由于1962年美国经济封锁，古巴无法进口新车，当地人将50-60年代的美国老爷车维修保养至今。坐上彩色老爷车兜风是访问哈瓦那（Havana）的必做事项，也是完美的摄影主题。'},
  {c:'旅游',q:'巴拿马（Panama）的"巴拿马运河"（Panama Canal）有什么历史意义？',o:['是世界上最古老的运河（16世纪建造）','完成于1914年，连接太平洋和大西洋，使船只无需绕行南美洲麦哲伦海峡，大大缩短了航运距离，是世界最重要的水路之一','是世界上最深的运河','只允许小型游艇通过，商业船只使用另一条通道'],a:1,e:'巴拿马运河（Panama Canal）于1914年由美国建造完成，全长约82公里，连接太平洋和加勒比海（大西洋）。船只通过时使用船闸（Locks）调节水位，这是工程奇迹。2016年扩建完成的新船闸（Neopanamax locks）可通行超大型集装箱船。Miraflores访客中心是观察船闸运作的最佳地点。'}
);

// ──────────────────────────────────────────────────────────────
// 【10】旅行高频词汇 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_TRAVEL.push(
  {c:'词汇',q:'"Bleisure travel"是什么新型旅行方式？',o:['只去极寒地区的旅行','Business + Leisure的组合——商务出差后延长行程进行休闲旅游，或在目的地工作同时旅游','只有老年人参与的轻松慢游','不预定任何行程的即兴旅行'],a:1,e:'"Bleisure"=Business + Leisure（商休游）。越来越多职场人在公务出差的前后多待几天进行观光，或利用出差机会探索目的地城市。这一趋势在新冠疫情后因远程办公普及而大幅增长。'},
  {c:'词汇',q:'"Responsible tourism"（负责任旅游）的核心理念是？',o:['旅行时绝对不消费，以节省资金','旅行时考虑对环境、当地经济和文化的影响，采取积极行动减少负面影响（如选择当地小企业、减少一次性塑料、尊重文化习俗）','只去政府推荐的景点','减少旅行次数以节约能源'],a:1,e:'"Responsible Tourism"强调：Make a positive difference（产生正面影响）。实践：①入住当地家庭旅馆而非连锁酒店②在当地市场购物而非国际品牌③学习几句当地语言④遵守文化礼仪⑤不参与伤害动物的旅游项目（如骑大象）⑥减少塑料垃圾。'},
  {c:'词汇',q:'"Visa waiver"（免签）和"Visa on arrival"（落地签）的区别是什么？',o:['两者完全相同','Visa waiver=完全无需任何签证手续即可入境（部分国家可能需申请eTA电子授权）；Visa on arrival=抵达目的地后在机场现场办理签证，需要填表和缴费','落地签比免签入境更方便','免签只适用于外交护照'],a:1,e:'Visa Waiver（免签）=持护照无需任何签证可直接入境（部分需提前申请eTA/ESTA电子授权，但不是传统签证）。Visa on Arrival（落地签）=到达目的地机场后在移民局现场申请，需填表、付费、提供照片等，耗时较长。总体来说，免签更方便。'},
  {c:'词汇',q:'"High season"（旺季）对旅行价格有什么影响？',o:['旺季价格通常更低，因为航空公司想吸引更多旅客','旺季（通常是暑假、圣诞节、法定假日等）机票和酒店价格大幅上涨，景点拥挤；淡季（Off-peak/Low season）价格便宜但可能有部分设施关闭','旺季和淡季价格完全相同','只有机票价格受旺季影响，酒店不受影响'],a:1,e:'旅行旺季（High season）=价格最高、游客最多的时期。避开旺季的"肩季"（Shoulder season，旺季前后）往往是最佳性价比时机：价格适中、游客适量、天气通常不错。如巴黎4-5月（春季肩季）或9-10月（秋季肩季），好过7-8月的旅游高峰。'},
  {c:'词汇',q:'"Complimentary upgrade"（免费升级）在旅行中什么情况下最容易获得？',o:['在节假日等航班/酒店最拥挤的时候','在航班/酒店入住率不高的情况下，航空公司/酒店会主动升级某些旅客；另外高级会员资格、特殊场合（蜜月/生日/纪念日）、礼貌询问也是获得升级的方式','升级从来不免费提供，只能购买','在抱怨服务之后总能获得'],a:1,e:'获得免费升级（Complimentary Upgrade）的窍门：①航空公司/酒店忠诚度计划高级会员②在航班/酒店入住率低时礼貌询问③提及特殊场合（蜜月/生日）④穿着得体显示是有素质的旅客⑤提前办理值机（有时系统会主动升级）⑥使用积分兑换升级。'},
  {c:'词汇',q:'"Long-term travel"（长期旅行）通常面临的最大挑战是什么？',o:['找不到吃喝的地方','持续管理资金（需要控制预算防止超支）、签证期限（需要定期更新或离境）和保持社交联系（可能感到孤独）是长期旅行者面临的最大挑战','不知道去哪里','语言障碍（但实际上可以通过翻译App解决）'],a:1,e:'长期旅行（超过3-6个月）的现实挑战：①财务管理——如何在有限预算内持续旅行②签证——各国停留时限不同，需要规划③孤独感——长期独自旅行可能产生孤独④健康——旅途疲劳、饮食不规律⑤家人担心——与家人保持联系的压力。这些都是值得提前规划的现实问题。'},
  {c:'词汇',q:'"Guided tour"（导览游）和"Self-guided tour"（自助游）各有什么优缺点？',o:['导览游完全没有缺点，自助游都是缺点','导览游：优点是省心、专业知识丰富、有时可进入不开放区域；缺点是时间受限、灵活性低、费用可能较高。自助游：优点是自由灵活、可深度探索；缺点是需要自己做功课、可能错过背景知识','自助游完全没有缺点，导览游都是缺点','两者完全相同，只是名字不同'],a:1,e:'实际选择建议：对陌生目的地、历史名胜（如博物馆、遗址）——有导游的半日游更有价值；对城市漫游、购物、餐厅探索——自助游更灵活惬意。许多旅行者会结合使用：特定景点用导览，其余时间自由探索。'},
  {c:'词汇',q:'"Airfare consolidator"（机票整合商）是什么？',o:['航空公司的直营订票平台','批量购买机票再低价转售的中间商平台（如Expedia、Kayak、Google Flights等），有时可以找到低于官网的机票价格','只出售商务舱机票的专业平台','机票退款的中介服务'],a:1,e:'机票整合商（也叫OTA，Online Travel Agency，在线旅行社）=Expedia、Booking.com、Kayak、Skyscanner等批量比价平台。使用建议：①先在比价平台比较，再去航空公司官网核实②直接在官网购买有时更便宜（省去中介佣金）③复杂行程（多地、多段）在OTA更方便③注意退改签政策可能比官网更严格。'},
  {c:'词汇',q:'"Hotel occupancy tax"（酒店住宿税）是什么？',o:['酒店自行设定的服务费，无法提前知道','各地政府向酒店住客征收的税费，通常在预订时未显示，在实际账单中才出现（纽约市约14.75%，旧金山约14%）','只适用于非本国公民的外国游客','这与酒店星级评定有关'],a:1,e:'Hotel tax（住宿税/酒店税）=地方政府向住客征收，通常以百分比计算，在最终账单中显示，Booking.com/Expedia上有时不含税价格展示，结账才发现涨价！纽约市住宿税约14.75%，旧金山约14%，芝加哥约17%——美国城市住宿税普遍较高，预算时须考虑进去。'},
  {c:'词汇',q:'"Seat pitch"和"Seat width"是衡量飞机座位舒适度的指标，分别是什么？',o:['Pitch是座椅材质；Width是靠背高度','Seat pitch=前后排座椅之间的距离（直接影响腿部空间）；Seat width=座椅宽度（通常17-20英寸）；两者越大越舒适','Pitch是靠背倾斜角度；Width是头枕宽度','两者都是测量飞机机身宽度的指标'],a:1,e:'飞机座位舒适度关键指标：①Seat Pitch（座椅间距）=同一排到前一排的水平距离，经济舱通常28-34英寸，30英寸以下非常拥挤②Seat Width（座椅宽度）=座椅实际坐面宽度，经济舱通常17-19英寸③Recline（倾斜角度）。订票时可以在SeatGuru.com查询各机型座椅数据，选择最好的座位。'},
  {c:'词汇',q:'"Connecting flight"（中转航班）和"Direct flight"（直达航班）有什么区别？',o:['两者完全相同，只是名字不同','Connecting flight=需要在中间城市下机换乘另一个航班；Direct flight=中途可能停靠但不换飞机（旅客不用下机）；Nonstop flight（直飞）=不中途停靠直接到达目的地','Direct flight不中途停靠，Connecting也不停靠','Connecting flight只适用于国际航班'],a:1,e:'区别：Nonstop（直飞）=从A直接飞到B，不停靠；Direct flight=可能在中途机场停靠加油/上下部分旅客，但你不用换飞机；Connecting flight=你需要在中途机场下机，再登上另一架飞机。Nonstop最方便，但价格通常最贵。'},
  {c:'词汇',q:'"Rail pass"（铁路通票）在哪些情况下最值得购买？',o:['任何情况下都比单独购票便宜','计划在短时间内（如2-3周）多次乘坐长距离列车时（如欧洲多城游）；如果只在一两个城市之间移动，单独买票往往更便宜','只有学生才能购买铁路通票','铁路通票只在欧洲有售'],a:1,e:'Rail Pass性价比分析：适合买pass的情况：在2-3周内乘坐多段长途列车（如欧洲8-10个城市游），总价值超过pass价格。不适合买pass：只去1-2个目的地，或短途城市间移动；或已找到特价票（欧洲Advance ticket可以非常便宜）。购买前用SplitMyFare等工具比较！'},
  {c:'词汇',q:'"Voluntourism"（志愿旅行）是什么？',o:['只接受捐款的慈善旅行','将旅行与志愿服务（义工）相结合，如教学、建设、环境保护、野生动物保育等，旅行者以此方式贡献当地社区','旅行途中完全依靠当地社区提供帮助','免费旅行，以劳动换取食宿'],a:1,e:'Voluntourism（义工旅行）=结合旅行和义工服务。例子：在柬埔寨教英语、在非洲参与野生动物保育、在尼泊尔地震后协助重建。注意事项：选择有信誉的组织、确保项目确实有益于当地（某些"孤儿院旅游"存在道德问题）、考虑自己能贡献的真正技能。'},
  {c:'词汇',q:'"Slow travel"（慢旅行）的核心理念是什么？',o:['指因交通问题导致旅行速度很慢','在一个地方停留更长时间（数周甚至数月），深度融入当地生活、文化和社区，而不是走马观花式地快速打卡多个景点','只乘坐火车和船只旅行','每天步行所有行程，不使用任何机动交通'],a:1,e:'Slow Travel（慢旅行）=与快节奏的打卡式旅行（见得越多越好）相对，强调在一个地方深度体验：住当地公寓（不是酒店）、去当地菜市场、和本地人交朋友、学习当地语言或烹饪。更环保（减少交通频率）、更经济（长租比短租便宜）、更有意义。'},
  {c:'词汇',q:'"Amenities"（设施/配套）在酒店语境里通常指什么？',o:['酒店的房间数量','酒店提供的设施和服务，如游泳池、健身房、餐厅、WiFi、洗漱用品、迷你吧等（分为In-room amenities和Hotel amenities）','酒店的建筑风格','酒店的地理位置优势'],a:1,e:'"Amenities"=配套设施。In-room amenities（房内设施）：洗漱用品（toiletries）、吹风机（hairdryer）、浴袍（bathrobe）、保险箱（safe）、熨斗（iron）、咖啡机（coffee maker）。Hotel amenities（酒店设施）：泳池、健身房、Spa、餐厅、商务中心。预订前阅读"Amenities"列表可以帮助判断是否物有所值。'}
);

// ──────────────────────────────────────────────────────────────
// 【11】日常生活词汇 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_VOCAB_DAILY.push(
  {c:'词汇',q:'在英国超市，"Ready meal"（即食餐）是什么？',o:['需要在餐厅现场烹制的菜肴','已经烹制好只需微波炉加热的包装食品，是英国人常见的快捷饮食方式','农场直送的新鲜食材','只需加水搅拌的速食汤粉'],a:1,e:'Ready meal（即食餐）=超市销售的预制食品，通常只需放入微波炉（microwave）加热3-5分钟即可食用。是英国超市最畅销的品类之一（Marks & Spencer、Waitrose的ready meals口碑较好）。长途旅行在自助公寓入住时非常实用！'},
  {c:'词汇',q:'在国外看病时，"GP"是什么？',o:['全球急救中心（Global Practitioner）','全科医生（General Practitioner）——提供初级医疗服务，非急症情况首先去看GP，再由GP转介到专科医生','政府药房（Government Pharmacy）','门诊护士（General Professional）'],a:1,e:'GP（General Practitioner）=全科医生，是英国、澳大利亚等英联邦国家医疗系统的"守门人"。非急症先看GP，再由GP转介（refer）到专科医生（Specialist）。急症直接去急诊室（A&E in UK, Emergency Room/ER in USA）。在美国看病通常需要提前预约（appointment）。'},
  {c:'词汇',q:'"Utility bills"（公用事业账单）在租房或长期住宿时通常包括什么？',o:['网购快递账单','水费（Water）、电费（Electricity/Gas）、网络费（Internet）等基础生活费用；长租公寓有时需要自己缴纳','酒店的一切额外消费','旅行险账单'],a:1,e:'Utility bills=生活基础费用账单，通常包括：①Electricity/Gas（电费/燃气费）②Water（水费）③Internet/Broadband（网费）④Sometimes Council Tax（英国市政税）。在英国等地长租时，这些费用有时需要租客自行注册缴纳，有时房东包含在租金内（Bills included）。入住前问清楚！'},
  {c:'词汇',q:'"Jet lag"通常在什么方向的旅行中感觉更严重？',o:['东西方向一样严重','向东飞行（如中国飞欧洲）通常比向西飞行（如中国飞美国西海岸）时差反应更严重','向西飞行总是更严重','时差与飞行方向无关，只与飞行时间长短有关'],a:1,e:'时差研究表明：向东飞行（需要提前睡眠时间）对人体生物钟的调整难度通常大于向西飞行（需要延后睡眠时间）。应对时差：①上飞机就把手表调到目的地时间②多喝水少喝酒精③尽量按目的地时间的日落入睡④到达后白天接受阳光照射（帮助调整生物钟）⑤短期旅行可考虑不调整生物钟。'},
  {c:'词汇',q:'在国外超市，"Buy one get one free"简写为？',o:['2 for 1（略有不同）','BOGOF（Buy One Get One Free）','50% off the second item（只是半价）','Buy 2 pay 1（另一种说法）'],a:1,e:'BOGOF=Buy One Get One Free（买一送一），是最常见的超市促销缩写。注意与相似促销区分：Buy 2 pay 1=和BOGOF一样；Half price on second=第二件半价（不是免费）；2 for £5=两件共5英镑（可能两件单价各3英镑，合起来便宜了1英镑）。'},
  {c:'词汇',q:'"Power adapter"（电源适配器）和"Power converter"（电压转换器）哪个必须携带？',o:['只需带Power converter，就可以在全球使用任何电器','取决于你的电器：现代充电设备（手机、电脑）通常是100-240V宽压，只需Power adapter（转换插头形状）即可；单压电器（如某些吹风机）则需要Power converter（转换电压）','两者都必须携带，缺一不可','两者只需带一个即可，随意选'],a:1,e:'简单判断：看你的充电器或电器标签。如写"Input: 100-240V"=宽压设备，只需plug adapter（插头转换器）就够了。如写"Input: 100V"或"220-240V only"=单压设备，换了国家须用Voltage converter（电压转换器）。大多数手机、电脑、相机充电器是宽压的，吹风机和某些美容电器可能是单压的。'},
  {c:'词汇',q:'在国外使用Wi-Fi时，"Public Wi-Fi"（公共WiFi）的主要安全风险是什么？',o:['公共WiFi信号更弱，无法流畅看视频','公共WiFi通常未加密，黑客可以在同一网络中截取你的数据（"Man-in-the-middle attack中间人攻击"），风险包括密码、银行信息等被盗','公共WiFi会导致手机耗电更快','公共WiFi只能在特定App上使用'],a:1,e:'公共WiFi安全建议：①不要在公共WiFi上进行网上银行操作或输入密码②使用VPN（虚拟私人网络）加密连接③确认WiFi名称（防止连接到黑客设置的假热点）④使用完记得退出账号和关闭WiFi自动连接。在机场、咖啡馆等地使用手机流量（4G/5G）比公共WiFi更安全。'},
  {c:'词汇',q:'在国外，"Pharmacist"（药剂师）能提供什么帮助？',o:['只能卖药，无法提供任何医疗建议','可以就非处方药、轻微病症（感冒、过敏、轻微疼痛）提供专业建议和推荐合适的OTC药物，比去医院更快捷；严重症状会建议就医','可以开具处方药','可以进行血液检查和X光检查'],a:1,e:'药剂师（Pharmacist）是旅途中非常有用的医疗资源！在英国，很多轻微病症（咽痛、感冒、轻微过敏等）可以直接去药店问药剂师，他们会给专业建议并推荐OTC药品，免费且比预约医生快。在澳大利亚、加拿大等地也有类似服务。'},
  {c:'词汇',q:'"Rooftop bar"（天台酒吧）作为旅行体验，有什么特别之处？',o:['通常位于地下室，有隔音效果','位于酒店或建筑顶层，提供城市全景视野，是欣赏城市景观和享受鸡尾酒的热门地点，在亚洲城市（曼谷、香港、新加坡）尤其著名','通常只在白天营业','只接待该酒店的住客'],a:1,e:'Rooftop bar（天台酒吧/屋顶酒吧）是城市旅行的热门体验。亚洲代表：曼谷Lebua State Tower（The Hangover悬崖餐厅拍摄地）、新加坡1-Altitude、香港Sevva；欧洲：巴黎各奥斯曼风格建筑屋顶吧；纽约：230 Fifth（俯瞰帝国大厦）。通常无需消费即可入内，但会设最低消费。'},
  {c:'词汇',q:'"Customs allowance"（海关免税额度）是什么意思？',o:['海关对旅客的礼貌服务','每个旅客在入境时可以免税携带的商品价值/数量上限（如超过限额须缴税申报）；各国规定不同','海关对外国人的特殊优惠政策','是护照上的一种特殊标注'],a:1,e:'Customs allowance=海关免税配额。中国海关规定：个人携带进境物品含税总值通常不超过5000元人民币；酒精类不超过1.5升；卷烟不超过400支（或其他量）。超出需申报并可能缴税。各目的地国家的免税额度也不同，购物前要了解，防止回国时被罚款。'},
  {c:'词汇',q:'在旅行中，"layover"超过24小时通常叫什么？',o:['Extended layover（延长中转）','Stopover——超过24小时的中间停留，很多人会利用此机会游览中转城市','Overnight transit（过夜中转）','Long connection（长时中转）'],a:1,e:'转机术语区分：Layover=较短的等待时间（通常几小时内）；Stopover=在中间城市停留超过24小时（可以出机场游览！）。很多航空公司允许免费Stopover（如新加坡航空在新加坡、卡塔尔航空在多哈、阿联酋航空在迪拜），这是"多国游"的省钱技巧！'},
  {c:'词汇',q:'"Concierge app"（礼宾应用）和传统酒店礼宾服务有什么区别？',o:['Concierge app是为酒店员工设计的内部工具','Concierge app是面向旅客的智能手机应用程序，提供当地餐厅推荐、景点信息、预订服务等，是传统人工礼宾服务的数字化版本','两者完全相同，只是界面不同','Concierge app只适用于商务旅客'],a:1,e:'数字化礼宾服务越来越普及：酒店App（如万豪、希尔顿的App）可以实现手机开门、客房送餐点单、导览服务等；Google Maps、TripAdvisor、Yelp等也扮演着数字礼宾的角色，帮助旅客找餐厅、景点和活动。结合传统礼宾（解决复杂个性化需求）和数字工具（自助快捷）效果最佳。'},
  {c:'词汇',q:'"Motion sickness"（晕动症）的最佳预防方法是什么？',o:['坐在交通工具的最后排','坐在交通工具中最稳定的位置（飞机靠近机翼、船的中部、汽车前排）、注视远方地平线、保持通风；若需要可提前服用晕车药（如苯海拉明）','闭上眼睛不看窗外','大量饮水，保持水分充足'],a:1,e:'Motion Sickness（晕动症）=晕车/晕船/晕机。预防：①选择最稳定的位置（飞机靠近机翼中段；船在中甲板、水线附近；车坐前排；巴士/火车朝向行进方向的座位）②注视远方固定物体（不要低头看书或手机）③保持通风③提前服晕车药（如乘晕宁、苯海拉明）或使用晕动贴（Scopolamine patch）。'},
  {c:'词汇',q:'"Sightseeing bus"（观光巴士）通常提供什么服务？',o:['普通城市交通，价格与普通公交相同','按固定路线经过主要景点的特色旅游大巴，通常可以随上随下（Hop-on Hop-off），提供导游解说（耳机多语言版）；价格通常比出租车划算','只为老年旅客提供的坐席巴士','免费的机场接送服务'],a:1,e:'Hop-on Hop-off（随上随下观光巴士）=购一日票可全天无限次乘坐，在任意站上下。主要品牌：Big Bus Tours、City Sightseeing（红色双层巴士，在欧洲非常普遍）。票价通常$20-50，适合初次到访一座城市快速了解全貌。耳机提供多语言解说（通常包括中文）。'}
);

// ──────────────────────────────────────────────────────────────
// 【12】旅行实用语法 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_GRAMMAR.push(
  {c:'语法',q:'以下哪个问句在询问价格时最礼貌自然？',o:['Price! Now!','How much would this cost? / Could you tell me the price, please?','What is the price of this item at this moment?','You, price, this, how much?'],a:1,e:'"How much would this cost?"（这要多少钱？）或"Could you tell me the price?"是礼貌自然的问价方式。would比will更礼貌，是一种委婉的假设语气。直接说"Price!"或"How much?"也能沟通，但显得较为粗鲁。'},
  {c:'语法',q:'"Have got"和"Have"在英式英语中有什么区别？',o:['Have got是错误的语法，应该避免使用','Have got在英式英语中极为常见，意思与Have相同；"I\'ve got a reservation."=I have a reservation.（我有预订）；Have got强调当前状态，Have更通用','Have got只在过去时中使用','Have got是美式英语专属用法'],a:1,e:'Have got（英式英语常见）=Have（拥有/有）。"Have you got a map?"=Do you have a map?（你有地图吗？）"I\'ve got a headache."=I have a headache.（我头痛）。在美式英语中，Do you have...?更常见；英式则Have you got...?非常普遍。两者都是正确的。'},
  {c:'语法',q:'"I\'m afraid the flight has been cancelled."中，"I\'m afraid"在这里表示什么？',o:['说话者感到恐惧或害怕','表达歉意或传达坏消息的礼貌方式（"我很遗憾/恐怕是..."），不表示真正的恐惧','表达不确定性（"我不确定..."）','表达强烈的惊讶'],a:1,e:'"I\'m afraid..."在英语中是传达坏消息、拒绝或道歉的礼貌前缀，与"恐惧"无关。"I\'m afraid there are no rooms available."（很遗憾，没有空房了）。类似表达："I\'m sorry to say..."、"Unfortunately..."、"I regret to inform you..."。'},
  {c:'语法',q:'"Shall we" 和 "Should we"在提出建议时有什么区别？',o:['两者意思完全相反','Shall we...?是更正式/英式的邀请/提建议方式；Should we...?是询问对方意见更常见的方式；"Shall we go?"（我们走吧/走？）vs "Should we go now?"（我们是否应该走了？）','Shall we只用于皇室成员','Should we只用于否定句'],a:1,e:'"Shall we go to the beach?"=更具主动性的邀请（多见于英式英语）。"Should we take a taxi or walk?"=在征询意见，请对方参与决策。实用旅行对话：Shall we split the bill?（我们各付各的吧？）Should we book in advance?（我们应该提前预订吗？）'},
  {c:'语法',q:'"No sooner had we arrived than it started raining."这个句子用了什么倒装结构？',o:['这是语法错误，should是正确的词','No sooner...than...=刚……就……（倒装句，主谓倒置：No sooner had we...）；等同于"As soon as we arrived, it started raining."','这是一个虚拟语气句子','This是正常语序，没有倒装'],a:1,e:'"No sooner...than..."结构：表示"刚……就……"，使用时No sooner后主谓倒置。"No sooner had I checked in than my phone died."（我刚办完入住，手机就没电了）类似结构："Hardly/Scarcely had we left when..."（我们刚离开……就）。这些都是英语写作中高级的时间状语从句。'},
  {c:'语法',q:'在英语中，"Miss"、"Mrs."和"Ms."有什么区别？在旅行场合应该如何使用？',o:['三者完全相同，可以随意互换','Miss=未婚女性；Mrs.=已婚女性；Ms.=不指定婚姻状况的女性通用称谓（现代最常用，避免假设对方婚姻状态）','Ms.是错误拼写','Mrs.比Ms.更礼貌'],a:1,e:'称谓使用建议：Mr.（男性，不区分婚姻）、Ms.（现代女性通用，不涉及婚姻）、Mrs.（已婚女性，较正式）、Miss（未婚/年轻女性）。在不确定对方婚姻状况时，Ms.最安全。旅行中填写表格时，选择Ms.不会出错。'},
  {c:'语法',q:'表达"你们餐厅最受欢迎的菜是什么？"，哪个句子最地道？',o:['What food do people like here mostly?','What\'s the most popular dish here? / What do you recommend?','Which your most famous food?','People like what to eat here?'],a:1,e:'What\'s the most popular dish here?是最自然的问法。Dish=一道菜。也可说"What would you recommend?"（你推荐什么？）或"What\'s the house specialty?"（招牌菜是什么？）These are all natural ways to ask for recommendations in a restaurant.'},
  {c:'语法',q:'在英语中，"I\'ve been to Paris."和"I went to Paris."有何不同？',o:['两者意思完全相同，可以随意互换','前者（现在完成时）强调去过巴黎这个人生经历，不强调时间；后者（一般过去时）强调某一具体时间去了巴黎；使用时机不同','前者比后者更礼貌','后者只用于书面语'],a:1,e:'区别：I\'ve been to Paris.=我去过巴黎（人生经历，现在完成时）；用于回答"你去过巴黎吗？"这类问题。I went to Paris last summer.=我去年夏天去了巴黎（特定时间，一般过去时）；强调具体时间点。使用具体时间词（last year, in 2023等）时必须用一般过去时，不能用现在完成时。'},
  {c:'语法',q:'当你想表达"这附近有没有好的餐厅？"最地道的说法是？',o:['Near here, restaurant good, any have?','Is there any good restaurant nearby? / Are there any good restaurants around here?','Nearby I want restaurant can?','Good restaurant, where is it?'],a:1,e:'"Is there a good restaurant nearby?"（附近有好餐厅吗？）是最标准的表达。注意：如果问多家，用"Are there any good restaurants around here?"（around here=在这附近）。这是旅行中最高频的问路场景之一！还可以加"Could you recommend one?"（能推荐一家吗？）'},
  {c:'语法',q:'"I\'d rather you didn\'t smoke here."这句话用的是什么语法？它表达了什么？',o:['这是普通的否定句，直接禁止吸烟','I\'d rather + 主语 + 动词过去时=礼貌地表达不希望某事发生的虚拟语气；这句话的意思是"我宁可你不要在这里抽烟"（委婉的请求/禁止）','这是条件句','这是过去时态，表示过去有人在这里抽烟'],a:1,e:'"I\'d rather + 人 + 动词过去时"是非常礼貌的请求方式。"I\'d rather you didn\'t"=我希望你不要（比"Don\'t!"更礼貌委婉）。旅行场景：I\'d rather you kept the noise down.（我希望你能小声一点）/ The hotel would rather you didn\'t smoke in the room.（酒店不希望您在房间内吸烟）。'},
  {c:'语法',q:'如何礼貌地拒绝一个你不感兴趣的旅游推销？',o:['不理睬对方直接走开','Thank you, but I\'m not interested. / I appreciate it, but I\'ll pass.（谢谢，但我不感兴趣/我就不参加了）','你的产品很差，我不想买','我没有钱（这可能导致更多追问）'],a:1,e:'礼貌拒绝推销的标准用语："No, thank you."（简洁有效）/ "I appreciate it, but I\'ll pass."（谢谢好意，我就不了）/ "We\'re all set, thanks."（我们不需要，谢谢）。说完后可以直接走开，不需要解释理由。坚定但礼貌是关键——过多解释反而给推销员机会继续说服。'},
  {c:'语法',q:'"Not only...but also..."句型在英语中的用法是什么？',o:['是一个表示时间的连接词','用于连接并强调两个相关信息：Not only A but also B；如果Not only放在句首，主句须倒装（Not only did they help us, but they also...）','只能用于正式书面语，口语中禁止使用','是表示转折的连接词'],a:1,e:'"Not only...but also..."=不仅……而且……；强调两件事同时成立。旅行描述："Not only is the hotel conveniently located, but it also offers great value."（这家酒店不仅位置便利，而且性价比很高）。当Not only置于句首时须倒装，这是一个高级语法点，用好了能让英语表达更有层次。'},
  {c:'语法',q:'询问某人是否已经做了某件事，正确的现在完成时问句是？',o:['Did you book the tickets yet?（可以，但不如现在完成时自然）','Have you booked the tickets yet? / Have you already made a reservation?','Did you already have booked the tickets?（语法错误）','Are you booked the tickets?（语法错误）'],a:1,e:'"Have you...yet?"=你……了吗？（用于询问某事是否完成，现在完成时）。Yet通常放在疑问句或否定句末尾。"Have you checked in yet?"（你办理入住了吗？）/ "Has your luggage arrived yet?"（你的行李到了吗？）注意：Already用于肯定句："I\'ve already booked."（我已经订好了）。'},
  {c:'语法',q:'你想向旅伴提出建议"我们不如去海滩"，哪种表达最自然轻松？',o:['You must go to the beach.（太强硬）','How about going to the beach? / Why don\'t we head to the beach?','Let\'s going to the beach.（语法错误）','I suggest you beach.（语法错误）'],a:1,e:'常用提建议的句型（从随意到正式）：①How about + V-ing?②Why don\'t we + V?③What if we + V?④Let\'s + V（注意Let\'s后接动词原形，不是V-ing）⑤Shall we + V?⑥I suggest (that) we + V。注意"Let\'s going"是常见语法错误，应为"Let\'s go"。'},
  {c:'语法',q:'描述正在进行的旅行中发生的连续动作，以下哪个句子时态使用正确？',o:['While I waited, I took photos and I was eating ice cream.（时态不一致）','While I was waiting for the train, I took some photos and had an ice cream.（等待=进行时背景；拍照/吃冰淇淋=完成的动作）','I have been waiting for train and took photos.（时态混用错误）','While waited, taking photos and eat ice cream.（没有主语，语法混乱）'],a:1,e:'"While + 过去进行时（was/were + V-ing）, 一般过去时"是描述"背景动作中发生的具体事件"的标准句型。"While I was walking down the street, I found a great little café."（当我正走在街上时，发现了一家不错的小咖啡馆。）While从句描述持续的背景状态，主句描述在此背景下发生的具体动作。'}
);

// ──────────────────────────────────────────────────────────────
// 【13】文化礼仪常识 ×15（答案在B/C/D）
// ──────────────────────────────────────────────────────────────
window.QB_EN_CULTURE.push(
  {c:'出国',q:'在以色列（Israel）安排行程时，需要注意什么宗教节日？',o:['每周五是宗教节日，商店全天关闭','安息日（Shabbat）从周五日落持续到周六夜晚——许多商店、餐厅和公共交通停止运营，旅行者须提前做好安排','每周六所有景点免费开放','以色列没有宗教节假日'],a:1,e:'Shabbat（安息日）是犹太教的每周休息日，从周五日落到周六天黑。在耶路撒冷（Jerusalem）等宗教城市影响尤为显著：很多商店关门、公共交通减少甚至停运、餐厅可能关闭。去以色列旅行须提前了解，在安息日前备好食物和出行安排。'},
  {c:'出国',q:'在尼泊尔（Nepal），与当地人互动时应避免什么行为？',o:['用右手接受食物或礼物（正确做法）','未经允许随意触摸神庙、佛塔内的宗教文物；用左手指向他人或传递物品；穿着暴露进入寺庙区域；触碰他人头部（头部被认为是神圣的）','穿登山装备在市区行走','向当地人询问登山路线'],a:1,e:'尼泊尔礼仪禁忌：①头部神圣，不要随意触摸他人头部（包括儿童）②左手不洁，用右手传递和接收物品③进寺庙须脱鞋④摄影前须获得许可（有些寺庙禁止拍照）⑤不要将皮革制品（腰带、皮包）带入印度教神庙（印度教圣牛文化）⑥向佛塔顺时针绕行（顺时针=佛教吉祥方向）。'},
  {c:'出国',q:'在墨西哥，"Día de los Muertos"（亡灵节）是一个什么性质的节日？',o:['一个恐怖阴暗的节日，外国游客应该避开','是墨西哥传统节日（每年11月1-2日），以欢乐的方式纪念和缅怀先人，设置祭坛（Ofrenda）、鲜花装饰（万寿菊）、骷髅装饰和游行；UNESCO非物质文化遗产','是墨西哥的独立日庆典','是西班牙殖民时期带入的万圣节习俗'],a:1,e:'Día de los Muertos（亡灵节）是墨西哥最重要的传统节日之一（融合了原住民和天主教传统），用鲜花、食物和记忆物品设祭坛迎接亡灵"回家"。节日气氛欢快而非悲伤，充满色彩。外国游客可以参观公共庆祝活动，但要尊重其文化意义，不要将其仅视为"万圣节"的异域版本。'},
  {c:'出国',q:'前往沙特阿拉伯旅行，现在的规定与几年前有何变化？',o:['沙特阿拉伯依然对旅游业完全封闭','沙特阿拉伯自2019年起向非穆斯林旅游者开放旅游签证，女性不再强制要求穿阿巴雅（但仍需着装保守），开放了音乐会、电影院等娱乐活动，是一个正在快速变化的旅游目的地','沙特阿拉伯允许饮酒和赌博','没有任何变化，规定完全和以前一样'],a:1,e:'沙特阿拉伯的"Vision 2030"改革（穆罕默德·本·萨勒曼王储主导）：2019年首次向旅游者开放；女性不再强制穿戴全身遮盖的黑袍；开放了电影院（35年来首次）和混性别音乐会；NEOM未来城市正在建设中。注意：饮酒仍然违法，公共场合行为仍须保守。'},
  {c:'出国',q:'在意大利，进餐厅前你应该了解的用餐礼仪是什么？',o:['意大利餐厅允许随时进入，无需等待服务员引座','意大利餐厅通常要等服务员引座（不要自己随意选座位）；不应该要求"to go"（外带）正式餐点；用餐通常分多道（不要一次全点）；卡布奇诺（Cappuccino）在意大利只喝早餐，午餐后点会被认为很奇怪','意大利餐厅随时可以外带食物','意大利没有固定的用餐文化，随意就好'],a:1,e:'意大利用餐文化：①正式餐厅要等引座（wait to be seated）②Cappuccino（卡布奇诺）是早餐饮品，午饭后意大利人只喝Espresso（浓缩咖啡）③不要催促用餐，意大利人认为吃饭是重要的社交仪式④"Coperto"（餐位费）是合法收费项目⑤面包篮通常收费。'},
  {c:'出国',q:'在东南亚国家旅行，"Saving face"（面子）文化对于处理冲突有什么影响？',o:['东南亚没有面子文化，可以直接表达不满','东南亚文化中维护"面子"极为重要——当众批评或让对方难堪会造成严重的文化冲突；处理问题时应私下、委婉地沟通，避免公开对峙，给双方留有余地','表达强烈不满反而能更快解决问题','面子文化只在商务场合才重要'],a:1,e:'"Face"（面子）在东南亚、东亚文化中至关重要。实际应用：如果对酒店/餐厅服务不满，请私下（side communication）而非当众发脾气；表达不满时措辞委婉，避免正面指责；给对方提供"解决方案"而非要求对方承认错误。这样反而更容易获得满意的结果。'},
  {c:'出国',q:'在澳大利亚、新西兰旅行，遇到"EFTPOS"是什么？',o:['一种当地的流行饮料品牌','电子资金转账服务（Electronic Funds Transfer at Point of Sale）——澳新两国极为普遍的刷卡付款系统，支持借记卡（Debit card）和信用卡付款','一种特殊的旅游通行证','当地的移民局名称'],a:1,e:'EFTPOS（EFT at POS）是澳大利亚和新西兰最主流的电子支付系统，类似中国的银行卡POS机。"Just tap"（感应支付）或"swipe"（刷卡）非常普遍，大多数场所接受Visa、Mastercard等国际卡。现金在这两个国家越来越少用（许多地方甚至只接受卡片支付）。'},
  {c:'出国',q:'在英国，"Boxing Day"（节礼日）是哪一天，有什么传统？',o:['圣诞节前一天（12月24日），人们交换礼物','12月26日——传统上是给服务业工作者（仆人、邮差等）送礼物的日子，现在主要以大型购物促销（类似黑五）和体育赛事（足球比赛）著名','全年最大的宗教节日','英国政府规定的强制休息日，与礼物无关'],a:1,e:'Boxing Day（节礼日）=12月26日，是英国、澳大利亚、加拿大、新西兰等英联邦国家的公众假日。传统上主人在这天向仆人和工人赠送"圣诞礼盒"（Christmas box）。现代最著名的是大型打折促销活动（提前开门，折扣比圣诞节前更大），以及英超足球联赛Boxing Day赛程（这是全世界最受关注的一天足球比赛）。'},
  {c:'出国',q:'在美国，"Black tie"着装要求是什么？',o:['全身必须穿黑色服装','最正式的晚间着装规范——男性须穿燕尾服（Tuxedo，即Black tie）配蝴蝶结领带和礼服裤；女性须穿晚礼服（Evening gown）','只需穿黑色领带，其他随意','Black tie就是商务正装（Business formal）'],a:1,e:'着装规范（Dress code）从正式到随意：Black tie（燕尾服）> Black tie optional（可选燕尾服或深色西装）> Formal/White tie（最正式，燕尾服+白领带）> Business formal（商务正装）> Business casual（商务休闲）> Smart casual（整洁休闲）> Casual（休闲）。参加正式活动前务必确认着装要求！'},
  {c:'出国',q:'在印度旅行，进入家庭和宗教场所时，通常应遵守什么习俗？',o:['可以保持穿鞋进入，因为印度室内地板通常很干净','脱鞋进入是普遍且重要的习俗（无论是寺庙、清真寺、锡克教神庙还是很多传统家庭）；接受食物或礼物时用右手；用双手接受长辈给予的东西表示尊重','要求主人先脱鞋才能进入','在进入前须洗手消毒'],a:1,e:'印度礼仪：①脱鞋（Remove shoes）是进入寺庙和很多家庭的必须礼节；神庙入口通常有鞋架或指定脱鞋区域②右手接受食物、握手，左手不洁③访问家庭可带小礼物（鲜花、糖果，但不带酒——很多印度家庭不饮酒）④避免用头（点头）表示摇头的意思（印度的摇头/点头文化与中国相反）。'},
  {c:'出国',q:'在坦桑尼亚（Tanzania）和肯尼亚（Kenya），见到斯瓦希里语（Swahili）问候"Jambo"，正确的回应是？',o:['说"Hello"即可','说"Sijambo"（我很好，没问题）或也说"Jambo"回应，即可建立友好的初次接触','说"Hakuna Matata"（这是歌曲台词）','保持沉默，点头即可'],a:1,e:'"Jambo"（=你好）是斯瓦希里语的日常问候，在坦桑尼亚和肯尼亚广泛使用。标准回应是"Sijambo"（我很好）。其他实用斯瓦希里语：Asante=谢谢，Asante sana=非常感谢，Karibu=欢迎，Kwaheri=再见。掌握几句当地语言会让非洲当地人眼前一亮，倍感亲切！'},
  {c:'出国',q:'在中东旅行，遇到穆斯林祈祷时间（Prayer time）应该注意什么？',o:['继续大声交谈和活动，不用理会','商店可能暂时关闭、交通可能短暂减少；穆斯林每天有5次祷告时间；若在户外遇到，保持安静和尊重，不要打断正在礼拜的人','所有公共场所全面关闭，旅客无法活动','只有周五（聚礼日）才有祷告时间影响'],a:1,e:'伊斯兰五次祷告（Salat）：晨礼、晌礼、晡礼、昏礼、宵礼——每次约15-30分钟，很多商店和餐厅会在此期间临时关闭（尤其在沙特、卡塔尔等保守国家）。周五午间聚礼（Jumu\'ah）影响最大，不少商店关闭2小时。旅行时了解当日祷告时间（当地报纸或App可查），合理安排行程。'},
  {c:'出国',q:'在西方国家，遇到陌生人时如何避免讨论"禁忌话题"？',o:['直接询问对方收入和政治立场作为开场白','普遍公认的敏感话题包括：政治（Political views）、宗教（Religion）、个人收入（Income）、体重外貌（Weight）；相对安全的话题：天气、旅行经历、当地美食、职业（笼统介绍）','在西方国家没有禁忌话题，任何问题都可以问','谈论对方国家的历史负面事件是好的开场白'],a:1,e:'跨文化交流禁忌话题：政治立场（尤其在选举年）、宗教信仰、个人收入/财富、体重/外貌、年龄（对某些文化的女性）、婚姻状况（带有评判含义时）。安全话题：What brings you here?（你来这里干什么？）、Have you tried the local food?（你尝过当地食物吗？）这些问题既友好又无冒犯风险。'},
  {c:'出国',q:'在欧洲很多国家，用餐结束时如何礼貌地结账？',o:['直接起身去收银台付款','向服务员做出书写姿势（模拟在空中签字）或说"L\'addition, s\'il vous plaît"（法语）/ "Il conto, per favore"（意大利语）/ "Die Rechnung, bitte"（德语）/ "Can we have the bill, please?"（英语）','大声呼叫服务员的名字','在餐桌上留下现金悄悄离开'],a:1,e:'在欧洲大多数国家，结账时：①不要离开餐桌自己去付款（不礼貌）②向服务员示意（视线接触+举手或模拟签字手势）③说当地语言的"结账请"：法语：L\'addition！意语：Il conto！西语：La cuenta！德语：Die Rechnung！葡语：A conta！英语永远是backup option在大多数旅游城市都管用。'}
);

